INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80007, 'Polodowcowe / Sielawowe', 3030, 10.6, 37.6, 'Niezwykle urozmaicone. Kluczowe są podwodne górki, zwłaszcza te w okolicy Pieczarek i wschodniej części jeziora, gdzie dno gwałtownie podnosi się z 15-20m na 2-4m. Znajdziemy tu też głębokie rynny i rozległe blaty sielawowe.', 'W przeważającej części twarde: piaszczyste, żwirowe i usłane kamieniami (uwaga na śruby silników przy górkach!). Muł występuje jedynie w najgłębszych rynnach oraz w osłoniętych zatokach.', 'Bardzo wysoka (standardowo 3-5m). Woda ma charakterystyczny, błękitno-zielony odcień, co wymusza na wędkarzach stosowanie długich przyponów z fluorocarbonu.', 'Bogate łąki podwodne (ramienice, rdestnice) sięgające nawet 5-6 metrów głębokości. Pas trzcin jest gęsty, ale poprzecinany licznymi wejściami i zatoczkami, szczególnie w południowej części przy przejściu na jezioro Kisajno.', 'Szczupak (często okazy 100cm+), Okoń (tzw. "garbusy" z górtek), Sielawa, Sieja, Sandacz, Leszcz, Węgorz', TRUE, 'Intensywne zarybienia prowadzone przez PZW Suwałki: regularnie wpuszczany narybek szczupaka i sandacza, a także podchowana sielawa, która stanowi bazę pokarmową drapieżników.', TRUE, 'Zezwolenie PZW Suwałki. Cena ok. 350-450 zł za cały rok (łódź + trolling). Dostępne e-zezwolenia okresowe (1, 3, 7-dniowe) w systemie online PZW.', FALSE, FALSE, 'Bardzo utrudnione. Linia brzegowa jest dzika i niedostępna. Realne szanse na wędkowanie z brzegu tylko w Pieczarkach, okolicach portu w Sztynortcie lub na nielicznych kempingach.', TRUE, TRUE, 'Bardzo dobry dojazd od strony Giżycka przez Pierkunowo lub od północy przez Pieczarki i Harsz. Drogi asfaltowe prowadzą blisko linii brzegowej w wyznaczonych punktach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80016, 'Leszczowo-szczupakowe', 140, 4.8, 12.5, 'Stosunkowo płaskie, ale z wyraźnymi "rynienkami" i korytami wzdłuż szlaku żeglownego. Charakterystyczne są rozległe blaty o głębokości 2-4 metrów, które jesienią stają się najlepszymi łowiskami szczupaka.', 'W większości miękkie, pokryte warstwą mułu i detrytusu, jednak w pasie przybrzeżnym i na niektórych blatach spotyka się twarde, piaszczyste placki, które uwielbiają okonie.', 'Średnia (ok. 1.5 - 2.5m). Woda szybciej "zakwita" niż na głównym plosie Mamr, co w upalne lato ogranicza widoczność, ale sprzyja maskowaniu się drapieżników.', 'Ekstremalnie bogata. Jezioro słynie z gigantycznych łąk podwodnych (moczaraka kanadyjska, rdestnica), które latem potrafią sięgać niemal samej powierzchni. Szeroki pas trzcin tworzy doskonałe kryjówki dla lina i białej ryby.', 'Szczupak (bardzo liczna populacja), Lin, Karaś srebrzysty, Okoń, Leszcz, Wzdręga', TRUE, 'Intensywne zarybienia szczupakiem. Naturalne tarło sandacza zachodzi tu rzadziej, ale ryba ta często wpływa z głębszego Darginu na nocne żerowania.', TRUE, 'Zezwolenie PZW Suwałki (wspólne z Jeziorem Mamry/Dargin). Koszt ok. 350-450 zł/rok (łódź + trolling). Możliwość zakupu zezwoleń krótkookresowych online.', FALSE, FALSE, 'Praktycznie niemożliwe z brzegu. Cała linia brzegowa to gęste trzcinowiska i podmokłe tereny. Wymagana łódź lub ponton.', TRUE, TRUE, 'Dojazd drogą asfaltową do Sztynortu, gdzie znajdują się profesjonalne porty, slipy i wypożyczalnie jednostek pływających.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80017, 'Sielawowe / Mezotroficzne', 1776, 7.8, 22.5, 'Urozmaicone, z licznymi głęboczkami i rozległymi płyciznami wokół wysp. Charakterystyczne są "kamieniska" – podwodne rafy z głazów narzutowych, które są kapitalnymi miejscówkami okoniowymi.', 'W strefie przybrzeżnej i na górkach twarde, piaszczysto-kamieniste. W rynnach i osłoniętych zatokach (np. Zatoka Plociczna) dno staje się miękkie i muliste.', 'Wybitna (często przekracza 4-5m). Woda jest krystaliczna, co sprawia, że ryby są tu bardzo płochliwe i wymagają od wędkarza niezwykłej finezji oraz cienkich przyponów.', 'Bardzo bogata. Jezioro słynie z gigantycznych łąk ramienicowych, które pokrywają dno nawet na głębokości 6 metrów. Szeroki pas trzcin jest niemal nienaruszony przez cywilizację.', 'Szczupak, Okoń (często złote, "kamieniste" garbusy), Leszcz, Lin, Płoć, Sielawa', TRUE, 'Zarybienia są ograniczone ze względu na status rezerwatu, jednak PZW Suwałki prowadzi zrównoważoną gospodarkę, wspierając populację szczupaka i sielawy.', TRUE, 'Zezwolenie PZW Suwałki (uwaga: trolling na Dobskim jest często dodatkowo uregulowany lub zabroniony – należy sprawdzić aktualny regulamin szczegółowy na dany rok).', FALSE, TRUE, 'Ekstremalnie trudne i w wielu miejscach zabronione (rezerwat). Wędkowanie z brzegu możliwe właściwie tylko w okolicach miejscowości Doba i Fuleda.', FALSE, TRUE, 'Dojazd utwardzony do miejscowości Doba (tam znajduje się port i parking) oraz do Fuledy (drogi szutrowe).', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80015, 'Eutroficzne / Szczupakowo-linowe', 48.5, 1.4, 3.1, 'Dno przypomina płytką misę. Brak wyraźnych góry podwodnych, jednak kluczowe są koryta i zagłębienia w pobliżu wejścia do kanału sztynorckiego oraz pasy wolnej wody między polami roślinności.', 'Silnie zamulone. Gruba warstwa osadów organicznych pokrywa niemal całe dno, co jest rajem dla lina i karasia, ale utrudnia łowienie klasycznym opadem.', 'Niska (ok. 0.8 - 1.5m). Woda ma charakterystyczny, ciemniejszy odcień ze względu na dużą ilość zawiesiny organicznej i płytkość akwenu.', 'Ekstremalna. Jezioro niemal w całości pokryte jest "podwodną dżunglą" (wywłócznik, moczarka). Na powierzchni dominują rozległe pola grążeli i lilii wodnych. Brzegi to niedostępne trzęsawiska i gęste trzcinowiska.', 'Szczupak (tzw. "pistolety", ale trafiają się i "mamuśki"), Lin (populacja medalowa), Karaś złocisty, Okoń, Wzdręga', TRUE, 'Jezioro zarybiane głównie narybkiem szczupaka. Stanowi naturalne tarlisko dla wielu gatunków ryb z systemu Mamr dzięki połączeniu z jeziorem Łabap.', TRUE, 'Zezwolenie PZW Suwałki (wspólne na cały kompleks). Ok. 350-450 zł/rok (łódź). Możliwe zezwolenia okresowe online.', FALSE, FALSE, 'Praktycznie niemożliwe z brzegu poza terenem samej mariny w Sztynortcie. Całość linii brzegowej to tereny bagienne i trzcinowiska.', TRUE, TRUE, 'Dojazd asfaltowy do samego Sztynortu. Na miejscu ogromne parkingi, pełna infrastruktura turystyczna i profesjonalne slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80072, 'Sandaczowo-leszczowe', 128, 6.5, 18.2, 'Wybitnie rynnowe, o stromych stokach i wyraźnej rynnie centralnej.', 'Głównie twarde, piaszczysto-żwirowe, kamieniste na spadach.', 'Bardzo wysoka (3.0 - 5.0m). Woda przejrzysta, o błękitnym zabarwieniu.', 'Umiarkowana. Wąski pas trzciny. Bogate łąki ramienicowe pod wodą.', 'Sandacz, Okoń, Szczupak, Leszcz, Płoć, Węgorz', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem przez GR Ostróda.', TRUE, 'Zezwolenie GR Ostróda (Jeziora Brodnickie).', FALSE, TRUE, 'Trudne. Brzegi wysokie i zalesione. Najlepiej łowić z łodzi.', FALSE, TRUE, 'Dobry dojazd do miejscowości Głowin, dalej drogi leśne.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80008, 'Linowo-szczupakowe', 211, 2, 5.8, 'Płytka misa z wyraźnym rynnowym pogłębieniem wzdłuż szlaku żeglownego. Średnia głębokość to ok. 2m, co sprzyja szybkemu nagrzewaniu się wody wiosną.', 'W większości muliste i miękkie. Twardsze, piaszczysto-żwirowe fragmenty występują jedynie w nurcie pod mostem sztynorckim.', 'Przeciętna (1.5-2m). Latem woda szybko zakwita. Duża ilość zawiesiny organicznej ze względu na charakter jeziora.', 'Potężne łąki podwodne (rdestnica, moczarka) i połacie grążeli. Trzcinowiska bardzo szerokie, tworzące liczne, niedostępne zatoczki.', 'Szczupak, Lin, Karaś złocisty, Okoń, Wzdręga, Leszcz', TRUE, 'Zarybienia szczupakiem i linem. Naturalne tarlisko ryb z całego kompleksu Mamr.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 300-450 zł/rok (łódź). Dostępne e-zezwolenia.', FALSE, FALSE, 'Bardzo utrudnione. Możliwe tylko z okolic mostu sztynorckiego. Wymagana łódź.', FALSE, TRUE, 'Asfalt do Sztynortu lub Harszu. Bezpośredni dostęp do brzegu bardzo ograniczony.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80018, 'Linowo-szczupakowe', 211, 2, 5.8, 'Płytka misa z wyraźnym pogłębieniem wzdłuż szlaku żeglownego. Liczne płycizny i rozległe blaty zarośnięte roślinnością zanurzoną. Brak gwałtownych uskoków terenu poza rynną toru wodnego.', 'Głównie miękkie, muliste z grubą warstwą osadów. Twardsze, piaszczyste dno występuje miejscami jedynie w nurcie pod mostem sztynorckim oraz na środku toru wodnego.', 'Średnia (1.5-2m). Latem woda szybko zakwita. Duża ilość zawiesiny organicznej ze względu na charakter jeziora.', 'Ekstremalnie bogata. Połacie grążeli, moczarka i rdestnica pokrywają większość dna. Brzegi to niedostępne, szerokie pasy trzcin tworzące bezpieczne kryjówki dla ryb.', 'Szczupak, Lin, Karaś złocisty, Okoń, Leszcz', TRUE, 'Zarybienia szczupakiem i linem. Naturalne tarlisko kompleksu Mamr.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 300-450 zł/rok (łódź). E-zezwolenia online.', FALSE, FALSE, 'Bardzo utrudnione. Możliwe jedynie w okolicach mostu sztynorckiego. 95% linii brzegowej niedostępne z lądu z powodu bagien i trzcin.', FALSE, TRUE, 'Asfalt do Sztynortu lub Harszu. Dojazd do samego brzegu mocno ograniczony.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80019, 'Leszczowo-szczupakowe', 40.5, 2.5, 5, 'Dno o charakterze misowatym, dość wyrównane, z łagodnym spadkiem w kierunku przesmyku łączącego z Mamrami. Najgłębsze punkty znajdują się w środkowej części akwenu.', 'Przeważnie muliste z dużą ilością detrytusu. W strefie przybrzeżnej oraz w pobliżu połączenia z głównym plosem dno staje się twardsze, piaszczyste.', 'Średnia (1.5 - 2.0m). Woda o zielonkawym odcieniu, typowa dla żyznych jezior. Przejrzystość wzrasta wiosną i późną jesienią.', 'Bogata roślinność zanurzona: moczarka i rdestnica tworzą gęste kępy. Brzegi porośnięte szerokim pasem trzcin i grążeli, szczególnie w zachodniej części.', 'Szczupak, Okoń, Leszcz, Płoć, Lin', TRUE, 'Zarybiane regularnie narybkiem szczupaka i lina przez PZW Suwałki w ramach gospodarki na kompleksie Mamr.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks). Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia online.', FALSE, FALSE, 'Możliwe w kilku punktach od strony miejscowości Pniewo, jednak większość linii brzegowej wymaga łodzi lub pontonu.', TRUE, TRUE, 'Dojazd drogą asfaltową do miejscowości Pniewo, następnie drogami gruntowymi pod samą linię brzegową w wyznaczonych miejscach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80020, 'Polodowcowe / Sielawowe', 2504, 11, 43.8, 'Ekstremalnie urozmaicone: potężne góry podwodne, strome spady schodzące do 40m oraz rozległe blaty sielawowe. Charakterystyczne są kamieniste rafy wokół wysp, będące domem dla wielkich okoni.', 'Przeważnie twarde: piasek, żwir i liczne głazy narzutowe. Grubsza warstwa mułu zalega jedynie w najgłębszych rynnach i osłoniętych zatokach.', 'Wybitna (3.5 - 5.5m). Woda ma błękitny odcień. Przy flaucie dno widać na kilku metrach, co wymusza stosowanie długich i cienkich przyponów z fluorocarbonu.', 'Bogate łąki ramienicowe sięgające głęboko (nawet do 7m). Pas trzcin jest szeroki, poprzecinany zatokami i przesmykami między wyspami (np. Upałty).', 'Szczupak, Okoń, Sielawa, Sieja, Sandacz, Miętus, Węgorz', TRUE, 'Regularne i intensywne zarybienia sielawą, sieją oraz szczupakiem i sandaczem prowadzone przez PZW Suwałki.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź + trolling). Dostępne e-zezwolenia okresowe online.', FALSE, FALSE, 'Utrudnione. Możliwe w rejonie Węgorzewa, miejscowości Kal i na nielicznych dzikich plażach. Zdecydowana większość brzegów dostępna tylko z łodzi.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy do Węgorzewa, Kal oraz Trygortu. Liczne mariny z profesjonalnymi slipami i parkingami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80021, 'Leszczowo-szczupakowe', 70, 2.8, 6.5, 'Dno o charakterze misowatym z łagodnymi spadami. Brak gwałtownych uskoków i podwodnych gór. Najgłębsze miejsca znajdują się w środkowej części akwenu, tworząc podłużną rynnę.', 'W przeważającej części miękkie, muliste, z dużą ilością osadów organicznych. Twardsze, piaszczyste fragmenty dna występują jedynie w strefie przybrzeżnej i przy plaży wiejskiej.', 'Średnia (1.2 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla żyznych jezior. Przejrzystość wzrasta wyraźnie wczesną wiosną oraz późną jesienią po opadnięciu roślinności.', 'Bardzo bogata. Szeroki pas trzcin, liczne pola grążeli żółtych oraz gęste podwodne łąki z moczarki i rdestnicy, które latem sięgają niemal powierzchni wody.', 'Szczupak, Lin, Okoń, Leszcz, Płoć', TRUE, 'Zarybiane regularnie przez PZW Suwałki narybkiem szczupaka i lina. Stabilna populacja ryb spokojnego żeru dzięki dużej ilości bazy pokarmowej.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks). Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia online oraz w sklepach wędkarskich w Węgorzewie.', FALSE, TRUE, 'Możliwe w kilku wyznaczonych punktach, m.in. w rejonie plaży wiejskiej w Węgielsztynie. Większość linii brzegowej niedostępna bez środków pływających.', TRUE, TRUE, 'Dojazd drogami asfaltowymi i gruntowymi do miejscowości Węgielsztyn. Wygodny dostęp do brzegu od południowej strony jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80022, 'Leszczowo-szczupakowe', 490.3, 3.5, 16.7, 'Urozmaicone, z licznymi głęboczkami i rozległymi wypłyceniami wokół wysp. Środkowa część głębsza, przechodząca w rynnę. Liczne podwodne przeszkody w postaci zwalonych drzew przy brzegach.', 'Głównie muliste i miękkie, jednak w okolicach wysp i na stokach rynny dno bywa twardsze, piaszczysto-żwirowe. Duża ilość osadów organicznych w zatokach.', 'Średnia (1.5 - 2.0m). Woda o barwie zielono-żółtej, co wynika z wysokiej żyzności akwenu. Najlepsza przejrzystość występuje wiosną.', 'Bardzo obfita. Szeroki pas trzcin i sitowia. Na płyciznach gęste łąki rdestnic i moczarki. W zatokach rozległe pola grążeli i lilii wodnych, stanowiące doskonałe kryjówki dla drapieżników.', 'Szczupak, Sandacz, Leszcz, Lin, Okoń, Węgorz', TRUE, 'Regularnie zarybiane przez PZW Suwałki szczupakiem, sandaczem oraz linem. Naturalne tarlisko i ostoja dla ptactwa wodnego, co sprzyja stabilnemu ekosystemowi.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Dostępne zezwolenia okresowe przez portal E-Zezwolenia.', FALSE, TRUE, 'Utrudnione ze względu na status rezerwatu i gęste trzcinowiska. Możliwe w wyznaczonych punktach przy miejscowości Pniewo i w rejonie śluzy.', TRUE, TRUE, 'Dojazd drogami asfaltowymi do miejscowości Pniewo i Rydzówka. Dalej drogi szutrowe prowadzące do brzegów i pól namiotowych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80116, 'Sielawowe', 68.8, 8.5, 23, 'Rynnowe, strome spady, twarde dno.', 'Piaszczysto-żwirowe, kamieniste.', 'Bardzo wysoka (4-6m)', 'Umiarkowana (łąki ramienicowe).', 'Sielawa, Szczupak, Okoń, Leszcz', TRUE, 'Zarybiane sielawą i szczupakiem.', TRUE, 'PZW Włocławek (zezw. nizinne).', FALSE, TRUE, 'Trudne (strome brzegi).', TRUE, TRUE, 'Dobry dojazd do miejscowości Ostrowite.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80088, 'Linowo-szczupakowe', 11.8, 1.5, 4.2, 'Typowo rynnowe, o bardzo wąskiej i wydłużonej niecce. Dno ulega naturalnemu procesowi wypłycania.', 'Miękkie, mulisto-torfowe. Gruba warstwa osadów organicznych na przeważającej powierzchni dna.', 'Niska/Średnia (0.8 - 1.5m). Woda o zielonkawym odcieniu, typowa dla zbiorników o wysokiej trofii.', 'Ekstremalnie bogata. Brzegi porośnięte gęstą trzciną. Na tafli liczne skupiska grążeli. Pod wodą gęste lasy moczarki.', 'Karaś złocisty, Lin, Szczupak, Płoć, Okoń', TRUE, 'Naturalna regeneracja populacji. Okresowe zarybienia szczupakiem w ramach gospodarki obwodowej.', TRUE, 'Zezwolenie GR Mrągowo. Te same zasady co na jeziorze Wągiel i Jeleń.', FALSE, TRUE, 'Bardzo utrudnione. Brzegi bagniste i porośnięte krzewami. Brak pomostów.', FALSE, TRUE, 'Utrudniony. Dojazd wyłącznie drogami polnymi i leśnymi od strony drogi nr 59. Drogi bywają grząskie po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80023, 'Leszczowo-szczupakowe', 119.5, 4.5, 15.5, 'Urozmaicone z łagodnymi spadami i wyraźnym rynnowym zagłębieniem w środkowej części. Liczne płycizny przybrzeżne porośnięte roślinnością tworzą naturalne tarliska i schronienia dla ryb.', 'W strefie przybrzeżnej przeważnie piaszczyste i twarde. W głębszych partiach oraz zatokach dno staje się miękkie, pokryte warstwą mułu i osadów organicznych.', 'Średnia (ok. 1.5 - 2.5m). Woda o zielonkawym odcieniu. Latem przejrzystość może spadać ze względu na zakwity planktonu, co sprzyja maskowaniu się drapieżników.', 'Bardzo obfita. Szeroki pas trzcin, liczne pola grążeli oraz gęste podwodne łąki (moczarka, rdestnica). Roślinność zanurzona sięga tu do około 4-5 metrów głębokości.', 'Szczupak, Okoń, Leszcz, Lin, Węgorz, Płoć', TRUE, 'Regularnie zarybiane przez PZW Suwałki narybkiem szczupaka i lina. Stabilna populacja ryb dzięki dużej dostępności naturalnego pokarmu w strefie roślinności.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online oraz w punktach stacjonarnych.', FALSE, FALSE, 'Możliwe w wielu punktach od strony miejscowości Silec i Solanka. Liczne kładki wędkarskie ułatwiają dostęp do czystej wody.', TRUE, TRUE, 'Dobra dostępność od strony wsi Silec. Drogi asfaltowe i utwardzone szutry prowadzą blisko linii brzegowej.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80024, 'Eutroficzne / Szczupakowo-linowe', 58, 2.5, 6.5, 'Dno o regularnym kształcie misy, bez gwałtownych uskoków. Większość akwenu to rozległe płycizny o głębokości do 3 metrów. Najgłębsze punkty znajdują się w środkowej części jeziora.', 'W przeważającej części bardzo miękkie, z grubą warstwą mułu i osadów dennych. Twardsze fragmenty występują jedynie punktowo w strefie przybrzeżnej od strony wschodniej.', 'Niska (0.8 - 1.5m). Woda o brunatno-zielonym zabarwieniu ze względu na dużą ilość substancji organicznych. Latem przejrzystość mocno ograniczona przez zakwity planktonu.', 'Ekstremalnie obfita. Ponad połowa dna pokryta łąkami moczarki. Olbrzymie pola grążeli i lilii wodnych. Brzegi niedostępne, porośnięte gęstymi trzcinowiskami i krzewami.', 'Szczupak, Lin, Karaś złocisty, Okoń, Płoć, Leszcz', TRUE, 'Zarybiane regularnie narybkiem szczupaka i lina przez PZW Suwałki. Bardzo dobra naturalna regeneracja populacji ryb spokojnego żeru.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). E-zezwolenia dostępne online oraz w kołach PZW w Kętrzynie.', FALSE, FALSE, 'Bardzo utrudnione. Linia brzegowa podmokła i niedostępna. Wędkowanie z brzegu możliwe tylko z nielicznych, prywatnych kładek lub wyciętych stanowisk.', FALSE, TRUE, 'Dojazd drogami polnymi i leśnymi od miejscowości Siniec. Wymagany pojazd o wyższym zawieszeniu, szczególnie po opadach deszczu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80025, 'Eutroficzne / Stawowe', 1100, 1, 3.5, 'Płaskie, misowate dno z nielicznymi zagłębieniami. Cały akwen jest bardzo płytki, co sprzyja szybkiemu zarastaniu i powstawaniu wysp pływających (pła). Brak gwałtownych spadków dna.', 'Wyłącznie miękkie, silnie zamulone. Gruba warstwa osadów organicznych i detrytusu pokrywa niemal 100% powierzchni dna, tworząc trudne warunki do poruszania się jednostek.', 'Niska (0.5 - 1.2m). Woda o dużej zawartości zawiesiny organicznej, często mętna i silnie zakwitająca latem. Przejrzystość wzrasta jedynie wczesną wiosną.', 'Ekstremalnie bogata. Olbrzymie pola trzcin, tataraku i grążeli. Roślinność zanurzona wypełnia niemal całą objętość wody, tworząc gęste podwodne dżungle.', 'Szczupak, Lin, Karaś złocisty, Leszcz, Płoć', TRUE, 'Brak regularnych zarybień ze względu na status rezerwatu ścisłego. Populacja oparta na naturalnym tarle w idealnych warunkach środowiskowych.', TRUE, 'Akwen objęty ochroną rezerwatową. Wędkowanie zazwyczaj całkowicie zabronione lub wymagające specjalnych zgód RDOŚ. Należy sprawdzić aktualny regulamin.', FALSE, TRUE, 'Niemożliwe. Brzegi bagniste, niedostępne i chronione jako rezerwat. Brak wyznaczonych stanowisk do wędkowania z lądu.', FALSE, FALSE, 'Dojazd utrudniony drogami gruntowymi do granicy rezerwatu w okolicach miejscowości Zielony Ostrów i Pasternak.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80026, 'Polodowcowe / Sielawowe', 813.8, 9.4, 28, 'Bardzo urozmaicone: gwałtowne spady, liczne głęboczki oraz rozległe, twarde blaty. Na wschodzie dno opada stromo, tworząc rynny przekraczające 25m głębokości. Charakterystyczne kamieniste rafy wzdłuż północnego brzegu.', 'Głównie twarde, piaszczysto-żwirowe z licznymi kamienistymi "górkami". W najgłębszych rynnach i osłoniętych zatokach (np. Zatoka Ogończyk) dno staje się miękkie i muliste.', 'Wybitna (3.0 - 5.0m). Woda o błękitnym odcieniu, bardzo czysta (I klasa). Wysoka przejrzystość wymusza na wędkarzach stosowanie bardzo dyskretnych i cienkich zestawów fluorocarbonowych.', 'Umiarkowana wzdłuż brzegów. Wąski pas trzcin, liczne łąki ramienicowe i rdestnice sięgające do 6m głębokości. Roślinność wynurzona najlepiej rozwinięta w południowej i zachodniej części jeziora.', 'Szczupak, Okoń, Sielawa, Sieja, Sandacz, Leszcz, Węgorz', TRUE, 'Intensywne i regularne zarybienia sielawą oraz sieją. Systematycznie wspierana populacja drapieżników (szczupak, sandacz) przez PZW Suwałki.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks Mamr). Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online.', FALSE, FALSE, 'Dobre w okolicach miejscowości Ogonki i w samym Węgorzewie. Liczne pomosty i ogólnodostępne plaże z twardym dnem.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy (droga krajowa nr 63) do miejscowości Ogonki, która leży bezpośrednio nad brzegiem jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80027, 'Leszczowo-szczupakowe', 409, 3.2, 12.5, 'Urozmaicone, z wyraźnymi rynnami w części środkowej i licznymi wypłyceniami. Linia brzegowa bardzo rozwinięta, tworząca liczne zatoki będące naturalnymi kryjówkami ryb.', 'Przeważnie miękkie i muliste, z dużą warstwą osadów organicznych. Twardsze, piaszczyste dno występuje punktowo przy przesmykach oraz na wybranych blatach w zachodniej części.', 'Średnia (1.0 - 2.0m). Woda o specyficznym zielonkawym zabarwieniu, typowa dla jezior o wysokiej żyzności. Przejrzystość wzrasta jesienią.', 'Bardzo silnie rozwinięta. Gęste łąki podwodne rdestnic i moczarki sięgające do 4m. Rozległe pola grążeli oraz szeroki, niemal nieprzerwany pas trzcin i oczeretów.', 'Szczupak, Sandacz, Lin, Leszcz, Węgorz, Okoń', TRUE, 'Regularne zarybienia szczupakiem, sandaczem oraz węgorzem prowadzone przez PZW Suwałki. Bardzo silna naturalna populacja lina i dużego leszcza.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks). Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online.', FALSE, FALSE, 'Bardzo utrudnione. Brzegi w większości bagniste i niedostępne. Wędkowanie z lądu możliwe tylko z nielicznych kładek i pomostów prywatnych.', TRUE, TRUE, 'Dojazd drogami asfaltowymi do miejscowości Ogonki i Stręgiel, dalej drogi szutrowe i polne prowadzące do nielicznych zjazdów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80083, 'Sielawowo-leszczowe', 176, 5.5, 13.8, 'Urozmaicone, z licznymi łagodnymi rynnami i piaszczystymi blatami. Brak gwałtownych uskoków, ale dno jest pofalowane.', 'W przeważającej części twarde, piaszczysto-żwirowe. W głębszych partiach i zatokach cienka warstwa mułu sielawowego.', 'Bardzo wysoka (3.0 - 5.0m). Woda krystaliczna, o błękitnym odcieniu, bardzo dobrze natleniona.', 'Bogata podwodna. Rozległe łąki ramienicowe sięgające głęboko. Pas trzcin dość wąski, ale zwarty.', 'Szczupak, Okoń, Leszcz, Sielawa, Płoć, Węgorz', TRUE, 'Systematycznie zarybiane szczupakiem i sielawą przez Gospodarstwo Rybackie w Mrągowie.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w sklepach wędkarskich w Mrągowie.', FALSE, TRUE, 'Możliwe z licznych pomostów i piaszczystych zejść przy ośrodkach wypoczynkowych.', TRUE, TRUE, 'Bardzo dobry dojazd drogą nr 59, a następnie lokalnymi asfaltami do miejscowości nadbrzeżnych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80028, 'Linowo-szczupakowe', 55, 2.1, 5.4, 'Dno o regularnym, misowatym kształcie z lekkim pogłębieniem wzdłuż nurtu przepływającej Sapiny. Brak gwałtownych spadów, dominują rozległe blaty o głębokości 2-3 metrów.', 'Przeważnie miękkie, muliste, ale dzięki przepływowi rzeki w wielu miejscach dno jest "przepłukane" i twardsze (piaszczyste). Liczne powalone pnie drzew przy brzegach.', 'Bardzo dobra (2.5 - 4.0m). Woda przejrzysta, o lekko brunatnym, torfowym odcieniu, co sprzyja maskowaniu się drapieżników w podwodnej roślinności.', 'Bujna. Brzegi otoczone pasem trzcin i wysokich traw. Na dnie gęste dywany ramienic, a w zatokach malownicze pola lilii wodnych i grążeli.', 'Szczupak, Lin, Okoń, Płoć, Leszcz, Wzdręga', TRUE, 'Zarybiane szczupakiem i linem. Naturalna migracja ryb z jezior Stręgiel i Gołdapiwo przez rzekę Sapinę zapewnia dużą różnorodność gatunkową.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia krótkookresowe przez system online.', FALSE, FALSE, 'Utrudnione ze względu na leśny, bagnisty charakter brzegów. Najlepiej łowić z łodzi lub pontonu. Możliwe nieliczne stanowiska przy ujściu rzeki.', TRUE, TRUE, 'Dojazd drogami szutrowymi i leśnymi od strony miejscowości Przerwanki. Wymagana ostrożność po opadach deszczu (możliwe piaszczyste koleiny).', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80029, 'Linowo-szczupakowe', 23, 1.8, 4.5, 'Dno o regularnym, misowatym kształcie, bez wyraźnych spadków. Większość powierzchni to płycizny do 2 metrów głębokości. Woda osłonięta od wiatru przez wysoki las, co sprzyja żerowaniu ryb spokojnego żeru.', 'Przeważnie bardzo miękkie, pokryte grubą warstwą mułu i detrytusu organicznego. W nielicznych miejscach przy brzegach piaszczyste naloty.', 'Średnia (ok. 1.0 - 2.0m). Woda o lekko torfowym, ciemniejszym zabarwieniu ze względu na leśne otoczenie. Przejrzystość wzrasta wyraźnie jesienią.', 'Bardzo obfita. Brzegi niemal w całości niedostępne, porośnięte trzciną. Na tafli liczne pola grążeli żółtych. Pod wodą gęste kępy rdestnic i moczarki.', 'Szczupak, Lin, Karaś złocisty, Okoń, Płoć', TRUE, 'Zarybiane narybkiem szczupaka i lina przez PZW Suwałki. Stabilna populacja ryb dzięki naturalnej migracji rzeką Sapiną łączącą jeziora kompleksu.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online przez portal PZW.', FALSE, TRUE, 'Ekstremalnie utrudnione. Linia brzegowa podmokła i leśna. Wędkowanie z brzegu możliwe właściwie tylko z kilku wyciętych stanowisk.', FALSE, TRUE, 'Dojazd drogami leśnymi i szutrowymi od strony miejscowości Stręgiel lub Przerwanki. Wymagana ostrożność, drogi mogą być piaszczyste.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80030, 'Linowo-szczupakowe', 38, 2.1, 4.8, 'Dno misowate, dość płaskie z łagodnymi spadami. Brak gwałtownych uskoków. Większość akwenu to rozległe wypłycenia sprzyjające rozwojowi roślinności zanurzonej.', 'Przeważnie piaszczysto-muliste. W porównaniu do sąsiednich jezior dno jest jaśniejsze i twardsze w strefie przybrzeżnej, co znajduje odzwierciedlenie w nazwie jeziora.', 'Dobra (2.0 - 3.5m). Woda jest czystsza niż w Jeziorze Stręgiel, z mniejszą zawartością zawiesiny organicznej, co ułatwia obserwację ryb na płyciznach.', 'Bogata. Pas trzcin i sitowia wokół brzegów. Liczne pola grążeli oraz podwodne łąki ramienic i rdestnic. Roślinność tworzy idealne warunki dla drapieżników.', 'Szczupak, Lin, Okoń, Płoć, Karaś złocisty', TRUE, 'Zarybiane szczupakiem i linem przez PZW Suwałki. Naturalna migracja ryb rzeką Sapiną zapewnia stały dopływ nowych osobników i różnorodność genetyczną.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online oraz w kołach PZW.', FALSE, TRUE, 'Utrudnione. Brzegi w większości bagniste i zarośnięte. Dostępne jedynie nieliczne wycięte stanowiska oraz kładki przy miejscowościach i kempingach.', TRUE, TRUE, 'Dojazd drogami szutrowymi i polnymi od strony miejscowości Stręgiel lub Przerwanki. Wymagana ostrożność po opadach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80009, 'Linowo-szczupakowe', 18, 1.5, 4, 'Dno misowate, wyrównane, bez gwałtownych uskoków. Wzdłuż osi jeziora ciągnie się lekkie pogłębienie stanowiące koryto rzeki Sapiny. Większość akwenu to rozległe płycizny sprzyjające tarliskom.', 'Wybitnie miękkie i muliste. Gruba warstwa osadów organicznych i detrytusu. Twardsze, piaszczyste miejsca występują jedynie przy wlocie i wylocie rzeki Sapiny oraz punktowo przy nielicznych kładkach.', 'Średnia (1.0 - 1.5m). Woda o zielonkawym zabarwieniu, bogata w plankton. Przejrzystość wzrasta jesienią po obumarciu roślinności zanurzonej. Typowa woda eutroficzna.', 'Bardzo silnie rozwinięta. Szeroki pas trzcin, liczne pola grążeli i lilii wodnych. Pod wodą gęste dywany moczarki i rdestnic, które latem sięgają niemal powierzchni, utrudniając pływanie jednostek.', 'Szczupak, Lin, Karaś złocisty, Okoń, Płoć', TRUE, 'Regularne zarybienia szczupakiem i linem. Jezioro zasilane naturalnie rybami migrującymi rzeką Sapiną z sąsiednich, większych akwenów kompleksu Mamr.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). E-zezwolenia dostępne online oraz w punktach sprzedaży w Pozezdrzu i Węgorzewie.', FALSE, TRUE, 'Bardzo utrudnione. Brzegi bagniste, zarośnięte i trudnodostępne. Wędkowanie z lądu możliwe tylko z nielicznych kładek lub wyciętych stanowisk przy ścieżkach leśnych.', FALSE, TRUE, 'Dojazd drogami leśnymi i polnymi od miejscowości Ogonki lub Pozezdrze. Wymagana ostrożność po opadach, drogi mogą być grząskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80010, 'Linowo-szczupakowe', 15, 1.2, 3.5, 'Dno płaskie, misowate, z lekkim rynnowym pogłębieniem wzdłuż nurtu rzeki Sapiny. Większość jeziora to rozległe wypłycenia, które latem niemal całkowicie zarastają roślinnością zanurzoną.', 'Głównie miękkie, silnie zamulone. Gruba warstwa osadów organicznych. Twardsze, piaszczyste miejsca występują jedynie punktowo w nurcie rzeki przy wlocie i wylocie z jeziora.', 'Niska (0.8 - 1.5m). Woda o zielonkawym odcieniu, bogata w materię organiczną. Latem przejrzystość ograniczona przez silne zakwity planktonu.', 'Ekstremalnie bogata. Szeroki pas trzcin, liczne pola grążeli i lilii wodnych. Pod wodą gęste dywany moczarki kanadyjskiej i rdestnic, utrudniające sprawne poruszanie się łodzią.', 'Szczupak, Lin, Karaś złocisty, Okoń, Płoć', TRUE, 'Naturalnie zasilane rybami z rzeki Sapiny. PZW Suwałki prowadzi okresowe zarybienia narybkiem szczupaka i lina w ramach gospodarki na całym szlaku.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks). Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online.', FALSE, TRUE, 'Bardzo utrudnione. Brzegi bagniste, zarośnięte i trudno dostępne. Wędkowanie z lądu możliwe tylko w kilku punktach przy ujściu rzeki lub z nielicznych kładek.', FALSE, TRUE, 'Dojazd drogami polnymi i leśnymi od strony Pozezdrza lub Kolonii Pozezdrze. Drogi bywają grząskie, szczególnie po opadach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80085, 'Linowo-szczupakowe', 14.5, 1.2, 3.5, 'Płytka niecka, dno misowate, niemal całkowicie wyrównane przez osady organiczne.', 'Miękkie, muliste. Gruba warstwa mułu i rozkładającej się roślinności.', 'Niska (0.5 - 1.2m). Woda o zielonkawym zabarwieniu, typowa dla małych, żyznych zbiorników leśnych.', 'Bardzo bogata. Powierzchnia tafli w 40% pokryta grążelami. Szeroki pas trzcin i pałki wodnej.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć', TRUE, 'Naturalna odnowa populacji. Okresowe zarybienia szczupakiem przez zarządcę.', TRUE, 'Zezwolenie GR Mrągowo. Te same zasady co na jeziorze Wągiel.', FALSE, TRUE, 'Utrudnione ze względu na bagniste brzegi. Wymagane wodery lub łowienie z kilku dzikich prześwitów.', FALSE, TRUE, 'Utrudniony. Dojazd drogami leśnymi i polnymi od strony drogi krajowej nr 59 lub Wierzbowa.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80011, 'Linowo-szczupakowe / Stawowe', 16.5, 1.1, 3.2, 'Płaskie dno z lekkim pogłębieniem wzdłuż koryta Sapiny. Brak gwałtownych uskoków. Jezioro przypomina rozległe rozlewisko rzeczne, które systematycznie zarasta i wypłyca się w procesie sukcesji.', 'Bardzo miękkie, wybitnie muliste. Dominują osady organiczne i gruby detrytus. Twarde dno występuje jedynie punktowo w samym nurcie przepływającej rzeki Sapiny.', 'Niska (0.7 - 1.2m). Woda o charakterystycznym zielono-brunatnym odcieniu. Duża zawartość zawiesiny organicznej i częste zakwity planktonu w okresie letnim.', 'Ekstremalnie bogata. Pas trzcin niemal całkowicie odcina dostęp do wody z lądu. Na tafli królują grążele żółte i lilie wodne. Pod wodą gęsta moczarka kanadyjska wypełniająca większość toni.', 'Szczupak, Lin, Karaś złocisty, Okoń, Wzdręga', TRUE, 'Zarybiane okresowo szczupakiem i linem przez PZW Suwałki. Populacja ryb opiera się głównie na naturalnym tarle i migracji ryb rzeką Sapiną.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks). Ok. 350-450 zł/rok (łódź). Możliwość zakupu zezwoleń krótkookresowych online.', FALSE, TRUE, 'Praktycznie niemożliwe. Brzegi bagniste i trzęsawiskowe. Wędkowanie z lądu wymaga specjalistycznego przygotowania i przedzierania się przez gęste trzcinowiska.', FALSE, TRUE, 'Utrudniony. Dojazd drogami leśnymi i polnymi od strony Pozezdrza. Drogi bywają bardzo piaszczyste lub błotniste, wymagany pojazd terenowy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80012, 'Sielawowe / Leszczowe', 105, 4.5, 10.5, 'Stosunkowo urozmaicone z kilkoma wyraźnymi głęboczkami i rozległymi blatami w części środkowej. Stoki opadają łagodnie, tworząc szerokie pasy roślinności zanurzonej. W zachodniej części dno bardziej płaskie.', 'Przeważnie twarde, piaszczyste i piaszczysto-żwirowe, szczególnie w strefie przybrzeżnej. W najgłębszych miejscach oraz w osłoniętych zatoczkach występuje cienka warstwa mułu.', 'Wysoka (2.5 - 4.0m). Woda krystaliczna, o bardzo dobrej przejrzystości przez większość roku. Sprzyja to rozwojowi bogatych łąk podwodnych i wymaga dyskrecji od wędkarza.', 'Bardzo bogata. Szeroki pas trzcin wokół całego jeziora. Pod wodą dominują rozległe dywany ramienic i moczarki. W zatokach liczne grążele i rdestnice, stanowiące świetne kryjówki dla szczupaka.', 'Szczupak, Okoń, Leszcz, Lin, Płoć, Węgorz', TRUE, 'Regularne zarybienia szczupakiem i linem prowadzone przez PZW Suwałki. Akwen posiada również silną naturalną populację okonia.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Możliwość zakupu zezwoleń okresowych (1, 3, 7-dniowych) online lub w Giżycku.', FALSE, TRUE, 'Dobre. Wokół jeziora znajduje się wiele dostępnych stanowisk, kładek oraz plaż, szczególnie od strony miejscowości Harsz.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy do wsi Harsz, następnie drogi utwardzone i polne prowadzące bezpośrednio do linii brzegowej.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80013, 'Leszczowo-szczupakowe / Głębokie', 14.2, 4.8, 15.8, 'Bardzo urozmaicone: dno gwałtownie opada od brzegów, tworząc wyraźne stoki i rynnowe pogłębienie w części centralnej. Występują podwodne półki z roślinnością, które są bankowymi miejscówkami.', 'Przeważnie twarde na stokach (piasek, żwir), przechodzące w muliste w najgłębszej rynnie. Liczne zwalone drzewa przy brzegach stanowią naturalne zaczepy i doskonałe kryjówki dla drapieżników.', 'Bardzo dobra (2.5 - 4.0m). Woda o wysokiej przejrzystości, co sprzyja rozwojowi roślinności podwodnej do znacznych głębokości. Ryby są tu czujne i wymagają dyskretnego podejścia oraz cienkich zestawów.', 'Wąski pas trzcin. Pod wodą dominują łąki ramienicowe i moczarka. W zatokach spotkamy grążele. Roślinność zanurzona schodzi głęboko, tworząc świetne warunki dla szczupaków i okoni.', 'Szczupak, Okoń, Leszcz, Lin, Płoć', TRUE, 'Regularnie zarybiane przez PZW Suwałki narybkiem szczupaka i lina. Dzięki połączeniu z kompleksem Mamr, populacja zasilana jest również naturalną migracją ryb.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks). Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online.', FALSE, FALSE, 'Możliwe z nielicznych wydeptanych stanowisk i kładek, jednak stromo opadające brzegi i roślinność sprawiają, że najskuteczniejsze jest łowienie z łodzi lub pontonu.', TRUE, TRUE, 'Dojazd drogami polnymi i leśnymi od strony miejscowości Świdry lub Pieczarki. Drogi mogą być piaszczyste i wymagające, szczególnie po intensywnych opadach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80014, 'Eutroficzne / Szczupakowo-linowe', 38.4, 1.5, 3.7, 'Dno misowate, bardzo wyrównane i płytkie. Brak gwałtownych uskoków. Większość akwenu to rozległe płycizny, które sprzyjają szybkiemu nagrzewaniu się wody wiosną i rozwojowi bujnej roślinności zanurzonej.', 'Wybitnie miękkie, muliste. Gruba warstwa osadów organicznych pokrywa niemal całe dno. Twardsze, piaszczyste miejsca występują jedynie punktowo w strefie przybrzeżnej od strony południowej.', 'Niska (0.8 - 1.5m). Woda o zielonkawym zabarwieniu, bogata w materię organiczną. Latem przejrzystość mocno ograniczona przez silne zakwity planktonu i pyłki roślin.', 'Ekstremalnie bogata. Brzegi porośnięte gęstą trzciną. Cała tarcza jeziora niemal całkowicie zarośnięta moczarką i rdestnicami. Rozległe pola grążeli i lilii wodnych stanowią idealne kryjówki ryb.', 'Szczupak, Lin, Karaś złocisty, Okoń, Płoć', TRUE, 'Regularnie zarybiane narybkiem szczupaka i lina przez PZW Suwałki. Jezioro słynie z doskonałych warunków do naturalnego tarła ryb spokojnego żeru.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia okresowe online.', FALSE, TRUE, 'Utrudnione. Brzegi w większości bagniste i niedostępne. Wędkowanie z lądu możliwe tylko w kilku wyznaczonych punktach i z nielicznych kładek.', FALSE, TRUE, 'Dojazd drogami polnymi i leśnymi od strony miejscowości Pieczarki lub Świdry. Drogi bywają grząskie, zalecany pojazd o wyższym zawieszeniu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80031, 'Sielawowo-leszczowe', 94.5, 5.5, 17.6, 'Bardzo urozmaicone: gwałtowne spady, podwodne górki i głęboka rynna centralna. Liczne półki na głębokości 4-6m porośnięte roślinnością podwodną.', 'Przeważnie twarde, piaszczysto-żwirowe na wypłyceniach i stokach. W najgłębszych partiach rynny dno pokryte jest cienką warstwą mułu i detrytusu.', 'Wysoka (2.5 - 4.0m). Krystaliczna woda o niebieskawym odcieniu. Przejrzystość utrzymuje się na wysokim poziomie przez większość sezonu.', 'Bogata roślinność podwodna (ramienice, moczarka). Pas trzcin jest zwarty, ale poprzecinany licznymi stanowiskami. Szerokość pasa trzcin to 2-5m.', 'Szczupak, Sandacz, Okoń, Leszcz, Lin, Płoć, Węgorz', TRUE, 'Systematyczne zarybienia szczupakiem i sandaczem. Jezioro słynie z dobrej naturalnej regeneracji populacji okonia i lina.', TRUE, 'Zezwolenie PZW Suwałki (cały kompleks). Ok. 350-450 zł/rok (łódź). E-zezwolenia dostępne online oraz w Giżycku.', FALSE, FALSE, 'Możliwe z licznych pomostów i stanowisk przy brzegach, szczególnie od strony południowej i zachodniej. Dobre dla wędkarzy spławikowych.', TRUE, TRUE, 'Bardzo dobry dojazd od strony miejscowości Pieczarki drogami szutrowymi i gruntowymi utwardzonymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80087, 'Sielawowo-szczupakowe', 162, 8.5, 30, 'Rynnowe, dno bardzo urozmaicone, liczne podwodne górki i głębokie uskoki.', 'Zróżnicowane: piaszczyste na górkach, muliste w rynnie głównej.', 'Wysoka (2.5 - 4.0m).', 'Bogata w zatokach. Szerokie pola grążeli i rdestnic. Pas trzcin zwarty.', 'Szczupak, Leszcz, Okoń, Sielawa, Płoć, Lin', TRUE, 'Regularnie zarybiane szczupakiem i sielawą.', TRUE, 'Zezwolenie GR Ostróda.', FALSE, TRUE, 'Dobre w rejonie miejscowości Łąkorz, pozostałe brzegi trudniej dostępne.', TRUE, TRUE, 'Bardzo dobry dojazd do miejscowości Łąkorz, dostęp do slipów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80033, 'Sielawowe', 124, 7.5, 26.5, 'Typowo rynnowe. Bardzo strome stoki schodzące do głębokiej rynny centralnej. Liczne podwodne progi i niewielkie wypłycenia w częściach zatokowych.', 'Zróżnicowane: na stokach przeważnie twarde, piaszczyste i kamieniste. W najgłębszych rynnach oraz w osłoniętych zatokach dno jest miękkie, pokryte warstwą mułu.', 'Wysoka (2.5 - 4.5m). Woda krystaliczna przez większość sezonu, co sprzyja rozwojowi bogatych łąk ramienicowych sięgających do 6-7 metrów głębokości.', 'Dobrze rozwinięta. Pas trzcin i sitowia jest szeroki i zwarty. Pod wodą dominują ramienice, moczarka kanadyjska oraz rdestnica połyskująca wzdłuż spadów.', 'Szczupak, Okoń, Sielawa, Sieja, Leszcz, Węgorz', TRUE, 'Systematycznie zarybiane szczupakiem, węgorzem oraz sielawą. Naturalne tarliska sprzyjają stabilnej populacji okonia i białorybu.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). Dostępne e-zezwolenia online oraz w Giżycku.', FALSE, FALSE, 'Możliwe z nielicznych kładek i stanowisk, jednak strome brzegi i gęste trzciny sprawiają, że najskuteczniejsze łowienie odbywa się z jednostek pływających.', TRUE, TRUE, 'Dojazd drogami polnymi i utwardzonymi od strony miejscowości Świdry lub Pieczarki. Niektóre zjazdy wymagają auta z wyższym zawieszeniem.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80034, 'Linowo-szczupakowe', 6.5, 1.2, 3.1, 'Dno misowate, bardzo wyrównane i płytkie. Brak jakichkolwiek gwałtownych uskoków. Jezioro systematycznie wypłyca się w procesie sukcesji roślinnej.', 'W przeważającej części bardzo miękkie, wybitnie muliste z grubą warstwą osadów organicznych. Brak twardych, piaszczystych partii dna.', 'Niska (0.5 - 1.0m). Woda o barwie zielono-brunatnej, często mętna ze względu na płytkość i intensywne żerowanie ryb dennych oraz zakwity letnie.', 'Ekstremalnie obfita. Ponad 80% powierzchni dna pokryte moczarką i rdestnicami. Na powierzchni ogromne pola grążeli i lilii wodnych, trzcinowiska szerokie i gęste.', 'Lin, Szczupak, Karaś złocisty, Okoń, Płoć', TRUE, 'Zarybiane okresowo narybkiem szczupaka i lina przez PZW Suwałki. Silna naturalna populacja karasia i płoci.', TRUE, 'Zezwolenie PZW Suwałki. Ok. 350-450 zł/rok (łódź). E-zezwolenia dostępne online.', FALSE, FALSE, 'Ekstremalnie utrudnione. Brzegi bagniste i niedostępne. Wymagane przedzieranie się przez trzciny; większość wędkarzy korzysta z małych pontonów.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi od strony miejscowości Świdry. Drogi bywają grząskie po opadach, wymagany pojazd o wyższym zawieszeniu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80035, 'Sielawowe', 2604, 10, 39.7, 'Bardzo zróżnicowane: liczne głęboczki, rozległe mielizny śródjeziorne i strome spady rynnowe. Dno obfituje w podwodne górki i twarde blaty otoczone głębią.', 'Piaszczysto-muliste, miejscami żwirowe. W okolicach Giżycka i Wilkas dno jest twardsze, piaszczyste; w głębokich rynnach dominuje muł i osady organiczne.', 'Średnia (1.5 - 3.0m). Widoczność zależna od pory roku i zakwitów planktonu. W ostatnich latach obserwowana stała poprawa przejrzystości dzięki nowoczesnym oczyszczalniom.', 'Trzcina pospolita zajmuje ok. 2/3 linii brzegowej. Roślinność zanurzona (rdestnice, moczarka) pokrywa ponad 15% powierzchni dna, tworząc bogate tarliska.', 'Sandacz, Szczupak, Leszcz, Okoń, Węgorz, Sielawa, Płoć', TRUE, 'Systematycznie zarybiane przez Gospodarstwo Giżycko szczupakiem, sandaczem i węgorzem. Silna naturalna populacja sielawy i okonia.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online i w sklepach w Giżycku.', FALSE, FALSE, 'Bardzo dobre w okolicach Giżycka, Wilkas i Rydzewa. Liczne plaże miejskie, porty i dzikie stanowiska na mniej zurbanizowanych odcinkach brzegu.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi (Giżycko, Wilkasy, Rydzewo). Liczne ekomariny i profesjonalne slipy dla łodzi wędkarskich.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80038, 'Leszczowo-szczupakowe', 62.5, 3.2, 7.8, 'Dno o charakterze rynnowym, lekko pofalowane z łagodnymi spadami. Brak gwałtownych uskoków. W części środkowej występuje wyraźne podłużne zagłębienie.', 'W przeważającej części muliste. Twardsze, piaszczyste i piaszczysto-żwirowe fragmenty dna występują głównie w strefie przybrzeżnej oraz w przesmyku do jeziora Wojnowo.', 'Średnia (1.0 - 2.0m). Woda o zielonkawym odcieniu, typowa dla jezior żyznych. Przejrzystość wzrasta jesienią, natomiast latem ograniczona jest przez zakwity planktonu.', 'Bardzo bogata. Szeroki pas trzcin i oczeretów. Liczne pola grążeli żółtych i lilii wodnych w zatokach. Pod wodą dominują gęste łąki moczarki i rdestnic.', 'Lin, Szczupak, Leszcz, Okoń, Wzdręga, Płoć', TRUE, 'Systematycznie zarybiane przez GR Giżycko szczupakiem i linem. Jezioro posiada bardzo dobre warunki do naturalnego tarła większości gatunków ryb spokojnego żeru.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w sklepach wędkarskich w Giżycku.', FALSE, FALSE, 'Możliwe z nielicznych kładek i pomostów, głównie od strony miejscowości Ruda. Większość linii brzegowej niedostępna z lądu z powodu gęstych trzcin.', TRUE, TRUE, 'Bardzo dobry dojazd od strony Giżycka przez wieś Ruda (asfalt, potem droga szutrowa). Dostępne dogodne miejsca do wodowania mniejszych łodzi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80039, 'Leszczowo-szczupakowe', 42.7, 5, 9, 'Dno o dość regularnej konfiguracji, misowate, z łagodnymi spadami. Brak gwałtownych uskoków terenu. Najgłębsze punkty znajdują się w środkowej części rynny jeziora.', 'W przeważającej części miękkie, muliste. Twardsze, piaszczyste partie dna występują punktowo w strefie przybrzeżnej oraz w południowo-wschodniej części przy wsi Grajwo.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu. Latem występują okresowe zakwity planktonu, co ogranicza widoczność, ale sprzyja żerowaniu białorybu.', 'Umiarkowana. Wąski, ale zwarty pas trzcin pospolitych. Pod wodą liczne kępy moczarki kanadyjskiej i rdestnic, tworzące naturalne schronienie dla narybku i drapieżników.', 'Leszcz, Płoć, Szczupak, Okoń, Lin, Sandacz', TRUE, 'Dzierżawca prowadzi okresowe zarybienia szczupakiem i linem. Jezioro zasilane naturalnie dzięki połączeniu z kompleksem jeziora Niegocin.', TRUE, 'Zezwolenie u dzierżawcy (B. Wyszyński). Punkty sprzedaży w Giżycku i bezpośrednio we wsi Grajwo.', FALSE, FALSE, 'Możliwe z kilku ogólnodostępnych punktów przy wsi Grajwo oraz z nielicznych kładek. Większość linii brzegowej wymaga łodzi.', TRUE, TRUE, 'Dojazd drogą asfaltową z Giżycka w stronę Grajwa, następnie drogi utwardzone prowadzące do miejscowości i brzegów jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80040, 'Linowo-szczupakowe', 13.5, 1.1, 2.5, 'Dno bardzo wyrównane, płaskie, typowe dla płytkich jezior eutroficznych. Brak wyraźnych rynien czy górek podwodnych. Akwen ulega systematycznemu wypłycaniu.', 'Wybitnie miękkie, muliste z grubą warstwą osadów organicznych. Brak twardych, piaszczystych partii dna, co sprzyja gatunkom dennym.', 'Niska (0.5 - 1.0m). Woda o silnym zabarwieniu organicznym, mętna, szczególnie w okresie letnich zakwitów planktonu.', 'Ekstremalnie bogata. Brzegi niedostępne, porośnięte gęstą trzciną i tatarakiem. Na tafli dominują grążele żółte, a pod wodą gęste dywany moczarki.', 'Lin, Karaś złocisty, Szczupak, Płoć, Okoń', TRUE, 'Zarybiane okresowo narybkiem szczupaka i lina przez Gospodarstwo Giżycko. Silna naturalna populacja ryb karpiowatych.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. Dostępne online oraz w Giżycku.', FALSE, FALSE, 'Niemożliwe z lądu ze względu na bagnisty brzeg. Wymagane spodniobuty, kładki lub mały ponton/łódź.', FALSE, TRUE, 'Dojazd drogą asfaltową Giżycko-Orzysz do miejscowości Kąp, następnie zjazdy polne w stronę zachodniego brzegu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80041, 'Linowo-szczupakowe', 12.5, 1.2, 3.2, 'Dno o regularnym, misowatym kształcie, ulegające naturalnemu procesowi wypłycania. Brak gwałtownych spadków dany i podwodnych przeszkód terenowych.', 'Wybitnie miękkie, muliste z bardzo grubą warstwą osadów organicznych. Brak piaszczystych partii dna, co sprzyja bytowaniu gatunków ryb żerujących w mule.', 'Niska (0.8 - 1.5m). Woda o zielonkawym odcieniu, bardzo żyzna, ze skłonnością do intensywnych zakwitów planktonu w miesiącach letnich.', 'Ekstremalnie bogata. Brzegi niedostępne, porośnięte gęstą trzciną. Powierzchnię tafli w dużej mierze pokrywają grążele żółte i lilie wodne. Pod wodą gęsta moczarka.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć', TRUE, 'Zarybiane okresowo szczupakiem i linem przez GR Giżycko. Stabilna populacja ryb dzięki doskonałym warunkom tarliskowym i małej presji wędkarskiej.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w sklepach w Giżycku.', FALSE, FALSE, 'Praktycznie niemożliwe z brzegu bez spodniobutów lub wyciętych prywatnych stanowisk. Większość linii brzegowej to bagniste trzcinowiska.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi od strony miejscowości Upałty. Wymagana ostrożność po opadach, drogi mogą być grząskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80042, 'Linowo-szczupakowe', 40.5, 2, 4.8, 'Dno o regularnej rynnowej konfiguracji z łagodnymi spadami. W części środkowej występuje wyraźne, podłużne pogłębienie. Brak gwałtownych uskoków i górek podwodnych.', 'Głównie miękkie i muliste, jednak w pasie przybrzeżnym występują fragmenty piaszczysto-żwirowe. W osłoniętych zatokach dno pokryte grubą warstwą osadów organicznych.', 'Średnia (1.0 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla jezior o wysokiej trofii. Widoczność znacznie wzrasta w okresie jesiennym po obumarciu planktonu.', 'Bardzo silnie rozwinięta. Szeroki pas trzcin pospolitych i pałki wodnej. Liczne pola grążeli żółtych. Pod wodą dominują gęste łąki moczarki oraz rdestnica połyskująca.', 'Lin, Szczupak, Leszcz, Okoń, Płoć, Wzdręga', TRUE, 'Systematycznie zarybiane przez GR Giżycko szczupakiem i linem. Jezioro słynie z doskonałej naturalnej regeneracji populacji ryb spokojnego żeru.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w sklepach w Giżycku.', FALSE, FALSE, 'Możliwe z nielicznych kładek, pomostów oraz wyciętych stanowisk wędkarskich, głównie od strony wschodniej. Większość brzegu wymaga łodzi.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi szutrami od strony miejscowości Upałty. Możliwość dojazdu bezpośrednio pod linię brzegową w kilku punktach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80044, 'Leszczowo-sandaczowe', 176.3, 6.3, 14.2, 'Rynnowe o urozmaiconym dnie. Liczne głęboczki, strome spady wzdłuż osi jeziora oraz rozległe blaty i podwodne górki w częściach środkowych i zatokowych.', 'Zróżnicowane: przeważnie twarde, piaszczysto-gliniaste na ławicach i stokach. W najgłębszych partiach rynny i w osłoniętych zatokach dno jest miękkie i muliste.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior żyznych. Przejrzystość wzrasta jesienią; latem możliwe okresowe zakwity planktonu.', 'Silnie rozwinięta. Szeroki pas trzciny pospolitej i pałki wodnej. Pod wodą rozległe dywany ramienic i moczarki sięgające 4-5m głębokości oraz liczne grążele.', 'Sandacz, Leszcz, Szczupak, Okoń, Węgorz, Płoć, Sielawa, Lin', TRUE, 'Systematycznie zarybiane przez GR Giżycko sandaczem, szczupakiem i węgorzem. Doskonałe warunki do naturalnego tarła leszcza i płoci.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w stacji paliw w Miłkach.', FALSE, FALSE, 'Możliwe z nielicznych pomostów i stanowisk przy wsiach Kleszczowo i Wojnowo. Większość brzegu wymaga łodzi lub pontonu.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi szutrami od strony miejscowości Miłki lub Kleszczowo.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80045, 'Leszczowo-szczupakowe', 22.5, 5.2, 15.1, 'Rynnowe, ze stosunkowo stromymi stokami opadającymi ku środkowi jeziora. Dno pofalowane z lokalnymi zagłębieniami w osi rynny głównej.', 'Przeważnie muliste w głębi, natomiast w strefie przybrzeżnej i na spadach występuje twardsze dno piaszczysto-muliste z domieszką gliny.', 'Średnia (1.0 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla jezior żyznych. Przejrzystość wzrasta jesienią; latem możliwe zakwity planktonu.', 'Dobrze rozwinięta. Pas trzciny pospolitej wokół całego jeziora. Pod wodą dominują dywany moczarki kanadyjskiej i rdestnic. W zatokach liczne pola grążeli.', 'Leszcz, Szczupak, Lin, Okoń, Płoć, Sandacz', TRUE, 'Zarybiane szczupakiem i sandaczem przez Gospodarstwo Rybackie w Giżycku. Silna naturalna populacja lina i dużego leszcza.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. Dostępne online oraz w punktach w Miłkach i Giżycku.', FALSE, FALSE, 'Możliwe z licznych pomostów i stanowisk przy miejscowości Miłki. Dostęp z brzegów niezagospodarowanych utrudniony przez trzciny.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi (trasa Giżycko-Orzysz) bezpośrednio do miejscowości Miłki i linii brzegowej.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80046, 'Sielawowe / Leszczowe', 270, 8.5, 27.1, 'Wybitnie rynnowe. Bardzo strome stoki, dno pofalowane z licznymi głęboczkami w osi głównej. Brak rozległych mielizn – dominują wąskie półki przybrzeżne.', 'Przeważnie twarde (piasek, żwir, glina) na stokach rynny. W najgłębszych partiach oraz w nielicznych zatokach dno jest pokryte cienką warstwą mułu i osadów organicznych.', 'Wysoka (2.5 - 4.0m). Woda o błękitno-zielonym odcieniu, bardzo czysta, co sprzyja rozwojowi roślinności zanurzonej do znacznych głębokości.', 'Pas trzcin wąski ze względu na strome brzegi. Pod wodą dominują ramienice, moczarka i rdestnica połyskująca, tworząc pasy wzdłuż brzegów do 6m głębokości.', 'Szczupak, Okoń, Sielawa, Leszcz, Węgorz, Płoć, Sieja', TRUE, 'Regularnie zarybiane przez GR Giżycko sielawą, szczupakiem i sandaczem. Jezioro posiada silną naturalną populację okonia i siei.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w sklepach w Giżycku.', FALSE, FALSE, 'Bardzo utrudnione ze względu na strome brzegi i brak płaskich stanowisk. Większość wędkowania odbywa się z łodzi lub pontonów.', TRUE, TRUE, 'Utrudniony. Dojazd drogami polnymi i leśnymi od miejscowości Miłki, Marcinowa Wola lub Cierzpięty. Drogi bywają strome i śliskie po deszczu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80086, 'Linowo-szczupakowe', 24.5, 2.2, 5.5, 'Dno misowate, o bardzo łagodnym ukształtowaniu. Brak gwałtownych uskoków i podwodnych górek.', 'Przeważnie miękkie, muliste, z grubą warstwą osadów leśnych. Nieliczne piaszczyste partie przy północnym brzegu.', 'Średnia (1.2 - 2.0m). Woda o barwie lekko brunatnej (huminowa), przejrzystość stała, bez silnych zakwitów letnich.', 'Bardzo bogata. Szeroki pas trzciny pospolitej i liczne pola grążeli żółtych. Pod wodą gęste łąki moczarki.', 'Lin, Szczupak, Okoń, Wzdręga, Płoć', TRUE, 'Zarybiane okresowo narybkiem szczupaka przez Gospodarstwo Rybackie w Mrągowie. Silna naturalna populacja lina.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w punktach sprzedaży w Mrągowie i Pieckach.', FALSE, TRUE, 'Utrudnione ze względu na zalesione i bagniste brzegi. Nieliczne dzikie stanowiska.', FALSE, TRUE, 'Trudny. Dojazd drogami leśnymi i polnymi od strony Piecek. Drogi bywają piaszczyste i wąskie.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80328, 'Sielawowo-sandaczowe', 480, 8.5, 30, 'Bardzo urozmaicone, 4 wyspy, liczne spadki.', 'Twarde, miejscami kamieniste.', 'Wysoka', 'Średnia.', 'Sandacz, Szczupak, Węgorz, Sielawa', TRUE, 'Zarybiane sandaczem.', TRUE, 'GR Augustów.', FALSE, FALSE, 'Umiarkowane.', TRUE, TRUE, 'Asfalt/Leśna.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80047, 'Linowo-szczupakowe', 11.2, 1.3, 3.5, 'Dno płaskie, misowate, typowe dla płytkich jezior zanikających. Brak rynien i górek podwodnych. Akwen ulega naturalnemu procesowi wypłycania i zamulania.', 'Wybitnie miękkie, bardzo silnie zamulone. Gruba warstwa osadów organicznych i detrytusu. Brak twardych, piaszczystych partii dna poza strefą przesmyku.', 'Niska (0.7 - 1.2m). Woda o silnym zabarwieniu organicznym, mętna w lecie z powodu zakwitów planktonu oraz żerowania ryb dennych w miękkim mule.', 'Ekstremalnie bogata. Brzegi otoczone szerokim pasem trzcin i pałki. Powierzchnia tafli w 40% pokryta grążelami i liliami. Pod wodą gęste łąki moczarki i osoki aloesowatej.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć, Okoń', TRUE, 'Systematycznie zarybiane narybkiem szczupaka i lina przez GR Giżycko. Doskonałe warunki do naturalnego tarła gatunków fitofilnych.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w sklepach wędkarskich w Giżycku.', FALSE, FALSE, 'Praktycznie niemożliwe z brzegu bez specjalistycznych pomostów lub kładek. Większość linii brzegowej to grząskie bagno i gęste zarośla.', FALSE, TRUE, 'Utrudniony. Dojazd drogami leśnymi od strony miejscowości Ublik. Drogi bywają piaszczyste i bardzo wąskie, wymagany ostrożny przejazd.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80049, 'Sielawowe / Leszczowe', 193.5, 8.9, 32.5, 'Typowo rynnowe o bardzo urozmaiconym dnie. Liczne głęboczki, strome stoki rynny głównej oraz podwodne górki i półki na głębokościach 5-8 metrów.', 'Przeważnie twarde, piaszczysto-żwirowe na stokach i stokach ławicy. W najgłębszych partiach rynny dno pokryte jest cienką warstwą mułu i osadów sielawowych.', 'Wysoka (2.5 - 4.5m). Woda krystaliczna o błękitnym odcieniu, doskonała przejrzystość sprzyja obserwacji ryb oraz rozwojowi roślinności podwodnej.', 'Umiarkowanie rozwinięta roślinność wynurzona (trzcina, pałka) zajmuje ok. połowę linii brzegowej. Roślinność zanurzona (wywłócznik, rogatek) porasta stoki do 6m głębokości.', 'Szczupak, Sieja, Okoń, Leszcz, Płoć, Lin, Sielawa, Węgorz', TRUE, 'Systematycznie zarybiane przez GR Giżycko sielawą, sieją oraz szczupakiem. Silna naturalna populacja dużego okonia i płoci.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. Zakup w sklepach w Giżycku lub u lokalnych dystrybutorów.', FALSE, TRUE, 'Utrudnione ze względu na wysokie i strome brzegi oraz pas trzcin. Najlepsze efekty daje połów z łodzi lub z profesjonalnie przygotowanych pomostów.', TRUE, TRUE, 'Bardzo dobry dojazd drogą asfaltową do miejscowości Ublik lub Wyszowate, dalej drogi utwardzone prowadzące do ośrodków i plaż.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80050, 'Linowo-szczupakowe / Bagienne', 11.5, 1.2, 3.8, 'Dno misowate, bardzo regularne, ulegające silnemu procesowi zamulania. Brak wyraźnych rynien; najgłębsze punkty znajdują się w centralnej części akwenu.', 'Wybitnie miękkie, muliste, o dużej zawartości detrytusu i osadów torfowych. Dno jest "żywe", bogate w bezkręgowce stanowiące bazę pokarmową lina.', 'Niska (0.5 - 1.0m). Woda o ciemnym, brunatnym zabarwieniu (huminowa), przejrzystość ograniczona przez zawiesinę organiczną i letnie zakwity.', 'Ekstremalnie bogata. Brzegi niedostępne, porośnięte gęstą trzciną, łozami i olszyną. Na tafli królują grążele żółte i osoka aloesowata. Pod wodą gęsta moczarka.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć', TRUE, 'Naturalna odnowa populacji. PZW/GR Giżycko rzadko prowadzi tu intensywne zarybienia, co sprzyja zachowaniu dzikiego charakteru rybostanu.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online.', FALSE, FALSE, 'Praktycznie niemożliwe. Brzegi trzęsawiskowe i bagniste. Brak pomostów i utwardzonych stanowisk.', FALSE, TRUE, 'Ekstremalnie trudny. Dojazd drogami leśnymi i polnymi od strony miejscowości Cierzpięty lub Ublik. Wymagane przedzieranie się przez gęsty las.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80051, 'Sielawowo-leszczowe / Głębokodna', 14.5, 4.5, 15.2, 'Typowo rynnowe. Bardzo strome stoki schodzące ku głębokiej osi środkowej. Dno pofalowane, z wyraźnymi krawędziami półek roślinnych na głębokości 4-6 metrów.', 'Przeważnie twarde, piaszczysto-żwirowe na stokach, w najgłębszych partiach pokryte niewielką warstwą jasnego mułu mineralnego. Bardzo czyste, bez dużych osadów organicznych.', 'Bardzo wysoka (3.5 - 5.0m). Krystaliczna woda o błękitnym odcieniu, doskonała widoczność nawet na dużych głębokościach, co determinuje styl łowienia.', 'Bogata roślinność podwodna, głównie łąki ramienicowe sięgające głęboko. Pas trzcin wąski, ale zwarty, porastający strome brzegi. Liczne zatopione drzewa przy brzegach.', 'Szczupak, Okoń, Leszcz, Lin, Wzdręga, Płoć', TRUE, 'Systematycznie zarybiane narybkiem szczupaka i lina przez GR Giżycko. Naturalna, zdrowa populacja okonia i płoci.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w Giżycku.', FALSE, TRUE, 'Utrudnione ze względu na strome i wysokie brzegi oraz leśne otoczenie. Dostępne nieliczne, dzikie stanowiska wędkarskie.', FALSE, TRUE, 'Utrudniony. Dojazd drogami leśnymi i polnymi od strony miejscowości Cierzpięty. Drogi bywają wąskie i wymagają uwagi przy przejeździe po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80052, 'Linowo-szczupakowe', 6.8, 1.4, 3.5, 'Dno misowate, regularne, ulegające silnemu procesowi zamulania organicznego. Brak wyraźnych rynien i górek podwodnych; dno łagodnie opada ku środkowi.', 'Wybitnie miękkie, mulisto-torfowe. Gruba warstwa osadów organicznych oraz detrytusu z opadających liści i igliwia.', 'Średnia (1.0 - 1.5m). Woda o charakterystycznym ciemniejszym, herbacianym odcieniu, co ogranicza przejrzystość w głębszych partiach.', 'Bardzo bogata. Brzegi porośnięte gęstą trzciną, łozami i zwisającymi olchami. Na tafli liczne pola grążeli żółtych. Pod wodą dominują gęste łąki moczarki.', 'Lin, Szczupak, Karaś złocisty, Płoć, Okoń', TRUE, 'Zarybiane okresowo narybkiem szczupaka i lina przez GR Giżycko. Silna naturalna populacja gatunków fitofilnych.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online.', FALSE, TRUE, 'Ekstremalnie utrudnione. Brzegi strome, bagniste i zarośnięte. Brak utwardzonych stanowisk i kładek.', FALSE, TRUE, 'Utrudniony. Dojazd wyłącznie drogami leśnymi od strony Cierzpięt lub Ublika. Drogi bywają wąskie i piaszczyste, wymagana ostrożność.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80054, 'Linowo-szczupakowe', 5.5, 1.5, 4, 'Dno misowate, wyrównane, ulegające procesom naturalnego wypłycania. Brak górek podwodnych; strefa najgłębsza znajduje się w centralnej części akwenu.', 'Wybitnie miękkie, muliste. Gruba warstwa osadów organicznych pochodzenia leśnego. Brak partii twardych, dno jest jednorodne na całej powierzchni.', 'Średnia/Niska (0.8 - 1.2m). Woda o zabarwieniu zielono-brunatnym, typowa dla małych zbiorników śródleśnych o dużej produktywności biologicznej.', 'Bardzo bogata. Szeroki pas trzciny i pałki wodnej. Na tafli liczne skupiska grążeli żółtych. Pod wodą gęste łąki moczarki kanadyjskiej i osoki.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć, Okoń', TRUE, 'Zarybiane okresowo szczupakiem przez GR Giżycko. Silna naturalna populacja lina i karasia ze względu na idealne warunki tarliskowe.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. Zakup online lub w Giżycku.', FALSE, FALSE, 'Praktycznie niemożliwe. Brzegi bagniste, trzęsawiskowe i porośnięte gęstą roślinnością. Brak kładek i utwardzonych stanowisk.', FALSE, TRUE, 'Trudny. Dojazd wyłącznie drogami leśnymi i piaszczystymi od strony Cierzpięt. Wymagane przedzieranie się przez las; brak wyznaczonych parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80055, 'Linowo-szczupakowe / Dystroficzne', 6.2, 1.2, 3.5, 'Dno misowate, niemal całkowicie płaskie, ulegające intensywnej sukcesji i zamulaniu. Brak wyraźnych zmian głębokości; najgłębsze punkty są w osi środkowej.', 'Wybitnie miękkie, mulisto-torfowe o dużej zawartości rozkładającej się materii organicznej. Dno jest bardzo grząskie, miejscami "podwójne" (kożuchy roślinne).', 'Niska (0.5 - 1.0m). Woda o barwie brunatnej (huminowa), przejrzystość mocno ograniczona przez zawiesinę organiczną i okresowe dywany rzęsy wodnej.', 'Ekstremalnie bogata. Brzegi porośnięte gęstą trzciną, pałką i krzewami olszy. Na tafli liczne pola grążeli i lilii. Pod wodą gęste skupiska wywłócznika i moczarki.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć', TRUE, 'Naturalna regeneracja populacji. Gospodarstwo Giżycko rzadko prowadzi tu intensywne zarybienia, co sprzyja zachowaniu dzikiego charakteru rybostanu.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online.', FALSE, FALSE, 'Praktycznie niemożliwe ze względu na bagniste brzegi. Wymagane przedzieranie się przez las i trzciny; brak kładek.', FALSE, TRUE, 'Ekstremalnie trudny. Dojazd wyłącznie drogami leśnymi od miejscowości Cierzpięty. Drogi piaszczyste i wąskie, wymagane przenoszenie sprzętu ręcznie.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80056, 'Sielawowe / Leszczowe', 1070.7, 6.6, 36, 'Ekstremalnie urozmaicone. Liczne wyspy, podwodne górki, gwałtowne spady i rynny. Dno bardzo pofalowane, z licznymi półkami na różnych głębokościach.', 'Zróżnicowane: przeważnie twarde, piaszczysto-żwirowe i kamieniste na górkach i stokach. W zatokach i najgłębszych rynnach dno miękkie, muliste.', 'Średnia/Wysoka (2.0 - 3.5m). Woda o błękitno-zielonym odcieniu. Przejrzystość dobra przez większość sezonu, okresowe zakwity planktonu w najżyźniejszych zatokach.', 'Bardzo bogata. Szerokie pasy trzcin, liczne pola grążeli w zatokach. Pod wodą rozległe łąki ramienicowe i rdestnice sięgające do 5-6 metrów głębokości.', 'Szczupak, Okoń, Leszcz, Sielawa, Węgorz, Sandacz, Płoć, Lin', TRUE, 'Systematycznie zarybiane przez GR Giżycko sielawą, szczupakiem i sandaczem. Silna naturalna populacja dużego okonia i białorybu.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, dostępne zezwolenia okresowe online i w punktach w Orzyszu.', FALSE, FALSE, 'Możliwe z licznych pomostów i plaż w miejscowościach Orzysz, Wierzbiny i Skomack Wielki. Wiele odcinków brzegów niedostępnych.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi (trasa nr 16 i 63) do miejscowości nadbrzeżnych. Liczne slipy i ogólnodostępne parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80057, 'Leszczowo-szczupakowe', 72.5, 3.1, 7.8, 'Rynnowe o łagodnym pofalowaniu dna. Najgłębsze partie znajdują się w centralnej osi jeziora; liczne wypłycenia w strefach przybrzeżnych i przy połączeniu z jez. Orzysz.', 'Zróżnicowane: przeważnie piaszczysto-muliste. W okolicach miejscowości Wierzbiny dno jest twardsze, piaszczyste; w zatokach zalega warstwa osadów organicznych.', 'Średnia (1.5 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla zbiorników eutroficznych. Przejrzystość wzrasta jesienią, latem widoczne okresowe zakwity.', 'Bardzo bogata. Szeroki i zwarty pas trzciny pospolitej i sitowia. Na powierzchni liczne pola grążeli i lilii wodnych. Pod wodą gęste łąki moczarki i rdestnic.', 'Lin, Szczupak, Okoń, Leszcz, Wzdręga, Płoć, Węgorz', TRUE, 'Systematycznie zarybiane przez GR Giżycko szczupakiem i linem. Jezioro pełni funkcję naturalnego matecznika dla białorybu z całego systemu orzyskiego.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. E-zezwolenia dostępne online oraz w sklepach w Orzyszu.', FALSE, FALSE, 'Możliwe i popularne z licznych kładek oraz pomostów przy miejscowości Wierzbiny. Dostęp do dzikich brzegów ograniczony przez gęstą roślinność.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi (trasa Orzysz-Ełk) do miejscowości Wierzbiny, następnie zjazdy bezpośrednio pod linię brzegową.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80059, 'Linowo-szczupakowe', 20.5, 1.8, 5.2, 'Dno misowate, wyrównane, o bardzo łagodnych spadach. Brak wyraźnych rynien i górek podwodnych; akwen ulega naturalnemu procesowi wypłycania.', 'Wybitnie miękkie, muliste. Gruba warstwa osadów organicznych na przeważającej powierzchni. Nieliczne twardsze partie występują jedynie w strefie przybrzeżnej.', 'Niska (0.8 - 1.5m). Woda o zielonkawym odcieniu, typowa dla zbiorników o wysokiej trofii. Latem występują okresowe zakwity planktonu.', 'Bardzo bogata. Szeroki i zwarty pas roślinności szuwarowej. Na tafli liczne skupiska grążeli żółtych. Pod wodą gęste dywany moczarki kanadyjskiej i rdestnic.', 'Lin, Szczupak, Karaś złocisty, Płoć, Okoń, Wzdręga', TRUE, 'Zarybiane okresowo narybkiem szczupaka i lina przez Gospodarstwo Rybackie w Giżycku. Silna naturalna populacja ryb karpiowatych.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko (Obwód jeziora Orzysz). Ok. 290 zł/sezon. Dostępne online.', FALSE, FALSE, 'Możliwe z kilku kładek i pomostów od strony miejscowości Strzelniki. Większość brzegu niedostępna z lądu przez bagniste trzcinowiska.', TRUE, TRUE, 'Bardzo dobry dojazd drogą asfaltową (trasa nr 16), następnie zjazdy utwardzone prowadzące bezpośrednio do miejscowości i jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80060, 'Sielawowo-leszczowe', 67.5, 6.2, 17.5, 'Typowo rynnowe: bardzo strome stoki, dno pofalowane z wyraźną rynną centralną. Liczne półki na głębokości 5-7 metrów.', 'Przeważnie twarde, piaszczysto-żwirowe na spadach. W najgłębszych partiach rynny dno pokryte cienką warstwą osadów mineralnych.', 'Wysoka (2.5 - 4.0m). Woda krystaliczna, przejrzysta przez większość sezonu, co sprzyja rozwojowi łąk podwodnych.', 'Umiarkowana. Wąski, ale zwarty pas trzcin. Pod wodą dominują ramienice i rdestnice, sięgające do głębokości ok. 6 metrów.', 'Szczupak, Sandacz, Okoń, Leszcz, Sielawa, Płoć, Węgorz', TRUE, 'Systematyczne zarybienia szczupakiem i sandaczem. Jezioro słynie z dobrej naturalnej regeneracji populacji sielawy i okonia.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Dostępne online oraz w punktach stacjonarnych w Orzyszu i Giżycku.', FALSE, FALSE, 'Możliwe z nielicznych kładek i stanowisk od strony miejscowości Rostki Skomackie. Większość brzegu wymaga łodzi.', TRUE, TRUE, 'Dobry dojazd od strony Orzysza drogą asfaltową, a następnie utwardzoną szutrową do samej miejscowości.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80061, 'Linowo-szczupakowe', 16.2, 2.5, 7.1, 'Dno misowate, wyrównane, o bardzo łagodnych spadach. Brak wyraźnych rynien czy górek podwodnych; strefa najgłębsza znajduje się w centralnej części akwenu.', 'Przeważnie miękkie, muliste. W strefie przybrzeżnej występują nieliczne partie twardsze, piaszczysto-muliste. Dno zasobne w materię organiczną.', 'Średnia (1.0 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla zbiorników eutroficznych. Przejrzystość wzrasta jesienią, latem możliwe okresowe zakwity planktonu.', 'Bogata. Szeroki i zwarty pas trzciny pospolitej i sitowia. Na powierzchni liczne pola grążeli żółtych. Pod wodą gęste łąki moczarki kanadyjskiej i rdestnic.', 'Lin, Szczupak, Leszcz, Okoń, Płoć, Wzdręga', TRUE, 'Zarybiane okresowo narybkiem szczupaka i lina przez GR Giżycko. Silna naturalna regeneracja populacji białorybu.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, dostępne zezwolenia okresowe online i w punktach w Orzyszu.', FALSE, FALSE, 'Możliwe z nielicznych dzikich stanowisk oraz pomostów od strony lokalnych gospodarstw. Większość brzegu wymaga łodzi.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i polnymi od strony miejscowości Skomack Wielki lub Rostki Skomackie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80329, 'Linowo-szczupakowe', 22.6, 1.3, 3.1, 'Płytka niecka, rynnowa.', 'Muliste.', 'Średnia', 'Bardzo bogata.', 'Lin, Szczupak, Wzdręga, Okoń', TRUE, 'Naturalna.', TRUE, 'GR Augustów.', FALSE, FALSE, 'Dobre.', FALSE, FALSE, 'Miejska asfaltowa.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80062, 'Linowo-szczupakowe', 132, 1.5, 4.8, 'Dno misowate, bardzo wyrównane, ulegające intensywnej sukcesji i zamulaniu organicznemu. Brak wyraźnych rynien i podwodnych wzniesień.', 'Wybitnie miękkie, muliste z grubą warstwą osadów organicznych i detrytusu. Nieliczne partie twardsze występują jedynie w strefach przybrzeżnych od strony zachodniej.', 'Niska/Średnia (1.0 - 1.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior o wysokiej trofii. Latem widoczne intensywne zakwity planktonu.', 'Ekstremalnie bogata. Brzegi otoczone szerokim pasem trzcin i pałki. Powierzchnia tafli w 30% pokryta grążelami. Pod wodą gęste dywany moczarki kanadyjskiej.', 'Lin, Szczupak, Karaś złocisty, Leszcz, Płoć, Okoń', TRUE, 'Zarybiane okresowo narybkiem szczupaka i lina przez Gospodarstwo Rybackie w Giżycko. Silna naturalna populacja gatunków fitofilnych.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, 20-55 zł/okresowe. Zakup online lub w punktach w Orzyszu i Skomacku.', FALSE, FALSE, 'Praktycznie niemożliwe ze względu na bagniste brzegi i gęstą roślinność szuwarową. Brak ogólnodostępnych pomostów i kładek.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi i utwardzonymi od strony miejscowości Skomack Wielki lub Ogródek. Drogi bywają grząskie po opadach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80064, 'Linowo-szczupakowe', 24.8, 2.2, 5.8, 'Dno misowate, wyrównane, o łagodnych spadach ku środkowi akwenu. Brak gwałtownych rynien czy podwodnych górek; naturalne wypłycanie w strefach przybrzeżnych.', 'W przeważającej części miękkie, muliste z grubą warstwą osadów organicznych. Nieliczne partie twardsze, piaszczyste, występują punktowo przy północnym brzegu.', 'Średnia (1.0 - 1.8m). Woda o zielonkawym zabarwieniu, typowa dla jezior żyznych. Latem widoczne okresowe zakwity planktonu, przejrzystość wzrasta jesienią.', 'Bogata. Zwarty pas trzciny pospolitej wokół całego jeziora. Liczne skupiska grążeli żółtych i lilii wodnych. Pod wodą gęste dywany moczarki i rdestnic.', 'Lin, Szczupak, Karaś złocisty, Płoć, Okoń, Leszcz', TRUE, 'Zarybiane okresowo narybkiem szczupaka i lina przez PZW Suwałki. Dobra naturalna odnowa populacji ryb spokojnego żeru.', TRUE, 'Zezwolenie PZW Suwałki (Gospodarstwo Ełk). Ceny zgodne z taryfikatorem PZW dla wód nizinnych (ok. 250-400 zł/rok).', FALSE, FALSE, 'Możliwe z nielicznych pomostów i stanowisk przy miejscowości Lipińskie Małe. Większość brzegu niedostępna z lądu przez bagniste trzcinowiska.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi szutrami od strony trasy Orzysz-Ełk. Dojazd bezpośrednio do wsi Lipińskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80065, 'Linowo-szczupakowe / Dystroficzne', 12.5, 1.2, 3.8, 'Dno misowate, bardzo regularne i wyrównane. Brak wyraźnych rynien i górek podwodnych; naturalne wypłycanie i zamulanie w osi środkowej.', 'Wybitnie miękkie, mulisto-torfowe. Gruba warstwa osadów organicznych. Brak twardych, piaszczystych partii dna poza nielicznymi wejściami.', 'Niska (0.5 - 1.0m). Woda o ciemnym, brunatnym zabarwieniu (huminowa), przejrzystość ograniczona przez zawiesinę organiczną i pyłki.', 'Ekstremalnie bogata. Brzegi niedostępne, otoczone szerokim pasem trzcin i mchów torfowców. Na tafli liczne pola grążeli. Pod wodą gęsta moczarka.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć', TRUE, 'Naturalna regeneracja populacji. Gospodarstwo Giżycko rzadko prowadzi tu intensywne zarybienia, co sprzyja zachowaniu dzikiego charakteru rybostanu.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon, dostępne online.', FALSE, FALSE, 'Praktycznie niemożliwe ze względu na trzęsawiskowe brzegi i brak utwardzonych stanowisk.', FALSE, TRUE, 'Trudny. Dojazd drogami polnymi i leśnymi od strony miejscowości Ogródek lub Skomack Wielki. Wymagane przenoszenie sprzętu ręcznie.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80066, 'Szczupakowo-linowe', 182, 3.2, 8.1, 'Bardzo urozmaicone. Liczne podwodne górki, zagłębienia rynnowe oraz rozległe blaty o głębokości 3-4 metrów. Linia brzegowa silnie rozwinięta z licznymi zatokami.', 'Zróżnicowane: przeważnie miękkie i muliste w zatokach i rynnie głównej. Na szczytach podwodnych górek i stokach dno jest twarde, piaszczysto-żwirowe i kamieniste.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym odcieniu, typowa dla jezior żyznych. Przejrzystość wzrasta jesienią; latem możliwe okresowe zakwity planktonu.', 'Bardzo silnie rozwinięta. Szerokie pasy trzciny pospolitej i pałki. Pod wodą rozległe łąki moczarki, wywłócznika i rdestnic. Liczne i duże pola grążeli żółtych.', 'Szczupak, Lin, Okoń, Leszcz, Sandacz, Płoć, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i sandaczem przez Gospodarstwo Jeziorowe w Ełku. Silna naturalna populacja lina i dużego leszcza.', TRUE, 'Zezwolenie PZW Suwałki (Gospodarstwo Ełk). Dostępne e-zezwolenia online oraz w sklepach wędkarskich w Ełku i Orzyszu.', FALSE, FALSE, 'Dobre. Liczne wycięte stanowiska wędkarskie oraz pomosty, szczególnie w rejonie miejscowości Zdedy i wzdłuż dostępnych brzegów polnych.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi szutrami bezpośrednio do miejscowości Zdedy oraz do kilku dzikich zjazdów nad wodę.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80067, 'Sielawowo-sandaczowe', 152.5, 8.5, 21.4, 'Wybitnie rynnowe o bardzo stromych stokach. Dno pofalowane z wyraźną rynną centralną i lokalnymi przegłębieniami. Liczne twarde blaty na głębokości 6-8 metrów.', 'Przeważnie twarde, piaszczysto-żwirowe i kamieniste na spadach. W najgłębszych partiach rynny dno pokryte cienką warstwą mułu mineralnego.', 'Wysoka (2.5 - 4.0m). Woda krystaliczna, o błękitno-zielonym odcieniu, bardzo dobra widoczność sprzyja rozwojowi bogatych łąk podwodnych.', 'Umiarkowanie rozwinięta. Wąski pas trzciny pospolitej ze względu na strome brzegi. Pod wodą dominują ramienice i rdestnica połyskująca sięgająca do 6m głębokości.', 'Sandacz, Szczupak, Okoń, Leszcz, Sielawa, Węgorz, Płoć', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem przez GR Giżycko. Silna naturalna populacja sielawy i okonia.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. E-zezwolenia dostępne online oraz w sklepach wędkarskich w Piszu.', FALSE, FALSE, 'Możliwe z nielicznych kładek i stanowisk od strony miejscowości Kociołek Szlachecki. Większość brzegu wymaga łodzi.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi szutrami od strony trasy Pisz-Biała Piska do miejscowości nadbrzeżnych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80069, 'Sielawowo-sandaczowe', 211.5, 9.2, 31, 'Rynnowe o bardzo stromych stokach i wyrównanej rynnie centralnej. Liczne podwodne półki na głębokości 5-8 metrów oraz twarde blaty.', 'Przeważnie twarde, piaszczysto-żwirowe na spadach. W najgłębszych rynnach występuje warstwa mułu mineralnego; brak grubych osadów organicznych.', 'Wysoka (2.5 - 4.5m). Woda krystaliczna o błękitno-zielonym odcieniu, doskonała widoczność sprzyja rozwojowi bogatych łąk podwodnych do 6m głębokości.', 'Umiarkowanie rozwinięta. Wąski, ale zwarty pas trzciny pospolitej. Pod wodą dominują ramienice, wywłócznik i rdestnica połyskująca.', 'Sandacz, Szczupak, Okoń, Leszcz, Sielawa, Węgorz, Płoć', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem przez GR Giżycko. Silna naturalna populacja sielawy i dużego okonia.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. E-zezwolenia dostępne online oraz w punktach w Piszu i Giżycku.', FALSE, FALSE, 'Możliwe z nielicznych kładek i stanowisk od strony miejscowości Białoławki. Większość brzegu wymaga łodzi.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi szutrami od strony trasy Pisz-Biała Piska do miejscowości Białoławki.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80143, 'Linowo-szczupakowe', 24.5, 2.5, 6.2, 'Dno misowate, pofałdowane.', 'Mulisto-piaszczyste.', 'Średnia (1.5m)', 'Bardzo bogata (trzciny, grążele).', 'Lin, Karaś złocisty, Szczupak, Płoć', TRUE, 'Naturalna regeneracja populacji.', TRUE, 'PZW Włocławek.', FALSE, FALSE, 'Umiarkowane.', TRUE, TRUE, 'Dojazd utwardzony/polny.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80070, 'Sandaczowo-szczupakowe', 11340, 5.8, 23.4, 'Rozległe, pofalowane dno z licznymi podwodnymi górkami, kamienistymi rafami i głazowiskami. Brak jednej głębokiej rynny; głęboczki są rozproszone po całym akwenie.', 'W przeważającej części twarde, piaszczyste i kamieniste (niebezpieczne głazy narzutowe). W zatokach i głębszych partiach dno pokryte cienką warstwą mułu mineralnego.', 'Średnia (1.5 - 3.0m). Przejrzystość mocno uzależniona od siły wiatru i falowania, które podrywa osady z dna. Woda o barwie zielonkawo-niebieskiej.', 'Bardzo szeroki pas trzcin (do 200m szerokości). Pod wodą rozległe łąki rdestnic, moczarki i ramienic, sięgające do głębokości ok. 5 metrów.', 'Szczupak, Sandacz, Okoń, Leszcz, Płoć, Węgorz, Sielawa', TRUE, 'Systematycznie zarybiane szczupakiem, sandaczem i węgorzem przez GR Giżycko. Silna naturalna regeneracja populacji okonia i leszcza.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. E-zezwolenia dostępne online oraz w licznych punktach wokół jeziora.', FALSE, FALSE, 'Bardzo trudne. Brzegi bagniste i porośnięte trzciną. Większość wędkowania odbywa się z łodzi. Nieliczne stanowiska w portach i na plażach.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi do miejscowości turystycznych: Mikołajki, Pisz, Nowe Guty, Niedźwiedzi Róg.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80071, 'Leszczowo-szczupakowe', 370, 3.5, 7, 'Dno misowate, wyrównane o bardzo łagodnych spadach. Brak gwałtownych uskoków i podwodnych górek; naturalne rynny występują wzdłuż głównego nurtu w stronę Kanału Jeglińskiego.', 'Przeważnie piaszczysto-muliste. Szerokie partie twardego, piaszczystego dna występują w zachodniej części, natomiast zatoki wschodnie są silnie zamulone.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior żyznych. Przejrzystość mocno uzależniona od falowania i kierunku wiatru od strony Śniardw.', 'Bardzo bogata. Szerokie pasy trzciny pospolitej (nawet do 100m). Pod wodą rozległe dywany moczarki, wywłócznika i rdestnic. Liczne pola grążeli w zatokach.', 'Szczupak, Leszcz, Okoń, Lin, Płoć, Węgorz, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i węgorzem przez GR Giżycko w ramach gospodarki na kompleksie Śniardw. Silna naturalna populacja białorybu.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. E-zezwolenia dostępne online oraz w Piszu i Giżycku.', FALSE, FALSE, 'Bardzo utrudnione ze względu na szeroki pas trzcin i bagnisty dostęp do wody. Większość wędkowania odbywa się z łodzi lub pontonów.', TRUE, TRUE, 'Dobry dojazd asfaltowy do miejscowości Zdory lub Jeglin, dalej drogi utwardzone i polne prowadzące do nielicznych plaż i przystani.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80074, 'Sielawowo-szczupakowe', 124.5, 8.8, 36.1, 'Bardzo urozmaicone, typowo rynnowe. Strome stoki, liczne głębokie rynny i podwodne półki. Dno pofalowane, brak rozległych mielizn przybrzeżnych.', 'Przeważnie twarde, piaszczysto-żwirowe i kamieniste. W najgłębszych rynnach cienka warstwa osadów sielawowych. Brak grubych osadów organicznych.', 'Bardzo wysoka (4.0 - 6.0m). Krystaliczna woda o błękitnym odcieniu, doskonała widoczność nawet na dużych głębokościach przez cały rok.', 'Umiarkowana. Wąski pas trzciny pospolitej. Pod wodą bogate łąki ramienicowe i rdestnica połyskująca, sięgające do głębokości nawet 7-8 metrów.', 'Szczupak, Okoń, Leszcz, Lin, Sielawa, Płoć, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i sielawą przez GR Giżycko. Silna naturalna populacja dużego okonia i płoci.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. Dostępne online oraz w punktach w Piszu i Giżycku.', FALSE, TRUE, 'Utrudnione ze względu na wysokie, zalesione brzegi i brak płaskich stanowisk. Nieliczne dzikie zejścia od strony lasu.', FALSE, TRUE, 'Trudny. Dojazd wyłącznie drogami leśnymi Puszczy Piskiej od strony miejscowości Snopki lub Jeglin. Drogi bywają piaszczyste.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80075, 'Linowo-szczupakowe / Dystroficzne', 10.5, 1.5, 4.2, 'Dno misowate, o regularnym ukształtowaniu, ulegające naturalnym procesom zamulania leśnego. Brak wyraźnych rynien i górek podwodnych.', 'Wybitnie miękkie, mulisto-torfowe z dużą zawartością osadów organicznych i liści. Brak twardych partii dna poza nielicznymi prześwitami przy brzegach.', 'Niska/Średnia (0.8 - 1.2m). Woda o herbacianym odcieniu, typowa dla jezior śródleśnych. Przejrzystość ograniczona przez barwniki huminowe.', 'Bardzo bogata. Brzegi porośnięte gęstą trzciną i krzewami. Na tafli liczne skupiska grążeli żółtych i lilii wodnych. Pod wodą gęste łąki moczarki.', 'Lin, Karaś złocisty, Szczupak, Okoń, Płoć, Wzdręga', TRUE, 'Naturalna regeneracja populacji ryb. Systematyczne zarybienia drapieżnikami w ramach gospodarki obwodowej GR Giżycko.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. Dostępne online oraz w punktach w Piszu.', FALSE, TRUE, 'Ekstremalnie utrudnione ze względu na bagniste, trzęsawiskowe brzegi. Wymagane wodery i ostrożność.', FALSE, TRUE, 'Ekstremalnie trudny. Dojazd wyłącznie drogami leśnymi Puszczy Piskiej od strony jeziora Jegocin lub miejscowości Snopki. Brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80076, 'Linowo-szczupakowe / Dystroficzne', 7.5, 1.4, 3.2, 'Dno misowate, wyrównane, ulegające procesom naturalnego wypłycania i zamulania torfowego. Brak rynien i górek podwodnych.', 'Wybitnie miękkie, mulisto-torfowe z grubą warstwą osadów organicznych i detrytusu leśnego (liście, igliwie).', 'Niska (0.7 - 1.2m). Woda o barwie brunatnej (huminowa), przejrzystość stała, ograniczona przez naturalne barwniki organiczne.', 'Bogata. Brzegi porośnięte gęstą trzciną i mchami torfowcami. Na tafli liczne skupiska grążeli żółtych. Pod wodą dominują gęste łąki moczarki.', 'Lin, Karaś złocisty, Szczupak, Płoć, Okoń', TRUE, 'Naturalna regeneracja populacji ryb. Systematyczne zarybienia drapieżnikami prowadzone rzadziej niż na głównych akwenach.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. E-zezwolenia dostępne online oraz w punktach w Piszu.', FALSE, TRUE, 'Ekstremalnie utrudnione ze względu na bagniste, trzęsawiskowe brzegi i gęste zarośla. Wymagane wodery.', FALSE, TRUE, 'Trudny. Dojazd wyłącznie drogami leśnymi Puszczy Piskiej od strony jeziora Jegocin lub miejscowości Snopki. Brak utwardzonych zjazdów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80077, 'Leszczowo-karasiowe', 159.5, 5.2, 17.2, 'Typowo rynnowe, wydłużone południkowo. Największe głębokości występują na osi zbiornika. Brzegi południowe i zachodnie strome, północne łagodne i płaskie.', 'Piaszczysto-muliste. W strefie przybrzeżnej dominują partie piaszczyste, natomiast w rynnie głównej i osłoniętych zatokach dno pokryte jest warstwą mułu organicznego.', 'Wysoka (2.5 - 4.0m). Woda krystalicznie czysta, o błękitnym odcieniu. Doskonała przejrzystość sprzyja rozwojowi łąk podwodnych do znacznych głębokości.', 'Średnio rozwinięta. Pas trzciny i pałki wodnej występuje miejscami intensywnie. Pod wodą bogate dywany rdestnic i moczarki. W płytszych zatokach liczne grążele.', 'Leszcz, Szczupak, Lin, Okoń, Płoć, Karaś złocisty', TRUE, 'Systematycznie zarybiane przez Okręg Mazowiecki PZW szczupakiem i białorybem. Stanowi naturalny, czysty matecznik dla okolicznych gatunków.', TRUE, 'Zezwolenie Okręgu Mazowieckiego PZW. Dostępne e-zezwolenia online oraz w biurach kół PZW. Obowiązuje karta wędkarska.', FALSE, TRUE, 'Możliwe z nielicznych kładek i stanowisk przy wschodnim brzegu. Dostęp od zachodu utrudniony przez strome, leśne zbocza.', TRUE, TRUE, 'Dobra od strony trasy Pisz-Ruciane Nida, dalej drogi utwardzone i leśne szutry prowadzące do punktów wodowania i kąpielisk.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80144, 'Sandaczowo-leszczowe', 34.2, 4.5, 11.5, 'Rynnowe, strome stoki.', 'Piaszczysto-żwirowe.', 'Średnia (2.0m)', 'Umiarkowana (wąski pas trzcin).', 'Sandacz, Leszcz, Szczupak, Okoń', TRUE, 'Zarybiane sandaczem.', TRUE, 'PZW Włocławek.', FALSE, FALSE, 'Dobre z nielicznych stanowisk.', TRUE, TRUE, 'Dojazd drogami lokalnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80073, 'Szczupakowo-leszczowe', 170.5, 6.2, 29, 'Bardzo urozmaicone. Liczne wyspy, podwodne górki, wyraźne rynny i rozległe płycizny. Linia brzegowa wyjątkowo silnie rozwinięta.', 'Zróżnicowane: piaszczyste na blatach i piaszczysto-żwirowe na spadach. W głębokich rynnach i osłoniętych zatokach dno pokryte cienką warstwą mułu.', 'Wysoka (2.5 - 4.5m). Woda czysta, o błękitno-zielonym odcieniu. Doskonała widoczność sprzyja rozwojowi bogatych podwodnych łąk rdestnic.', 'Bardzo bogata. Szerokie pasy trzcin i pałki. Na powierzchni liczne pola grążeli i lilii. Pod wodą gęste dywany ramienic i moczarki do głębokości ok. 6m.', 'Szczupak, Okoń, Leszcz, Lin, Płoć, Węgorz, Wzdręga', TRUE, 'Regularnie zarybiane szczupakiem i węgorzem przez Gospodarstwo Rybackie w Giżycku. Silna naturalna populacja lina i dużego leszcza.', TRUE, 'Zezwolenie Gosp. Rybackiego Giżycko. Ok. 290 zł/sezon. E-zezwolenia dostępne online oraz w ośrodkach w miejscowości Wiartel.', FALSE, TRUE, 'Dobre z licznych pomostów oraz brzegów przy miejscowości Wiartel i ośrodkach wypoczynkowych. Wiele odcinków leśnych niedostępnych.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi z Pisza do miejscowości Wiartel, dalej drogi utwardzone prowadzące do linii brzegowej.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80037, 'Leszczowo-szczupakowe', 436.2, 4.3, 10.2, 'Dno mało urozmaicone, misowate z kilkoma łagodnymi przegłębieniami. Linia brzegowa rozwinięta, z wyraźnymi półwyspami dzielącymi akwen na kilka części.', 'Przeważnie piaszczysto-muliste. W strefie przybrzeżnej i na stokach półwyspów dno jest twardsze, piaszczyste. W rynnie centralnej zalega warstwa mułu.', 'Średnia/Niska (1.0 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla zbiorników o wysokiej produktywności biologicznej. Latem możliwe zakwity.', 'Bardzo bogata. Szeroki pas trzciny pospolitej i pałki wodnej (do 10-15m szerokości). Pod wodą rozległe łąki moczarki i rdestnic. Liczne pola grążeli.', 'Leszcz, Szczupak, Sandacz, Okoń, Płoć, Lin, Węgorz', TRUE, 'Systematycznie zarybiane szczupakiem, sandaczem oraz węgorzem przez Gospodarstwo Rybackie w Szczytnie.', TRUE, 'Zezwolenie GR Szczytno. Ceny zgodne z taryfikatorem gospodarza (ok. 25-50 zł za dobę). Dostępne w sklepach wędkarskich w Szczytnie.', FALSE, TRUE, 'Dobre. Wzdłuż zachodniego brzegu i w miejscowościach turystycznych (np. Wałpusz) znajduje się wiele pomostów i dogodnych stanowisk.', TRUE, TRUE, 'Bardzo dobry dojazd drogą krajową nr 58 (Szczytno-Ostroleka) lub lokalnymi drogami asfaltowymi. Liczne zjazdy bezpośrednio nad wodę.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80079, 'Leszczowo-szczupakowe', 165, 4.5, 12.1, 'Rynnowe, o pofalowanym dnie z wyraźną rynną centralną. Linia brzegowa umiarkowanie rozwinięta, brzegi przeważnie wysokie i suche, częściowo zalesione.', 'Piaszczysto-muliste. W partiach przybrzeżnych dno jest twardsze, piaszczyste; w głębszych rejonach rynny zalega warstwa ciemnego mułu organicznego.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym odcieniu, przejrzystość dobra wiosną i jesienią, latem ograniczona przez okresowe zakwity planktonu.', 'Bogata. Szeroki pas trzciny pospolitej i pałki wodnej. Na powierzchni liczne skupiska grążeli żółtych. Pod wodą gęste łąki moczarki i wywłócznika.', 'Leszcz, Szczupak, Płoć, Sandacz, Okoń, Lin, Węgorz', TRUE, 'Regularnie zarybiane szczupakiem, sandaczem i węgorzem przez Gospodarstwo Rybackie w Szczytnie.', TRUE, 'Zezwolenie GR Szczytno. Dostępne w sklepach wędkarskich w Szczytnie oraz w punktach sprzedaży zezwoleń online.', FALSE, TRUE, 'Bardzo dobre. Liczne pomosty wędkarskie i dogodne stanowiska brzegowe, szczególnie od strony Starych Kiejkut.', TRUE, TRUE, 'Dobry dojazd drogą krajową nr 58, a następnie drogami lokalnymi bezpośrednio do miejscowości Stare Kiejkuty.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80080, 'Sielawowe', 116.8, 11, 39.5, 'Typowo rynnowe o bardzo stromych stokach. Dno mało pofalowane, z wyraźną, głęboką rynną centralną biegnącą wzdłuż osi jeziora.', 'Przeważnie twarde, piaszczysto-żwirowe i kamieniste na spadach. W najgłębszych partiach rynny dno pokryte cienką warstwą mułu sielawowego.', 'Bardzo wysoka (I klasa czystości). Przejrzystość sięgająca 4-6 metrów, woda o błękitnym odcieniu, bardzo dobrze natleniona.', 'Uboga w strefie wynurzonej (wąski pas trzciny). Bardzo bogata podwodna (łąki ramienicowe i wywłócznik sięgające głębokości 7 metrów).', 'Sielawa, Szczupak, Okoń, Leszcz, Płoć, Węgorz', TRUE, 'Systematycznie zarybiane sielawą i szczupakiem przez Gospodarstwo Rybackie w Szczytnie. Naturalna odnowa populacji okonia.', TRUE, 'Zezwolenie GR Szczytno. Ok. 30-50 zł/doba. Dostępne w sklepach wędkarskich w Szczytnie oraz online.', FALSE, TRUE, 'Możliwe tylko w nielicznych miejscach ze względu na strome i zalesione brzegi. Większość wędkowania odbywa się z łodzi.', FALSE, TRUE, 'Dojazd drogami leśnymi i utwardzonymi od strony miejscowości Orzyny lub przez ośrodek „Kulka”. Drogi bywają wąskie i piaszczyste.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80036, 'Linowo-szczupakowe', 13.8, 1.8, 4.5, 'Dno misowate, wyrównane, bez gwałtownych uskoków. Jezioro ulega naturalnemu procesowi wypłycania.', 'Wybitnie miękkie, muliste. Gruba warstwa osadów organicznych na przeważającej powierzchni akwenu.', 'Niska/Średnia (0.8 - 1.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior żyznych. Przejrzystość mocno ograniczona w miesiącach letnich.', 'Bardzo bogata. Szeroki pas trzcin i pałki. Powierzchnia tafli w dużej części pokryta grążelami żółtymi. Pod wodą gęste dywany moczarki.', 'Lin, Karaś złocisty, Szczupak, Płoć, Okoń', TRUE, 'Zarybiane okresowo szczupakiem przez GR Szczytno. Silna naturalna populacja lina i karasia.', TRUE, 'Zezwolenie GR Szczytno. Ok. 30-55 zł/doba. Dostępne w punktach sprzedaży w Szczytnie i Dźwierzutach.', FALSE, FALSE, 'Bardzo utrudnione. Brzegi bagniste i trzęsawiskowe. Brak utwardzonych stanowisk i kładek.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi i leśnymi od strony miejscowości Orzyny. Po opadach drogi bywają grząskie.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80082, 'Linowo-szczupakowe', 104.2, 3.2, 7.8, 'Rynnowe, o dość wyrównanym dnie z łagodnymi spadami. Brak gwałtownych uskoków i podwodnych górek; najgłębsze punkty znajdują się w środkowej części rynny.', 'Przeważnie muliste i piaszczysto-muliste. W strefie przybrzeżnej występują partie twardsze, piaszczyste, szczególnie od strony miejscowości Rańsk.', 'Średnia (1.0 - 2.0m). Woda o zielonkawym odcieniu, typowa dla zbiorników eutroficznych. Przejrzystość wzrasta jesienią, latem widoczne okresowe zakwity.', 'Bogata. Wyraźny pas trzcin i pałki wodnej wokół większości akwenu. Liczne skupiska grążeli żółtych. Pod wodą gęste łąki moczarki i rdestnic.', 'Lin, Szczupak, Leszcz, Płoć, Okoń, Węgorz, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i linem przez Gospodarstwo Rybackie w Szczytnie. Dobra naturalna odnowa populacji białorybu.', TRUE, 'Zezwolenie GR Szczytno. Ok. 30-55 zł za dobę. Dostępne w punktach sprzedaży w Szczytnie, Dźwierzutach oraz online.', FALSE, FALSE, 'Dobre. Wzdłuż brzegów znajduje się wiele wyciętych stanowisk wędkarskich oraz nieliczne kładki i pomosty.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi bezpośrednio do miejscowości Rańsk i nad brzeg jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80063, 'Szczupakowo-linowe', 17.5, 3.2, 8.5, 'Rynnowe, dno pofalowane, brzegi dość strome i zalesione.', 'Piaszczysto-muliste, z dużą ilością osadów leśnych w zatokach.', 'Wysoka (2.0 - 3.0m). Woda stosunkowo czysta przez cały sezon.', 'Umiarkowana. Pas trzcin wąski, ale zwarty. Pod wodą kępy moczarki.', 'Szczupak, Lin, Płoć, Okoń, Wzdręga', TRUE, 'Naturalna regeneracja populacji, wspierana okresowymi zarybieniami szczupakiem.', TRUE, 'Zezwolenie GR Ostróda. Dostępne online i w lokalnych punktach sprzedaży.', FALSE, TRUE, 'Umiarkowane. Wymaga znalezienia prześwitów w zaroślach leśnych.', TRUE, TRUE, 'Dojazd drogami leśnymi i utwardzonymi od strony miejscowości Płowężek.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80089, 'Sielawowo-leszczowe', 155, 7.5, 24.8, 'Typowo rynnowe o stromych stokach. Dno pofalowane z wyraźną rynną centralną i licznymi twardymi blatami na głębokości 5-8 metrów.', 'Przeważnie twarde, piaszczysto-żwirowe. W najgłębszych partiach cienka warstwa osadów sielawowych; brak grubego zamulenia organicznego.', 'Wysoka (2.5 - 4.5m). Woda krystaliczna, błękitna, o bardzo dobrej przejrzystości przez większość sezonu.', 'Umiarkowanie rozwinięta. Wąski pas trzciny ze względu na strome brzegi. Pod wodą bogate łąki ramienicowe i rdestnice.', 'Szczupak, Okoń, Leszcz, Sielawa, Sandacz, Płoć, Węgorz', TRUE, 'Systematycznie zarybiane sielawą i szczupakiem przez Gospodarstwo Rybackie w Mrągowie.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w sklepach wędkarskich w Mrągowie i Pieckach.', FALSE, TRUE, 'Utrudnione ze względu na strome, zalesione brzegi. Nieliczne pomosty przy ośrodkach wypoczynkowych.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i leśnymi szutrami od strony trasy Mrągowo-Biskupiec.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80090, 'Leszczowo-szczupakowe', 123, 5.2, 19.8, 'Rynnowe, o pofalowanym dnie z wyraźną rynną centralną. Linia brzegowa wydłużona, brzegi wysokie, miejscami strome.', 'Zróżnicowane: piaszczysto-muliste. W strefie przybrzeżnej liczne partie piaszczyste, w rynnie osady muliste pochodzenia rzecznego.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior przepływowych o wyższej trofii.', 'Bogata. Szeroki pas trzciny pospolitej. Liczne pola grążeli i lilii wodnych w zatokach. Pod wodą moczarka i rdestnice.', 'Leszcz, Szczupak, Okoń, Płoć, Lin, Węgorz, Wzdręga', TRUE, 'Regularnie zarybiane szczupakiem i węgorzem. Naturalna migracja ryb systemem rzeki Krutyni.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w punktach sprzedaży w Pieckach.', FALSE, FALSE, 'Dobre. W miejscowości Dłużec oraz przy polach namiotowych znajduje się wiele pomostów i stanowisk brzegowych.', TRUE, TRUE, 'Bardzo dobry dojazd drogą asfaltową do miejscowości Dłużec, liczne zjazdy nad samą wodę i slipy dla łodzi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80092, 'Linowo-szczupakowe', 5.8, 1.5, 3.8, 'Dno misowate, wyrównane, o regularnym ukształtowaniu. Brak wyraźnych rynien i górek podwodnych.', 'Wybitnie miękkie, mulisto-torfowe. Gruba warstwa osadów organicznych i leśnego detrytusu.', 'Niska (0.8 - 1.2m). Woda huminowa o ciemnym zabarwieniu, typowa dla jezior leśnych.', 'Bogata. Brzegi porośnięte gęstą trzciną i krzewami. Liczne grążele na powierzchni tafli.', 'Lin, Karaś złocisty, Szczupak, Okoń, Płoć', TRUE, 'Naturalna regeneracja populacji. Okresowe zarybienia szczupakiem przez Gospodarstwo Rybackie w Mrągowie.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online i w punktach sprzedaży w Pieckach.', FALSE, TRUE, 'Ekstremalnie utrudnione ze względu na bagniste brzegi. Wymagane wodery.', FALSE, TRUE, 'Trudny. Dojazd wyłącznie drogami leśnymi i piaszczystymi od strony miejscowości Dłużec.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80093, 'Sielawowo-leszczowe', 101.5, 5.8, 14.9, 'Rynnowe, o pofalowanym dnie z wyraźną rynną centralną i licznymi twardymi blatami.', 'Przeważnie twarde, piaszczysto-żwirowe. W głębszych partiach cienka warstwa osadów sielawowych.', 'Wysoka (2.5 - 3.5m). Woda o błękitnym odcieniu, dobrze natleniona przez cały sezon.', 'Umiarkowana. Pas trzciny pospolitej oraz podwodne łąki ramienicowe sięgające głębokości ok. 5m.', 'Szczupak, Okoń, Leszcz, Sielawa, Płoć, Węgorz', TRUE, 'Systematycznie zarybiane szczupakiem i sielawą przez Gospodarstwo Rybackie w Mrągowie.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online i w sklepach wędkarskich w okolicy.', FALSE, TRUE, 'Możliwe z nielicznych dzikich stanowisk oraz kładek przy miejscowości Piłaki.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i szutrowymi od strony trasy Piecki-Mrągowo.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80094, 'Leszczowo-sandaczowe', 139.8, 4.5, 11.2, 'Typowo rynnowe, o pofalowanym dnie z wyraźną rynną centralną i podwodnymi półkami.', 'Zróżnicowane: piaszczyste na spadach i mulisto-piaszczyste w głębszych rejonach akwenu.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior przepływowych o wyższej trofii.', 'Bogata. Szeroki pas trzcin i pałki. Pod wodą rozległe łąki moczarki i rdestnic, szczególnie w zatokach.', 'Sandacz, Szczupak, Leszcz, Okoń, Płoć, Węgorz, Lin', TRUE, 'Systematycznie zarybiane szczupakiem i sandaczem. Stały napływ ryb systemem rzeki Krutyni.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w punktach sprzedaży w Sorkwitach i Mrągowie.', FALSE, FALSE, 'Dobre. Liczne wycięte stanowiska wędkarskie oraz pomosty przy polach namiotowych i miejscowościach.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi bezpośrednio do miejscowości Mołdyty i nad brzeg jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80095, 'Leszczowo-szczupakowe', 151.2, 6.5, 22.8, 'Rynnowe, o pofalowanym dnie z wyraźną rynną centralną i podwodnymi górkami. Linia brzegowa urozmaicona z kilkoma półwyspami.', 'Przeważnie twarde, piaszczysto-żwirowe. W głębszych partiach rynny występuje cienka warstwa mułu mineralnego.', 'Wysoka (2.5 - 4.0m). Woda o błękitno-zielonym odcieniu, dobrze natleniona. Wysoka przejrzystość przez większość sezonu.', 'Bogata. Wyraźny pas trzciny pospolitej. Pod wodą rozległe łąki moczarki i ramienic, sięgające głębokości ok. 6 metrów.', 'Szczupak, Leszcz, Okoń, Płoć, Węgorz, Lin, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem, sandaczem i węgorzem przez Gospodarstwo Rybackie w Mrągowie.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w punktach sprzedaży w Sorkwitach i Mrągowie.', FALSE, TRUE, 'Możliwe z licznych pomostów oraz dzikich stanowisk wzdłuż brzegów leśnych. Wiele miejsc dostępnych tylko z łodzi.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi szutrami od strony miejscowości Suraż i Sorkwity.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80096, 'Sielawowo-szczupakowe', 278, 9.5, 38.5, 'Typowo rynnowe, o bardzo stromych stokach i głębokiej rynnie centralnej. Liczne podwodne półki i twarde blaty.', 'Przeważnie twarde, piaszczysto-żwirowe i kamieniste. W najgłębszych partiach cienka warstwa mułu sielawowego.', 'Bardzo wysoka (3.0 - 5.0m). Woda krystaliczna, bardzo dobrze natleniona nawet w głębokich partiach.', 'Umiarkowanie rozwinięta w strefie wynurzonej. Bardzo bogate podwodne łąki ramienicowe i rdestnice sięgające głębokości 7m.', 'Szczupak, Okoń, Leszcz, Sielawa, Sandacz, Węgorz, Płoć', TRUE, 'Systematycznie zarybiane sielawą, szczupakiem i sandaczem przez Gospodarstwo Rybackie w Mrągowie.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w sklepach wędkarskich w Mrągowie i Sorkwitach.', FALSE, TRUE, 'Dobre z licznych pomostów w Sorkwitach, Maradkach oraz przy ośrodkach wypoczynkowych.', TRUE, TRUE, 'Bardzo dobry dojazd drogą krajową nr 16 bezpośrednio do Sorkwit, liczne zjazdy i slipy nad wodę.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80142, 'Sandaczowo-leszczowe', 158, 4.5, 12.5, 'Misowate, bardzo urozmaicone, liczne górki.', 'Zróżnicowane (piasek/muł).', 'Średnia (1.5m)', 'Bardzo bogata.', 'Sandacz, Leszcz, Szczupak, Okoń, Węgorz', TRUE, 'Intensywne zarybienia sandaczem.', TRUE, 'PZW Włocławek.', FALSE, FALSE, 'Bardzo dobre (liczne pomosty).', TRUE, TRUE, 'Bardzo dobry dojazd (blisko DK67).', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80108, 'Linowo-szczupakowe', 18.5, 2.5, 6, 'Niecka o regularnym kształcie, dno łagodnie opadające ku środkowi bez gwałtownych uskoków.', 'Mulisto-piaszczyste. W strefie brzegowej pas twardego dna, w głębszych partiach zalega warstwa mułu organicznego.', 'Średnia (1.0 - 2.0m). Woda o barwie zielonkawej, typowa dla jezior polnych.', 'Bogata. Wyraźny pas trzcin i pałki wodnej, liczne grążele w osłoniętych zatokach.', 'Lin, Szczupak, Karaś złocisty, Okoń, Płoć', TRUE, 'Okresowe zarybienia szczupakiem i linem prowadzone przez GR Bogaczewo.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online i w lokalnych sklepach wędkarskich.', FALSE, FALSE, 'Dobre. Kilka stałych, wydeptanych stanowisk wzdłuż dostępnych brzegów.', TRUE, TRUE, 'Dojazd drogami polnymi i utwardzonymi od strony Sztumu lub Postolina.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80097, 'Sielawowo-sandaczowe', 444, 7.9, 27, 'Bardzo urozmaicone, typowo rynnowe. Liczne podwodne wyspy, górki i głębokie rynny centralne. Linia brzegowa silnie rozwinięta.', 'Zróżnicowane: przeważnie twarde, piaszczysto-kamieniste na wzniesieniach i spadach. W głębi osady muliste i sielawowe.', 'Wysoka (2.5 - 4.5m). Woda o błękitno-zielonym odcieniu, bardzo przejrzysta wiosną i jesienią.', 'Bogata. Wyraźny pas trzciny pospolitej. Pod wodą rozległe łąki ramienicowe i moczarki, szczególnie w okolicach wysp.', 'Szczupak, Sandacz, Okoń, Leszcz, Sielawa, Węgorz, Płoć', TRUE, 'Regularnie zarybiane sandaczem, szczupakiem i sielawą przez GR Mrągowo.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w Sorkwitach i Mrągowie.', FALSE, TRUE, 'Dobre z licznych pomostów w Starym Gielądzie i przy ośrodkach. Wiele odcinków dzikich dostępnych tylko z łodzi.', TRUE, TRUE, 'Bardzo dobry dojazd drogą nr 16 do Sorkwit, a następnie drogami lokalnymi bezpośrednio do miejscowości nadjeziornych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80098, 'Linowo-szczupakowe', 129.5, 3.5, 8.5, 'Urozmaicone, pofałdowane dno z łagodnymi spadami. Brak gwałtownych rynien; najgłębsze punkty rozproszone w środkowej części.', 'Przeważnie muliste z piaszczystymi partiami w rejonie półwyspów i przy brzegach zachodnich.', 'Średnia (1.0 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla jezior żyznych. Latem przejrzystość ograniczona przez roślinność.', 'Bardzo bogata. Szeroki pas roślinności wynurzonej (trzcina, pałka). Liczne i rozległe pola grążeli i lilii wodnych.', 'Lin, Szczupak, Leszcz, Karaś złocisty, Okoń, Płoć, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i linem przez GR Mrągowo.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w punktach sprzedaży w Mrągowie.', FALSE, FALSE, 'Umiarkowane. Wymaga znalezienia wyciętych stanowisk w trzcinach lub korzystania z lokalnych kładek.', TRUE, TRUE, 'Dojazd drogami utwardzonymi i polnymi od strony drogi nr 16. Miejscami droga może być piaszczysta.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80100, 'Linowo-szczupakowe', 53.5, 3.2, 7.5, 'Rynnowe, o wydłużonym kształcie i dość wyrównanym dnie. Brzegi wschodnie i zachodnie strome, porośnięte lasem.', 'Zróżnicowane: w strefie przybrzeżnej piaszczyste, w głębszych partiach i zatokach muliste z dużą zawartością detrytusu leśnego.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior o średniej żyzności.', 'Bogata. Szerokie pasy trzciny pospolitej i pałki wodnej. Liczne pola grążeli żółtych. Pod wodą moczarka i rdestnice.', 'Szczupak, Lin, Okoń, Leszcz, Płoć, Karaś złocisty', TRUE, 'Systematycznie zarybiane szczupakiem i linem przez GR Mrągowo.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w punktach sprzedaży w Pieckach i Mrągowie.', FALSE, TRUE, 'Umiarkowane. Wymaga znalezienia wyciętych stanowisk w trzcinach lub korzystania z nielicznych pomostów.', TRUE, TRUE, 'Utrudniony. Dojazd drogami leśnymi i piaszczystymi od strony miejscowości Babięty lub Machary.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80101, 'Sielawowo-szczupakowe', 250.2, 21.5, 65, 'Wybitnie rynnowe, o bardzo stromych stokach i głębokiej rynnie centralnej. Liczne podwodne tarasy i twarde blaty.', 'Przeważnie twarde, piaszczyste, żwirowe i kamieniste na spadach. W najgłębszych rynnach cienka warstwa osadów sielawowych.', 'Bardzo wysoka (4.0 - 7.0m). Krystaliczna woda o błękitnym odcieniu, doskonała widoczność przez cały rok.', 'Uboga w strefie wynurzonej (wąski pas trzciny). Bardzo bogata podwodna (łąki ramienicowe sięgające głębokości 8-10m).', 'Szczupak, Okoń, Sielawa, Leszcz, Węgorz, Płoć', TRUE, 'Systematycznie zarybiane sielawą i szczupakiem przez GR Mrągowo. Silna naturalna populacja dużego okonia.', TRUE, 'Zezwolenie GR Mrągowo. Dostępne online oraz w sklepach wędkarskich w okolicy.', FALSE, TRUE, 'Trudne ze względu na strome i zalesione brzegi. Najlepsze wyniki osiąga się łowiąc z łodzi.', FALSE, TRUE, 'Dobry dojazd do miejscowości Babięty, dalej drogi leśne prowadzące do nielicznych miejsc wodowania.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80103, 'Szczupakowo-linowe', 1147, 1.2, 3, 'Wybitnie wyrównane, misowate, typowe dla płytkich jezior deltowych. Głębsze rynny występują jedynie w osiach przepływu wód (np. rzeka Elbląg).', 'Bardzo miękkie, muliste. Gruba warstwa osadów organicznych pokrywa niemal całą powierzchnię dna.', 'Niska (0.5 - 1.0m). Woda o dużej zawartości zawiesiny organicznej, często mętna, o barwie brunatno-zielonej.', 'Ekstremalnie bogata. Jezioro niemal w całości zarasta grążelem żółtym, lilią wodną i rdestnicami. Potężne pasy trzcinowisk.', 'Szczupak, Lin, Leszcz, Karaś srebrzysty, Okoń, Płoć', TRUE, 'Zarybiane regularnie szczupakiem i linem przez PZW Elbląg. Bardzo silna naturalna regeneracja populacji.', TRUE, 'Zezwolenie PZW Elbląg + wymagane zapoznanie się z regulaminem rezerwatu. Dostępne online (e-pzw).', FALSE, TRUE, 'Praktycznie niemożliwe. Cała linia brzegowa to niedostępne trzęsawiska i trzcinowiska. Wędkowanie wyłącznie z łodzi.', FALSE, TRUE, 'Bardzo dobry dojazd do miejscowości Węgle-Żukowo lub Janów, gdzie znajdują się bazy wędkarskie i wypożyczalnie łodzi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80104, 'Linowo-szczupakowe', 30.5, 3.8, 12.5, 'Rynnowe, o wydłużonym kształcie. Dno pofalowane, z kilkoma mniejszymi rynnami w centralnej części.', 'Piaszczysto-muliste. W strefie przybrzeżnej liczne partie piaszczyste, głębiej zalega miękki muł organiczny.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym odcieniu, okresowo ulegająca zakwitom w pełni lata.', 'Bogata. Wyraźny pas trzcin i pałki wodnej. Pod wodą liczne kępy moczarki i rdestnic.', 'Lin, Szczupak, Okoń, Wzdręga, Leszcz, Płoć', TRUE, 'Systematycznie zarybiane szczupakiem przez Gospodarstwo Rybackie w Bogaczewie.', TRUE, 'Zezwolenie Gosp. Rybackie Bogaczewo. Dostępne online oraz w sklepach w Dzierzgoniu.', FALSE, FALSE, 'Dobre. Wzdłuż brzegów znajduje się wiele dzikich stanowisk oraz nieliczne prywatne kładki.', TRUE, TRUE, 'Dobry dojazd drogami lokalnymi i utwardzonymi szutrami bezpośrednio w pobliże linii brzegowej.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80105, 'Leszczowo-szczupakowe', 51.2, 4.2, 14, 'Misowate z jedną wyraźną rynną centralną. Brak podwodnych górek, dno łagodnie opadające ku środkowi.', 'Głównie muliste. Wąski piaszczysty pas występuje jedynie przy północnym brzegu.', 'Średnia/Niska (1.0 - 2.0m). Woda o barwie zielonej, o wysokiej zawartości substancji organicznych.', 'Bardzo bogata. Bardzo szeroki pas trzciny pospolitej. Pod wodą dominują wywłócznik i moczarka.', 'Leszcz, Szczupak, Okoń, Płoć, Lin, Węgorz', TRUE, 'Zarybiane okresowo narybkiem szczupaka i węgorza przez zarządcę.', TRUE, 'Zezwolenie Gosp. Rybackie Bogaczewo. Dostępne online oraz w punktach sprzedaży w Sztumie.', FALSE, FALSE, 'Utrudnione. Wymaga korzystania z pomostów lub wyciętych stanowisk w trzcinach.', TRUE, TRUE, 'Dojazd drogami polnymi i utwardzonymi od strony miejscowości Kaniewo. Drogi bywają grząskie.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80107, 'Sielawowo-sandaczowe', 58.5, 6.5, 20.2, 'Urozmaicone, typowo rynnowe. Dno z wyraźnymi uskokami i piaszczystymi półkami na różnych głębokościach.', 'W przeważającej części twarde, piaszczyste i żwirowe. Brak grubszych osadów mulistych w strefie przybrzeżnej.', 'Wysoka (2.5 - 4.5m). Woda o błękitnym odcieniu, jedna z najczystszych w powiecie sztumskim.', 'Umiarkowana. Wąski pas trzcin, pod wodą bogate łąki ramienicowe sięgające do głębokości ok. 6 metrów.', 'Sandacz, Okoń, Szczupak, Leszcz, Sielawa, Płoć', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem. Silna naturalna populacja sielawy.', TRUE, 'Zezwolenie Gosp. Rybackie Bogaczewo. Możliwość zakupu online lub w sklepie "U Darka" w Sztumie.', FALSE, TRUE, 'Bardzo dobre. Liczne pomosty, kładki oraz piaszczyste brzegi idealne do połowu z gruntu.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi bezpośrednio pod jezioro. Parkingi przy plaży miejskiej.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80330, 'Leszczowe', 251, 9, 30.5, 'Rynnowe, rozwinięta linia, wyspy.', 'Piaszczysto-muliste.', 'Wysoka', 'Średnia.', 'Leszcz, Sandacz, Węgorz, Okoń, Szczupak', TRUE, 'Regularne zarybienia.', TRUE, 'GR Augustów.', FALSE, TRUE, 'Dobre.', TRUE, TRUE, 'Asfalt.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80109, 'Leszczowo-sandaczowe', 49.8, 6.8, 24.5, 'Rynnowe, o bardzo stromych stokach w niektórych partiach. Dno pofalowane z wyraźną rynną centralną.', 'Zróżnicowane: od piaszczysto-żwirowego przy bulwarach po muliste w najgłębszych punktach rynny.', 'Średnia (1.5 - 2.5m). Woda regularnie monitorowana, o przyzwoitych parametrach czystości jak na akwen miejski.', 'Umiarkowana. Wąski pas trzciny, pod wodą rdestnice i moczarka w płytszych partiach.', 'Leszcz, Sandacz, Szczupak, Okoń, Węgorz, Płoć', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem. Silna naturalna populacja leszcza.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online oraz w sklepie wędkarskim w Sztumie.', FALSE, FALSE, 'Bardzo dobre. Dostęp do wody wzdłuż całego bulwaru miejskiego oraz licznych pomostów.', TRUE, TRUE, 'Idealny. Jezioro znajduje się w samym centrum miasta, z licznymi parkingami wokół bulwaru.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80081, 'Linowo-szczupakowe', 22.4, 1.8, 3.5, 'Dno misowate, niemal całkowicie wyrównane przez osady organiczne. Brak rynien i górek.', 'Wybitnie miękkie, muliste. Duża zawartość osadów organicznych.', 'Niska (0.5 - 1.5m). Woda o silnym zielonkawym zabarwieniu, typowa dla zbiorników silnie zarastających.', 'Ekstremalnie bogata. Szeroki pas trzciny i pałki, rozległe pola grążeli i moczarki.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Leszcz, Płoć', TRUE, 'Naturalna regeneracja populacji lina. Okresowe zarybienia szczupakiem.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online i w punktach w Sztumie.', FALSE, FALSE, 'Utrudnione. Wymaga znalezienia wyciętych stanowisk w trzcinach lub korzystania z lokalnych kładek.', TRUE, TRUE, 'Dobry dojazd asfaltowy od strony Sztumu do Barlewic. Kilka miejsc postojowych przy drodze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80068, 'Szczupakowo-linowe', 12.5, 3.2, 8.5, 'Dno o urozmaiconym kształcie, z jedną wyraźniejszą głębią w centralnej części.', 'Przeważnie piaszczysto-muliste. Niespodziewanie dużo twardych partii dna przy południowym brzegu.', 'Średnia/Wysoka (1.5 - 2.5m). Woda stosunkowo czysta jak na akwen polny.', 'Umiarkowana. Zwarty pas trzciny, pod wodą rdestnice i liczne kępy wywłócznika.', 'Szczupak, Okoń, Lin, Płoć, Wzdręga', TRUE, 'Okresowe zarybienia drapieżnikami prowadzone przez GR Bogaczewo.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online i w lokalnych sklepach.', FALSE, FALSE, 'Umiarkowane. Wymaga przedzierania się przez zarośla do nielicznych dzikich stanowisk.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi od strony miejscowości Mątki. Po opadach droga może być grząska.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80110, 'Linowo-szczupakowe', 21.5, 2.2, 5, 'Dno misowate, niemal całkowicie wyrównane, łagodnie opadające ku środkowej części akwenu.', 'Wybitnie miękkie, muliste. Duża zawartość osadów organicznych pochodzenia polnego.', 'Niska (0.8 - 1.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior silnie eutroficznych.', 'Bardzo bogata. Szeroki pas trzciny pospolitej i pałki. Liczne pola grążeli żółtych na tafli wody.', 'Lin, Karaś złocisty, Szczupak, Płoć, Wzdręga', TRUE, 'Okresowe zarybienia szczupakiem i linem prowadzone przez GR Bogaczewo.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online oraz w punktach sprzedaży w Kwidzynie.', FALSE, FALSE, 'Dobre z nielicznych, wyciętych stanowisk w trzcinach. Większość brzegów bagnista.', FALSE, TRUE, 'Dobry dojazd drogami utwardzonymi i polnymi od strony miejscowości Brachlewo.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80111, 'Leszczowo-szczupakowe', 72.4, 5.8, 14.5, 'Urozmaicone, typowo rynnowe. Dno z wyraźnymi głęboczkami i piaszczystymi wzniesieniami podwodnymi.', 'Zróżnicowane: piaszczysto-żwirowe na spadach, muliste w najgłębszych rynnach akwenu.', 'Wysoka (2.5 - 3.5m). Woda stosunkowo czysta, o dobrej przejrzystości przez większą część sezonu.', 'Umiarkowanie bogata. Zwarty pas trzcin, pod wodą liczne rdestnice i kępy moczarki.', 'Szczupak, Okoń, Leszcz, Węgorz, Płoć, Lin', TRUE, 'Regularnie zarybiane szczupakiem, sandaczem i węgorzem przez GR Bogaczewo.', TRUE, 'Zezwolenie GR Bogaczewo. Możliwość zakupu online lub w sklepach wędkarskich w Prabutach.', FALSE, FALSE, 'Bardzo dobre. Liczne pomosty, kładki oraz piaszczyste brzegi sprzyjające zasiadkom.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi bezpośrednio pod jezioro.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80112, 'Linowo-szczupakowe / Rezerwat', 82.5, 0.8, 1.7, 'Wybitnie wyrównane, misowate, dno ulegające stałemu procesowi wypłycania i zamulania.', 'Bardzo miękkie, muliste. Gruba warstwa osadów organicznych pochodzenia roślinnego.', 'Niska (0.5 - 1.0m). Woda o dużej zawartości zawiesiny organicznej, często mętna.', 'Ekstremalnie bogata. Cały akwen silnie zarasta roślinnością wynurzoną i pływającą (grążele).', 'Lin, Karaś srebrzysty, Szczupak, Wzdręga, Płoć', TRUE, 'Naturalna regeneracja populacji ryb pod osłoną rezerwatu.', TRUE, 'Zezwolenie PZW Elbląg + wymagane przestrzeganie regulaminu rezerwatu.', FALSE, TRUE, 'Ekstremalnie trudne. Brzegi to bagniste trzęsawiska niedostępne z lądu.', FALSE, FALSE, 'Utrudniony. Jezioro znajduje się w bezpośrednim sąsiedztwie Prabut, dojazd do granicy rezerwatu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80113, 'Leszczowo-szczupakowe', 68.5, 4.5, 10.5, 'Rynnowe, o pofalowanym dnie z wyraźną rynną centralną i licznymi podwodnymi półkami.', 'Piaszczysto-muliste. W strefie przybrzeżnej liczne partie twardszego, piaszczystego dna.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym odcieniu, dobra przejrzystość wiosną.', 'Bogata. Wyraźny pas trzcin i pałki. Pod wodą liczne kępy moczarki kanadyjskiej i rdestnic.', 'Szczupak, Leszcz, Okoń, Płoć, Lin, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i narybkiem ryb spokojnego żeru przez PZW Elbląg.', TRUE, 'Zezwolenie PZW Elbląg. Dostępne online i w punktach sprzedaży w Prabutach.', FALSE, FALSE, 'Dobre. Wzdłuż brzegów znajduje się wiele wyciętych stanowisk oraz dogodnych dojść do wody.', TRUE, TRUE, 'Dobry dojazd drogami lokalnymi i utwardzonymi szutrami od strony miejscowości Sowica.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80114, 'Sielawowo-sandaczowe', 75.5, 6.2, 18.5, 'Typowo rynnowe, o urozmaiconym dnie z wyraźną rynną centralną i licznymi podwodnymi wzniesieniami.', 'Przeważnie twarde, piaszczysto-żwirowe. W najgłębszych partiach rynny występuje cienka warstwa mułu.', 'Wysoka (2.5 - 4.0m). Woda o błękitnym odcieniu, bardzo dobra przejrzystość wiosną i jesienią.', 'Umiarkowanie bogata. Zwarty pas trzciny pospolitej, pod wodą bogate łąki ramienicowe i rdestnice.', 'Szczupak, Sandacz, Leszcz, Okoń, Płoć, Węgorz', TRUE, 'Regularnie zarybiane sandaczem i szczupakiem przez Gospodarstwo Rybackie w Bogaczewie.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online oraz w sklepach wędkarskich w Prabutach.', FALSE, FALSE, 'Bardzo dobre. Liczne pomosty wędkarskie oraz piaszczyste stanowiska wzdłuż brzegów.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi szutrami od strony miejscowości Grażymowo.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80124, 'Linowo-szczupakowe', 34.5, 3.5, 7, 'Dno misowate z łagodnymi spadkami, brzegi wysokie i zalesione.', 'Piaszczysto-muliste, dużo roślinności podwodnej.', 'Wysoka (2.5 - 3.5m).', 'Bardzo bogata. Liczne grążele, moczarka, szeroki pas trzcin.', 'Lin, Szczupak, Płoć, Okoń, Wzdręga', TRUE, 'Naturalna regeneracja, okresowo narybek szczupaka.', TRUE, 'Zezwolenie GR Ostróda.', FALSE, TRUE, 'Umiarkowane. Kilka wydeptanych stanowisk wzdłuż brzegu.', TRUE, TRUE, 'Dojazd drogami leśnymi, utrudniony po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80133, 'Sielawowo-szczupakowe', 323, 9.5, 31.5, 'Bardzo urozmaicone, rynnowe, z licznymi wyspami, górkami podwodnymi i głębokimi rynnami.', 'Twarde (piasek, żwir, kamienie) na stokach, w rynnach muł sielawowy.', 'Bardzo wysoka (3.0 - 6.0m). Jedno z najczystszych jezior w Polsce.', 'Umiarkowana. Trzcina pospolita, pod wodą rozległe łąki ramienicowe (do 7-8m).', 'Szczupak, Okoń, Sielawa, Leszcz, Węgorz, Płoć', TRUE, 'Intensywnie zarybiane sielawą, szczupakiem i sandaczem.', TRUE, 'Zezwolenie GR Ostróda (Specjalne na Partęczyny).', FALSE, TRUE, 'Dobre w rejonie ośrodków wypoczynkowych, pozostałe brzegi dzikie.', TRUE, TRUE, 'Dobry dojazd do miejscowości Wielkie Partęczyny i Tereszewo, liczne slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80115, 'Linowo-szczupakowe', 28, 2.5, 5.8, 'Dno misowate, wyrównane, o łagodnym ukształtowaniu. Jezioro ulega naturalnemu procesowi wypłycania.', 'Muliste. Gruba warstwa osadów organicznych pochodzenia roślinnego na przeważającej powierzchni.', 'Średnia/Niska (1.0 - 1.8m). Woda o zielonkawym zabarwieniu, typowa dla jezior żyznych.', 'Bardzo bogata. Szeroki pas trzcin i pałki, rozległe pola grążeli i lilii wodnych na tafli.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć', TRUE, 'Okresowe zarybienia szczupakiem i linem prowadzone przez GR Bogaczewo.', TRUE, 'Zezwolenie GR Bogaczewo. Te same zasady co na jeziorze zachodnim.', FALSE, FALSE, 'Utrudnione ze względu na bagniste brzegi. Nieliczne dzikie stanowiska wymagające woderów.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi i leśnymi od strony Grażymowa lub Sowicy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80078, 'Leszczowo-szczupakowe', 42.5, 3.8, 9.5, 'Niecka o regularnym kształcie, dno łagodnie opadające ku środkowi z jedną rynną centralną.', 'Mulisto-piaszczyste. W strefie brzegowej pas twardszego dna, w głębi zalega muł organiczny.', 'Średnia (1.2 - 2.0m). Woda o zielonkawym odcieniu, przejrzystość dobra wiosną.', 'Bogata. Wyraźny pas trzciny pospolitej, pod wodą liczne kępy moczarki kanadyjskiej.', 'Leszcz, Lin, Szczupak, Okoń, Płoć, Wzdręga', TRUE, 'Zarybiane okresowo szczupakiem przez Gospodarstwo Rybackie w Bogaczewie.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online i w punktach sprzedaży w Kwidzynie.', FALSE, FALSE, 'Dobre. Wzdłuż brzegów znajduje się kilka wyciętych stanowisk oraz pomostów.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi bezpośrednio do miejscowości Morawy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80102, 'Linowo-szczupakowe', 14.8, 1.5, 3.2, 'Dno misowate, wyrównane, dno ulegające naturalnemu procesowi wypłycania organicznego.', 'Wybitnie miękkie, muliste. Duża zawartość detrytusu roślinnego.', 'Niska (0.7 - 1.2m). Woda o barwie brunatno-zielonej, bardzo żyzna.', 'Bardzo bogata. Szeroki pas trzcin, na powierzchni liczne i rozległe pola grążeli żółtych.', 'Lin, Karaś złocisty, Szczupak, Płoć, Wzdręga', TRUE, 'Naturalna regeneracja populacji ryb. Okresowe zarybienia szczupakiem.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online i w lokalnych punktach.', FALSE, FALSE, 'Utrudnione. Wymaga korzystania z nielicznych, dzikich stanowisk w trzcinach.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi i utwardzonymi od strony miejscowości Morawy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80048, 'Linowo-szczupakowe', 14.8, 1.8, 4.5, 'Dno misowate, wyrównane, łagodnie opadające ku środkowi bez gwałtownych uskoków.', 'Miękkie, muliste z dużą ilością osadów organicznych (liście, igliwie).', 'Niska/Średnia (0.8 - 1.5m). Woda o herbacianym odcieniu, typowa dla zbiorników leśnych.', 'Bogata. Wyraźny pas trzcin i pałki, liczne grążele żółte w osłoniętych zatoczkach.', 'Lin, Szczupak, Karaś złocisty, Okoń, Płoć', TRUE, 'Naturalna regeneracja populacji ryb. Okresowe zarybienia szczupakiem.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online i w punktach sprzedaży w Kwidzynie.', FALSE, TRUE, 'Utrudnione ze względu na zalesione brzegi. Nieliczne dzikie stanowiska.', FALSE, TRUE, 'Trudny. Dojazd wyłącznie drogami leśnymi od strony drogi nr 55 lub miejscowości Morawy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80117, 'Leszczowo-szczupakowe', 32.5, 3.5, 8.2, 'Dno o regularnym kształcie niecki, pofałdowane z jedną wyraźną rynną centralną.', 'Piaszczysto-muliste. W strefie przybrzeżnej liczne partie twardszego dna.', 'Średnia (1.2 - 2.0m). Woda o zielonkawym zabarwieniu, typowa dla jezior polnych o wysokiej trofii.', 'Bogata. Zwarty pas trzciny pospolitej wokół niemal całego akwenu. Liczne rdestnice pod wodą.', 'Leszcz, Szczupak, Okoń, Płoć, Lin, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i białorybem przez GR Bogaczewo.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online oraz w sklepach w Kwidzynie i Gardei.', FALSE, FALSE, 'Bardzo dobre. Liczne pomosty oraz wycięte stanowiska w trzcinach od strony miejscowości Rybno.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi bezpośrednio do miejscowości Rybno.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80118, 'Sandaczowo-leszczowe', 152, 7.8, 22.5, 'Wybitnie rynnowe, o stromych stokach i głębokiej rynnie centralnej. Liczne podwodne górki i półki.', 'Przeważnie twarde, piaszczysto-żwirowe i kamieniste. Osady muliste tylko w najgłębszych rynnach.', 'Wysoka (2.5 - 4.0m). Woda o błękitnym odcieniu, bardzo dobra przejrzystość wiosną.', 'Umiarkowana. Pas trzcin dość wąski, ale zwarty. Pod wodą bogate łąki ramienicowe do 6m głębokości.', 'Sandacz, Leszcz, Szczupak, Okoń, Płoć, Węgorz, Lin', TRUE, 'Regularnie zarybiane sandaczem, szczupakiem i węgorzem przez GR Bogaczewo.', TRUE, 'Zezwolenie GR Bogaczewo. Dostępne online i w punktach sprzedaży w Gardei i Kwidzynie.', FALSE, FALSE, 'Dobre. Wzdłuż brzegów znajduje się wiele pomostów oraz dogodnych stanowisk brzegowych.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi od strony miejscowości Kucki.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80119, 'Linowo-szczupakowe', 24.5, 2.2, 5, 'Dno misowate, niemal całkowicie wyrównane przez osady organiczne. Brak wyraźnych rynien.', 'Miękkie, mulisto-torfowe. Duża zawartość osadów organicznych.', 'Niska (0.7 - 1.5m). Woda o ciemniejszym, brunatno-zielonym odcieniu, typowa dla zbiorników żyznych.', 'Bardzo bogata. Szeroki pas trzciny i pałki. Na powierzchni liczne pola grążeli i lilii wodnych.', 'Lin, Szczupak, Karaś złocisty, Płoć, Wzdręga, Okoń', TRUE, 'Okresowe zarybienia szczupakiem przez Gospodarstwo Rybackie w Bogaczewie.', TRUE, 'Zezwolenie GR Bogaczewo. Te same zasady co na jeziorze Kucki i Rybno.', FALSE, FALSE, 'Utrudnione. Wymaga korzystania z pomostów lub znalezienia wyciętych stanowisk w roślinności.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i polnymi od strony miejscowości Gardeja.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80121, 'Linowo-szczupakowe', 21.4, 1.8, 3.3, 'Dno misowate, wyrównane, ulegające naturalnemu procesowi wypłycania organicznego. Brak wyraźnych rynien i podwodnych górek.', 'Miękkie, mulisto-torfowe. Duża zawartość detrytusu roślinnego na przeważającej powierzchni dna.', 'Niska/Średnia (0.8 - 1.5m). Woda o zielonkawym odcieniu, przejrzystość stała, bez silnych zakwitów letnich.', 'Bogata. Szeroki pas trzciny pospolitej i pałki. Liczne i rozległe pola grążeli żółtych na tafli wody.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć, Okoń', TRUE, 'Systematycznie zarybiane szczupakiem i linem przez Okręg PZW w Toruniu.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online (e-pzw) oraz w punktach sprzedaży w Gardei.', FALSE, FALSE, 'Umiarkowane. Wymaga korzystania z nielicznych, wyciętych stanowisk w trzcinach lub korzystania z woderów.', FALSE, TRUE, 'Dobry dojazd drogami utwardzonymi i polnymi od strony miejscowości Gardeja lub Słupia.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80122, 'Leszczowo-szczupakowe', 56.9, 2.3, 5.1, 'Rynnowe, o wydłużonym kształcie i dość wyrównanym dnie. Przez środek akwenu przebiega koryto rzeki Gardęgi.', 'Piaszczysto-muliste. W osi przepływu dno jest twardsze, w zatokach i przy brzegach zalegają osady organiczne.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu, typowa dla jezior przepływowych o wyższej trofii.', 'Bogata. Wyraźny pas trzciny pospolitej i rdestnic. Pod wodą liczne kępy moczarki kanadyjskiej.', 'Leszcz, Szczupak, Płoć, Okoń, Lin, Węgorz, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i białorybem. Stały napływ ryb systemem rzeki Gardęgi.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Obwód Kuchnia nr 2a. Dostępne online i w punktach sprzedaży.', FALSE, FALSE, 'Bardzo dobre. Liczne pomosty wędkarskie oraz wycięte stanowiska brzegowe.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi bezpośrednio do miejscowości nadbrzeżnych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80043, 'Linowo-szczupakowe', 12, 2.5, 6, 'Wąska rynna, brzegi wysokie.', 'Piaszczysto-muliste.', 'Średnia (2.0m)', 'Bardzo bogata (trzciny, pałka).', 'Lin, Szczupak, Wzdręga, Okoń', TRUE, 'Naturalna regeneracja.', TRUE, 'GR Ostróda.', FALSE, TRUE, 'Umiarkowane.', FALSE, TRUE, 'Dojazd utwardzony.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80123, 'Sandaczowo-leszczowe', 117.7, 7.5, 27, 'Wybitnie rynnowe, o bardzo stromych stokach i pofalowanym dnie. Liczne podwodne półki, górki i głęboka rynna centralna.', 'Przeważnie twarde, piaszczysto-żwirowe i kamieniste. W najgłębszych partiach rynny cienka warstwa osadów rzecznych.', 'Wysoka (2.5 - 4.0m). Woda o błękitnym odcieniu, bardzo dobra przejrzystość wiosną i jesienią.', 'Umiarkowanie bogata. Zwarty pas trzcin, pod wodą bogate łąki rdestnic i moczarki do 5m głębokości.', 'Sandacz, Szczupak, Leszcz, Okoń, Węgorz, Boleń, Płoć', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem przez Okręg PZW w Toruniu.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Obwód Nogat nr 1. Dostępne online i w punktach sprzedaży.', FALSE, FALSE, 'Dobre. Wzdłuż brzegów znajduje się wiele pomostów oraz dogodnych stanowisk brzegowych.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi bezpośrednio do miejscowości Nogat i Łubień.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80125, 'Linowo-szczupakowe', 60.9, 2, 3.2, 'Dno misowate, niemal całkowicie wyrównane przez osady organiczne. Brak gwałtownych uskoków i rynien.', 'Głównie miękkie, muliste. Duża zawartość substancji organicznych pochodzenia polnego.', 'Niska (0.8 - 1.5m). Woda o zielonkawym odcieniu, typowa dla zbiorników o bardzo wysokiej trofii.', 'Bardzo bogata. Szeroki pas trzciny pospolitej i pałki. Na powierzchni liczne pola grążeli i rdestnic.', 'Lin, Leszcz, Szczupak, Okoń, Płoć, Wzdręga', TRUE, 'Okresowe zarybienia szczupakiem i linem przez zarządcę obwodu.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online (e-pzw) oraz w punktach sprzedaży zezwoleń.', FALSE, FALSE, 'Umiarkowane. Wymaga znalezienia wyciętych stanowisk w trzcinach lub korzystania z nielicznych kładek.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i polnymi od strony miejscowości Święte lub Guba.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80126, 'Sandaczowo-leszczowe', 160.5, 6.2, 18.5, 'Rynnowe, o urozmaiconym dnie z licznymi podwodnymi wzniesieniami i wyraźną rynną centralną.', 'Zróżnicowane: piaszczysto-żwirowe na górkach, muliste w najgłębszych partiach akwenu.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym odcieniu, okresowo ulegająca zakwitom letnim.', 'Bogata. Wyraźny pas trzciny pospolitej i rdestnic. Pod wodą liczne kępy moczarki kanadyjskiej.', 'Sandacz, Szczupak, Leszcz, Okoń, Płoć, Węgorz, Lin', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem przez Okręg PZW w Toruniu.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online (e-pzw) oraz w punktach sprzedaży w Łasinie.', FALSE, FALSE, 'Bardzo dobre. Dostęp do wody wzdłuż bulwaru miejskiego oraz licznych pomostów wędkarskich.', TRUE, TRUE, 'Idealny. Dojazd drogami asfaltowymi bezpośrednio pod jezioro, liczne parkingi miejskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80128, 'Linowo-szczupakowe', 20.2, 1.5, 3.5, 'Dno misowate, niemal całkowicie wyrównane przez osady organiczne. Brak gwałtownych uskoków.', 'Wybitnie miękkie, muliste. Duża zawartość substancji organicznych pochodzenia polnego.', 'Niska (0.7 - 1.2m). Woda o zielonkawym zabarwieniu, typowa dla zbiorników silnie eutroficznych.', 'Bardzo bogata. Szeroki pas trzcin i pałki wodnej. Na powierzchni liczne pola grążeli.', 'Lin, Karaś złocisty, Szczupak, Płoć, Wzdręga', TRUE, 'Okresowe zarybienia szczupakiem prowadzone przez zarządcę obwodu.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online i w punktach sprzedaży.', FALSE, FALSE, 'Umiarkowane. Wymaga znalezienia wyciętych stanowisk w trzcinach lub korzystania z woderów.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi od strony miejscowości Lisnowo.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80129, 'Linowo-szczupakowe', 15.5, 1.2, 2.8, 'Płytka niecka, dno misowate, niemal całkowicie wyrównane przez osady organiczne.', 'Miękkie, muliste z dużą zawartością detrytusu roślinnego.', 'Niska (0.5 - 1.0m). Woda o barwie brunatno-zielonej, bardzo żyzna.', 'Ekstremalnie bogata. Brzegi porośnięte gęstą trzciną. Powierzchnia tafli w dużej części pokryta grążelami.', 'Lin, Karaś złocisty, Szczupak, Wzdręga, Płoć', TRUE, 'Naturalna regeneracja populacji ryb. Okresowe zarybienia drapieżnikami.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online i w lokalnych kołach PZW.', FALSE, FALSE, 'Trudne ze względu na bagniste brzegi. Wymagane korzystanie z nielicznych kładek.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi od strony miejscowości Lisnowo.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80130, 'Szczupakowo-linowe', 174.5, 2.5, 6.4, 'Obszerna niecka o wyrównanym dnie. Przez akwen przebiega wyraźne koryto rzeki Osa.', 'Piaszczysto-muliste. W osi przepływu dno jest twardsze, w zatokach zalegają osady muliste.', 'Średnia (1.5 - 2.0m). Woda o zielonkawym odcieniu, typowa dla jezior przepływowych.', 'Bardzo bogata. Szeroki pas trzciny pospolitej i pałki wodnej. Liczne pola grążeli i lilii wodnych.', 'Szczupak, Lin, Leszcz, Płoć, Okoń, Węgorz, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i linem przez Okręg PZW w Toruniu.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online oraz w punktach sprzedaży w Jabłonowie i Brodnicy.', FALSE, FALSE, 'Dobre. Wzdłuż brzegów znajduje się wiele wyciętych stanowisk oraz dogodnych dojść do wody.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi bezpośrednio do miejscowości Płowęż.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80131, 'Linowo-szczupakowe', 15.2, 1.8, 4.2, 'Dno misowate, niemal całkowicie wyrównane przez osady organiczne.', 'Miękkie, muliste. Duża zawartość substancji organicznych.', 'Niska (0.8 - 1.2m). Woda o zielonkawym zabarwieniu, typowa dla jezior polnych.', 'Bogata. Szeroki pas trzciny pospolitej, liczne pola grążeli żółtych.', 'Lin, Karaś złocisty, Szczupak, Płoć, Wzdręga', TRUE, 'Okresowe zarybienia szczupakiem prowadzone przez PZW Toruń.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online i w lokalnych kołach.', FALSE, FALSE, 'Umiarkowane. Wymaga korzystania z wyciętych stanowisk w trzcinach.', FALSE, TRUE, 'Dobry dojazd drogami polnymi i utwardzonymi od strony miejscowości Płowężek.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80132, 'Leszczowo-szczupakowe', 12.8, 3.5, 8.5, 'Rynnowe, o wydłużonym kształcie. Dno pofalowane z jedną rynną centralną.', 'Piaszczysto-muliste. W strefie przybrzeżnej liczne partie twardszego dna.', 'Średnia (1.5 - 2.5m). Woda o barwie zielonkawej, stosunkowo czysta.', 'Umiarkowana. Pas trzciny pospolitej, pod wodą kępy rdestnic.', 'Szczupak, Leszcz, Płoć, Okoń, Lin', TRUE, 'Naturalna regeneracja populacji ryb. Okresowe zarybienia szczupakiem.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online i w punktach sprzedaży w Jabłonowie.', FALSE, FALSE, 'Umiarkowane. Wymaga znalezienia wyciętych stanowisk lub korzystania z woderów.', FALSE, TRUE, 'Dojazd drogami utwardzonymi i polnymi od strony miejscowości Zaleń.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80053, 'Linowo-szczupakowe', 8.5, 2.5, 6.2, 'Wąska rynna o stromych stokach, dno urozmaicone przez zwalone drzewa.', 'Mulisto-piaszczyste z dużą ilością detrytusu leśnego.', 'Niska/Średnia (1.0 - 1.8m). Woda o zabarwieniu huminowym (herbacianym).', 'Bogata podwodna. Nieliczne trzciny, dużo powalonych pni i gałęzi.', 'Szczupak, Okoń, Lin, Płoć, Wzdręga', TRUE, 'Naturalna odnowa populacji pod osłoną lasu.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online i w lokalnych punktach.', FALSE, TRUE, 'Utrudnione ze względu na zalesione brzegi. Wymaga przedzierania się przez zarośla.', FALSE, TRUE, 'Trudny. Dojazd wyłącznie drogami leśnymi i piaszczystymi szlakami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80058, 'Linowo-szczupakowe', 6.4, 1.5, 3.2, 'Płytka niecka o wyrównanym dnie, ulegająca naturalnemu zamulaniu.', 'Wybitnie miękkie, muliste. Gruba warstwa osadów organicznych.', 'Niska (0.7 - 1.2m). Woda o zielonkawym odcieniu, bardzo żyzna.', 'Bardzo bogata. Szeroki pas trzcin i pałki, liczne skupiska grążeli.', 'Karaś srebrzysty, Lin, Szczupak, Płoć, Wzdręga', TRUE, 'Naturalna regeneracja populacji ryb.', TRUE, 'Zezwolenie Okręgu PZW Toruń. Dostępne online i w punktach w okolicy.', FALSE, FALSE, 'Dobre z nielicznych dzikich stanowisk wzdłuż brzegu.', FALSE, TRUE, 'Umiarkowany. Dojazd drogami polnymi od strony miejscowości Płoczeń.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80134, 'Linowo-szczupakowe', 4.1, 1.5, 3.5, 'Niecka, dno misowate, wyrównane.', 'Miękkie, muliste.', 'Średnia (1.5m)', 'Bardzo bogata (grążele, trzcina).', 'Lin, Szczupak, Płoć, Okoń', TRUE, 'Naturalna regeneracja.', TRUE, 'GR Ostróda - zezwolenie na jeziora brodnickie.', FALSE, TRUE, 'Utrudnione (las).', FALSE, TRUE, 'Leśna, trudna.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80135, 'Linowo-karasiowe', 5.2, 1.2, 2.5, 'Płytkie, zarastające.', 'Torfowe, bardzo miękkie.', 'Niska (herbaciana)', 'Ekstremalnie bogata.', 'Karaś złocisty, Lin, Szczupak', TRUE, 'Naturalna regeneracja.', TRUE, 'GR Ostróda.', FALSE, TRUE, 'Niemożliwe bez woderów.', FALSE, TRUE, 'Tylko pieszo/rowerem przez las.', FALSE);
