INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80137, 'Linowo-karasiowe', 1.2, 1, 2.5, 'Płytkie, zarastające oczko.', 'Miękkie, torfowe.', 'Niska', 'Ekstremalnie bogata.', 'Karaś złocisty, Lin, Szczupak (pistolety)', TRUE, 'Naturalna regeneracja.', TRUE, 'GR Ostróda.', FALSE, TRUE, 'Niemożliwe bez woderów.', FALSE, FALSE, 'Tylko pieszo przez las.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80138, 'Leszczowo-szczupakowe', 91.5, 5.2, 15.5, 'Typowo rynnowe, o pofalowanym dnie i stromych spadach.', 'Piaszczysto-muliste.', 'Średnia (1.8 - 2.5m)', 'Umiarkowana (pas trzcin, rdestnice).', 'Leszcz, Szczupak, Okoń, Płoć, Lin', TRUE, 'Systematycznie zarybiane szczupakiem i sandaczem.', TRUE, 'GR Ostróda.', FALSE, TRUE, 'Bardzo dobre (liczne pomosty).', TRUE, TRUE, 'Dobry dojazd od strony Brodnicy i Żmijewka.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80139, 'Leszczowo-szczupakowe', 89.5, 4.8, 14.5, 'Typowo rynnowe, dno pofałdowane z wyraźną rynną centralną i licznymi podwodnymi półkami.', 'Piaszczysto-muliste. W strefie przybrzeżnej liczne partie twardszego dna.', 'Średnia (1.5 - 2.5m). Woda o zielonkawym zabarwieniu, okresowe zakwity letnie.', 'Bogata. Wyraźny pas trzcin i pałki. Pod wodą liczne kępy moczarki i rdestnic.', 'Leszcz, Szczupak, Płoć, Okoń, Lin, Węgorz', TRUE, 'Regularnie zarybiane szczupakiem i sandaczem przez GR Ostróda.', TRUE, 'Zezwolenie GR Ostróda. Dostępne w sklepach wędkarskich w Brodnicy i online.', FALSE, FALSE, 'Bardzo dobre. Liczne pomosty, kładki oraz piaszczyste brzegi.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi miejskie przy plaży.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80140, 'Sandaczowo-leszczowe', 76.2, 6.5, 19.8, 'Rynnowe, o stromych stokach i pofałdowanym dnie. Liczne podwodne górki i uskoki.', 'Zróżnicowane: piaszczysto-żwirowe na spadach, muliste w najgłębszych rynnach.', 'Średnia/Wysoka (2.0 - 3.5m). Woda stosunkowo czysta i dobrze natleniona.', 'Umiarkowana. Wąski pas trzcin, pod wodą bogate łąki ramienicowe do 5m głębokości.', 'Sandacz, Szczupak, Leszcz, Okoń, Lin, Węgorz, Płoć', TRUE, 'Systematycznie zarybiane sandaczem i szczupakiem przez GR Ostróda.', TRUE, 'Zezwolenie GR Ostróda (Jeziora Brodnickie).', FALSE, TRUE, 'Dobre. Wzdłuż brzegów znajduje się wiele wyciętych stanowisk oraz pomostów.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i szutrowymi od strony miejscowości Chojno.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80141, 'Linowo-szczupakowe', 15.5, 3.2, 7.8, 'Rynnowe, dno pofalowane.', 'Mulisto-piaszczyste.', 'Średnia (1.8m)', 'Bogata (grążele, rdestnice).', 'Lin, Szczupak, Płoć, Okoń', TRUE, 'Zarybienia szczupakiem.', TRUE, 'GR Ostróda.', FALSE, TRUE, 'Dobre z nielicznych stanowisk.', TRUE, TRUE, 'Dojazd polny/utwardzony.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80145, 'Szczupakowo-leszczowe', 51, 3.8, 9.5, 'Rynnowe, urozmaicone dno.', 'Mulisto-piaszczyste.', 'Średnia (1.8m)', 'Bogata (szerokie trzcinowiska).', 'Szczupak, Leszcz, Węgorz, Płoć', TRUE, 'Zarybiane szczupakiem i węgorzem.', TRUE, 'PZW Włocławek.', FALSE, FALSE, 'Bardzo dobre.', TRUE, TRUE, 'Bardzo dobry dojazd (miejscowość Wielgie).', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80146, 'Sielawowo-szczupakowe', 46.5, 6.5, 22, 'Rynnowe, strome stoki, czyste dno.', 'Twarde, piaszczysto-kamieniste.', 'Bardzo wysoka (4-6m)', 'Umiarkowana (łąki ramienicowe).', 'Szczupak, Okoń, Sielawa, Leszcz', TRUE, 'Regularnie zarybiane sielawą.', TRUE, 'PZW Włocławek.', FALSE, TRUE, 'Trudne (strome brzegi).', TRUE, TRUE, 'Dobry dojazd do plaż i ośrodków.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80147, 'Szczupakowo-linowe', 485, 1.2, 3.5, 'Zbiornik zaporowy, dno płaskie, bardzo liczne kępy roślinności wynurzonej i zanurzonej.', 'Miękkie, mulisto-torfowe, z dużą warstwą osadów organicznych.', 'Niska (0.5 - 1.0m). Woda o herbacianym odcieniu, duża zawartość zawiesiny.', 'Ekstremalnie bogata. Jezioro przypomina podwodną dżunglę (moczarka, grążele, trzcina).', 'Szczupak, Lin, Karaś srebrzysty, Leszcz, Płoć', TRUE, 'Regularnie zarybiane szczupakiem i linem przez PZW Białystok.', TRUE, 'Zezwolenie PZW Białystok (zbiornik specjalny).', FALSE, FALSE, 'Bardzo utrudnione. Brzegi bagniste, wymagane łowienie z łodzi lub nielicznych kładek.', FALSE, TRUE, 'Dojazd utwardzony do miejscowości Czechowizna, dalej drogi polne.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80148, 'Leszczowo-szczupakowe', 235.5, 3.2, 6, 'Rynnowe, dno wyrównane, bez gwałtownych uskoków.', 'Mulisto-piaszczyste.', 'Średnia (1.5m). Woda o zielonkawym zabarwieniu.', 'Bogata. Szeroki pas trzcin wokół całego jeziora, liczne rdestnice pod wodą.', 'Leszcz, Szczupak, Okoń, Płoć, Wzdręga', TRUE, 'Systematycznie zarybiane szczupakiem i białorybem.', TRUE, 'Zezwolenie PZW Suwałki.', FALSE, FALSE, 'Utrudnione. Wymaga znalezienia wyciętych stanowisk w trzcinach.', TRUE, TRUE, 'Dojazd drogami polnymi od strony miejscowości Tajno Stare.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80149, 'Linowo-szczupakowe', 7.6, 1.5, 3.5, 'Niecka wytopiskowa o wyrównanym dnie, łagodnie opadającym ku środkowi.', 'Mulisto-piaszczyste. W strefie brzegowej pas twardszego dna.', 'Średnia/Wysoka (1.5 - 2.5m). Woda stosunkowo czysta, o błękitnym odcieniu.', 'Umiarkowana. Zwarty pas trzciny pospolitej, pod wodą kępy moczarki.', 'Szczupak, Okoń, Płoć, Lin, Wzdręga', TRUE, 'Naturalna regeneracja populacji ryb pod osłoną pogranicza.', TRUE, 'Zezwolenie Wód Polskich (RZGW Białystok). Obwód jeziora Wiżajny nr 4.', FALSE, FALSE, 'Umiarkowane. Wymaga znalezienia wyciętych stanowisk w trzcinach.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi od strony miejscowości Burniszki.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80150, 'Linowo-szczupakowe', 293, 2.3, 5.5, 'Obszerna niecka rynnowa, dno pofałdowane z licznymi wypłyceniami i trzema wyspami w części środkowej.', 'Głównie muliste z piaszczystymi partiami w rejonie plaż i wysp.', 'Średnia (1.0 - 2.0m). Woda żyzna, o zielonkawym odcieniu, skłonna do zakwitów.', 'Bardzo bogata. Szeroki i zwarty pas trzciny pospolitej. Pod wodą rozległe łąki rdestnic i moczarki.', 'Szczupak, Lin, Leszcz, Okoń, Węgorz, Płoć', TRUE, 'Systematycznie zarybiane szczupakiem i węgorzem przez RZGW Białystok.', TRUE, 'Zezwolenie Wód Polskich (RZGW Białystok). Dostępne online.', FALSE, TRUE, 'Utrudnione przez szeroki pas szuwarów. Zalecane łowienie z łodzi lub pomostów.', TRUE, TRUE, 'Bardzo dobry dojazd do miejscowości Wiżajny, liczne parkingi i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80152, 'Linowo-szczupakowe', 18.5, 1.3, 2.4, 'Dno wybitnie misowate, wyrównane przez grube osady organiczne. Jezioro w stadium lądowacenia.', 'Miękkie, mulisto-torfowe. Duża zawartość detrytusu roślinnego.', 'Niska (0.5 - 1.2m). Woda o barwie brunatno-zielonej, bardzo żyzna.', 'Ekstremalnie bogata. Brzegi porośnięte gęstą trzciną. Powierzchnia tafli w dużej części pokryta grążelami.', 'Lin, Karaś złocisty, Szczupak, Płoć, Wzdręga', TRUE, 'Naturalna regeneracja populacji ryb w warunkach silnego zarastania.', TRUE, 'Zezwolenie Wód Polskich (RZGW Białystok). Obwód jeziora Wiżajny nr 4.', FALSE, FALSE, 'Ekstremalnie trudne. Brzegi to bagniste trzęsawiska, wymagana łódź.', FALSE, TRUE, 'Utrudniony. Dojazd drogami polnymi od drogi Wiżajny - Rutka-Tartak.', FALSE);
