INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80536, 'Sielawowe (Głębinowe)', 562, 12, 27.5, 'Szeroka misa z kilkoma basenami, strome uskoki, wyspy, piaszczyste blaty.', 'Piaszczysto-żwirowe, punktowo kamienie.', 'Bardzo wysoka (I klasa)', 'Umiarkowana.', 'Sielawa, Szczupak, Sandacz, Okoń, Leszcz', TRUE, 'Systematycznie sielawą i drapieżnikiem.', TRUE, 'Zezwolenie GR Suwałki.', FALSE, TRUE, 'Dobre w wybranych zatokach.', TRUE, TRUE, 'Asfalt/Leśna.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80538, 'Sielawowo-okoniowe (Rezerwat)', 75, 9.5, 22, 'Stromy kocioł polodowcowy, stoki wpadające od razu na 10m.', 'Twarde (osad leśny).', 'Bardzo wysoka', 'Bardzo uboga.', 'Okoń, Szczupak, Płoć', TRUE, 'Ograniczona ingerencja (Rezerwat).', TRUE, 'Zezwolenie specjalne/GR Suwałki.', FALSE, TRUE, 'Bardzo trudne (las i stoki).', FALSE, TRUE, 'Leśna.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80539, 'Leszczowo-szczupakowe', 215, 5.5, 18, 'Rynnowa misa, wyspa pośrodku, rozległe piaszczyste wypłycenia.', 'Piaszczysto-muliste.', 'Wysoka', 'Bogata (szeroki litoral).', 'Leszcz, Szczupak, Płoć, Lin', TRUE, 'Zarybiane lokalnie.', TRUE, 'Zezwolenie GR Suwałki.', FALSE, TRUE, 'Dobre.', FALSE, TRUE, 'Szutrowa.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80540, 'Linowo-szczupakowe (Zarastające)', 135, 1.2, 4.5, 'Wybitnie płytkie rozlewisko o płaskim dnie.', 'Bardzo miękkie, muł organiczny.', 'Średnia', 'Ekstremalna (nawet 80% lustra wody zarośnięte).', 'Lin, Wzdręga, Szczupak, Karaś', TRUE, 'Naturalna regeneracja ze Szwałku Wielkiego.', TRUE, 'Zezwolenie GR Suwałki.', FALSE, TRUE, 'Bardzo trudne.', FALSE, TRUE, 'Polna/Leśna.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80541, 'Szczupakowo-płociowe', 42, 4.5, 12, 'Zaciszna, otoczona lasem rynna z wyrównanymi spadkami.', 'Muliste / Piaszczyste.', 'Wysoka', 'Umiarkowana.', 'Szczupak, Okoń, Płoć, Lin', TRUE, 'Zarybiane szczupakiem.', TRUE, 'Zezwolenie GR Suwałki.', FALSE, TRUE, 'Utrudnione (las opadający do wody).', FALSE, TRUE, 'Leśna.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80684, 'Rynnowe leśne', 180, 5.5, 14.5, 'Regularna niecka rynnowa, strome piaszczyste skarpy, brak górek podwodnych.', 'Twarde: jasny piasek i drobny żwir, marginalna ilość osadów organicznych.', 'Wysoka (I klasa), krystaliczna toń widoczna do kilku metrów.', 'Umiarkowana: wąski pas trzcin, podwodne łąki ramienic.', 'Lin, Okoń, Wzdręga, Szczupak, Płoć', TRUE, 'Zarybienia linem i szczupakiem, stabilna naturalna populacja.', TRUE, 'Zezwolenia lokalnego gospodarstwa rybackiego.', FALSE, TRUE, 'Średnia, ograniczone do wydeptanych stanowisk w pasie leśnym.', TRUE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi, miejsca postojowe w borze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80542, 'Zbiornik zaporowy (górski)', 4720, 22, 60, 'Ekstremalne spady, podwodne góry, pionowe urwiska skalne, zalane koryta rzek, ruiny i lasy.', 'Głównie twarde: skały, łupki, kamienie, na wypłyceniach i w starych korytach naniesiony muł.', 'Wysoka (poza okresem intensywnych opadów nawiedzających rzekę San).', 'Bardzo uboga. Brak klasycznego pasa trzcin. Sporadyczna roślinność zanurzona w najpłytszych zatokach.', 'Sandacz, Okoń, Szczupak, Sum, Leszcz, Karp', TRUE, 'Intensywne zarybienia drapieżnikiem (sandacz, szczupak, sum) oraz narybkiem gatunków karpiowatych.', TRUE, 'Składki PZW Krosno, dostępne dopłaty na łódź i okresowe e-zezwolenia.', FALSE, TRUE, 'Możliwe, ale trudne ze względu na bardzo strome, niedostępne brzegi i gliniaste urwiska.', FALSE, TRUE, 'Drogi asfaltowe do głównych miejscowości (Polańczyk, Solina, Chrewt), duża baza slipów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80543, 'Zbiornik zaporowy (podgórski)', 130, 4.5, 14, 'Wyraźne stare koryto rzeki Wisłok, łagodne stoki po stronie wschodniej i ostre urwiska po zachodniej.', 'Mieszane: kamienisto-żwirowe w rejonie koryta, w zatokach osady ilaste i warstwa miękkiego mułu.', 'Średnia, silnie uzależniona od opadów w górnym biegu rzeki.', 'Umiarkowana. Częściowo porośnięte brzegi, w płytszych zatokach grążele i pasy tataraku.', 'Szczupak, Okoń, Kleń, Świnka, Płoć', TRUE, 'Systematyczne zarybienia szczupakiem i białorybem.', TRUE, 'Zezwolenie PZW Krosno.', FALSE, TRUE, 'Dostępne z brzegu w wybranych sektorach, wiele miejsc zarośniętych krzakami lub ze stromą skarpą.', FALSE, TRUE, 'Dojazd drogami asfaltowymi i utwardzonymi szutrówkami. Miejsca do wodowania lekkich łodzi z przyczepki.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80545, 'Zbiornik zaporowy (górski)', 306, 13, 31, 'Głęboka rynna koryta rzeki Ropa. Miejscami rozległe, piaszczyste blaty spadające nagle w dwudziestometrową głębinę.', 'Twarde: glina, otoczaki, skały osadowe, żwir.', 'Dobra (często zielonkawy odcień od fitoplanktonu).', 'Praktycznie brak ze względu na kamieniste podłoże i częste wahania lustra wody.', 'Sandacz, Szczupak, Płoć, Pstrąg potokowy, Kleń', TRUE, 'Głównie zarybienia sandaczem, który ma tu świetne warunki do rozrodu.', TRUE, 'Zezwolenie PZW Nowy Sącz.', FALSE, TRUE, 'Tylko w wyznaczonych zatokach i w rejonie cofki u ujścia rzeki. W większości strome urwiska.', FALSE, TRUE, 'Droga asfaltowa wzdłuż wschodniego brzegu. Możliwość slipowania z łagodnych zjazdów przy zaporze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80546, 'Zbiornik zaporowy (nizinno-podgórski)', 1600, 5, 30, 'Dno spłaszczone przez lata nanoszenia osadów. Pozostałości starego koryta Dunajca mocno zasypane mułem.', 'W 70% gruba warstwa mułu, jedynie przy zaporze i na wlotach bystrzyn podłoże twardsze (kamienie).', 'Niska do średniej. Woda latem często "kwitnie" z uwagi na żyzność osadów.', 'Słabo rozwinięta roślinność podwodna, za to bogaty pas trzcinowisk w zatokach i przy brzegach.', 'Leszcz, Sum, Sandacz, Boleń, Ukleja', TRUE, 'Regularnie zarybiane, przede wszystkim sandaczem, szczupakiem i gatunkami reofijnymi przy wlotach.', TRUE, 'Zezwolenie PZW Nowy Sącz. Obowiązują opłaty na łódź.', FALSE, FALSE, 'Bardzo przystępne brzegi z dużą ilością plaż, murków oporowych i kempingów. Dobry dostęp gruntowy.', TRUE, TRUE, 'Dojazd dobry, zbiornik turystyczny, szeroka baza noclegowa, łatwe slipowanie w wielu portach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80547, 'Zbiornik wyrównawczy / przepływowy', 346, 3.5, 9, 'Silnie pofałdowane z uwagi na szybki nurt. Rynny rzeczne, prądy wsteczne, warkocze i dołki wymyte przez wodę.', 'Zmienne: żwirowo-piaszczyste w nurcie, muliste w zaciszach i spokojnych zatokach cofki.', 'Średnia, zależy od zrzutów wody z wyżej położonego Rożnowa.', 'Pasy roślinności wynurzonej (trzcina pospolita), rzadziej grążel żółty w spokojniejszych obszarach.', 'Brzana, Kleń, Świnka, Boleń, Szczupak', TRUE, 'Baza dla zarybień rzecznych gatunków reofilnych. Uzupełniane populacje szczupaka.', TRUE, 'Zezwolenie PZW Nowy Sącz / Tarnów (należy sprawdzić dokładny odcinek graniczny).', FALSE, FALSE, 'Bardzo dobry dostęp do większości stanowisk. Ścieżki wydeptane przez wędkarzy wzdłuż obu brzegów.', FALSE, TRUE, 'Zjazd z drogi krajowej 75, wiele polnych dróg dojazdowych blisko brzegów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80548, 'Zbiornik zaporowy (górski)', 1224, 14, 50, 'Niezwykle zróżnicowane. Zatopiona droga, ruiny, mosty, ostre krawędzie skalne, ogromne spady do 40 metrów w dół.', 'Twarde i czyste: żwir, duże bloki skalne, miejscami zalane łąki.', 'Wybitnie krystaliczna (widoczność do 4-5 metrów). Wymaga używania niewidocznych przyponów.', 'Uboga, skupiona tylko w bardzo wąskim pasie płytkiego litoralu przy niektórych łagodniejszych brzegach.', 'Szczupak, Sandacz, Okoń, Pstrąg, Leszcz, Sielawa', TRUE, 'Systematyczne zarybienia drapieżnikami oraz pstrągami. Ostoja tarłowa na dopływach.', TRUE, 'Zezwolenie PZW Nowy Sącz. Konieczna dopłata za wędkowanie z łodzi.', FALSE, TRUE, 'Ekstremalnie trudne, możliwe na bardzo krótkich odcinkach wokół Niedzicy lub w rejonie Frydmana.', TRUE, TRUE, 'Wygodny dojazd asfaltem. Profesjonalne slipy w Mizernie, Niedzicy i Czorsztynie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80549, 'Jezioro eutroficzne (płytkie)', 107, 1.5, 2.5, 'Kształt misy. Dno niemal całkowicie płaskie, bez wyraźnych antyp i dołków.', 'Miękkie, silnie zamulone (grubość mułu sięgająca nawet metra).', 'Słaba, woda szybko mętnieje podczas upałów i żerowania ryb karpiowatych.', 'Brzegi gęsto zarośnięte trzciną. W wodzie miejscami wywłócznik i grzybień biały.', 'Karp, Amur białopłetwy, Leszcz, Sum, Karaś', TRUE, 'Bogate zarybienia karpiem (często sztuki handlowe). Zarybienia linem i karasiem.', TRUE, 'Zezwolenie PZW Lublin.', FALSE, FALSE, 'Bardzo dobra dostępność z wałów okalających jezioro. Liczne wyrwy w trzcinach przygotowane przez wędkarzy.', TRUE, TRUE, 'Dojazd drogami gruntowymi po zjeździe z asfaltu, w czasie deszczu miejscami bywa błotniście.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80550, 'Jezioro naturalne (płytkie, torfowe)', 45, 1.2, 2.2, 'Równinne dno bez rynien, misy silnie zarastające od brzegów.', 'Głównie torfowo-muliste, miękkie.', 'Średnia, woda często ma ciemny, "herbaciany" odcień od związków humusowych.', 'Bardzo obfita: rozległe pasy trzcin, pałki wodnej, trzciny. W wodzie gęste łąki rdestnicy.', 'Lin, Karaś pospolity, Szczupak, Płoć', TRUE, 'Zarybienia linem, szczupakiem (narybek jesienny).', TRUE, 'Zezwolenie PZW Lublin.', FALSE, TRUE, 'Ograniczone przez podmokłe brzegi i gęstą roślinność. Najczęściej wymaga woderów lub kładek.', TRUE, TRUE, 'Dojazd leśnymi i polnymi duktami. Po silnych deszczach dostęp uciążliwy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80551, 'Jezioro krasowe (rynnowe)', 57, 7.3, 25.4, 'Gwałtowne spady zaledwie kilka metrów od brzegu. Bardzo strome stoki, zwężająca się rynna denna.', 'W przeważającej części twarde (piasek, kreda, kamień). Warstwa mułu występuje tylko w najgłębszych punktach rynny.', 'Wysoka przejrzystość przez większość sezonu, woda ma specyficzną, zielonkawą barwę.', 'Skąpa w strefie przybrzeżnej, szybko się urywa z uwagi na gwałtowny spadek dna.', 'Okoń, Szczupak, Sielawa, Leszcz, Płoć', TRUE, 'Zarybienia sielawą, szczupakiem i bardzo liczna naturalna populacja okonia.', TRUE, 'Zezwolenie PZW Lublin.', FALSE, TRUE, 'Możliwe niemal wyłącznie z solidnych, wybudowanych kładek wędkarskich, które opasują jezioro.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi bezpośrednio pod łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80603, 'Jezioro rynnowo-krasowe', 85, 5.5, 15, 'Bardzo ostre, wąskie rynnowe zwężenie lecące kaskadą tuż obok tataraku u góry rzutu dna z piasku szczupakowych dołów obok słońca ech w dół krasowych.', 'Twarde z usypiskami od góry rynny piaszczystych skosów krawędzi ok.', 'Dobra klarowność pod okiem twardych uskoków toni krasu ok.', 'Uporczywe gęste rdzawe pasy sitowia przed wodom lądu ok.', 'Szczupak Trzcin lilii opadów, Okoń dębu rynnowego, Karp krawędzi', TRUE, 'Regulowana rybą spokojną u PZW rzutu ok.', TRUE, 'Opłata PZW ok.', FALSE, FALSE, 'Ciężka twarda bez ucięć u zarośli wymaga wody ok.', TRUE, TRUE, 'Rzadko i utrudnione bez asfaltów ok.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80106, 'Jezioro eutroficzne (polesiowe)', 318, 1.2, 3.1, 'Płaskie jak stół, o minimalnych różnicach głębokości na całym rozległym plosie.', 'Bardzo miękkie, gruba warstwa osadów dennych i szczątków organicznych.', 'Niska. Woda mętna wskutek płytkości i falowania podnoszącego osady denne.', 'Niezwykle bogata: otoczone kilkudziesięciometrowym pierścieniem trzcin, w lecie liczne kwitnące grążele i rdestnice.', 'Lin, Karaś pospolity, Szczupak, Wzdręga', TRUE, 'Gospodarka oparta na gatunkach jezior płytkich (lin, szczupak, karaś).', TRUE, 'Zezwolenie PZW Lublin.', FALSE, TRUE, 'Niemożliwe z uwagi na kilkudziesięciometrowy pas bagnistych trzcinowisk. Wymagana łódź płaskodenna.', FALSE, TRUE, 'Dojazd dobry, ale parkingi oddalone od linii brzegowej; slipowanie bywa ręczne przez przecinki w trzcinach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80553, 'Jezioro eutroficzne (polesiowe)', 42, 1.3, 4.3, 'Płaska misa bez wcięć ani fałd, powolny i równomierny przyrost głębokości.', 'Prawie 100% muliste, gruba warstwa osadów gnijącej roślinności brzegowej i dennej.', 'Woda słabo przejrzysta, tendencja do mętności z dużą ilością zielenic latem.', 'Bardzo obfita. Trzcinowiska na brzegach i wielkie połacie grążela na całej powierzchni.', 'Lin, Karaś srebrzysty, Szczupak, Wzdręga', TRUE, 'Wspomagane populacje szczupaka polnego oraz intensywne zarybienia linem narybkowym.', TRUE, 'Zezwolenia PZW Lublin z wymaganą dopłatą na sprzęt pływający.', FALSE, TRUE, 'Ekstremalnie trudne. Trzcina zajmuje całą linię, wymagany środek pływający.', FALSE, TRUE, 'Droga gruntowa z wsi Grabniak, brak utwardzonej infrastruktury tuż przy brzegach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80554, 'Jezioro nizinne (słabo eutroficzne)', 91, 2.5, 6.2, 'Powolne, łagodne stoki bez nagłych uskoków dna. Największa głębokość w rynnie środkowej.', 'Miękkie, silnie torfowe. Piaszczyste odcinki występują jedynie przy ścieżkach plażowych.', 'Średnia przejrzystość, latem widoczność spada do ok. 1.5 - 2m w wyniku zakwitu.', 'Umiarkowana, przeważają rozrzucone płaty rdestnicy pływającej i wąski pas trzcin.', 'Leszcz, Karp, Szczupak, Okoń, Płoć', TRUE, 'Częste zarybienia z ramienia PZW, woda systematycznie uzupełniana zarybkiem karpia.', TRUE, 'Zezwolenia okresowe lub roczna składka okręgowa PZW Lublin.', FALSE, TRUE, 'Wygodne, dojazd i wędkowanie udostępnione z wałów i naturalnych zatoczek.', TRUE, TRUE, 'Dobry dojazd z Urszulina utwardzoną drogą szutrowo-asfaltową.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80555, 'Jezioro pod obwałowaniem', 85, 1.5, 3.3, 'Kształt misowaty, brak górek podwodnych, bardzo równa głębokość ok. 1.5m na całym akwenie.', 'Torf i lepki muł; ciężkie wędkarskie zestawy denne mocno zapadają się w podłożu.', 'Słaba, osady torfowiskowe i muł podnoszony przez żerujące ryby mocno mętną wodę.', 'Zarośla często zrośnięte z groblą obwałowania, występuje osoka aloesowata.', 'Karaś "Bąk", Płoć, Lin, Sum, Krąp', TRUE, 'Zbiornik bogaty naturalnie, zarybiany corocznie gatunkami spokojnego żeru i sumem.', TRUE, 'Wody ogólnodostępne w ramach zintegrowanego pozwolenia okręgowego PZW Lublin.', FALSE, FALSE, 'Dostępne wyłącznie na wale okalającym akwen ze schodkami do poszczególnych rewirów.', FALSE, TRUE, 'Dojazd boczny asfaltowy, jednak bardzo limitowane miejsca postojowe na obrzeżach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80556, 'Jezioro krasowe (rynnowe)', 83, 14.2, 38.8, 'Słynie z gwałtownych załamań dna i głębokiego krasowego leja osiągającego niemal 39m.', 'W większości biały piasek krasowy i żwir przechodzący w głębinowe łupki i czystą glinę.', 'Woda w I klasie czystości, niesamowita widoczność rzędu 5-7 metrów w bezwietrzne dni.', 'Uboga w pasie przybrzeżnym. Głębokie łąki ramienic urywają się na pierwszych spadach.', 'Sielawa, Wielki Okoń, Szczupak Pelagiczny, Płoć, Karp', TRUE, 'Gospodarka prowadzona pod kątem ochrony drapieżników i czystości niezwykłego ekosystemu.', TRUE, 'Zazwyczaj dzierżawa akademicka lub prywatna, wymagane uiszczenie odrębnych opłat.', TRUE, TRUE, 'Świetne piaszczyste plaże umożliwiające rzuty gruntowe (głównie poza sezonem urlopowym).', TRUE, TRUE, 'Doskonały dojazd asfaltowy, pełna infrastruktura wypoczynkowa wokół jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80557, 'Jezioro dystroficzne', 145, 1.8, 6.5, 'Rozległa, płaska struktura z bagiennymi strefami i wąskimi rynnami sięgającymi ok. 6m.', 'Torfowo-gnilne, miękkie podłoże bez piasku powstałe wskutek humifikacji obumarłej flory.', 'Zabarwienie brunatne ("herbaciane"), charakterystyczne dla wód torfowych. Niska widoczność.', 'Ekstremalnie gęsta. Akwen otoczony jest osoką aloesowatą oraz nieprzebytymi borami bagiennymi.', 'Szczupak dziki, Lin żółty, Krasnopióra, Węgorz', TRUE, 'Rezerwat. Ekosystem nie jest objęty masowym zarybianiem, naturalna reprodukcja.', TRUE, 'Wymagane osobne, ściśle limitowane opłaty z dyrekcji Poleskiego Parku Narodowego.', FALSE, TRUE, 'Całkowity zakaz z brzegu. Łowienie dozwolone tylko z wyznaczonych pomostów dyrekcji PPN.', TRUE, TRUE, 'Auto należy zostawić przed lasem, dojście pieszo ścieżkami wytyczonymi przez Park.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80558, 'Zbiornik retencyjny / nizinny', 485, 1.2, 3.2, 'Powierzchnia kilkuset hektarów w kształcie płytkiego talerza. Zalane łąki bez skarp.', 'Miękkie błoto. Twardsze podłoże występuje w starych rowach irygacyjnych i zalanych groblach.', 'Niska przejrzystość. Akwen podatny na zmętnienie od wiatru i bardzo mocne zakwity letnie.', 'Mocno zarośnięte. Pływające wyspy lilii, połamane trzcinowiska i rozległe kożuchy wywłócznika.', 'Sandacz, Karpiowate, Szczupak', TRUE, 'Regularnie wpuszczane drapieżniki w celu ograniczania populacji skarłowaciałego białorybu.', TRUE, 'Standardowe zezwolenia okręgu PZW Lublin (wymagane dopłaty na łódź).', FALSE, FALSE, 'Wędkowanie stacjonarne powszechne z kamienistych wałów polderowych i rejonów przy śluzach.', FALSE, FALSE, 'Dojazd techniczny groblami i drogami szutrowymi do stacji pomp wokół rzeki.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80559, 'Jezioro krasowe głębokie', 58, 8.5, 23.4, 'Centralny lej krasowy z bardzo stromymi i głębokimi uskokami blisko brzegu.', 'Twarde i czyste - biały piasek naniesiony przez rzekę oraz otoczaki krasowe z wapieniem.', 'I/II klasa czystości wody poza sezonem turystycznym. Bardzo krystaliczne piaszczyste brzegi.', 'Uboga. Roślinność wodna rzadko występuje z uwagi na strome spady piaszczystego dna.', 'Okoń "garbus", Sielawa, Sandacz, Węgorz, Leszcz', TRUE, 'PZW utrzymuje znakomitą populację sandacza, szczupaka i dbając o cyrkulację narybku.', TRUE, 'Opłaty PZW Lublin + konieczne dopłaty okręgowe na środki pływające.', FALSE, TRUE, 'Utrudnione latem ze względu na duży ruch. Zimą i jesienią czyste plaże są dostępne.', TRUE, TRUE, 'Drogi asfaltowe bezpośrednio przy ośrodkach z możliwością łatwego zjazdu pod samą wodę.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80560, 'Jezioro rynnowo-krasowe', 56, 4.2, 9.4, 'Wydłużona rynna denna z wysepkami żwiru i wapiennymi kopcami urozmaicającymi profil.', 'Twarde krasowe podłoże i żwir przeplatające się z miękkim mułem w spokojnych zatokach.', 'Zmienna, zależna od falowania. Płytsze partie potrafią mętnieć po deszczowych okresach.', 'Rozległe łąki rdestnicy na płyciznach, u wylotów zatok piękne grążele przyciągające liny.', 'Sandacz, Lin, Leszcz, Okoń', TRUE, 'Baza szkoleniowa kół PZW, bardzo mądrze i racjonalnie gospodarowana wodą mieszaną.', TRUE, 'Woda PZW Lublin z dopłatami. Pełny regulamin wędkarski na całym obszarze zbiornika.', FALSE, FALSE, 'Dużo stanowisk! Wydeptane dzikie wycinki w trzcinach i stabilne, zbudowane przez PZW kładki.', TRUE, TRUE, 'Ulica blisko samej wody ułatwia rozładowanie ciężkiego sprzętu karpiowego przed zasiadką.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80724, 'Polodowcowe rynnowe', 45, 5.5, 18, 'Wyraźna centralna rynna o stromych piaszczystych skarpach.', 'Twarde: głównie jasny piasek i żwir polodowcowy.', 'Wysoka, woda bardzo czysta i dobrze natleniona.', 'Skąpa: wąski pas trzciny pospolitej, mało rogatka.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny rozród wspierany okresowo przez okręg PZW.', TRUE, 'Standardowe zezwolenia PZW Olsztyn.', FALSE, FALSE, 'Średnia, dostępne wydeptane stanowiska brzegowe.', FALSE, TRUE, 'Drogi polne, piaszczyste, zalecane wyższe zawieszenie.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80561, 'Jezioro eutroficzne sztucznie zasilane', 46, 1.1, 2.9, 'Całkowicie płaskie bez wgłębień dna. Cytrkulacja wody odbywa się rynnami przepływowymi z rur.', 'Ekstremalnie gruba warstwa mułu – klasyczne koszyczki z zanętą grzęzną i przestają pracować.', 'Woda jest bardzo mętna, po opadach przyjmuje odcień gęstej herbaty od rozkładających się osadów.', 'Mocno zarośnięte gęstą pałką i ostrym sitowiem, woda bardzo płytka pod warstwą grążeli.', 'Karp, Amur, Wzdręga, Karaś, Lin', FALSE, 'Ogromna pula zarybień ciężkim linem i karpiem karmiącym się na bogatych osadach z dna.', TRUE, 'Wymagane standardowe uiszczenie ogólnodostępnej składki wędkarskiej PZW Lublin.', FALSE, FALSE, 'Dostępne wyłącznie po przygotowaniu miejscówki, skoszeniu traw i zaopatrzeniu się w wodery.', TRUE, FALSE, 'Polne ścieżki po deszczach stają się podmokłe, mogą utrudnić dotarcie autem osobowym.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80562, 'Jezioro eutroficzne mocno zarastające', 35, 1, 3.8, 'Misa niemal w całości wypełniona wodnością flory. Brak wyraźnych rynien i górek.', 'Zatopiona darń obrosła mchem oraz całkowity brak piasku tworzą miękki, czarny dywan podwodny.', 'Przejrzystość rzadko przekracza metr przez kwitnącą zawiesinę i szczątki roślinne.', 'Latem jezioro to gigantyczna łąka lilii wodnych i grzybieni pokrywająca lustro wody.', 'Szczupak, Węgorz, Karaś "Bąk", Krasnopióra', TRUE, 'Występuje bardzo liczna i zdrowa populacja dzikiego szczupaka, kontrolująca mały narybek.', TRUE, 'Standardowe opłaty PZW, obszar zarządzany przez lokalne struktury Lasów i Związku.', FALSE, TRUE, 'Dostęp brzegowy praktycznie niemożliwy przez gęste trzęsawiska, wykopane rowy i podmokłe dno.', FALSE, TRUE, 'Brak infrastruktury. Dojazd wyboistymi leśnymi duktami bez wydzielonych parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80563, 'Jezioro krasowe głębokie rynnowe', 75, 11.2, 33.4, 'Świetnie wyprofilowane strome kanty rynnowe schodzące w podwodną przepaść centralnego leja.', 'Bardzo twarde, żwirowo-kredowe spady. Dają doskonałe "czucie opadu" podczas spinningowania.', 'Jedno z najczystszych w regionie. Bardzo wysoka klarowność toni sięgająca kilku metrów.', 'Skupiska trzcin wyłącznie blisko brzegu. Nieliczne pasy roślin dają doskonały dostęp do wody.', 'Okoń "garbus", Wielki Leszcz, Płoć pelagiczna', TRUE, 'Regularne i precyzyjne uzupełnianie drapieżników pelagicznych w głębokiej toni jeziora.', TRUE, 'Ogólnodostępne łowisko zrzeszone w PZW, w sezonie konieczne opłaty za korzystanie z łodzi.', FALSE, FALSE, 'Idealne piaszczyste plaże umożliwiają dalekie wyrzuty gruntowe pod same stoki rynnowe.', TRUE, TRUE, 'Dojazd pod wodę utwardzonym asfaltem. Rozbudowane mola turystyczne z dojściem dla wędkarzy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80564, 'Jezioro eutroficzne klasyczne', 61, 3.4, 7.6, 'Klimatyczna forma dna obniżonego rynnowo na boki. W zatokach łagodne, płytkie wyloty.', 'Na otwartej wodzie piasek, w cichych bocznych zatokach zalegają osady denne i miękki muł.', 'Dobra widoczność pozwalająca na skuteczne operowanie zestawami, bywa nieco mętna latem.', 'W zatokach skupiska lilii (świetne na amura), w wodzie rdestnice chroniące wylęg okonia.', 'Szczupak, Amur, Leszcz, Lin, Okoń', TRUE, 'Zdrowy rybostan, samodzielna reprodukcja dzikich ryb spokojnego żeru i stałe zarybienia PZW.', TRUE, 'Zezwolenia PZW dostępne na stacjach i w lokalnych nadleśnictwach okręgu u turystów.', FALSE, FALSE, 'Znakomity brzeg z wieloma dzikimi zatoczkami w liliach, rewelacyjnymi na spławik od świtu.', FALSE, TRUE, 'Dojazd dobry, szerokie leśne ubite szosy bez problemu przepuszczające małe samochody.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80565, 'Jezioro umiarkowanie krasowe', 44, 4, 8, 'Łagodne piaszczyste wypłycenia szybko załamujące się ostrym, twardym uskokiem do rynny.', 'Biały krasowy piasek przy brzegach, w głębi rynny miękki muł okrzemkowy z opadających liści.', 'Lekko herbaciana barwa związana z kwasami humusowymi z dębowych lasów. Dobra jakość toni.', 'Roślinność mieszana. W płytszych miejscach bardzo gęsta, poniżej 3m szybko ulega rozrzedzeniu.', 'Dziki Szczupak, Okoń, Lin, Płoć', TRUE, 'Szczupaki doskonale się tu mnożą w zaciszu barier roślinnych twardych stoków piaszczystych.', TRUE, 'Licencje okręgowe PZW uprawniające do łowienia nocnego i wędkowania z małych pontonów.', FALSE, TRUE, 'Cudowne, osłonięte krzewami dzikie nęciska dające świetne rezultaty na delikatny spławik.', FALSE, TRUE, 'Spokojny wjazd, utwardzone miejsca postojowe między drzewami obok łagodnych wejść na plaże.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80566, 'Jezioro eutroficzne wydłużone rynnowo', 67, 4.5, 9.8, 'Długa, wąska rynna i koryta głębin dochodzące do 10m. Akwen otoczony jest obwałowaniami.', 'Na płyciznach lepki osad i błoto torfowe, na dnie głównej rynny przeważa usypany żwir i muszle.', 'Tendencja do zakwitów i zmętnienia, widoczność rzadko bywa bardzo dobra podczas lata.', 'Otoczone jest ekstremalnie gęstym pierścieniem barierowych trzcin chroniących tarliska.', 'Sum, Szczupak, Karp królewski, Okoń', TRUE, 'Słynne stada sumów polujących na leszcze. Woda od lat utrzymywana w drapieżnikach okręgu.', TRUE, 'Standardowe warunki PZW, ujęta strefa nocna po wpisach dodatkowych dopłat łodzi i pontonów.', FALSE, FALSE, 'Znalezienie wolnego dojścia to ogromny problem przez zarośla i tereny błotniste okalające ląd.', FALSE, TRUE, 'Okolice wsi bardzo ucywilizowane, wybudowano twarde ścieżki poślizgowe na przyczepy wędkarskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80567, 'Jezioro krasowe leśne czyste', 49, 4.3, 10.1, 'Łagodne plaże przełamują się na podwodne, żwirowo-kamieniste doły z twardymi zjazdami.', 'Wybitnie twarde! Zbite usypiska wapienno-piaskowe nie powodujące więźnięcia kotwic zestawów.', 'Jedna z najbardziej natlenionych i przezroczystych wód krasowych w okolicy. I klasa widoczności.', 'Bardzo rzadka - niewielkie wysepki sitowia tylko u wejść plaż nie przeszkadzające rzutom.', 'Okoń "pasiak", Dziki Szczupak, Krasnopióra', TRUE, 'Twarde dno i zimna ton chroni stada naturalnego drapieżnika z sielawowych odmian czystej wody.', TRUE, 'PZW z regularnymi okresami wjazdowymi na taryfy pontonowe. Obowiązują wymiary ochronne gatunków.', FALSE, TRUE, 'Piaskowe mikro-zatoczki pozwalają rzucać spinning z ustronnych krzewów z pełną swobodą walki.', FALSE, TRUE, 'Twarde dukty piaszczyste ukryte pośród dębów, idealne na szybkie wypady pod mały namiot w nocy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80568, 'Jezioro krasowe bardzo głębokie duże', 106, 14.8, 33.6, 'Plaże, pionowe ostre kanty i uskokowe ściany piasku zjeżdżające w otchłań sięgającą 33m.', 'Krasowy, biały, wypłukany piasek idealny na plaże; w rynnach opady denne kłusujące u dna.', 'Krystaliczna widoczność pelagiczna pozwalająca namierzać ryby echosondami do wielu metrów.', 'Ubogi pas przybrzeżny nie utrudnia operowania długimi zestawami. Flora jedynie tłem brzegów.', 'Pelagiczny Szczupak, Wielki Okoń, Amur', TRUE, 'Złożona naturalnie ochrona rynny głównej i chłodne dno utrzymują znakomite stada pasiaków.', TRUE, 'Odrębnie biletowane u zarządców terenowych z wieloma turystycznymi taryfami stref wakacyjnych.', FALSE, FALSE, 'Plaże znakomite do dalekiego zarzucania na dużego karpia, jednak głośne podczas letnich wakacji.', TRUE, TRUE, 'Pełna, szeroka komercyjna asfaltyzacja ułatwiająca zrzuty łodzi z najwyższej klasy pojazdów z osiami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80569, 'Zbiornik zaporowy (podgórski)', 2077, 9.5, 22, 'Zróżnicowane. Od zachodu płaskie piaszczyste wypłycenia, ku wschodowi strome spady i usypiska.', 'Przeważa twardy piasek i żwir, w starym korycie i przy tamie osady skaliste oraz ruiny.', 'Wysoka z wyjątkiem okresu zakwitów alg w pełni lata i powodzi rzecznych.', 'Uboga z uwagi na kamieniste dno, częściowe zalesienia i wahania lustra wody.', 'Sandacz, Okoń, Szczupak, Leszcz, Karp', TRUE, 'Intensywne zarybienia mętnookim sandaczem z wód krajowych Wód Polskich.', TRUE, 'Opłaty wniesione na Wody Polskie / RZGW, dopłaty na użytkowanie środków pływających.', FALSE, TRUE, 'Wygodne w miejscach z dojazdem. Od strony Głębinowa liczne łagodne zejścia i plaże.', FALSE, TRUE, 'Dobry, pełna asfaltowa infrastruktura obok tamy i głównych zatok. Profesjonalne slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80570, 'Zbiornik zaporowy (nizinno-podgórski)', 2060, 5, 18, 'Stare koryto Nysy, rozległe, rozmyte i stosunkowo równe blaty denne. Dołki przy zrzutach.', 'Mieszane: kamieniste opaski brzegów, w korycie piasek, na blatach bardzo gruba warstwa mułu.', 'Średnia, silnie podatna na wahania z powodu przepływowego charakteru rzeki.', 'Skąpa, występuje punktowo przy spokojnych, płytszych zaciszach po zachodniej stronie.', 'Leszcz, Karp, Sandacz, Szczupak, Boleń', TRUE, 'Działania wspierające gatunki reofilne u wejścia rzeki, solidne populacje zarybień karpiem.', TRUE, 'Pozwolenia RZGW/Wody Polskie.', FALSE, FALSE, 'Wyśmienite stanowiska z kamiennych wałów i opasek na całym obwodzie otaczającym akwen.', FALSE, TRUE, 'Szerokie drogi techniczne na wałach. Wiele dzikich oraz utwardzonych zjazdów dla sprzętu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80571, 'Jezioro polodowcowe (rynnowe)', 52, 4.3, 11, 'Faliste fałdy denna układające się rzędowo, głębokie rynny opadające z wysokich leśnych urwisk.', 'Zwarty piasek przechodzący szybko w pasie stoku w miękki leśny detrytus z liści borowych.', 'Bardzo dobra. Woda przybiera brunatny odcień wskutek kwasów humusowych z szpilek dębowych.', 'U wylotów do wsi pasy zwartego rogatka, szeroki, mocny trzcinowiec oddzielający z brzegu.', 'Lin, Szczupak, Okoń, Płoć, Krąp', TRUE, 'Bogate naturalne szczupaki leśne, zarybienia jeziorne lnem PZW.', TRUE, 'Zezwolenia standard PZW Okręg.', FALSE, TRUE, 'Utrudnione dla spławikowców ze względu na wysoką skarpę w wielu piaszczystych miejscach.', FALSE, TRUE, 'Leśne dukty o piaszczystym poszyciu. Dojazd po burzy tylko dla aut wysokich i SUVów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80572, 'Jezioro krasowo-rynnowe', 61, 5.2, 14.5, 'Klasyczna, podłużna litera V. Z każdej plaży gwałtowny opad i lejowate, gładkie wcięcia środka.', 'Bardzo twarde, piaszczyste skosy porośnięte gęsto raszplą i racicznicą wędkarską.', 'Doskonała z uwagi na krasowo-osadową filtrację, chłodna toń wzdłuż rynny.', 'Wąski pierścień trzcin na brzegach. Pod wodą ubogo na zjazdach rynny z uwagi na brak oparcia.', 'Okoń, Sandacz, Szczupak, Węgorz, Wzdręga', TRUE, 'Regulowana drapieżna fauna pod okręgowymi ochronami PZW ryb pelagicznych.', TRUE, 'Składki PZW Zielona Góra wraz z e-zezwoleniami dobowymi.', FALSE, FALSE, 'Dziesiątki przygotowanych i wykarczowanych dziur brzegowych idealnych pod 1-2 stanowiska!', TRUE, TRUE, 'Bardzo dobry utwardzony dojazd przez wioskę, parking przy plażach głównych bez opłat.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80573, 'Zbiornik retencyjno-przepływowy', 188, 7.5, 21, 'Sztucznie profilowany wał z korytami odrzutowymi z turbin, warkocze, ostre stoki betonowe.', 'Płyty betonowe i gabiony kamienne; dno wymyte i twarde od przepływu silnych prądów szczytowych.', 'Niska. Silny prąd odrzuca muł z dna potęgując "kawowe" zmętnienie wody w czasie działania pomp.', 'Całkowicie pozbawiony darni i traw z powodu szalonych wręcz wahań poziomu wody.', 'Boleń, Sandacz, Brzana, Śwnika, Kleń', TRUE, 'Głównie ostoja i miejsce gromadzenia się drapieżników w uciągu rzeki u ujścia tam.', TRUE, 'Standard RZGW Wody Polskie.', FALSE, FALSE, 'Niebezpieczne i karkołomne wejścia ze śliskich betonów; absolutnie wymaga ostrożności.', FALSE, TRUE, 'Szosy oporowe elektrowni ze szlabanami w wielu miejscach wymuszające dojście piesze z klamotami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80574, 'Jezioro eutroficzne (płytkie, polne)', 45, 1.2, 2.5, 'Całkowicie plaski, bagnisty talerz bez wzniesień i górek. Powolny przyrost po wyjściu z błot.', '100% gruby osad mułu organicznego na całej przestrzeni uniemożliwiający lądowanie koszyka.', 'Wysoce mętna latem od zakwitów alg; mocno zawiesista zawartość rośłinna toni.', 'Zarasta błyskawicznie "od brzegu do brzegu". Łąki grążeli, rogatka i tataraku pokrywają wodę.', 'Karaś złoty, Lin, Szczupak, Wzdręga, Płoć', TRUE, 'Idealna, naturalnie rozmnażająca się baza lokalnego drapieżnika chronionego gęstwiną flory.', TRUE, 'Pełne składki PZW z wymogiem ostrożnego traktowania ostoi wodnych.', FALSE, TRUE, 'Dostęp możliwy tylko w pojedynczych oczkach wyrwanych siekierą z zarośli przez kłusowników.', FALSE, TRUE, 'Błotne ścieżki polne, bardzo ograniczone miejsca postojowe między krzakami olszyn bez aut.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80575, 'Jezioro rynnowe leśne', 89, 4.4, 11.2, 'Brzegi urozmaicone małymi cyplami i krawędziami osuwających się, stromych stoków na 4 metry.', 'Piasek puszczański okraszony dużą ilością zwalonych pni dębowych, głębiej śluz organiczny.', 'Wysoka z charakterystyczną leśną paletą kolorystyczną na zjazdach rynny wodnej.', 'Pasy gęstej lilii u wschodnich brzegów dzikich osłoniętych lasami liściastymi pojezierza.', 'Szczupak leśny, Okoń, Wielki Leszcz rynnowy', TRUE, 'Lokalne zarybienia potężnymi pulami drapieżnika przez obwody leśno-związkowe fauny rybnej.', TRUE, 'Opłaty pełne PZW Zielona Góra, dostęp okręgowy ze zgodą Lasów.', FALSE, TRUE, 'Doskonałe przygotowane przez nadleśnictwa kładki w odstępach zapobiegających hałasowi stoisk.', TRUE, TRUE, 'Twarde pożarowe drogi w lesie Bytnickim z doskonałymi przygotowanymi obwodami pod miejsca kół.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80576, 'Jezioro torfowiskowe / dystroficzne', 34, 1.1, 2.8, 'Gładka linia bagienna uformowana przez dziesiątki lat narastającej puszczy bez wgłębień dna.', 'Żyjąca gąbka z torfu z grubym, sprężystym mułem gnijącej roślinności całkowicie bez żwiru.', 'Rdzawo-brunatna woda, w pełni torfowa; słaba przenikalność dla słońca po wierzchu.', 'Kokon roślinny odgradzający środek. Trzcina zajmująca brzegi chroni absolutną dzicz mchu.', 'Lin "smoła", Dziki Szczupak zielska, Krasnopióra', TRUE, 'Brak ingerencji sztucznej. Woda podlega całkowicie naturalnej selekcji ryb drapieżnych rezerwatu.', TRUE, 'Zezwolenia PZW, zachowanie ciszy; obwody ochronne flory mogą podlegać okresom rezerwatów dziczy.', FALSE, TRUE, 'Ekstremalnie bagienne trzęsawiska, które utrzymają tylko bardzo lekkie wędzisko bez krzesełek.', FALSE, FALSE, 'Zakaz wjazdu w bagniska. Wymagane dojście z plecakiem sprzętowym kilka kilometrów z duktów Lasu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80578, 'Jezioro krasowe rynnowe czyste', 55, 7.8, 19.4, 'Stoki urywają się ołowiem od samych twardych plaż; ostry profil bez blatów bocznych głębin.', 'Jasny piasek wymieszany z wapienno-krasowymi łupkami otaczającymi mroczną rynnę ze środka.', 'Kryształ. Widoczność uchodzi za wybitną na twardych łupkach stoków zachodnich piaszczystych plaż.', 'Bardzo rzadka przez gwałtowne utraty wysokości u brzegów wody uniemożliwiające zakorzenienie łodyg.', 'Okoń "pasiak", Pelagiczny Szczupak, Płoć sielawowa', TRUE, 'Twardy zakaz ingerencji w drapieżniki pojezierza dające wspaniały ekosystem samowystarczalności.', TRUE, 'PZW pełny okręg Zielona Góra.', FALSE, TRUE, 'Tylko parę wycinków twardej skały. Najlepiej operować z jednostek uśpionych w zatoczkach z wiatru.', FALSE, TRUE, 'Las iglasty z cichymi polankami umozliwiającymi zaparkowanie samochodu niedaleko plażowych uskoków.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80579, 'Jezioro polodowcowe głębokie', 485, 12, 34.6, 'Kompleks potężnych podwodnych gór u szczytów sielawy. Zawiłe półwyspy, doły i potężne skarpy.', 'Zmienny. Na mieliznach i wlotach piasek, pod 20m zwały gliny i muliste rynny sielawowe drapieżców.', '1 Klasa Czystości! Krystalicznie czysta, niesłychanie przejrzysta ton pelagiczna całego akwenu.', 'Roślinność bogata we wschodnich zatokach uciekających do brzegu, reszta pozbawiona gęstwin z dna.', 'Szczupak wielki, Okoń, Lin, Sielawa, Leszcz', TRUE, 'Złożone i mądre operowanie ilością odłowów sielawy podtrzymującej drapieżniki pelagiczne pod ton.', TRUE, 'Opłaty pełne plus potężne obostrzenia dotyczące turystyki w strefach chronionych wysp ptaków.', FALSE, TRUE, 'Wyśmienite rozległe plaże we wschodniej części umożliwiają dalekie rzuty zestawów spławikowych.', TRUE, TRUE, 'Zabudowa komercyjna jeziora ułatwiająca zrzuty łodzi z profesjonalnych podjazdów i parkingów wsi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81171, 'Staw hodowlany', 22, 1, 1.5, 'Płytka misa', 'Muł i torf', 'Niska', 'Kępy tataraku i trzciny', 'Karp, Karaś złoty, Lin', TRUE, 'Produkcja towarowa', TRUE, 'Zakaz amatorskiego połowu', FALSE, TRUE, 'Średnia', FALSE, FALSE, 'Polna utwardzona', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80580, 'Jezioro polodowcowe rynnowe', 104, 6.2, 23, 'Skomplikowane fałdy żwirowe przechodzące w ostre spadki 14m u dołów rynny obok zachodu na środku.', 'Uskoki wapienne przy gliniastych wzniesieniach; dno u góry twarde, schodzi szybko w muł u rynien.', 'Zielonkawa, dobra przezierność ale osłabiona gęstym pożywieniem alg i zawiesin obfitych lata pór.', 'Wyschnięte tataraki i odnogi starych korzeni zatopione na wschodnich bliskich płyciznach z brzegu.', 'Sandacz twardy, Duży Okoń, Karp, Płoć pelagiczna', TRUE, 'Sandacz w rynnie obficie zasilany co sezon dla łowców wertykalnych opadów u dna głębokich rowów PZW.', TRUE, 'Zezwolenia standard PZW Okręg Zielona z biletami łodzi w okresach na dopłaty do opadów drapieżnika.', FALSE, FALSE, 'Spora dostępność brzegowa i wydeptane po bokach piaszczyste oczka wyśmienite na metodę z krzesła.', TRUE, TRUE, 'Utwardzone place z miasta pozwalają parkować do brzegów na osiedlach tuż nad piaszczystym wjazdem.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80581, 'Jezioro krasowe rynnowe czyste', 45, 9.3, 21, 'Dynamicznie ściany od rzadkiej rośliny u progu do wcięcia dna na rynnę pod ponad 20 metrów z brzegu.', 'Wybitnie czyste, ostre, żwirowo-kamieniste blaty w rynnie otoczone czystym podłożem piasku rzutu kłów.', 'Zimne wody krasowe źródłami utrzymują fenomenalny błysk na dużych opadach słońca po deszczu opadu dna.', 'Uboga u wlotu, wąsy grążeli rzadko spotykane przed uderzeniem głębi krasowej odgrodzonej z tatarakiem.', 'Okoń "pasiak", Duża Płoć, Szczupak "pelagiczny"', TRUE, 'Rezerwa sielawowych toni i dzika natura okoni osiadłych na dnie twardym wód zarybianych w narybku PZW.', TRUE, 'Standardy w opłatach związku PZW z e-zezwoleniem.', FALSE, TRUE, 'Wymaga wprawy w szukaniu rzadkich otworów, dno szybko urywa spławiki na bocznych kamieniach rynnowych.', FALSE, TRUE, 'Dzikie przeciwpożarowe utwardzenia Lasów pozwalają wjechać bliżej by znieść ponton na rękach u brzegu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80582, 'Jezioro rynnowo-przepływowe', 72, 3.4, 10, 'Kanałowe łączenia po bokach wymusiły wyżłobienia nurtowe na mieliznach blisko piaszczystych blatów 3m.', 'Mulisto piaszczyste u głębin wyżłobionych nurtem dawnych rzek pod polodowcowe dno; bardzo wyrównane wloty.', 'Mętna latem z uwagi na szlak wodny uciagów kanałowych kajaków podnoszący osady łopatami rzecznych opadów.', 'Wyczyszczone plaże rekreacji ale obfite w wyśmienite grążele na spokojnych odcinkach odgrodzonych wzdłuż szuwaru.', 'Boleń prądowy, Sum kanałowy, Gruby Leszcz, Karp', TRUE, 'Regulowana fauna przed presją wędkarską rzutu obok licznych stanowisk turystyk wód śródlądowych drapieżnika w PZW.', TRUE, 'Regulamin wód udostępnionych związku i ośrodków doliczając dopłaty nocnych połowów karpiowych letnich obozów na wody.', FALSE, FALSE, 'Idealne do połowów na leżakach. Pomosty u ośrodków dają super warunki rodzinne.', TRUE, TRUE, 'Wsie w pełni gotowe u wjazdów ze ścieżkami ułatwionymi na dojazd pod wodę rekreacji rodzin.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80584, 'Jezioro polodowcowe (rynnowe)', 187, 8.4, 22, 'Głęboka rynna pocięta licznymi płytkimi blatami i podwodnymi wzniesieniami blisko zatok.', 'Twarde, wysadzane wapieniami i żwirem, jedynie w zatokach piaszczysto-muliste.', 'Bardzo dobra, z widoczną termokliną na ok. 6-8 metrach przez większą część sezonu.', 'Bujna w zatokach (grążele, lilie), szybki zanik roślinności na gwałtownych stokach rynny.', 'Sandacz, Okoń, Szczupak, Leszcz, Sielawa', TRUE, 'Intensywne i bardzo udane zarybienia mętnookim sandaczem oraz drapieżnikami toni toni PZW.', TRUE, 'Standardowe opłaty PZW Zielona Góra, z dodatkiem okręgowym na łódź wędkarską.', FALSE, TRUE, 'Urozmaicona, z wieloma łatwymi, piaszczystymi zejściami z zatok na szerokie twarde stanowiska.', TRUE, TRUE, 'Szybki dojazd utwardzony z szos krajowych wprost pod wjazdy do pensjonatów i na dzikie parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80585, 'Jezioro eutroficzne (leśne)', 38, 2.5, 6.2, 'Bardzo powolny, płaski zjazd formujący się z zatok w bardzo miękką, równomierną misę.', 'Dno wyścielone głęboką warstwą miękkiego, organicznego mułu po liściach u brzegu mchu.', 'Ciemna, często mętna i podlegająca mocnym, letnim zakwitom z wysoką temp. dna.', 'Ekstremalnie gęsta! Litoral trzcin i ogromne skupiska grążeli pokrywające wodę brzegu.', 'Lin, Karaś pospolity, Szczupak, Wzdręga', TRUE, 'Woda wybitnie produktywna naturalnie dla lina i karaśka z lekką wspierającą ręką wędkarzy.', TRUE, 'Licencje lokalne okręgowe z dzierżawią dla związkowców przy zjazdach w puszczę po opłacie.', FALSE, TRUE, 'Wędkowanie ograniczone tylko do kilku siłowo wyciętych stanowisk za grążelami na bagnach.', FALSE, TRUE, 'Drogi pożarowe leśne o sypkim piasku, nierzadko tworzące pułapki dla małych, miejskich kół.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80586, 'Jezioro rynnowe wąskie', 96, 7.3, 16.5, 'Skrajnie podłużna fałda ukształtowana z bardzo szybkim uskokiem z dwóch linii piaszczystych plaż rzutu.', 'Twardy, usypany drobnym ziarnem żwir o piaszczystej barierze obrzeży i minimalnym osadzie srodka dna wód.', 'Zjawiskowo czysta rynna, świetna filtrowana przez strome żwirowe warstwy dna w leśnych ostojach.', 'Znikoma na spadkach stoku, lekki, nierzucający się szczupaczy warkocz grążelowy rdestów przy obrzeżu jeziora.', 'Okoń "pasiak", Węgorz, Płoć, Karp', TRUE, 'Dbałość PZW z naturalnym naciskiem na ogromnego sielawowego drapieżnika rynny ożywionej.', TRUE, 'Pozwolenie powszechne u związku z wpisem opłat dojazdowych pod okręg Zielona Góra e-bilet.', FALSE, FALSE, 'Idealne rzuty u strome skarp, gdzie dno szybko i bez zawad ucieka w 3 metry dając luksus wędkowania u brzegu.', FALSE, TRUE, 'Twarde i szerokie polne trasy ułatwiające łatwy zwod dla turystów bez specjalnych ułatwień technicznych rur.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80587, 'Jezioro krasowe głębokie rynnowe', 43, 9.8, 26.5, 'Słynny gwałtowny opad "krasowy" (lejek) rynny dający oszałamiający krater po 3 metrach w dal brzegu wody dołu.', 'Ostre wapienne klify podpiaskowe i kreda. Dno potężnie stawia opór jiggowi a w środku twardy ubity szlam uśpiony.', 'Wybitna klasa! Bardzo przejrzysta o unikalnej szmaragdowej głębokości pozwalająca badać skały krasu wody dna echem.', 'Kompletny brak zwartego pierścienia u gwałtownej stromizny krawędzi, rzadkie plamki zarośli jedynie na dnie.', 'Pelagiczny Szczupak, Okoń u skarp krasu, Węgorz toni', TRUE, 'Surowy leśny akwen u rynnowych ustronnych puszczy ze wspaniałą ochroną w zarybianiach rynny toni wodnej.', TRUE, 'Dostęp biletowany do rezerwu krasu rynnowych głębin drapieżnika ryb w nadleśnictwach lokalnych.', FALSE, TRUE, 'Niesamowicie dzika lina bagien nie pozwala komfortowo operować na twardej głębi ok!', FALSE, FALSE, 'Do piaszczystej drogi po puszczy o słabym dojeździe u głębokich piaszczystych i trudnych krawędzi jeziora.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80588, 'Jezioro eutroficzne rynnowe łagodne', 74, 3.5, 9.2, 'Powolne, bardzo płaskie piaszczysto-błotne stoki, szerokie misowate dno przerywane uskokiem do rynny.', 'Wypłycenia okryte piaskiem jeziora o powolnym przejściu w gęsty mętny muł z listowia i drewna na środku uskoków.', 'Klarowność spada szybko w maju podnosząc mętną i natlenioną warstwę pod obfite roślinne wegetacje u szczytów lata.', 'Bogata linia trzcin osłaniająca od wiatru z wplatanymi licznymi "wyspami" moczarki i grążeli przed tłem.', 'Leszcz u rynny, Szczupak lilii, Płoć, Karp gruby', TRUE, 'Mądra gospodarka mieszana podrzucająca rybom rekreacji karpia u wędkarzy lądowych i obronie drapieżnika jeziora.', TRUE, 'PZW Lubuskie opłacone powszechne z dostępem dla rekreacji amatorskiej na wędki pod okręgowymi stawkami.', FALSE, FALSE, 'Fantastycznie dużo wyrw wyciętych na 1-2 krzesełka po bokach od liliowych oaz rzutowych do rynny dna połowów.', TRUE, TRUE, 'Dobre dojazdy polno-leśne z ubiciami dla lekkich transportów osobowych tuż przy leśnych skrajach osad.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81755, 'Polodowcowe rynnowe', 25, 3.2, 6.5, 'Regularna rynna, łagodne spadki dna.', 'Piaszczysto-muliste', 'Dobra', 'Bogata (moczarka, trzcina)', 'Szczupak, Płoć, Okoń, Lin', TRUE, 'Systematyczne zarybienia PZW Bydgoszcz', TRUE, 'Standardowe składki PZW', FALSE, FALSE, 'Dobra', FALSE, TRUE, 'Szutrowa', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80589, 'Jezioro eutroficzne podmiejskie', 58, 2.6, 5.8, 'Standardowa równina jeziora, bardzo leniwe osunięcia od obrzeży. Brak gwałtownych fałd rynnowych u koryt dołów dna.', 'Mulisto torfowa poducha osadzona w całej objętości wody pozwalająca w grząskiej gęstwinie kryć pokarmy rybom jeziora.', 'Latem niestety podatna na mocne zielenienie. Woda traci bystrość pod masą zawiesin glonowych u ciepłych płytkich dna.', 'Potężne pasma zielska otulają równe części wody dając schron obfity w drobny narybek PZW ławic przed wlotami rzeki.', 'Lin ciemny, Wzdręga złota, Płoć rzeczna, Szczupak rzutowy u brzegu', TRUE, 'Aktywny staw dający super schron na zarybienia, obfity w rybę sportową u ryb pzw drapieżnika u gąszczy lilii.', TRUE, 'Podmiejska taryfa PZW z rygorystycznym regulaminem i ograniczeniami sportowymi w zawodach u związków obwodów.', FALSE, FALSE, 'Dozwolone na wielu twardych ścieżkach przygotowanych pomostach gminnych we współpracy po kosiarkach brzegów.', TRUE, TRUE, 'Wyborna bliskość rzepina, parking pod samą krawędzią do rzutu z asfaltowej nakładki i szutrowych alei u wejść twardych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80552, 'Jezioro dystroficzne (bagienne)', 28, 1.2, 3.1, 'Całkowicie plaski bagnisty rezerwuar pozbawiony głęboczków opadający o drobne centymetry co kilkanaście metrów dna rzutu.', 'Zatapiany żywy dywan mchu, bardzo głęboki obumarły detrytus i błoto. Ciężki sprzet tonie przed wyczuciem sygnałki na dnie!', 'Ciemnobrunatna, typowo torfowa. Bardzo niska przenikalność świetlna po opadzie gnijących zarośli dołów dna rynnowych osadów.', 'Okalające akwen szczelne drzewostany okraszone liliami na tafli wyłapujące promienie przed zejściem do ciemnej rynny słońca', 'Lin "smoła", Karaś Złocisty, Szczupak top-waterowy żabi płycizn', TRUE, 'Rezerwatowy samoistny cykl przed rzadką dłonią wędkarską. Dzika natura po powalonych dębach brzegowych bagien chroni pzw ryb.', TRUE, 'Okręg i rygory ochrony wód dzikich PZW, doliczki u związków rybackich w bagnach leśnych po dojazdach pożarowych ścieżek lasu.', FALSE, TRUE, 'Piekielnie ciężka. Grząski bagienny grunt przed rzutnią zmusza używać woderów z pasem dającym szanse bez obsuniecia rzutów bagien!', FALSE, FALSE, 'Niezalecane wjezdzanie w dukt - piaszczysta linia leśna u błota zatopi auto natychmiast u skrętu na doły piaszczyste lasu ryb.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80590, 'Jezioro polodowcowe krasowe czyste', 114, 8.8, 18, 'Przepiękne twarde półki opadające stopniowo po usypanych krasowych rynnach! Spadki wyprofilowane rewelacyjnie u dołu tła.', 'Piaszczysto-wapienny u zjazdów w uskok dający oparcie wędkarzom na brzegu bez miękkich zatopień litoralu pod wodą drapieżną!', 'I klasa toni pelagicznych. Czysta i mroźna głębiną przepuszczającą ostre światło w dołki piaszczyste dna rzutu spiningu ok!', 'Minimalistyczna. Lekki sitowy włos na opasce i obfite ale głęboko schowane dywany ramienic dających okoniom u okrycia w wód dołu!', 'Okoń "garbus" z fluorocarbonu, Sielawa, Leszcz na rzut u góry', TRUE, 'Twardy regulamin ochrony drapieżników podtrzymujący wielkie zasoby łowiska pełnego czystej sielawowej pasiastej ryby rynny.', TRUE, 'Standardowe opłaty PZW Zielona z ostrym zakazem nęcenia szkodliwego twardym obwarowaniem ekosystemów leśnych toni jezior góry!', FALSE, FALSE, 'Idealne piaszczyste wjazdy dla rzutów spławikowo gruntowych po za wakacyjnym festiwalem urlopowym głośnym w lecie plażowym z dołu!', TRUE, TRUE, 'Wspaniałe szosy komercyjne do ośrodków i utwardzone parkingowe wjazdy nad rynną i po bokach dzikich leśnych wlotach plaż tła ok!', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80591, 'Jezioro eutroficzne chłodne leśne', 52, 2.4, 5, 'Leniwie wciśnięta w puszczę misa z wyrównanymi połaciami mętnych, cichych obniżeń rzadko twardszych u srodka osi pod dnem wędek ok.', 'Miękka i bardzo organiczna z liściastej i iglastej naleciałości potęgująca pożywienie bentosowe dla dzikiej płoci na wyleżeniach dna rynny.', 'Bardzo ciche i rzadko falujące, przezierność dość mocna wiosną i opadająca z ciepłem po wschodach osadów podwieszeniowych lilii u dna dołów.', 'Obficie zarosłe pięknymi zatoczkami, w których gąszcz dębów opada na dno, chroniąc drapieżne sztuki okoni gąszczu od światła słonecznego rzutu ok.', 'Płoć gruba jeziorna, Szczupak powalonych drzew liliowych w gęstym', TRUE, 'Wędkarskie dołożenia i wyborne naturalne warunki reprodukcji karpiowatych wśród ostoi tatarakowych gąszczów jeziorowych leśnej dziczy rzutu obok.', TRUE, 'PZW. Lokalnie bez dopłat z wyłączeniem silnikowych wymogów ekologii.', FALSE, TRUE, 'Utrudniona z uwagi na las i korzenie lecz parę piaszczystych wyrw uśpionych w zaroślach to mistrzostwo dające relaks wagglera bez sprzętu toni ech!', FALSE, TRUE, 'Leśne ubite dukty pozwalające przemykać z uwagą na zawały drzew na parkini w lesie bez problemów błota pożarowych odcinków lasu omijając bagna!', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80592, 'Jezioro eutroficzne polne nagrzane', 39, 1.4, 3.2, 'Całkowita płaska poduszka u dołu, taca osadów pozbawiona spadek rynnowych dołków i podwodnej batymetri u góry przed korytkiem.', 'Potworna warstwa głębokiego śluzu powiązanego z algami utrudniająca łowienie denna żyłką i twardym rzutem z gruntu koszem obok mułu rzutu!', 'Ekstremalnie nagrzana a zatem mętna u zielenicy w lata. Przezierność bywa zaledwie po kilkanaście centymetrów u samej góry słońca na tafli wody gąszczu!', 'Opanowana rogatkiem, i pałką u brzegu. Gigantyczne dywany zasłaniające dno dające świetne domy pod płoć u schowków tatarakowych drapieżnika rzutu zębatego!', 'Karaś złoty podwodny, Lin ciemnozielony pancerz jeziora u wód!', TRUE, 'Narzucana z góry polityka narybkowa uzupełniająca mocne, ciepłolubne stada z wód gładkich po jeziorach okręgowych łagodnych pzw terytoriów dzikiej dziczy bagien.', TRUE, 'Standard. Ogólnodostępna pula po wykupieniu znaczków i biletów okręgu drapieżnego i karpiowych taryf PZW Ośna pod drapieżcę u biletów z rzutu łodzi!', FALSE, FALSE, 'Dziko zarosłe, wymagane wodery by wejść i spuścić się za tatarakowe przeszkody rzutu obok drapieżnika lądowych wycięć od wód bez pomostu ok!', FALSE, FALSE, 'Wypłukane gliniaste szosy okrążające twardą krawędzią nie sprzyjające parkowaniu bez wejść bagiennych i podmokłych omijających dno wody rzutów ok!', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80593, 'Jezioro rynnowo-krasowe', 46, 6.2, 13.5, 'Szybki krasowy uskok schodzący pod ostrym skosem w ciemną głębinową wnękę piaszczystych twardych osadów od plaż miasteczka słońca.', 'Jasne twarde wapienne złoża okalane kredą schodzące u mroku rynny z mniejszą piaszczystą poduchą na której żerują u brzegu ryb karpiowatych!', 'Wyborna! Czysta chłodna toń obfitująca w przezierność w nocy dla spinningów drop shotów w rynnach pełnych sielaw rzucających bliki u boku echosondy u dołów!', 'Skąpa i czysta, w dużej mierze przygotowana pod plażowe wypustki co daje wolne od zaczepu odległościowe wyrzuty na grunt dla turysty karpiarza w nocy!', 'Karp Ośna potężny, Okoń sielawowy rynny krasowej na twardych stokach', TRUE, 'Sztucznie wspomagane przez gminę i pasjonatów nęcących regularnie stada rekreacyjne ryb by połów w nocy przynosił nagrody na piaszczystych wyrzutniach toni!', TRUE, 'Porozumienia gminy z twardymi obostrzeniami miejskimi dot. hałasu łodzi doliczonych wędkarskich PZW z regulaminem rybackim po rzutach!', FALSE, FALSE, 'Fantastyczne bulwary i wycięte miejsca piaszczyste pozwalające rzucać odległościową gruntówką bez kaloszy w garniturach nocy!', FALSE, TRUE, 'Centrum miasta. Asfalt i kostka, bezwzględnie najlepszy dojazd i parking u piaszczystych deptaków od wyjść wody bez błota lasu obok auta rzutu!', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80594, 'Jezioro polodowcowe rozległe duże', 386, 7.6, 22, 'Wspaniała batymetria polodowcowych pagórków u dna z ostrą linią piasku i rynnami obok piaszczystych wysp wystających z u głębi piaszczystych półwyspów rzutu.', 'Zmienne ukształtowania obfite w ubite skosy i warkocze piasku z ciemnym organicznym szlamem po wyciszonych wiatrami dołkach zarybionych wysp połaci bocznych akwenu!', 'Krystalicznie natleniona na falowaniach. Rzadko mocno obita gniciem z dreszczami glonowymi, przezroczystość do paru metrów na spokojnej wnęce od dłuższego brzegu ok!', 'Urozmaicona obok wysp. Przeplatana i twarda na falistym dnie dając miejsca okoniowe drapieżne rzutu pod sielawowe drapieżniki bocznego spadku na wyspie piaszczystej ok!', 'Gigantyczny Sandacz Wielki, Leszcz toni, Gruba płoć na bat na kładce', TRUE, 'Precyzyjna gospodarka z drapieżnikami na okonia i mętnookiego po rynnach i u zrzutów dołów obok wód od liliowych wzniesień sielaw w toni przed wiatrem dołów łodzi PZW ok.', TRUE, 'Opłata okręgu z ostrymi strefami ptactwa. Obowiązuje zakaz na silniki. PZW na wody pełne udostępnionych rejestrów po piaszczystym e-zezwoleniu wód ok!', FALSE, FALSE, 'Ograniczone rozmiarami i falami ale dziesiątki przygotowanych wycieć z piasku dają luksus wędkarzom lądowym nocy po wielkie sielawy rzutu ok!', TRUE, TRUE, 'Pełne w drogi szutrowe po okrągłej połaci zachodu ułatwiające dostęp i zjazd pontonem przy twardym parkingu dzikim u plaż dla wedkarza ok!', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80596, 'Jezioro polodowcowe rynnowe puszczy', 75, 6.8, 17, 'Stromy lej krasowy obok podłużnego wzniesienia zjeżdżający drastycznie twardymi schodami okoni pod zwalone pnie z dna ciemnego rowu lasu puszczy rzutu.', 'Twarde ubite krawędzie gliniasto-żwirowe po spadzie wapieni dające doskonałe podłoże dla sandacza drapieżnych wód opadów słońca do piasku letnich wód przed spadem obok.', 'Super czysta I i II kl. Nienaruszona przez algi dając jasny ołów przeświecony na wielu metrach rzutu drapieżnego oka z fluorocarbonu dół chłodnej wody ryb dzikich przed puszczą.', 'Wybitnie znikoma za sprawą ostrych urwisk brzegu ok.', 'Okoń u rynny wertykalnie, Wielki dziki puszczański Szczupak, Karp obok zrębów', TRUE, 'Tylko precyzyjna rezerwatowa ochrona odłowu.', TRUE, 'Licencjonowana i udostępniana okręgowi szczecin na specjalnych opłatach pontonowych bez ingerencji drapieżnych pzw łodzi rzutu ryb dzikiej przyrody puszczy drapieżnych rzutu wodom.', FALSE, TRUE, 'Utrudniona z uwagi na las ale twarda krawędź u góry ok.', FALSE, FALSE, 'Dukty ukryte w głębokim rezerwacie by zrzucić wędkę pieszo na plecach z okoniowym setem rzutu puszczy u dołów ok!', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80597, 'Jezioro polodowcowe wyspowe bardzo głębokie', 198, 10.4, 29.8, 'Pocięte i niesamowite spady przybrzeżnej i potężny komin wyspowy z korytem nurtowym w warkoczach ołowianych szczupakowych dołów krasowych skosów w dół przed wodom toni wyspy rzutu piaszczystej.', 'Rygorystycznie twarde żwirowe obrzucenia u rynny z opadem gliny piaszczystej w połaci wschodniej bez miękkiego opadnięcia do sielawowego mroku u dół zjazdu ołowianych okoni rybackich opadów wód ryb sielawy echa rynny.', 'Wysoka klarowność w głąb w strefach prądowych obok komina dołów krasowych i przy słońcu u zjazdów w wyspie ok.', 'Ostro skrócone do wąskich krawędzi piaszczystych wysp ok.', 'Sielawowy drapieżnik rynny wyspowej, potężny Sandacz echosond dołów, Gigant leszcza toni ołowiu.', TRUE, 'Tylko potężna baza samo regenerująca w wodach chłodnych ok.', TRUE, 'Twarde opłaty i rygor u ptactwa dla pontonowych i zakaz spalin obok rejestrów łowisk udostępnionych turystycznie w Szczecińskim rewirze drapieżnych rzutów pzw.', FALSE, TRUE, 'Dzikie wyloty dla pasjonatów nęcenia nocnego po ukrytych zjazdach na groble drapieżnego dna rzutu spławika bez ludzi latem na zwaliskach w doły sielawy!', TRUE, TRUE, 'Pożarowe okładziny z dębowego drewna u dzikiej puszczy wyboiste przed brzegami u parkingowych dziczy ok!', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80598, 'Jezioro krasowe szczelinowe ostre', 82, 12, 27, 'Ściany uskokowe! Kaskady krasowych pęknięć lecących od razu w 15m mroku po piaszczystej małej skarpie z kredowych osadów ryb drapieżnych sielawy u rzutu kłów w słońce obok sielawowych dołów wody rzutu obok piasku skosów piaszczystych spadek dna toni.', 'Kreda osadzona na krasie obfity w sielawy usiany od szczupaka omijających zarysowania u miękkich dołów wody rzutu góry ryb rynnowych drapieżnych głębin pod wodą piasku kredowych pęknięć krasowych słońca!', 'Kryształ najwyższej I kl widoczny na wielu m u sielaw przed wodom krasowych ok.', 'Brak zwarcia i łodyg co zrywa plecionki obok ok.', 'Okoń mityczny sielawy z toni, Gruba "Sielawa", Szczupak pelagiczny krasu ok.', TRUE, 'Zakaz komercji rybackiej dający wolną oazę ok.', TRUE, 'Opłaty pełne na Szczecin Okręg ok.', FALSE, TRUE, 'Dzika, wymaga akrobacji z drzew pod rzut bata na szczelinowe urwiska z brzegu ok!', TRUE, TRUE, 'Słabe, utajnione wręcz by powstrzymać kłusowników w puszczy bez nawierzchni obok piaszczystych rzutów lasu przed krasowych opadnięć słońca.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80599, 'Jezioro polodowcowe - kryptodepresja głębokie', 345, 14.5, 60, 'Ewenement głębi! Piaszczyste mola obok ucieczki krasowej pękniętej do ponad 60 metrow w mrok lodu rynnowych dołów sielawy rzutu ok.', 'Twardy, zwarty kras, wymyty na skarpach przed lądami dołów rynny u góry głębi ok.', 'Ekstremalnie przejrzysta ton I kl mitycznych sielaw obok rzutu słońca krasu głębi drapieżnych rynnowych ech ok.', 'Zminimalizowane obok plaży z dołu głębi ok.', 'Miętus, Mityczny Szczupak Pelagiczny dna łodzi ech, Sielawa ok.', TRUE, 'Chronione, drapieżniki pelagiczne pilnowane ok.', TRUE, 'Taryfy turystyczne wód obficie doliczane ok.', FALSE, TRUE, 'Potężne wspaniałe na koszyk z dalekich molo plażowych nocnych dołów obok ludzi latem u rzutu ok!', TRUE, TRUE, 'Komercja moryńska ułatwia wjazdy, slipy betonowe perfekcyjne pod auta duże rzutu obok ech ok.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80600, 'Jezioro eutroficzne zarośnięte płytkie taca', 145, 1.2, 3.5, 'Idealnie równe bez rynny! Płaska potężna równina opadająca powoli od tataraków z słońcem góry płycizn rzutu łodzi dna lilii bagien obok.', 'Miąższ i śluz ogromnych rozmiarów przed osadami z lilii dna gnicia tacy u dołu ok.', 'Zawiesista od lata potężnie grzejąca płycizny ok.', 'Ogromne puszcze rdestnicy z dołów wyłażące nad tafle ok.', 'Lin w łodygach, Potężny Amur Karp Mętna, Szczupak obok lilii', TRUE, 'Karp narybek sypany dający raj u brzegów ok.', TRUE, 'Standard ok.', FALSE, FALSE, 'Dziesiątki przygotowanych wyrw u bagien dające rzuty przed amurem nocą obok rzutu statywu karpi ok.', FALSE, TRUE, 'Szutry błotniste z dnem wybojów przed bagien rzutu ok.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80602, 'Jezioro polodowcowe małe dębowe rynnowe', 42, 3.5, 7.5, 'Strome i szybkie wloty od pochyłych urwisk od piasku słońca u góry dna drapieżnych wód opadów obok uskokowych rynnowych wcięć po drzewach ok.', 'Wypłukane na spadach liśćmi obalone z dębu ok.', 'Ciemne ale chłodne, dobrze podtrzymywane od spodu ok.', 'Pasy lilii dające chwyt przed rzutami na płytkie obok wlotów dna łodzi ok.', 'Płoć Spławik z bata lilii, Szczupak u liści.', TRUE, 'Umiarkowana naturalna dołów rynnowych reprodukcja ok.', TRUE, 'PZW szczecin bez doliczek pontonu obok rzutu ok.', FALSE, FALSE, 'Spokojnie rozłożysz rzut za krzakiem u ustronnej plaży lasu tła obok tataraków ok.', FALSE, FALSE, 'Dość łagodnie polne u dróg ok.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80625, 'Rynnowe leśne', 38, 5.5, 12.5, 'Regularna rynna leśna o twardym dnie i stromych zboczach.', 'Twarde: jasny piasek krasowy i drobny żwir, mało mułu.', 'Wysoka, krystaliczna toń o sielankowym charakterze.', 'Znikoma: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Słupsk.', FALSE, TRUE, 'Trudna przez wysokie skarpy i las; kilka dzikich wejść.', FALSE, TRUE, 'Dojazd drogami leśnymi, piaszczystymi; zalecane auta wyższe.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80604, 'Jezioro eutroficzne podmiejskie', 35, 1.3, 2.5, 'Całkowicie płaska misa bez fałdowań i uskoków dna. Powolny przyrost po wyjściu z brzegu.', 'Wysoce muliste i grząskie. Gruba warstwa torfu i detrytusu organicznego gnijącego latem.', 'Słaba, szybko zakwitająca latem, silnie zawiesista z mętnej zielenicy płytkich wód.', 'Pasy litych szuwarów twardych oddzielają ląd. Środek usiany rdestnicą i rozległym grążelem.', 'Lin, Karaś pospolity, Szczupak "polny"', TRUE, 'Wspomagane pule karasia i szczupaka PZW, samoistna produkcja doskonałych ryb białych ziela.', TRUE, 'Standardowe opłaty PZW Okręgu Szczecin ze znaczkiem na łodzie u wód otwartych.', FALSE, TRUE, 'Ekstremalnie utrudnione! Brak dojść brzegowych, konieczność wycinania stanowisk do lilii.', FALSE, TRUE, 'Szutrowe pobocza obok puszczańskich piaszczystych duktów leśnych. Wymaga aut terenowych.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80605, 'Zatoka morska / jezioro przybrzeżne', 1850, 1.5, 3.2, 'Równinny blat piaskowy, poprzecinany morskimi "cofkami" i naniesionymi rynnami piasku.', 'Piasek i żwir wymieszany z grubym mułem w spokojnych odnogach uchodzących na boki akwenu.', 'Mętna latem, falowanie dna ciągle miesza zawiesinę i piasek tworząc mętną mgłę u dołu.', 'Rzadka z uwagi na wiatry, jedynie twarde trzcinowiska obrzeżne zatoki bronią lądu płycizn.', 'Sandacz morski, Duży Okoń, Wielki Leszcz, Płoć', TRUE, 'Stada napływowe z Zalewu Szczecińskiego dają gigantyczny rezerwuar dzikich drapieżców toni.', TRUE, 'Wymagane pozwolenia morskie OIRM (nie PZW) z zachowaniem limitów wód przymorskich ryb.', FALSE, FALSE, 'Dostępne wały u Nowego Warpna, wyśmienite, twarde ścieżki rekreacyjne dla feedera u brzegu.', TRUE, TRUE, 'Pełna infrastruktura asfaltowa miejska, komercyjne twarde miejsca parkingowe, pirsy łodzi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80606, 'Jezioro dystroficzne (leśne)', 76, 2.2, 5.8, 'Słabe stoki opadające misowato do ciemnej rynny srodkowej zaleganej detrytusem rzutu dna.', 'Opadły osad z liści iglastych tworzy poduchę, a w gorszych wlotach czysty torf bez piasku.', 'Ciemnobrunatna (herbaciana), pochłaniająca światło u góry z uwagi na dno torfowisk dębu.', 'Niezwykle zarośnięte! Wianuszek obfitych trzcin i moczarki ukrywa brzegi przed rybami lądu.', 'Lin "smoła", Złota Krasnopióra, Szczupak', TRUE, 'Regulowana leśna natura, ograniczona ingerencja związku w celu podtrzymania ostoi puszczy.', TRUE, 'Zezwolenia PZW Szczecin u leśnych dojazdów w okręgach u dzierżaw bez obciążeń doliczek łodzi.', FALSE, TRUE, 'Trzęsawiska! Podejście grozi ugrzęźnięciem i zniszczeniem sprzętu, wymagane małe pontony.', FALSE, TRUE, 'Wyboiste pożarówki piaszczyste, auto można zawiesić obok skarp na mchu podczas obfitych burz.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80608, 'Jezioro polodowcowe rynnowe WPN', 65, 4.2, 8.5, 'Krawędzie brzegu uskokowe i piaszczyste. Zrzucają ton na łagodną misę rynny okręgu.', 'Piasek przechodzący obficie w miękki osad organiczny na środkowych częściach podłoża dołu.', 'Dobra klarowność lekko zabarwiona lasami liściastymi u góry dająca sielankowy kolor rzutu.', 'Czyste piaszczyste wyłomy okraszone liliami na mniejszych stokach piaszczystych wysp rzutu.', 'Szczupak leśny, Okoń u skarp, Piękny Lin', TRUE, 'Naturalnie selekcyjna drapieżna baza wybitnie chroniona przed presją PZW u góry rezerwatu.', TRUE, 'Rygorystyczna licencja dyrekcji Wolińskiego Parku Narodowego na amatorski połów u wycięć.', FALSE, TRUE, 'Wyłącznie na specjalnie uznaczonych pomostach i palikach drewna dyrekcji Parku WPN brzeg.', TRUE, FALSE, 'Parkowe zakazy łodzi, rezerwat zakazuje ingerencji pychówek i rzutów z pływających platform.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80609, 'Jezioro rynnowe leśne WPN', 45, 3.8, 7.2, 'Powolny stromy spadek od linii buków okalających wodę z leśnymi zawałami obok dębów.', 'Czysty piach po wschodniej części, gęsty detrytus i warkocze starych korzeni dna w rynnie.', 'Lekko ciemniejsza z zachowaną świetną przeziernością pozwalającą wędkować w czystych oazach.', 'Grążele na wcięciach, twardy trzcinowiec z rzadszym wywłócznikiem w głębi chroniącym liny.', 'Płoć WPN, Gruby Leszcz, Dziki Szczupak, Okoń', TRUE, 'Zakaz odłowu sieciowego czyni rynnę wyśmienitą dla dużego szczupaka naturalnych rzutów ech.', TRUE, 'Zezwolenia płatne bezwzględnie w WPN (BIP lub na miejscu). Kontrole straży obfite w lato.', FALSE, TRUE, 'Ograniczone do pomostów, zakaz deptania litoralu leśnego brzegu WPN z krzesłem karpiowym!', TRUE, FALSE, 'Brak możliwości i kategoryczny zakaz poruszania się łodziami wędkarskimi na tafli rezerwatu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80610, 'Jezioro rynnowe głębokie rogalowe', 81, 6.5, 12.8, 'Słynny kształt rogala dający uskokowe, bardzo strome ściany przy półwyspie centralnym echa.', 'Twarda skała piaszczysta i wapienne ostre wypłukania! Osad na dnie marginalny u koryta WPN.', 'Czysta rynna jeziora sprzyjająca łowieniu na ciemne naturalne kolory rybek sielaw u zjazdów.', 'Uboga przy ostrej skarpie, wybitna i gruba w łagodnych zaroślach południowych ramion lilii.', 'Okoń "pasiak", Wielki Szczupak dębu, Płoć rynny', TRUE, 'Tylko rygor Parku z zakazami rzezi drapieżnika tworzy wspaniałą pulę u rynnowych dołów lądu.', TRUE, 'Licencja Parku (WPN) opłacana dniowo/sezonowo dla wędkowania z desek zatwierdzonych kładek.', FALSE, TRUE, 'Niesamowicie trudna logistyka! Wolno tylko z zatwierdzonych wycięć brzegowych rzutu ok.', TRUE, FALSE, 'Niedostępne. Surowy zakaz używania wszelkiego sprzętu wodnego pod groźbą konfiskaty na WPN.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80611, 'Jezioro eutroficzne WPN spokojne', 48, 2.3, 5.5, 'Spokojniejszy kuzyn rynnowych głębin. Misa jest bardzo spłaszczona u dołów bagiennego dna.', 'Gruby muł niosący żyzną glebę dla lina rzucanego w bąbelkowiska wędkarskich nęceń ok.', 'Mętna latem, brązowa, pełna roju bentosowego i owadów u brzegu grążelowych okładzin słońca.', 'Bardzo zarośnięte po wschodzie; wyłomy zrobione dla stanowisk odsłaniają czyste blaty dna.', 'Karaś Złoty, Lin pancerz, Leszcz bąblowy', TRUE, 'Szczupak kontroluje w naturalny sposób potężne lęgi słodkowodnej uklei rzutowej u rzutu.', TRUE, 'Licencja WPN. Obowiązują okrojone rygory dotyczące stref połowu (zakaz nocnych na dziko).', FALSE, TRUE, 'Znakomite przygotowane przez WPN pomosty do obsiadania spławikami za grubym karasiem łodzi.', TRUE, FALSE, 'Strefa absolutnej ciszy wodnej rezerwatu - zakaz jednostek nawodnych z brzegu jezior WPN.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80612, 'Jezioro krasowe głębokie WPN', 51, 12, 29.8, 'Przerażający opad po plaży i krasowe leje uciekające szybko na 20m czystego piaszczystego mroku.', 'Wybitnie twarde! Zbite usypiska wapienno-piaskowe dające ostre dno rynny rzutu łupków z góry.', 'Szmaragd i kryształ głębin wodnych. Ryba doskonale widzi każdy źle schowany węzeł z dna!', 'Szybko urywa się przez krawędzie krasu! Znikoma roślinność podwodna toni piaszczystych plaż.', 'Pelagiczny Szczupak, Gigant Okoń, Płoć Krystaliczna', TRUE, 'Potężna rezerwa ryby sielawowej utrzymującej sielankowy rozród rynnowy mrocznych dołów krasu.', TRUE, 'Licencja drogich wód WPN, surowe ograniczenia nęcenia paszowego by nie niszczyć wód rezerwatu.', FALSE, TRUE, 'Wyłącznie parę punktów dopuszczonych do łowienia przez WPN. Skazane na gigantyczny fart z dna!', FALSE, FALSE, 'Brak opcji wypłynięcia czymkolwiek. Dostęp tylko pieszego rzutu gruntówką z krawędzi plaż ok!', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80683, 'Rynnowe przepływowe', 1431, 5, 19, 'Twarde dno, dawne koryto rzeki Piaśnicy, wymuszone prądy wody.', 'Głównie twardy piasek i żwir, przy tamie betonowe umocnienia.', 'Średnia, silnie zależna od pracy elektrowni i dopływu Piaśnicy.', 'Skąpa: głównie twarda trzcina w zatokach, mało roślinności miękkiej.', 'Szczupak, Sandacz, Okoń, Leszcz, Węgorz', TRUE, 'Systematyczne zarybianie szczupakiem i gatunkami reofilnymi.', TRUE, 'Zezwolenia PZW Gdańsk / specjalne u zarządcy rybackiego.', FALSE, FALSE, 'Dobra od strony betonowych wałów i przystani w Nadolu.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy od strony Wejherowa i Gniewina.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80613, 'Jezioro dystroficzne płytkie (bagienne)', 22, 0.8, 1.5, 'Skrajnie plaskie, uformowane jako mroczna błotnista zupa u dołów roślin torfowych rezerwuarów.', '100% gruby śluz bagienny, torf sprężynujący, wędki wbijają się u brzegu na 2 metry wgłąb.', 'Rdzawo brązowa toń torfowa o praktycznie braku naświetlania dennych struktur słońca góry.', 'Kożuch wodny! Lilia, rzęsa wodna szczelnie zamyka lustro wody rezerwatu przed wędkarzem.', 'Lin Ciemny, Krępy Szczupak zielska, Karaś', TRUE, 'Torfowy szczupak "bagienniak" króluje u samej powierzchni czatując na gąszczu żab zielska.', TRUE, 'Wymaga zapytania WPN z powodu okresowych zamknięć terytorium ostoi ptasich rezerwatów z dziczy.', FALSE, TRUE, 'Tylko bardzo specyficzne dziury wędkarskie u wybudowanych kładeczek bagiennych nad rzęsą.', TRUE, FALSE, 'Surowy zakaz parkowych jednostek łodzi u dystroficznej ostoi śluzowisk torfowych puszczy WPN!', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80614, 'Jezioro eutroficzne karasiowe małe', 18, 1.2, 3, 'Klasyczna, powolna misa jeziora bez urozmaiceń stoku. Łagodnie zstępuje pod okrywę lilii z brzegu.', 'Miękkie, gliniasto muliste po dębach zwalonych przez aktywność bobrową okalającą wodę dziczy.', 'Dość jasna na początku wiosny, niestety latem mętnieje po grubszych falach nagrzanej zielenicy.', 'Obfite tataraki wycinane dziko, podwodne grążele zamykają rzuty ciężkie z opadów na szczupaki.', 'Lin wiosenny, Płoć, Mniejszy Szczupak PZW', TRUE, 'Rozwój kontrolowany samoistnie z wpuszczaniem karasiowym okręgów miejskich w zarośla narybku.', TRUE, 'PZW Szczecin powszechne opłaty związkowców dozwolone z dojazdów pod okręgi turystyki małej.', FALSE, FALSE, 'Dziesiątki przygotowanych i wykarczowanych dziur brzegowych idealnych pod stanowiska łowców.', FALSE, FALSE, 'Spokojnie wjeżdża się na dukty przy rowach do małych piaszczystych wyrw parkingowych dziczy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80615, 'Jezioro rynnowo-eutroficzne otwarte', 165, 3.4, 8.5, 'Faliste, równe stoki piaskowe przerywane mulistymi wgłębieniami głównego szlaku na środku jeziora.', 'Miejscami żwir i czysty piasek doskonały by położyć koszyczki z zanętą na twardo bez opadu dna.', 'Wysoce dobra poza letnim uderzeniem zielenicy obok uciagów turystycznych pól komercji u góry.', 'Rozległe ale urozmaicone dające strefy piaszczyste pozbawione zielska z dogodnymi rzutami wody.', 'Duża Płoć, Leszcz na rzut, Piękny Karp twardy', TRUE, 'Bogata i świetnie zarządzana woda komercyjna we współpracy z okręgami PZW obok piaszczystych plaż.', TRUE, 'Składki ogólne PZW z doliczeniami do nocnych obozowisk z namiotami taryf okręgowych łodzi rzutu.', FALSE, FALSE, 'Cudowne, wygolone obok golfa trawiaste zjazdy by wejść z fotelami bez cięcia dżungli wędkarskiej.', TRUE, TRUE, 'Pełny, doskonały dojazd asfaltami na wspaniałe ubite darmowe parkingi obok twardych brzegów wody.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80616, 'Jezioro nadmorskie (płytkie, ogromne)', 489, 1.5, 3.2, 'Rozległy na setki hektarów piaszczysto-błotny talerz o niemal idealnym wypłaszczeniu od brzegów.', 'Przeplatany muł i piasek wymywany przez dziki wiatr od morza rozkładający tace dna wód łachy.', 'Słaba u góry. Mieszanie falami z płytkiego dna całkowicie brudzi wodę piaskiem z naniesień morskich.', 'Ogromne strefy wysepek trzcinowych na 100 metrach w dno chroniące potężny narybek wód i żaby góry.', 'Gigant Szczupak piaszczysty, Leszcz ławicy, Okoń', TRUE, 'Otwarty obieg z morzem dający ujścia i ucieczki narybkom u wód przymorskich szczupakom wielkim wód.', TRUE, 'PZW Szczecin połączone z wodami przepływowymi z wymogiem ostrej weryfikacji sprzętów połowu łodzi.', FALSE, FALSE, 'Niemal całkowicie pozbawione punktu z wędki u brzegu! Potężne bagno i łódź to absolutny wymóg.', FALSE, TRUE, 'Trasy ułatwione od Świętouścia asfaltem pod bazy rybackie z dobrym wylotem dla spuszczania pontonów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80617, 'Jezioro polodowcowe gigant rynnowy', 809, 10.4, 28.1, 'Epickie krasowe załamania schodzące kaskadami wapienia tuż po wyjściu z płytkich twardych zatok.', 'Żwir u brzegu, kreda i strome podwodne klify na rynnie w uśpionej na dole mrocznej toni sielaw.', 'Kryształ I kl.! Woda tak przejrzysta że łodzie z echem widzą okonie uciekające z 10m uskoków góry!', 'Rzadka krawędź u góry by oprzeć plecionkę ok.', 'Gigant Szczupak Pelagiczny, Wielki Okoń, Sielawa, Leszcz na dnie', TRUE, 'Złożona polityka ryb reofolijnych i pelagicznych z G.R. chroniąca sielawy z łowcami gigantów okoni.', TRUE, 'Opłata w GR Ińsko ze znacznymi dopłatami u łodzi spinningowych i echosond w okresach drapieżnego.', FALSE, FALSE, 'Dostęp zaledwie w rejonach łagodnych płani (Cieszyno). Większość urywa zestawy na zjazdach rynny!', TRUE, TRUE, 'Komercyjnie i wędkarsko bardzo wyśmienite, twarde ścieżki leśne i obfite parkingi ośrodków u brzegu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80618, 'Jezioro polodowcowe rynnowe dębowe', 145, 6.4, 15.2, 'Bardzo wyrównane rynny i strome skosy uskokowe usypane gliną na zachód twardych podjazdów u góry.', 'Wspaniałe sandaczowe blaty z piaszczystej gliny u dołów zjazdów z małym śluzem u spokojnych zatok.', 'Zielonkawa lecz głęboko przejrzysta po opadach, świetnie trzyma opór planktonowy z chłodem słońca.', 'Miejscowo obfita na łagodnych krawędziach po zachodzie dająca zacisza liliowe lina ze spławików ech.', 'Sandacz twardy, Okoń opadowy, Płoć spławika, Leszcz na rzut u brzegu', TRUE, 'Regularne zarybienia mętnookim sandaczem PZW rzutu dla twardego wędkarza opadów u skosów gliniastych.', TRUE, 'Standard. PZW Szczecin z wykupem taryf łodzi u sprzętowych opadów wód ryb echosond drapieżnych w dół.', FALSE, FALSE, 'Bardzo obszerne piaszczyste stanowiska dla feederów z łagodnym wejściem do wód obok miejskich deptaków.', TRUE, TRUE, 'Centrum miasta daje idealny dojazd kostką by stanąć rzutem pod piękne opaski parkingowe wód ok.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80620, 'Jezioro krasowe szczelinowe ostre rynnowe', 123, 14.5, 33.4, 'Zabójcze stoki urywające się od pierwszego metra brzegu! Otchłań wapienna po krasowych zrzutach tła.', 'Zwarte gliniaste blaty i ściany kredowe bez najmniejszych osadów okrzemek na podwodnych urwiskach piaszczystych.', 'Absolutny kryształ! Widoczność pozwala dojrzeć szczupaka rzutu na kilku metrach w dół u ostrego lądu ok.', 'Niedostępna krawędź powoduje ubogie skupiska rzadkiego sitowia nie rzutującego na walkę z ułowami drapieżców!', 'Sielawa toni, Okoń Pelagiczny fluorocarbonu, Szczupak Zawieszony.', TRUE, 'Regulowana ochrona ryb chłodnych (sielawa) daje znakomity wzrost potęg okonia pelagicznego toni rzutu!', TRUE, 'PZW / G.R. Ińsko na wody szczególne obfite w opłaty turystyk echosond na łodzi z okręgowych rewirów wód.', FALSE, TRUE, 'Tylko bardzo trudny rzut boczny z drzew z uwagi na brak plaż do rzutów głębokich za okoniem krasu u góry!', TRUE, TRUE, 'Trasy wybitnie rzadko piaszczyste dające dojechać dzikimi lasami na zrzuty łodzi u twardych krzaków u lądu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80621, 'Jezioro rynnowe głębokie', 114, 6.2, 17.5, 'Uskoki tnące stoki przy plażach, szybki zjazd na głębokie żwirowe rynny i płaskie półki wcięć.', 'Mieszane: czysty twardy piasek na blatach przechodzi płynnie w zbitą glinę w rynnie opadów.', 'Dobra klarowność toni. Przejrzystość ułatwia obserwację ławic na stokach do kilku metrów.', 'Mocny, zwarty pas trzciny u brzegu, podwodna roślinność szybko zanika z powodu krawędzi dna.', 'Sandacz twardy, Okoń opadowy, Płoć, Leszcz', TRUE, 'Twarde zarybiania PZW drapieżnikiem w celu budowy populacji mętnookiego (sandacza) z opadu.', TRUE, 'PZW Szczecin opłata ogólna. Dodatki okręgowe z włączeniem łodzi i wód górskich bez opłat rzek.', FALSE, TRUE, 'Utrudniony zarys brzegów przez zwarty trzcinowiec zmusza na pływające pontony lub łodzie ech.', FALSE, TRUE, 'Drogi pożarowe twarde, udostępnione parkingi ziemne u lasów na szybkie spuszczenie łódki PZW.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80622, 'Jezioro eutroficzne płytkie', 65, 1.8, 4.2, 'Rozległa, łagodnie usypana i niezwykle równa misa jeziorna bez fałd rynnowych i głębokich rzek.', 'Twardego dna brak! Głęboki, puszysty i bogaty bentosem muł przykrywający dno niemal w całości.', 'Niska, często zielonawa z uwagi na kwitnienie nagrzanych latem wód, mało przejrzysta pod grążel.', 'Ekstremalnie gęsta! Trzcinowisko, tatarak, ogromne "dywany" grążela ograniczają wędkowanie.', 'Lin ciemny, Karaś złoty, Szczupak u lilii', TRUE, 'Narzut naturalnej hodowli wspomaganej karasiowymi rybami dla regulacji fauny dzikich płytkich zarośli.', TRUE, 'Zezwolenia amatorskie na wędkowanie udostępnione przez okręg PZW na obwody dzikie wód.', FALSE, TRUE, 'Brak możliwości szerokiego zarzutu przez ścianę lilii! Łowienie tylko w wyrąbanych oczkach.', FALSE, FALSE, 'Dziko ubite polne skraje z utrudnieniami na błotach przy ulewach ograniczające dojazdy rzutów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80623, 'Jezioro dystroficzne (leśne)', 38, 2.5, 6.5, 'Skryty w dole kocioł z płaskim opadaniem krawędzi bez ostrych urwisk i zrębów polodowcowych wód.', 'Śliska poducha na obumarłych, wieloletnich liściach olszynowych przegradzająca torf i błoto.', 'Ciemnobrunatna - typowa ton kwasów humusowych. Przezierność niska pod korzenie drzew obok.', 'Skąpa roślinność litoralu wyparta przez opad drzew okalających brzegi, w wodzie minimalna trawka.', 'Wzdręga krasnopióra, Dziki Szczupak w cieniu', TRUE, 'Regulowana przez drapieżniki w zrównoważonym ekosystemie wód leśnych odciętych od turystyki wód.', TRUE, 'Opłata w kołach leśnych/okręgu PZW pozwalająca rzucać wyłącznie po brzegach pożarówek dziczy.', FALSE, TRUE, 'Karkołomne przez olsy! Zwalone dęby utrudniają chodzenie obok brzegu z wędką bez woderów mchu.', FALSE, FALSE, 'Droga ukryta w leśnym dukcie dająca radę do przejścia pieszego z ekwipunkiem obok małego auta!', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80624, 'Jezioro polodowcowe rynnowe czyste', 145, 8.4, 21, 'Spadziste brzegi, głębokie i uskokowe rynny z kilkoma żwirowymi podniesieniami dna (blaty) toni.', 'Wyśmienicie twarde! Żwirowe zjazdy i łupki na skarpach dające opór gumom drop-shot na echo.', 'Kryształ. Wysoka przejrzystość z tonią pozwalającą penetrować ryby echosondami w głąb u rynny.', 'Rzadkie trzcinowiska znikające na stromiznach. Czysta linia bez uciążliwych warkoczy pod wodą.', 'Okoń "pasiak", Sandacz w głębi, Szczupak, Płoć', TRUE, 'Regulowany wylew obfitego narybku by wzmocnić duże sielawowe drapieżniki pelagiczne rynnowe.', TRUE, 'Licencja okręgu PZW z doliczonym używaniem łodzi motorowych elektrycznych z echosondami łowów.', FALSE, FALSE, 'Dozwolone na urokliwych i twardych opaskach plaż wschodnich wolnych od rygoru gąszczu rzutu.', FALSE, TRUE, 'Cudownie utrzymane asfalty i odcinki ubite, dobre piaszczyste miejsca u łatwego slipu z koł.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80626, 'Jezioro eutroficzne z blatami', 85, 3.5, 7.8, 'Pofałdowane z wyraźnymi usypiskami tworzącymi półki dzikiego bentosu u uciętych zatok płytkich.', 'Piaszczyste skosy i bardzo żwirowe stoły wędkarskie uciekające powoli w dół mulistego dna srodka.', 'Mętna latem, chłodna wczesną wiosną, posiada zielonkawą obfitą paletę zawiesin planktonu ryb.', 'Wyważone zarośla u obrzeży z przepięknymi trzcinowymi wyspami nie ograniczającymi rzutu metod.', 'Karp łuskowy, Szczupak litoralu, Płoć, Karaś', TRUE, 'Obfite dolewki dużych partii ryb spokojnego żeru np. karpia rekreacyjnego i walecznych leszczy.', TRUE, 'Związek Wędkarski powszechny okręg, doliczany regulamin na łodzie wędkarskie bez dopłat motor.', FALSE, FALSE, 'Znakomite, przygotowane trawy i skoszone miejsca dzikie by wejść do jeziora z feederem u nóg.', FALSE, TRUE, 'Łagodny i w pełni cywilizowany pas dla aut dających schować się bezpiecznie przy polanach ok!', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80627, 'Jezioro polodowcowe rynnowe zarośnięte', 36, 4.5, 11, 'Zapadlisko krasowe okalane lasem ściągające głębokie rynnowe zrzuty bardzo symetrycznie w oś.', 'Torfowo muliste brzegi przechodzące w piaskowo-żwirowy zrzut po twardej fali opadowej rynien.', 'Jasna zielonkawa, w rynnie kryształ dający opór chłodnych źródeł pod dębami okalającymi brzegi.', 'Gęste łąki grążeli u brzegów, liczne krzewy rdestnicy kryjące ciemno-zielone drapieżniki na echa.', 'Dziki Szczupak cienia, Wzdręga złota, Duży Lin', TRUE, 'Dzikie wody w ostoi leśnej, naturalna wędrówka okoni na spadkach opadowych wokół zwalonych pni.', TRUE, 'Kółowe PZW zgody na połów rekreacyjny po dojazdach pożarowych Lasów bez łodzi napędowych pzw.', FALSE, TRUE, 'Bardzo utrudnione! Obwód lasu i twarde nawisy podmokłe dają zakaz wejść bez dobrych woderów ech!', FALSE, FALSE, 'Dzika i słabo oznakowana przeprawa lasu. Auto terenowe ma szanse, niskie zahaczy o korzenie rur.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80628, 'Jezioro rynnowe szczelinowe wąskie', 56, 7.2, 19.5, 'Ekstremalne kaskady opadające po obu bokach wąskiego wału wodnego dającego chłód w toni.', 'Twarde gliniaste ściany rynny idealne dla twardych uderzeń główek wolframowych o piasek krasu.', 'I Klasa. Czyste prześwity w słońcu na wapienne kamienie dające ucieczkę garbatym okoniom z dna.', 'Brak ze względu na ostrą ścianę u brzegu nie ułatwiającą łodygom wsparcia na glinie stoku ryb.', 'Sandacz mętnooki, Okoń rynnowy, Wielki Leszcz', TRUE, 'Sandacz jest oczkiem w głowie PZW dla pasjonatów opadów jigowych drapieżnika u gliniastych dołów.', TRUE, 'Zezwolenia PZW pełne u obwodów udostępnionych dla łodzi na głębokie metody sielawowych echosond.', FALSE, TRUE, 'Ze względu na zrzut głębi do zera metrów przy lądzie łowienie spławikiem możliwe wzdłuż stoku.', FALSE, TRUE, 'Krótkie twarde ubite ujęcia obok dróg głównych pozwalają na slip pychówek od ustronnych piaszczyst.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80629, 'Jezioro polodowcowe krasowe czyste', 215, 9.8, 25.5, 'Krasowe "Tatry" po wodą! Wypłycenia żwirowe na rynnie i uskokowe ściany dna uciekające w dół.', 'Biały żwir, kreda na ścianach, skałki piaszczyste i marginalne błotniste wgłębienia srodka echa.', 'Kryształ najwyższej I kl widoczny na wielu m u sielaw przed wodom krasowych ok.', 'Brak na blatach, piaszczyste dno uniemożliwia przyrost grubych puszczy rdestnic dających uwiązy!', 'Pelagiczny Szczupak sielawy, Duży Okoń, Karp', TRUE, 'Sielawa oraz okonie pod ochroną potężnych regulaminów PZW po włożeniach zarybków sielaw jeziora.', TRUE, 'Opłata PZW / G.R. Drawsko pozwalająca wypłynąć w poszukiwaniu drapieżnika systemem Live Scope w dół.', FALSE, FALSE, 'Wspaniałe twarde plaże obok cywilizacji dające rozbić potężne karpiowe bazy bez grzęzawiska do rzutu.', TRUE, TRUE, 'Twardy asfalt i obfite parkingowe komercyjne tace pozwalające spuścić ciężkie okręty wędkarskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80630, 'Jezioro eutroficzne wszechstronne', 121, 3.8, 8.4, 'Poduszki mułu na blatach przeplatają się gładko w uśpione, średnie zagłębienia misowe rynien.', 'Mieszanka błota z piaszczystymi zjazdami u brzegów dająca swobodne operowanie hakami dna w liliach.', 'Zmienna. Wiosną bystra, latem niosąca zawiesinę odżywczą po wiatrowym mieszaniu w mniejszej głębi.', 'Rozległe u wschodu gdzie grążel i grzybienie dają znakomite domy tatarakom ryb spokojnych żerów.', 'Lin ciemnozielony, Krępy Szczupak łachy, Płoć', TRUE, 'PZW utrzymuje znakomitą bazę naturalnych drapieżców wspierając rybę białą na dołkach wędkarskich.', TRUE, 'Związkowa opłata w okręgu pod wędki stacjonarne bez dodatków echosond drapieżnych wód sielawy ok!', FALSE, FALSE, 'Dziesiątki pięknych wyrw tatarakowych by ustawić krzesło w oderwaniu od gwarnych zatoczek rzutu.', FALSE, TRUE, 'Piaskowe dobre wjazdy na zarośla leśnych oaz dające spokój, auta podjeżdżają niemal na koła kocyk.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81289, 'Antropogeniczny (Osadnik)', 50, 2.5, 5, 'Płaska niecka pokopalniana', 'Wapienne (biały osad)', 'Wysoka (nienaturalnie turkusowa)', 'Brak (pH uniemożliwia rozwój)', 'Brak (zbiornik martwy)', FALSE, 'Brak', FALSE, 'Zakaz wstępu do wody', FALSE, FALSE, 'Tylko punkt widokowy', FALSE, FALSE, 'Asfaltowa/Szutrowa', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80631, 'Jezioro krasowe rynnowe czyste małe', 54, 7.8, 16.5, 'Dynamicznie ściany u progu uderzające we wcięcia dna rynny pod krasowe uskokowe ściany od 10m dół.', 'Wybitnie czyste, ostre, żwirowo-kamieniste dno okalane czystym podłożem piasku krasowej echosondy.', 'Zimne wody zjawiskowych źródeł podtrzymują głęboką czystość po deszczach rzutu piasku u dołów skał.', 'Znikoma i cicha u pasów opasek dębowych nie rzutująca zjawisk gąszczu obcinających plecionki u dna!', 'Okoń "pasiak" z dno kamieni, Szczupak głębin', TRUE, 'Naturalne wylęgarnie w twardym i ostrym ekosystemie dają zdrową i ostrą populację pasiaków w echa.', TRUE, 'PZW na dopłatach łodzi bez ingerencji spalin i ciężkiej weryfikacji turystyki łowców okoniowych ech.', FALSE, TRUE, 'Wolne bezludne plaże w ustronnych krzakach świetne do wypadu odległościowego bez kaloszy rzutu obok.', FALSE, TRUE, 'Ścieżki wydeptane u leśnych dróg ale twarde i bez kłopotów dla zwykłej osobówki po burzach słońca.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80632, 'Jezioro eutroficzne pofalowane', 75, 4.2, 9.8, 'Mocna batymetria wycięta falą u wiatrów na gładkich osunięciach łachy dających rynienkę środka pzw.', 'Na bagnistych częściach rzutu z mułem u góry piasek przechodzący w detrytus powalonych konarów dna.', 'Wybitnie zależy od rzutu. Lato powoduje zakwity płycizn utrudniając wgląd dna na 1.5 m u góry wód.', 'Wyschnięte tataraki i odnogi starych trzcinowisk tworzące u lądu wyborną ostoję ciemnych łowców ryb.', 'Duży Leszcz w rynnie, Gruby Szczupak Trzcinowy', TRUE, 'Dbane roczniki ryby białej by uderzyć w stada zielska grubym karpiem letniego sezonu od spławika.', TRUE, 'Ogólne zezwolenia okręgu wód połączone opłatami rejestrów u rzutów stacjonarnych rybaka brzegów.', FALSE, FALSE, 'Zabójczo trudna lina gąszczy tataraków by wędkować u lądu. Brak wyrw i miejsc spławikowych lilii.', FALSE, TRUE, 'Zjazdy bardzo rzadkie w lesie i ułożone twardo od szos. Można dojechać pod zrzut pychówek obok wód.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80633, 'Jezioro dystroficzne płytkie, gnilne', 42, 1.2, 3.4, 'Talerz krasowy o potężnym nawarstwieniu mułów u góry bez ucięć dających schron z opadu głębin obok.', '100% gruby osad liściasty dębów bagien u góry dna dając wędkarskie opary metanu pod wodą rzutów lili.', 'Brunatna i zakryta, absorbująca światła puszczańskich wód torfów dając okonia u cieniu lili drapieżnych.', 'Grążele na całym profilu rzutu wody. Gąszcz utrudniający wgląd drapieżny od wód przed trzcinowisk.', 'Lin Pancerz Mchów, Szczupak bagienny, Wzdręga', TRUE, 'Tylko drapieżny rezerwat dziczy pozbawiony wybijania sieciami drapieżnika u gąszczy obok bagien ech.', TRUE, 'Opłata w okręgach w obwodzie Lasów po rejestrach wędkarskich na pożarowych wodach dziczy okręgowej.', FALSE, TRUE, 'Utrudniony. Grzęzawiska, wciągający w uderzenie bagien mech po dębach, absolutny brak miejsca lądu.', FALSE, FALSE, 'Do puszczy ciężkimi wozami by piaszczysta leśna dróżka puściła lekki ponton wędkarskich wód u pni.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80634, 'Jezioro rynnowo-krasowe', 84, 5.5, 14.8, 'Szybkie ucięcie gliny u zjazdu pod strome uskokowe fałdy wapienne dające cień rynnie w uśpienia.', 'Glina mieszana z twardym okrzemkowym błotem bez gnijących zapadnięć koszyczków method pod rzuty ech.', 'Zielona, jasna wczesnym świtem i doskonale filtrująca głębie po obfitych uderzeniach chłodnych źródeł.', 'Uporczywe gęste rdestnice tylko po opadłych skarpach w dół pozwalając rzucać obok czystej toni z dna.', 'Sandacz twardych blatów, Duży Okoń jiga', TRUE, 'Wspaniała odnowa mętnookich zanderów u dołu opadów dla wędkarzy drapieżnych w twardym rezerwuarze.', TRUE, 'Zezwolenia amatorskie na wędki pod okręgowymi stawkami łodzi wędkarskich u drapieżnika PZW w opadach.', FALSE, FALSE, 'Kilka piaszczystych wyrw uśpionych w zaroślach to rzut z karpiowych spławików bez sprzętu gąszczu.', FALSE, TRUE, 'Wyborny, piaszczyste zatoczki w cieniu lasów z twardym parkingiem dzikim by uleżeć się u namiotu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80635, 'Jezioro polodowcowe krasowe wyspowe skaliste', 188, 12.8, 38, 'Przerażający opad góry i kaskady głazów narzutowych sielawowych echosond. Skały obok opadów rynny.', 'Rygorystycznie twarde, ostre, żwirowo-kamieniste i pełne zatopionych skał obok rynnowych ustron ech.', 'I klasa. Krystaliczna głębia toni obfitej w prześwity od dołów do 7 metrów rzutu piasku krawędzi dna!', 'Zminimalizowane. Twarde stoki wapienia nie ułatwiają kotwiczenia łodygom przed rzutami bez zielska.', 'Pelagiczny Szczupak sielawy, Mętnooki Kamieni, Okoń', TRUE, 'Silne stada rynnowej dziczy ukryte w kamieniołomach wód. Surowa i dzika ryba twardych podłoży wody.', TRUE, 'PZW Koszalin na wędki rzutu pontonami obok echosond w wodach z turystyką sielawową z wędkami opadu.', FALSE, TRUE, 'Dzikie nawisy na skarpach powodują rwanie zestawów w kamieniach uciekających dołu wody obok rzutni!', TRUE, TRUE, 'Zabudowane asfalty rzutu komercji dające łodzie echosond u slipów u wybrzeży piasku obok góry wód.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80636, 'Jezioro rynnowe z blatami (gigant)', 289, 8.4, 25.4, 'Rozległa sieć łagodnych piaskowych zatok i cypli uciekających gwałtownie z rynny ołowianych okoni dna.', 'Zróżnicowane u wód! Od piasku z twardym litoralu, po rzadkie łupki rynnowe otoczone miękkim w dołku.', 'Bardzo dobra rynna, tnąca wiatr i dająca prześwit u zachodu przy opadach z sielawami na blatach tła.', 'Bogata we wschodnich rewirach lilii dając gęste sploty ukryć lina i karpia rzutu pod piaskiem obok rynny.', 'Leszcz blatów, Gigantyczny Okoń sielawy, Szczupak pelag.', TRUE, 'Przemyślane zarybienia wielką sztuką sielawy dla okoni drapieżnych rynnowych ech łodzi echosond ok.', TRUE, 'Wody G.R./PZW z dopłatami sprzętowymi pontonami na ryby pelagiczne z rejestrami zarybienia u góry.', FALSE, FALSE, 'Piaszczyste deptaki na feedery dające łagodny pas rzutu w stoki sielaw dla zjazdów z gruntówek wód!', TRUE, TRUE, 'Ośrodki turystyk ułatwiają spadek pontonu by z góry rzucać okonie po wędkarskich dojazdach obok echa.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80637, 'Jezioro eutroficzne wszechstronne z dołami', 78, 4.2, 10.5, 'Spokojna łacha pofalowana rynną polodowcową wyłożoną z wiatru od spłaszczenia u liliowych dołów u brzegu.', 'Wypłukane piaskowe boki dają oparcie z koszykami rzutu, u dołu gęstszy miąższ u śluzów liści z lądu ok.', 'Zadowalająca do skutecznych rzutów bez zawiesin psujących widok alg. Niosąca ciche chłody góry rzutu.', 'Zwarte grążele pocięte naturalnymi lukami rzutu dają spławikowi ostoję ryb żerujących w trawach tła ok.', 'Gruba Płoć Rynnowa, Szczupak u dna bagiennych zawiesin', TRUE, 'Wspaniała wylęgarnia płoci dająca karmę dla grubych szczupaków torpedujących latorośl w obwodach ech.', TRUE, 'Składki ogólne PZW Koszalin na wody jezior podmiejskich obfitych w rzuty gruntowych opłat łodzi brzegu.', FALSE, FALSE, 'Ułatwiony! Czyste, wycięte oazy u wylotów z gąszczu lilii dające luksus nęceń pod same łodygi płoci!', TRUE, TRUE, 'Pełno urokliwych i piaszczystych, szerokich ścieżek wyłożonych przy pożarowych by zjechać autem ok.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80638, 'Jezioro krasowe szczelinowe ostre z rynną', 46, 8.2, 15.5, 'Skraje urywają się ołowiem od góry stromej skarpy do rynny w kaskadach krasowych z rzutów łupków opadu.', 'Wapienie i u zboczy lita gęsta glina dająca nieskazitelne uderzenia czucia u jigów w rzuty opadem góry.', 'Wysoka klarowność w głąb krasowego okna dając w słońcu chłodne refleksy dla drapieżnych mroków echa.', 'Niedostępne stoki na głębokości dają znikome ujęcia łodyg i nie psują gum prowadzonych z opadem dna.', 'Sandacz twardej gliny, Garbaty Okoń echa, Szczupak z wód', TRUE, 'Kluczowe łowisko zanderów wspomagane rzadszym obwodem PZW na rybę pelagiczną echa rynnowych dołów łodzi.', TRUE, 'Twardy obwód e-zezwoleń z opłatą z ujęcia wędkarskiego łodzi dla rzutów spiningu rynny głównej nocy.', FALSE, FALSE, 'Dziko opadająca ściana lądu pozwala rzucić pod krawędź obok drzew rzutu batem, ale gruntówka utonie!', TRUE, TRUE, 'Ukryte i mroczne dukty puszcz nie ułatwiają gładkiej wpadki u zjazdu pod strome rynny echa u zrzutu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80639, 'Jezioro polodowcowe - kryptodepresja ogromne', 729, 14.5, 45, 'Ewenement sielawy! Piaszczyste mola wyspowe uciekające szybko na mroczne głębiny krasowych rynien ech.', 'Twardy, zwarty wapień wypłukany rynną sielawowych drapieżców okalających wyspowe piaski dołów mroku.', 'I Klasa Czystości! Niesamowita głębia przenikliwa na 10m by obaczyć rzuty sielaw pod echo drapieżców!', 'Zminimalizowane z uwagi na otwarte i mordercze fale z morza dające łysy kras na opaskach sielawy ech.', 'Sielawa Głębin, Mityczny Pelagiczny Szczupak, Gigant Okoń', TRUE, 'Tylko restrykcje rybnych gospodarzy na pelagiczne uderzenia by woda odżyła dla łodzi echosond PZW ok.', TRUE, 'Bilet G.R. Drawsko doliczony turystykami jezior morskich na echosondy rzutów nocnych u opłat łodzi.', FALSE, TRUE, 'Wspaniałe piaski deptaków i łagodne zatoki piaszczyste rekreacji od rzutu obozu z wywózek łodzi ok!', TRUE, TRUE, 'Komercja w pełni ułożona, asfalty, kostki dla wielkich echosond by slipować ogromne tace turystów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80640, 'Jezioro rynnowo-przepływowe warkoczowe', 135, 4.5, 15, 'Rzeka przepływa wyżłabiając mroczne warkocze starych głęboczków w mule rzutu dając ostre łachy piasku.', 'Piasek wypłukany by rzeka nanosiła żwir pod wlot, z głębszym ciemnym detrytusem rynien dębu u echa ok.', 'Czysta z rzeki z chłodnym bystrym obwodem na głębszym rzutu dając zdrową florę dla sielaw i rzeki tła.', 'Zwarte po lądzie u pasów trzcin na rzece u wylotu i grążel by ostudzić prądy u dębowych barier rzutu.', 'Gruby Leszcz rzeki, Płoć Płynąca, Jaź, Sandacz rynny u ech', TRUE, 'Mieszany typ i ujęcia obwodowe na drapieżce i grube karpie rekreacyjne u rzutu PZW i wód polskiej ok.', TRUE, 'Wody udostępnione opłatą rzeczną/jeziorną PZW Koszalin za wędki obwodów brzegu obok zrzutu do wód.', FALSE, FALSE, 'Dziesiątki przygotowanych wycięć do rzutu gruntówką od rzeki u rynny w ciche gładkie zarośla dziczy ok!', TRUE, TRUE, 'Dość ucywilizowany pas u wjazdu by stanąć autem za ustronnymi pożarowymi zjazdami dębów z rzeki ok.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80641, 'Jezioro przepływowe dystroficzne ciche', 165, 4.2, 14.5, 'Przepływowy kocioł z rzeką, tworzący żwirowe naniesienia u zrzutów dołów bagnistych puszczy po poligonie.', 'Wymyty żwir u rzek uciekających rynną po ciemny osad w dole tła dębowych spadów u mrocznych drapieżców.', 'Świetna rzeczna klarowność od prądów wlotu, z umiarkowaną u dołu po zawiesinach dębów od liści bagien ok.', 'Gąszcze tataraku po obwodach mrocznych dziczy dających rzekom zatrzymać stada lilii przed rzutem bata ok.', 'Boleń Rzeczny u Wlotów, Sandacz rynny, Lin, Kleń rzutowy', TRUE, 'Tylko przelotne rzeczne stada rygorów pzw dające naturze oazę odłowu łowisk drapieżnych w dół wód rzeki.', TRUE, 'PZW Koszalin na rzeki połączone i wód z łodzi obok opłat na rzuty do wód w puszczańskim obwodzie ech.', FALSE, FALSE, 'Dziko utrudnione! Wojskowe wstrzymania i potężne dzikie oazy po lewej utrudniają rzuty wędką u woderów.', TRUE, FALSE, 'Odgrodzenia u wód, wojskowe lasy by zepchnąć auto na brzeg, brak udogodnień cywilizacyjnych rzutni wód.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80647, 'Jezioro polodowcowe rynnowe', 356, 8.5, 29.5, 'Ostry, twardy rów ze gwałtownymi, schodkowymi spadkami w ciemne głębiny tuż przy lądach wód.', 'Zbity piasek, krasowe łupki i twarda, zwirowa glina wyśmienita dla pukania jigami w głębinę dna.', 'Wysoka przezroczystość wynikająca z podziemnych źródeł, ułatwiająca odczyt echa w toni sielaw.', 'Brak zwartej roślinności w mroku na głębinowych opadach rynny u stoków ucieczki wód.', 'Okoń "pasiak", Sandacz gliny, Sielawa, Szczupak pelag.', TRUE, 'Rozsądna kontrola stad głębinowych drapieżców przez władze dających ostoje wędkarskich rekordów.', TRUE, 'Opłata w G.R. Drawsko lub lokalnych kołach. Konieczne obostrzenia do nocnych rzutów z łodzi rynny.', FALSE, FALSE, 'Dość wąskie piaszczyste strefy u wejść rynnowych dołów dające przestrzeń dla feedera po wywózce.', TRUE, TRUE, 'Dojazdy w obwodach PZW u twardych obozowisk z łatwym wodowaniem i ubitymi stanowiskami z dębu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80648, 'Jezioro krasowe-rynnowe GIGANT', 1781, 17.5, 79.7, 'Przepotężne uskoki klifowe, krasowe szczeliny do 80m, górki i potężne wielokilometrowe podwodne góry.', 'W rynnie kreda, otoczaki na "Tatrach", twardy wypłukany żwir po sielawowych zjazdach fal głębin.', 'Krystaliczna głębia klasy I. Wybitny kryształ ułatwiający precyzyjne odczyty na ekranach echosond.', 'Znikoma! Gigantyczna woda niszczy falą rozwój lilii, pas trzcin gęsty u płytszych zatok wysp wód.', 'Sielawa, Gigant. Pelagiczny Szczupak i Okoń, Wielki Leszcz', TRUE, 'Pilnie strzeżony rezerwat wędkarski olbrzymich okoni. Odnawiana rynna chroniona u pelagicznego PZW.', TRUE, 'Obowiązkowe G.R. Drawsko z opłatami w rzutach na głęboką rynnę z turystycznymi doliczkami ponton.', FALSE, FALSE, 'Mnóstwo miejskich piaszczystych plaż u Czaplinka pod ciężki feeder by dosięgnąć uskoków w dołku.', TRUE, TRUE, 'Pełna, szeroka komercja miejska! Profesjonalne slipy betonowe by zjechać wozem pod głębię wód ok.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80649, 'Jezioro rynnowo-eutroficzne', 105, 7.5, 17.5, 'Szybkie gliniaste stoki obok obrzeży miejskich plaż, równomierny, korytowy rów usiany blatem dna.', 'Twarda glina, dużo pisaku i żwirowych obrzeży na sandaczowych wyłamaniach spłyconych koryt słońca.', 'Bardzo klarowna poza szczytowymi burzami lata gdzie piasek miesza się w falach pod bulwarem ok.', 'Lekkie pasy oczeretów chroniące narybek, nie przeszkadzają podczas uderzeń spiningu z obrzeży rzutu.', 'Sandacz blatów, Szczupak rynny, Okoń obok molo', TRUE, 'Wyborne okręgowe systemy wpuszczania sandacza dające stabilne żerowania u opadów w głębi obok ech.', TRUE, 'Dostępne w okręgu lub gminie, dopuszczony rekreacyjny dołów po obwodowych miejskich zrzutniach.', FALSE, FALSE, 'Wspaniałe, koszone promenady miejskie pozwalające na luksus obozów przy koszykach bez gąszczu rzutu.', TRUE, TRUE, 'Wspaniała infrastruktura! Kostka i asfalty prosto do deptaków z autami na plaży miasta obok wód.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80650, 'Jezioro dystroficzne zaciszne', 34, 1.8, 4, 'Równinny i gładki spadek powleczony głęboką wyściółką na ustronnych płyciznach w lasach u dębu ok.', 'Śliski, grząski muł puszczański powlekający się o rozkład dzikiej fauny liści obok powalonych rur.', 'Odcinek ciemno-brunatny; mocno ściągająca światło, zawiesista przy nagrzanej strefie letnich pni ok.', 'Bujne, zwarte pasma lilii wodnych. Rogatek pokrywający szerokie dno dając kryjówkę zielonym linom.', 'Lin "pancerz zielony", Szczupak polny o ciemnej barwie', TRUE, 'Tylko ingerencja naturalnych roczników ryby ziela, w pełni dzikie ostoje lęgowe drapieżników.', TRUE, 'PZW / G.R Drawsko na wody mniejsze bez opłat pontonowych dla wyciętych rewirów w dziczy leśnej ok.', FALSE, TRUE, 'Praktycznie beznadziejne ujęcia obok gąszczów bez pancerza dębu, wymóg pontonów o woderów dżungli.', FALSE, FALSE, 'Dziko wciśnięte leśne drożyny o trudnym przejeździe w czasie pluchy, mało miejsca pod zwody lądu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80652, 'Jezioro rynnowe wydłużone', 78, 6.2, 14.5, 'Falisty wał wyżłobiony polodowcową wodą tnącą ostro ląd na schodki piaskowe blisko 8 metrów u echa.', 'Ostre kamieniste zjazdy i przepłukany w wietrze żwir sprzyjający rzutom rynnowego spiningu u echa.', 'Wybitnie puszczańska, ostra chłodna klarowność na opadach słońca pozwalająca widzieć u góry lądu ok.', 'Twarda puszczańska krawędź gubiąca rdestnice po ostrych tnących falami skosach w krawędzie dołów.', 'Gruby Leszcz dołu, Okoń skarp, Szczupak rynny, Płoć', TRUE, 'Utrzymywane populacje dla łowców rynny. Odwzorowane ostoje krasu pozwalają się rozmnażać ławicom.', TRUE, 'G.R. Drawsko lub obwody okręgowe dające swobodę poławiaczom obok zrzutów po łódki wędkarskie wód.', FALSE, FALSE, 'Spora swoboda, liczne pola pozwalają odstawić spławik z wiatrem do łagodnej zatoki z rzutu o dół ok.', FALSE, TRUE, 'Okolice czaplinka z dobrymi utwardzeniami do lądu na piaszczystych parkingowych obozowiskach ułów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80645, 'Jezioro polodowcowe szczelinowe', 145, 8.4, 21, 'Przerażająco stromy opad krawędzi piaszczystej urywający się krasem w dół chłodnej rynny sielawowej.', 'Dno niesłychanie twarde okraszone obwodem piaszczysto-wapiennym gubiącym zielska u samej głębi echa.', 'Kryształ dający fenomenalną transmisję światła w głąb okonia po spadkach pod krawędzie skał obok rzut.', 'Płycizny piaszczyste bez silnych dywanów gnilnych pod opadającymi uskokowo skarpami lasu dołów ok.', 'Okoń mrocznej wody, Duży Amur, Szczupak Pelagiczny ech.', TRUE, 'Gigantyczny okoniowy rezerwuar objęty kontrolami i uchroniony naturalną rynnową mroczną głębią echa.', TRUE, 'Taryfy G.R. Drawsko. Restrykcyjne zasady stref echosond w wodach chronionych obok zrzutów u łodzi.', FALSE, TRUE, 'Z powodu natychmiastowej głębi, ląd to miejsce karkołomne dla łowców karpia wymuszające dalekie echa.', TRUE, TRUE, 'Twarde pożarowe pasy dla wędkarzy i wycięte miejsca pod biwak dla aut terenowych u zrzutów pychówek.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80653, 'Jezioro krasowe-przepływowe rynnowe czyste', 198, 14.2, 38.5, 'Kamieniste stoki, pionowe krawędzie przepaści i potężne blaty z opadami usypanymi przez zrzut Drawy.', 'Skała, głazy i wypłukany nurtowo sypki piasek rynnowych zapadlisk ostrej mroźnej toni krasu obok.', 'Super-klarowny. "Srebrna" toń z przepływem rzeki tworząca rewelacyjne optyczne parametry I klasy.', 'Rzadkie opaski u głazów. Rwąca fala u ujść nie pozwala na rozwój gnilnych lilii i rogatka echa.', 'Boleń Rzeki ucieczki, Okoń z rynny, Pelagiczny Szczupak sielawy', TRUE, 'Twardy rybostan u rzek i krystalicznych jezior pod ciągłą rezerwatową uwagą echosond pzw sielaw ok.', TRUE, 'G.R. / PZW na rzekach udostępnianych taryfie obwodowych połowów obok głębokich rzutów pontonem ok.', FALSE, TRUE, 'Niesamowicie twarde łagodne zjazdy blisko Starego Drawska pozwalające wyłuskać płoć u plaży o świt.', TRUE, TRUE, 'Luksusowe, tuż obok asfaltu trasy wybitne by zeskoczyć z ciężką łodzią by warkoczami od rzeki iść.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80654, 'Jezioro polodowcowe szczelinowe czyste', 386, 12.8, 35.5, 'Skraje urywają się ołowiem od wysokiej dębowej skarpy wprost z kaskady piasku o 20 metrowych mrokach.', 'Wybitnie skalisto-żwirowe; echa pokazują dno twarde jak beton pozbawione mulistych zagłębień mchów.', 'Przepiękny kryształ, wspaniale chłodny i bystry w głębi pozwalając dostrzec ławice rynnowych okoni.', 'Niedostępne głębokości eliminują płocha roślin w środku rynny co sprzyja okoniarzom w rzutach ech.', 'Sandacz twardej gliny, Sielawa rynny, Szczupak echosond', TRUE, 'Potężne naturalne drapieżniki pelagiczne pilnowane biletami by zachować ostoje rzadkiego piękna ton.', TRUE, 'Twardy obwód e-zezwoleń na echosondy i pontony rzutów spinningu u głębi na opłatach wód okręgowych.', FALSE, TRUE, 'Skarpy uniemożliwiają wędrówki! Trudne dębowe osuwiska nie puszczą rzutu pod korzenie u dna rynny.', TRUE, FALSE, 'Ukryte polne drogi utrudniają dotarcie gładko, wymóg by nie grzęznąć na stromym dojeździe obok lasu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80655, 'Jezioro eutroficzne z blatami rynny', 245, 4.5, 11.2, 'Powolny rozlew na bokach pocięty miękkimi spadkami na umiarkowane głębiny polodowcowych zrzutów rzek.', 'Twardy żwir obok lilii dający fenomenalne wsparcie koszykom by grząskie dołki zachować dla okoni ech.', 'Dobrze wymieszana przez uciagi i wiatry jeziorne, latem w łagodniejszych zatokach słabsza na 1.5m.', 'Szerokie "łąki" podwodne obok wysepek trzcin dające okoniowi gąszcze łowów przed płyciznami słońca.', 'Karp pełnołuski, Lin w liliach, Szczupak trzcinowy, Płoć.', TRUE, 'Bogata pula "Karpia" z wędkarskiej strony rzutów feedera i ochrona sandaczyka na uskokach rynien PZW.', TRUE, 'Zezwolenia w obwodach PZW/G.R. rzucając gruntowo dla doliczek łodziowych od nocy z obozowisk echa.', FALSE, FALSE, 'Fantastycznie skoszone obok trzcin by łagodnie oprzeć krzesło u plaży do wylegiwania nocy przy brzegu.', TRUE, TRUE, 'Obszerne wjazdy piaszczyste obok miasta dające wbić statyw karpiowy przy aucie darmowego parking u ech.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80656, 'Jezioro eutroficzne-dystroficzne leśne', 42, 1.8, 3.5, 'Skrajnie plaskie zapadlisko schodzące ustronnie od pni dębowych do bagiennych, śliskich torfowisk dna.', 'Gruby muł niosący śluzowe wyściółki gnijącej puszczy uniemożliwiający uderzenie rzutowym gruntem.', 'Brunatna barwa torfu z małą przepuszczalnością niosąca oazę lina u okładzin grążela rdestnicy obok.', 'Rzęsa dusi płytkie oazy dając kryjówkę gęstych lasów liliowych rzutom pod szczupaki i złote liny pzw.', 'Lin Mchu zielony, Krasnopióra rzęsy, Szczupak o ciemnej barwie', TRUE, 'Torfowiska bronią się w bagnach naturalnie by złote stada karasi opadały bez wybijania u rzutów PZW.', TRUE, 'Standard okręgu G.R bez silników. Oaza wymaga ciszy u zakazów niszczenia lęgowych łach rzęsy obok.', FALSE, TRUE, 'Koszmar! Brodzenie w błocie twardym pochłania buty by z lądu wyrwać wędkarskie stanowisko u drzew.', FALSE, FALSE, 'Dzika polna przeprawa u wozu pozwala uniknąć bagien w rezerwuarach puszczy obok wycięć dla kół ok.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80657, 'Jezioro polodowcowe rynnowe czyste małe', 78, 6.4, 18, 'Wyśmienicie pofalowane krawędzie uciekające szybko na mroczną pochyłość wapieni głębi drapieżnych wód.', 'Półki ze twardej krasowej skały, piaszczyste placki od litoralu dające rewelacyjne rzuty u drop-shot.', 'Przejrzystość I/II kl nie znikająca w pełni upałów, pozwala wyłowić okonie na fluorocarbon echem.', 'Skąpe, rozrzucone lilie z oparami trzcin zanikające u skarp głębokiej gliny z opadów u słońca ok.', 'Duży Okoń opadowy, Sandacz wapieni, Szczupak głębin ech.', TRUE, 'Zarządzanie u wędkarskiego drapieżnika podbudowujące cyrkulację narybków na uskokach rynnowych opadów.', TRUE, 'Opłaty pełne na spinningowych pontonach u okręgów z obwodami wędkarskimi echosond drapieżnych rzutu.', FALSE, FALSE, 'Dozwolone z łagodnych, twardych plaż umożliwiających lądowanie leszczy rzutów u głębin dla kół aut!', TRUE, TRUE, 'Obfite pożarówki leśne ustronnie przygotowane na plażach piaszczystych bez problemu u wód nocnych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80659, 'Jezioro bagienne mocno zarośnięte ustronne', 25, 1.2, 2.5, 'Całkowita płaska poduszka błotna uśpiona po łagodnym zejściu dzikich polan bagien bez skarp rynny ok.', '100% muł i gęsta torfowa śluzowata roślinność rozkładowa. Ciężary więzną w puszystej glebie kłączów.', 'Często mętnieje po grubszych falach zawiesin torfów obfitych w dno gęstych alg u mroku dębu osad.', 'Pierścienie o szerokości zaporowej pałki wodnej blokujące łowcę spławika by gęstwą rogatków obniżyć.', 'Lin dziki wściekły, Karaś Złoty liliowy, Dziki mały Szczupak', TRUE, 'Torfowiska dbane jedynie samoistnie w kłącza lęgowe u drapieżników jezior z rzutów pzw w zielsk ok.', TRUE, 'PZW / Lasy lokalne. Tylko na ciszy obwodowej wycięć wędkarskich, bez opłat sprzętu echosond u łodzi.', FALSE, TRUE, 'Niemal całkowicie zalane bagnem! Trzęsawisko odbiera szansę zarzucenia z ziemi bez solidnych desek.', FALSE, FALSE, 'Zakaz wlotu do rygoru i ucięte drogi z korzeniami uniemożliwiają dostęp bez butów bagien u zjazdów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80680, 'Eutroficzne podmiejskie', 38, 2.8, 6, 'Misa jeziorna o regularnym kształcie z piaszczystymi wypłyceniami przy plażach.', 'Muliste, lokalnie piaszczyste w strefie litoralu i na kąpieliskach.', 'Średnia, typowa dla jezior żyznych; latem widoczność do 1.5 metra.', 'Średnio obfita: trzcina, pałka wodna, rogatek w głębszych partiach.', 'Leszcz, Płoć, Szczupak, Sandacz, Okoń', TRUE, 'Regularne zarybienia rybami białymi i drapieżnymi przez G.R. Złotów.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Złotów.', FALSE, FALSE, 'Doskonała dzięki licznym miejskim pomostom i promenadzie.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi w samej miejscowości Zakrzewo.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81298, 'Antropogeniczny (Rekultywowany)', 20, 3.2, 8.5, 'Urozmaicona po wydobyciu', 'Piaszczyste i muliste', 'Dobra', 'Bogata (moczarka, trzcina)', 'Szczupak, Okoń, Płoć, Amur', TRUE, 'Systematyczne zarybienia drapieżnikiem', TRUE, 'Standardowe PZW Konin', FALSE, FALSE, 'Dobra', FALSE, TRUE, 'Dobra szutrowa', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80660, 'Jezioro rynnowo-krasowe GIGANT militarny', 980, 14.2, 43.8, 'Epickie "Zatopione Lasy", gruz militarny w wodzie, uskokowe wnęki sielawowe dające rów 40 m echa wód.', 'Piorunująco niebezpieczne dno z korzeniami dębów w toni, ostre skały rynny i gruz oporu u jigowania.', 'Dobra rynnowa bystrość ukrywająca w mrokach potężnego okonia, świetna przeświecalność głębin łupków.', 'Ubogie strefy u gwałtownych skał wysp ułatwiają trollowanie bez zawiesin opadów z rdestnicy pzw w mrok.', 'Gigant Szczupak echa, Mityczny Sandacz pni, Wielki Okoń sielawy', TRUE, 'Złożona naturalna rezerwa uchroniona tonią przed bezduszną wycinką by drapieżce echosond wyrosły w moc.', TRUE, 'G.R. / Wody objęte surowym e-zezwoleniem z potężnym cennikiem sprzętu łowców z Live Scope na łodziach.', FALSE, FALSE, 'Dziko oblegane na łagodniejszych molo plażowych przez obozy rzutowe ciężkiego karpiowania u nocy!', TRUE, TRUE, 'Doskonały slip miejski, asfalty, wózki, wielkie parkingi dla naczep potężnych jednostek pływających.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80661, 'Jezioro polodowcowe rynnowe czyste bunkrów', 145, 6.8, 16.2, 'Piękne piaskowe łachy tnące ląd obok gwałtownych rynnowych wnęk spadających od opaski dębów z okopów.', 'Żwirowo-krasowe twarde schody od uskoku na dole obfitego rynnowego nurtu bez zamulających rzuty wód echa.', 'I Kl widoczności od góry dająca genialny refleks mrocznych ołowianych chłodów na sielawy u głębin.', 'Odsłonięta krawędź krasowa pozbawiona uwięzień spiningowych roślin u dołów słońca dających łowcę luz.', 'Sandacz twardych schodów, Płoć "sielawowa" echa, Okoń w jigu', TRUE, 'Precyzyjnie doliczana rynna okoniowa i sandacz PZW u twardych obozowisk pod wsparciem echosond okręgu.', TRUE, 'Wykup u dzierżawcy ze wstawkami nocnymi echa obok pontonów bez spalin na zjawiskowych krasowych opadach.', FALSE, FALSE, 'Wyborne piaszczyste mola schowane w lasach do rzutu gruntówką sielawowego leszcza u świtu obok cienia.', TRUE, TRUE, 'Rozwinięte polne trasy ułożone dębową kłodą by uciec do twardych wjazdow parkingowych leśnych ukryć.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80662, 'Jezioro eutroficzne wydłużone', 198, 2.5, 6.2, 'Powolna gładka pofalowana poduszka o mniejszych spadkach i uśpionych łagodnych twardych rzadszych łatkach.', 'Śluz od roślin na gładkim piasku i błocie jeziornym z głębi u gęstszym obwodzie opadających lilii obok.', 'Zawiesista od planktonu lata i wiosny by utrudnić wędkowanie echem a dać ochronę białorybom na blatach.', 'Gęste, liliowe obrzeża i duże pierścienie w litoralach dające domy wylęgowi grubej drapieżnej fauny lądu.', 'Wielki Karp Włosowy, Wielka Rzeczna Płoć 30+, Leszcz na method', TRUE, 'Rekordy u zarybień dających komercyjnie silną obfitą rybę wędkarzom na lądowych obozowiskach nocy ech.', TRUE, 'PZW / obwody lokalne. Spokojna woda pozbawiona doliczek pelagicznych łodzi rzutów okręgowych biletów.', FALSE, FALSE, 'Dziesiątki pięknych koszonych trawników dające relaks u wywózki pod karpie obok cichych stanowisk.', FALSE, TRUE, 'Dość ucywilizowane drogi ze zjazdami po ustronnych piaszczystych alejkach przed łagodnym wałem wody.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80664, 'Jezioro torfowo-eutroficzne zapomniane płytkie', 28, 1.2, 3.1, 'Błotna patelnia uciekająca płasko od liliowych wlotów na mętne dno pełne lęgowisk bagiennych ryb PZW ok.', 'Liście gnijące i 100% gruby śluz torfowy gdzie zacięcie method powoduje zatopienie przynęty pod zupą dna.', 'Kolor mocno "kakaowy", zero echa świetlnego obok ujęć z powodu grubego ziela i opadających osadów torfu.', 'Całkowita inwazja zaroślowa i trzcinowa odgrodzona od kół wody potężnym uciskiem dywanów wodnych rzęsy.', 'Wzdręga bagienna lili, Lin ciemny ukryty, Karaś u tataraku rzutu', TRUE, 'Torfowiska ujęte tylko samoistnymi prawami chronią ostoje i tataraki u wód dzikich obok ustronnych łowisk.', TRUE, 'Lokalne rekreacyjne, by chronić osady i uniemożliwiać echosondy u płytkich cichych wód bez napędu łodzi.', FALSE, TRUE, 'Koszmarne przejście z racji na grząskie oazy mchu i zatapiające buty u kładzenia się w wodzie by ująć lina.', FALSE, FALSE, 'Ciężko o dojazd gładki. Auto może zabagnąć w dziczy przed dojściem bez pożarowego żwiru pod błotami ok.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80666, 'Jezioro eutroficzne bardzo płytkie "taca"', 568, 1.2, 2.5, 'Rozlazła, równinna "zupa" o wielkich wiatrowych przestrzeniach obok małych łagodnych wgłębień rzutu łodzi.', 'Rozciągnięte dno o śluzowatych, organicznych pochyłościach gniciowych i mułach obfitych u brzegów dna rzutu.', 'Niesamowicie mętna i rdzawa od wiatrowego falowania śluzu podnoszonego ze dna u uderzeń jeziorowych fal.', 'Rozległe u wschodnich wlotów do połowy wysp. Grążel pływa obok trzcin tworząc raj lęgowy lina pod ławice.', 'Ogromny dziki Szczupak lilii, Płoć Płytka, Karaś', TRUE, 'Wybitny rozród zębatych łowców lilii! Szczupak króluje kontrolując dziesiątki drobnic w gąszczu litoralu.', TRUE, 'Standard na wędki rekreacyjne okręgu powiększane do wjazdu u pontonów z dryfów przed wędkami w gąszczach.', FALSE, TRUE, 'Bardzo skąpe okna w litoralu, rzuty stacjonarne uniemożliwione gigantycznym odjazdem trzcin na kilometry.', FALSE, TRUE, 'Wjazdy do nielicznych wcięć od szos wymagają często terenowego uderzenia pod same bagniste ustronia u wód.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80667, 'Jezioro rynnowo-krasowe zimne rzeczne', 105, 8.5, 23.4, 'Ściany uskokowe! Kaskady krasowych rynien opadających z opasek dębów po twarde żwirowo piaszczyste rzuty dół.', 'Żwir wypłukany od uciągów w chłodnych wapieniach pękających u toni daje echo bystre u jigowania drapieżców.', 'Świetna bystra u sielawowych echosond pozwala drapieżnym wyciągać oko od wód w ołowiany zrzut lodu krasu ok.', 'Znikoma i wyrwana brakiem miejsca by uwiązać obiekty grążelowe w ostrych dębowych schodach słońca echa.', 'Okoń twardy rynny, Szczupak ołowiany sielawy, Płoć sielawowa echa', TRUE, 'Tylko precyzyjna i ostra selekcja na wędkarskiej wodzie dająca piękne sielawowe twarde i zdrowe opady rzutu.', TRUE, 'G.R / PZW okręg na obwody dzierżawiąc drapieżcom pontonowych rzutów od wód jeziora z obostrzeniem ciszy ech.', FALSE, TRUE, 'Piękne ostre ujęcia rzutów gruntem na piaszczystych plażach dają czyste dno do łopat leszczy nad ranną wodą.', TRUE, TRUE, 'Komercja w pełni ułożona, równe zjazdy i szerokie leśne dębowe miejsca na zrzucenie kół echa w obwody ok!', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80668, 'Jezioro krasowe-szczelinowe wąskie głębokie', 42, 11.2, 28.5, 'Strome przepaście tuż od wianków drzew lecą na złamanie karku wędką w uśpione doły mroku chłodnych rynien ech.', 'Potężne zwały wapienia, kłód dębowych zwalonych w piaski twardych ucieczek szczelinowych ryb drapieżców opadów.', 'Cudowny, surowy krystaliczny prześwit od I kl wód dając widoki na kamienie z echosond u góry rzutu drapieżnego.', 'Wycięte do zera rynnowym uskokiem. Nie łapiąca kotwic i haków woda daje swobodę na wiertykal u góry słońca.', 'Mroczny Sandacz w kłodach drzew, Pelagiczny Okoń w toni, Szczupak', TRUE, 'Sielawa chroniona przez strome opady dające drapieżnej faunie twarde sandaczowe schrony opadów u mroku ech.', TRUE, 'Taryfy G.R. i kół lokalnych wód z doliczoną nocną przepustką echa na sielawowych drapieżnikach twardych skał.', FALSE, TRUE, 'Tragedia z brzegu! Zero plaż z powodu gwałtownych ścian wąwozowych puszczy nie puści rzutni pod głaz słońca.', FALSE, TRUE, 'Surowa przeprawa dębowa na stromym zboczu pozwala tylko lżejszym u ustronnym bykom zwodować małe echo w pniu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80682, 'Rynnowe', 190, 5.2, 19.5, 'Wyraźna centralna rynna, strome stoki, piaszczyste blaty w części północnej.', 'Twarde: glina i piasek, muliste w najgłębszych punktach rynny.', 'Dobra do średniej, latem możliwe okresowe zakwity fitoplanktonu.', 'Bogata: gęste pasy trzcin, rdestnica i moczarka na podwodnych spadach.', 'Sandacz, Leszcz, Szczupak, Okoń, Płoć', TRUE, 'Intensywne zarybienia sandaczem i szczupakiem przez PZW Bydgoszcz.', TRUE, 'Standardowe składki PZW Bydgoszcz.', FALSE, FALSE, 'Bardzo dobra, liczne pomosty wzdłuż promenady i wejścia leśne.', TRUE, TRUE, 'Asfalt do Więcborka, dalej drogi szutrowe i polne wokół akwenu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80669, 'Jezioro eutroficzne z falami GIGANT PŁYTKI', 1860, 1.3, 3.2, 'Potężne łachy piaszczyste i bagniste wyspy trzcin usłane gładko od brzegu na tysiącach hektarów rzutu płytkich.', 'Miękki śluz i wymyte morzem fałdy równej piaskowej tacy rozwijające niesamowity rozwój zielenicy lata echa.', 'Mętna rdzawa u dół i od wiatru ciągle mącona z dna tacy dając świetny i gęsty kamuflaż potężnym drapieżcom.', 'Gigantyczne trzcinowe potęgi wysepek, zarośnięte płycizny setki metrów od brzegu ok.', 'Szczupak płycizn potężny (na swimmbaity), Wielki Leszcz, Krąp', TRUE, 'Otwarte lęgi jeziora po burzach oddające obfite ilości dzikiej drobnej zielenicy gigantom szczupaków tła.', TRUE, 'G.R Szczecinek twardy bilet łodziowy i dzierżawy okręgowe na nocne ułowiska u pontonów drapieżnika opadów.', FALSE, FALSE, 'Dziesiątki pięknych uformowanych przez pzw do uderzeń plaż z woderów by karpiować leszcze u tacy ławic echa.', TRUE, TRUE, 'Rewelacyjna miejska asfaltyzacja i solidne miejsca parkingowe by bez lęku wjechać pychówką od dołów słońca.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80670, 'Jezioro rynnowo-pelagiczne z wyspami duże', 734, 10.4, 25.5, 'Szerokie zapadliska przerywane łagodnym dołem po zachodzie schodzące potężnym dębowym stosem z 20m głębin wód.', 'Pół na pół u góry żwir u boku i piękna jednolita twarda warstwa gliny by jiggować okonie po schodach echa.', 'Kryształ I Kl! Wysoka przejrzystość na kilkanaście metrów zachęcająca sielawowe drapieżniki do ułowów cienia.', 'Wyważona. Łagodne płocha dają zacisza łodygom przed nagłym urywkiem sielawowej przepaści po rzutni echa ok.', 'Pelagiczny Szczupak LiveScope echa, Sielawa rynny, Gruby Okoń, Sandacz', TRUE, 'Twardo pilnowane zarybianie sielawą i ukleją rzeczną w celu wykarmienia olbrzymów okoni echosond u góry rzutu.', TRUE, 'Standard wędkarski z potężnym dopiskiem G.R. i taryf pontonowych wędkarskich turystów rekreacji u drapieżnika.', FALSE, FALSE, 'Przepiękne twarde wyspowe i dzikie plaże zachodu dla namiotów by uderzyć ciężkim rzutem obok głębokich łach!', TRUE, TRUE, 'Pełen profesjonalny sprzęt miejski, asfalty od szosy po solidne ustronne równe dojazdy wozów komercji ok.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80672, 'Jezioro polodowcowe rynnowe', 185, 9.4, 26.5, 'Skomplikowana batymetria z licznymi podwodnymi górkami i głębokimi rynnami w osi jeziora.', 'Twarde, głównie gliniasto-żwirowe na górkach, piaszczyste u brzegów, muliste w dołach.', 'Dobra klarowność, woda natleniona, sprzyjająca bytowaniu sielawy i drapieżników.', 'Wąski pas trzcin, roślinność podwodna skupiona głównie na stokach podwodnych górek.', 'Sandacz, Okoń, Szczupak, Leszcz, Sielawa', TRUE, 'Intensywne zarybienia sandaczem i szczupakiem, stabilna populacja ryb białych.', TRUE, 'Zezwolenie G.R. Szczecinek, dopłata za połów z łodzi i echosondę.', FALSE, FALSE, 'Ograniczone przez wysokie skarpy i gęstą roślinność przybrzeżną; wymaga łodzi.', TRUE, TRUE, 'Drogi pożarowe i leśne, piaszczyste, zalecane auta z wyższym zawieszeniem.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80673, 'Jezioro eutroficzne', 32, 3.5, 7.5, 'Regularna misa z łagodnymi spadkami dna, brak gwałtownych uskoków i głazowisk.', 'Przeważnie miękkie i muliste, z lokalnymi piaszczystymi wypłyceniami przy plażach.', 'Średnia przejrzystość, latem podatna na zakwity, woda ciepła i żyzna.', 'Bardzo obfita: szerokie pasy trzcin, lilie wodne i gęste łąki moczarki na dnie.', 'Lin, Karaś pospolity, Szczupak, Płoć', TRUE, 'Systematyczne zarybienia linem i karasiem w celu podtrzymania atrakcyjności łowiska.', TRUE, 'Standardowe opłaty Gospodarstwa Rybackiego w Szczecinku.', FALSE, FALSE, 'Dobra dostępność z przygotowanych stanowisk brzegowych i pomostów wędkarskich.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi, bliskość miejscowości Spore.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80674, 'Jezioro polodowcowe rynnowe', 90, 5.5, 16.5, 'Wyraźna rynna w osi głównej z piaszczystymi blatami i stromymi stokami przy brzegach.', 'Mieszane: twardy piasek na wypłyceniach, miękki muł i osady organiczne w głębinach.', 'Dobra, woda przejrzysta wiosną i jesienią, latem możliwe okresowe zakwity alg.', 'Średnio obfita: pasy trzcin, rdestnica pływająca i sporadyczne kępy grążeli.', 'Szczupak, Okoń, Leszcz, Płoć, Sandacz', TRUE, 'Systematyczne zarybienia drapieżnikami i rybami białymi przez G.R. Szczecinek.', TRUE, 'Standardowe opłaty Gospodarstwa Rybackiego Szczecinek.', FALSE, FALSE, 'Dobra dostępność z brzegów miejscowości Spore i licznych dzikich wejść leśnych.', TRUE, TRUE, 'Dojazd drogami asfaltowymi do wsi, dalej utwardzonymi drogami polnymi i leśnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80676, 'Jezioro polodowcowe rynnowe', 25, 4.8, 12, 'Regularna rynna leśna o dość stromych stokach i wyrównanym dnie w części środkowej.', 'Zróżnicowane: piaszczyste skarpki leśne oraz muliste i torfowe osady w rynnie.', 'Dobra, lekko herbaciany odcień wody wynikający z kwasów humusowych z otaczającego boru.', 'Umiarkowana: pasy trzcin, lilie wodne i liczne zatopione kłody drzew leśnych.', 'Szczupak, Lin, Karaś pospolity, Okoń, Płoć', TRUE, 'Głównie naturalny rozród wspomagany okresowymi zarybieniami przez okręg PZW.', TRUE, 'Standardowe składki PZW Koszalin, zezwolenia okresowe dostępne online.', FALSE, TRUE, 'Utrudnione przez gęsty las i strome skarpy; ograniczone do kilku dzikich stanowisk.', FALSE, TRUE, 'Trudny dojazd piaszczystymi drogami leśnymi, zalecane auta z wyższym zawieszeniem.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80677, 'Polodowcowe rynnowe', 22, 4.5, 12, 'Regularne stoki rynnowe z licznymi zatopionymi drzewami i karczami przy brzegach.', 'Mieszane: piasek na spadkach, miękki muł liściasty w najgłębszych partiach.', 'Wysoka, lekko brunatny odcień od otaczających lasów, dobra przez cały sezon.', 'Umiarkowana: pasy trzcin, rdestnica i grążele w zacisznych zatokach.', 'Okoń, Szczupak, Lin, Płoć', TRUE, 'Naturalny rozród wspierany okresowymi zarybieniami szczupakiem przez PZW.', TRUE, 'Składki PZW Koszalin, zezwolenia okresowe dostępne online.', FALSE, TRUE, 'Utrudnione przez strome skarpy i las; ograniczone do kilku dzikich wejść.', FALSE, TRUE, 'Leśne drogi piaszczyste, zalecane auto z wyższym zawieszeniem.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80678, 'Rynnowe sielawowe', 212, 6.8, 15.5, 'Bardzo urozmaicone: podwodne górki, głębokie rynny i rozległe piaszczyste blaty.', 'Twarde: piasek, żwir i glina, lokalnie cienka warstwa osadów organicznych.', 'Dobra do średniej, latem możliwe okresowe zakwity fitoplanktonu.', 'Bogata: szerokie pasy trzcin, wywłócznik i moczarka na podwodnych blatach.', 'Szczupak, Sandacz, Leszcz, Okoń, Płoć', TRUE, 'Intensywne zarybienia drapieżnikami i rybami białymi przez G.R. Złotów.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Złotów, dostępne w sklepach i online.', FALSE, FALSE, 'Bardzo dobra dzięki licznym pomostom i łagodnym zejściom do wody.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80679, 'Eutroficzne', 45, 3.2, 7.5, 'Niecka o łagodnych spadkach, dość wyrównane dno bez gwałtownych uskoków.', 'Przeważnie miękkie, muliste z grubą warstwą osadów organicznych.', 'Średnia, woda żyzna, ciepła, latem często mętna od planktonu.', 'Bardzo obfita: gęste trzcinowiska, liczne połacie grążeli żółtych.', 'Lin, Karaś złoty, Szczupak, Amur, Płoć', TRUE, 'Systematyczne zarybienia linem i karasiem w celu podtrzymania populacji.', TRUE, 'Zezwolenie PZW Bydgoszcz, dopłata na środki pływające.', FALSE, FALSE, 'Ograniczona przez gęstą roślinność; wymaga woderów lub kładek.', TRUE, TRUE, 'Dojazd polny, utwardzony, dostępny dla aut osobowych przy dobrej pogodzie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80723, 'Rynnowe', 168, 6.2, 14.5, 'Regularna rynna, piaszczyste wypłycenia, powalone drzewa.', 'Mieszane: piasek u brzegów, mulisty szlam w rynnie środkowej.', 'Dobra, woda przejrzysta wiosną, latem lekkie zakwity.', 'Bogata: gęste trzcinowiska, liczne łąki rdestnicy.', 'Szczupak, Lin, Okoń, Płoć, Leszcz', TRUE, 'Regularne zarybienia szczupakiem i białą rybą.', TRUE, 'Zezwolenia PZW Olsztyn dostępne online.', FALSE, TRUE, 'Dobra, liczne pomosty wędkarskie w rejonie zabudowań.', TRUE, TRUE, 'Dojazd asfaltowy do miejscowości Dąbrówno.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80685, 'Nadmorskie przybrzeżne', 280, 1.2, 3.2, 'Skrajnie płytki talerz, brak urozmaicenia dna, strefy przybrzeżne bagniste.', 'Piasek wymieszany z miękkim mułem organicznym.', 'Niska, woda często mętna od piasku podrywanego wiatrem z dna.', 'Bogata: gęste trzcinowiska, rdestnice i roślinność słonolubna.', 'Szczupak, Węgorz, Okoń, Płoć, Krąp', TRUE, 'Głównie naturalny rozród i napływ węgorza kanałami z morza.', TRUE, 'Standardowe zezwolenia PZW Słupsk.', FALSE, FALSE, 'Trudna przez bagniste brzegi; głównie brodzenie lub połów z łodzi.', FALSE, TRUE, 'Dobry dojazd do miejscowości Przybrzeże, parkingi przy przystaniach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80686, 'Nadmorskie lagunowe', 7142, 2.3, 6.3, 'Gigantyczna płaska misa, liczne mielizny, rynny tylko w kanałach wylotowych.', 'Piaszczyste i muliste, z płatami muszli w strefach prądowych.', 'Niska, woda słonawa, silnie mętna podczas sztormów i wiatru.', 'Szeroki pas trzcin, moczarka, rdestnica w osłoniętych zatokach.', 'Okoń, Szczupak, Sandacz, Węgorz, Leszcz', TRUE, 'Ochrona gatunkowa SPN, znikoma ingerencja sztuczna (zarybienia węgorzem).', TRUE, 'Specjalne limity i opłaty Słowińskiego Parku Narodowego.', FALSE, TRUE, 'Ograniczona do ściśle wyznaczonych punktów Parku.', TRUE, TRUE, 'Dojazd asfaltowy do Łeby i Kluk, dalej ograniczenia Parku.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80688, 'Eutroficzne przybrzeżne', 156, 1.4, 3, 'Płytka misa o dnie równinnym, silnie zarastająca od brzegów.', 'Bardzo miękkie, mulisto-torfowe, głęboka warstwa osadów leśnych.', 'Średnia do niskiej, woda o lekko brunatnym zabarwieniu.', 'Ekstremalnie bogata: jezioro niemal w całości porośnięte roślinnością.', 'Wzdręga, Szczupak, Lin, Płoć', TRUE, 'Brak masowych zarybień, całkowicie naturalny rybostan.', TRUE, 'Licencja Słowińskiego Parku Narodowego (SPN).', FALSE, TRUE, 'Bardzo trudna przez bagno; ograniczone do kładek dydaktycznych.', TRUE, FALSE, 'Zakaz używania łodzi dla osób prywatnych na terenie SPN.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80689, 'Dystroficzne przybrzeżne', 6, 0.7, 1.5, 'Płaski talerz otoczony bagnami, dno bez urozmaiceń.', 'Głęboki, płynny muł organiczny i torf.', 'Niska, woda o ciemnym (herbacianym) odcieniu.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce.', 'Wzdręga, Szczupak, Karaś', TRUE, 'Brak zarybień, całkowicie naturalny rybostan.', TRUE, 'Licencja SPN, bardzo rygorystyczne limity.', FALSE, TRUE, 'Ograniczona do wyznaczonych punktów na brzegu.', FALSE, FALSE, 'Dojście piesze szlakami SPN (kilka km od parkingu).', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80690, 'Lagunowe przymorskie', 2469, 1.3, 2.6, 'Rozległa, płytka niecka o niemal płaskim ukształtowaniu.', 'Piaszczysto-muliste, w osi rzeki Łupawy twardsze.', 'Niska do średniej; woda słonawa i mętna od wiatru.', 'Bogata: gęste trzcinowiska, wywłócznik, rdestnica.', 'Szczupak, Okoń, Sandacz, Leszcz, Węgorz', TRUE, 'Zarybienia węgorzem i ochrona naturalnych tarlisk.', TRUE, 'Specjalna licencja Słowińskiego Parku Narodowego.', FALSE, TRUE, 'Średnia, dostępne pomosty w Gardnie i Rowach.', TRUE, TRUE, 'Dobry dojazd asfaltowy do miejscowości Gardna Wielka.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80691, 'Przymorskie / przybrzeżne', 1059, 2.3, 6.1, 'Płaska misa z lekkim zagłębieniem w części środkowej.', 'Muliste, lokalnie piaszczyste w strefie mierzei.', 'Średnia, okresowo mętna (woda żyzna i słonawa).', 'Umiarkowana: pasy trzcin, rogatek, moczarka.', 'Szczupak, Sandacz, Węgorz, Leszcz, Okoń', TRUE, 'Systematyczne zarybianie gatunkami drapieżnymi.', TRUE, 'Standardowe zezwolenia PZW Słupsk.', FALSE, FALSE, 'Utrudniona przez trzciny; głównie pomosty i łodzie.', TRUE, TRUE, 'Dobry dojazd do miejscowości Jezierzany i Wicko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80692, 'Lagunowe przybrzeżne', 789, 1.9, 4, 'Równinny blat piaszczysty z osadami organicznymi.', 'Głównie piaszczyste z warstwą mułu i detrytusu.', 'Niska do średniej; woda słonawa, silnie wietrzna.', 'Uboga w pasie mierzei, gęstsze trzciny na południu.', 'Sandacz, Okoń, Szczupak, Leszcz, Płoć', TRUE, 'Naturalny rozród i zarybienia drapieżnikami PZW.', TRUE, 'Zezwolenia PZW Słupsk.', FALSE, FALSE, 'Ograniczona do kilku miejsc od strony wsi Kopań.', FALSE, TRUE, 'Dojazd drogami utwardzonymi, miejsca przy brzegu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80694, 'Lagunowe przybrzeżne', 1747, 1.8, 2.8, 'Monotonna, płytka misa o dnie piaszczysto-mulistym.', 'Piasek i muł, twarde dno w pasie Kanału Szczuczego.', 'Niska do średniej; woda słonawa, dobrze natleniona.', 'Bogata w zatokach: trzcina, rdestnica, wywłócznik.', 'Sandacz, Okoń, Leszcz, Certa, Szczupak', TRUE, 'Intensywne zarybienia sandaczem i węgorzem.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Mielno.', FALSE, FALSE, 'Dobra od strony Dąbek i Bukowa Morskiego.', TRUE, TRUE, 'Asfalt i drogi utwardzone, parkingi w Dąbkach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80695, 'Lagunowe przybrzeżne', 2240, 1.4, 3.9, 'Skrajnie płaska niecka, dno bardzo zamulone.', 'Głównie bardzo miękki muł i osady organiczne.', 'Niska; woda bardzo mętna, silnie eutroficzna.', 'Bardzo bogata: gigantyczne pasy trzcinowisk.', 'Leszcz, Sum, Sandacz, Szczupak, Krąp', TRUE, 'Zarybienia sumem, szczupakiem i karpiem.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Mielno.', FALSE, FALSE, 'Średnia, dostępne stanowiska w Unieściu i Mielnie.', TRUE, TRUE, 'Pełny dojazd asfaltowy, liczne przystanie i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80696, 'Lagunowe przymorskie', 577, 1.5, 2.8, 'Płytki talerz piaszczysto-mulisty bez wyraźnych rynien.', 'Piasek przy mierzei, muł w częściach południowych.', 'Średnia do niskiej; woda żyzna i słonawa.', 'Bujna: trzcina, pałka, liczne łąki podwodne.', 'Szczupak, Sandacz, Okoń, Leszcz, Węgorz', TRUE, 'Regularne zarybienia drapieżnikami przez zarządcę.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Mielno.', FALSE, FALSE, 'Dobra od strony Dźwirzyna i ośrodków w Rogowie.', TRUE, TRUE, 'Dobry dojazd asfaltowy do Dźwirzyna i Rogowa.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80697, 'Nadmorskie rezerwatowe', 475, 0.9, 1.7, 'Bardzo płytka misa, silnie zapiaszczona od morza.', 'Piasek wymieszany z mułem i detrytusem liściastym.', 'Niska, woda mętna i słonawa (wpływy morskie).', 'Ekstremalna: szerokie trzcinowiska, moczarka.', 'Szczupak, Lin, Karaś srebrzysty, Węgorz, Flądra', TRUE, 'Brak zarybień (rezerwat), naturalna reprodukcja.', TRUE, 'Specjalna licencja PZW + zgoda rezerwatu.', FALSE, TRUE, 'Ograniczona do wyznaczonych pomostów Parku.', TRUE, FALSE, 'Zakaz pływania dla osób prywatnych (rezerwat).', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80698, 'Nadmorskie lagunowe', 240, 1.5, 3.2, 'Płaski blat piaszczysto-mulisty, liczne naniesienia po powodziach rzecznych.', 'Piasek z warstwą żyznego mułu, miejscami twardsze żwirowe łachy.', 'Niska, woda mętna, słonawa, silnie podatna na mieszanie wiatrem.', 'Bogata: szerokie pasy trzcin, rogatek i rdestnice w zacisznych zatokach.', 'Szczupak, Sandacz, Okoń, Leszcz, Certa', TRUE, 'Naturalna migracja ryb z rzeki Dziwny, wspierana zarybieniami węgorzem.', TRUE, 'Zezwolenie OIRM na morskie wody wewnętrzne.', FALSE, FALSE, 'Średnia, dostępne stanowiska od strony wałów i lądowych wycięć.', FALSE, TRUE, 'Dojazd asfaltowy do miejscowości Piaski i dalej drogi utwardzone.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80700, 'Eutroficzne przybrzeżne', 180, 1.2, 2.5, 'Skrajnie płytki talerz, brak rynien, dno niemal całkowicie płaskie.', 'Bardzo miękkie, głęboki muł i osady organiczne z trzcinowisk.', 'Niska, woda często mętna i kwitnąca w okresie letnim.', 'Ekstremalna: jezioro niemal w całości porośnięte roślinnością miękką.', 'Lin, Karaś srebrzysty, Szczupak, Wzdręga', TRUE, 'Głównie naturalny rozród, okresowe zarybienia karasiem i linem.', TRUE, 'Zezwolenie PZW Szczecin lub taryfa morska (zależnie od strefy).', FALSE, FALSE, 'Utrudniona przez bagniste brzegi; głównie wyznaczone kładki.', TRUE, TRUE, 'Dojazd polny, utwardzony, miejsca postojowe przy przystaniach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80701, 'Rynnowe sielawowe', 130, 7.5, 18.2, 'Wyraźna centralna rynna, strome piaszczyste spady, podwodne górki.', 'Twarde: piasek i żwir, marginalna ilość mułu w najgłębszych punktach.', 'Wysoka (I klasa), krystaliczna toń widoczna do 4-5 metrów głębokości.', 'Umiarkowana: wąski pas trzcin, głębokie łąki ramienicowe.', 'Okoń, Szczupak, Płoć, Leszcz, Sielawa', TRUE, 'Systematyczne zarybienia sielawą i gatunkami drapieżnymi.', TRUE, 'Standardowe zezwolenia PZW Chojnice.', FALSE, TRUE, 'Utrudniona przez strome skarpy i las; ograniczone do kilku stanowisk.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi; parkingi w borze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80702, 'Rynnowe przepływowe', 1362, 10.5, 30.5, 'Potężna rynna z głębokimi rowami, wyspami i rozległymi blatami podwodnymi.', 'Zróżnicowane: piasek, glina, lokalnie głazy narzutowe i żwir.', 'Dobra do średniej; w rynnie kryształ, w zatokach okresowe zakwity.', 'Bogata: szerokie trzcinowiska, wywłócznik i moczarka na blatach.', 'Szczupak, Sandacz, Leszcz, Okoń, Płoć', TRUE, 'Intensywna gospodarka zarybieniowa drapieżnikiem i białorybem.', TRUE, 'Zezwolenia G.R. Charzykowy / PZW Chojnice.', FALSE, FALSE, 'Doskonała dzięki licznym pomostom, plażom i promenadzie.', TRUE, TRUE, 'Pełny dojazd asfaltowy, liczne przystanie, porty i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80703, 'Eutroficzne leśne', 45, 2.5, 5.5, 'Regularna niecka o łagodnych spadkach, brak gwałtownych uskoków.', 'Miękkie, dno wyścielone osadem liściastym i mułem organicznym.', 'Średnia do niskiej, woda o lekko herbacianym odcieniu.', 'Bardzo obfita: pasy trzcin, lilie wodne, rozległe kępy rdestnicy.', 'Lin, Karaś, Szczupak, Płoć, Wzdręga', TRUE, 'Głównie naturalna reprodukcja, wspomagana narybkiem szczupaka.', TRUE, 'Zezwolenia PZW Chojnice.', FALSE, TRUE, 'Średnia, ograniczone do dzikich wejść w pasie leśnym.', FALSE, TRUE, 'Dojazd drogami leśnymi, piaszczystymi; zalecane auta wyższe.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80704, 'Rynnowe przepływowe', 215, 6.8, 20, 'Wyraźne stare koryto Brdy, twarde rynny prądowe, piaszczyste spady.', 'Twarde: piaszczysto-żwirowe u wlotów, muliste w zaciszach rynny.', 'Średnia, zależna od nurtu rzeki i opadów w górnym biegu.', 'Umiarkowana: trzciny na brzegach, roślinność prądolubna w nurcie.', 'Sandacz, Leszcz, Szczupak, Boleń, Okoń', TRUE, 'Systematyczne zarybienia sandaczem i gatunkami reofilnymi.', TRUE, 'Zezwolenia G.R. Charzykowy / PZW.', FALSE, FALSE, 'Dobra od strony pól i wyznaczonych obozowisk leśnych.', TRUE, TRUE, 'Dojazd drogami utwardzonymi i szutrowymi wokół akwenu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80658, 'Rynnowe leśne', 55, 5.2, 14.5, 'Regularna rynna o stromych zboczach, liczne podwodne przeszkody.', 'Głównie twarde: piasek i drobny żwir, cienka warstwa osadów w osi.', 'Wysoka, woda przejrzysta i dobrze natleniona przez cały rok.', 'Skąpa: wąski pierścień trzcin, mało roślinności podwodnej.', 'Okoń, Szczupak, Płoć, Krąp, Leszcz', TRUE, 'Regularne zarybienia szczupakiem przez lokalne koło PZW.', TRUE, 'Standardowe składki PZW Chojnice.', FALSE, TRUE, 'Średnia, dostępne stanowiska brzegowe i małe kładki.', TRUE, TRUE, 'Dojazd drogami polnymi i leśnymi; utwardzone wjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80595, 'Rynnowe przepływowe', 105, 4.3, 10.2, 'Pofalowane dno z naniesionym piaskiem rzecznym i centralną rynną.', 'Zmienne: piasek u ujść Brdy, miękki muł w spokojnych partiach.', 'Średnia; woda natleniona, lekko zabarwiona kwasami humusowymi.', 'Bogata: liczne zatoczki z grążelami i szerokie pasy trzcin.', 'Leszcz, Jaź, Szczupak, Boleń, Płoć', TRUE, 'Naturalny rozród ryb prądolubnych, zarybienia białorybem.', TRUE, 'Zezwolenia G.R. Charzykowy / PZW Chojnice.', FALSE, FALSE, 'Bardzo dobra, liczne plaże i piaszczyste dojścia przy szlaku kajakowym.', TRUE, TRUE, 'Asfalt i utwardzone szutry w Swornegaciach; łatwy dostęp.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80706, 'Rynnowe leśne', 68, 4.8, 12.5, 'Wyraźna, wąska rynna o twardym podłożu i stromych piaszczystych skarpach.', 'Twarde: jasny piasek krasowy i drobny żwir polodowcowy.', 'Wysoka, krystaliczna toń o sielankowym, niebieskawym odcieniu.', 'Znikoma: wąski pas trzciny pospolitej, rzadka moczarka na dnie.', 'Okoń, Szczupak, Płoć, Leszcz, Sielawa', TRUE, 'Naturalny ekosystem wspierany zarybieniami sielawą i okoniem.', TRUE, 'Pozwolenie PZW Chojnice.', FALSE, TRUE, 'Trudna przez strome skarpy; wędkowanie z nielicznych wycięć.', FALSE, TRUE, 'Dojazd leśnymi duktami; piaszczyste pożarówki puszczańskie.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80707, 'Polodowcowe rynnowe', 145, 6.5, 15.2, 'Wyraźna centralna rynna, strome stoki, piaszczyste wypłycenia w części północnej.', 'Twarde: piasek i drobny żwir, lokalnie cienka warstwa osadów organicznych.', 'Wysoka (I klasa), krystaliczna toń, widoczność do kilku metrów głębokości.', 'Skąpa: głównie trzcina i podwodne łąki ramienicowe na spadkach dna.', 'Sielawa, Szczupak, Okoń, Leszcz, Płoć', TRUE, 'Systematyczne zarybienia sielawą i gatunkami drapieżnymi przez PZW.', TRUE, 'Standardowe zezwolenia PZW Chojnice.', FALSE, TRUE, 'Utrudnione przez las i strome brzegi; wyznaczone pojedyncze punkty.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony dla niskich aut.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80708, 'Eutroficzne leśne', 35, 2.2, 5.5, 'Regularna misa o łagodnych spadkach, dno wyrównane bez gwałtownych uskoków.', 'Miękkie: muł organiczny i detrytus roślinny, piaszczyste pasy przy brzegu.', 'Średnia do niskiej; latem okresowe zakwity alg i fitoplanktonu.', 'Bardzo obfita: gęste trzcinowiska, szerokie połacie grążeli żółtych.', 'Lin, Karaś pospolity, Szczupak, Wzdręga, Płoć', TRUE, 'Naturalny rozród wspierany okresowymi zarybieniami linem i szczupakiem.', TRUE, 'Składki PZW Chojnice.', FALSE, TRUE, 'Bagniste brzegi; dostęp ograniczony do kilku wydeptanych wejść.', FALSE, TRUE, 'Piaszczyste dukty leśne; zalecane auta z wyższym zawieszeniem.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80709, 'Oligotroficzne (lobeliowe)', 22, 5.8, 12, 'Misa o stromych, piaszczystych stokach i wyrównanym podłożu w centrum.', 'Bardzo twarde: czysty piasek, brak osadów organicznych i mułu.', 'Ekstremalnie wysoka; woda krystalicznie czysta przez cały sezon.', 'Unikatowa: lobelia jeziorna, poryblin; brak trzcin, roślinność podwodna.', 'Okoń, Szczupak, Płoć', TRUE, 'Brak zarybień sztucznych; ochrona naturalnego, rzadkiego ekosystemu.', TRUE, 'Wymagana specjalna zgoda rezerwatu / PZW Chojnice.', TRUE, TRUE, 'Bardzo trudna przez rygory rezerwatu; ograniczone do punktów dydaktycznych.', FALSE, FALSE, 'Zakaz używania łodzi prywatnych na terenie rezerwatu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80710, 'Dystroficzne (humusowe)', 18, 1.5, 3.5, 'Płaska niecka bez wyraźnych rynien, dno silnie zamulone i torfowe.', 'Bardzo miękkie: płynny muł organiczny i głęboki osad torfowy.', 'Niska; woda o charakterystycznym ciemnobrunatnym (herbacianym) kolorze.', 'Średnia: pasy trzcin, mchy torfowce na obrzeżach, roślinność grążelowa.', 'Szczupak, Okoń, Karaś, Lin', TRUE, 'Brak zarybień masowych; stabilna populacja dzikich drapieżników.', TRUE, 'Zezwolenia PZW Chojnice.', FALSE, TRUE, 'Utrudniona przez bagniste mszary; wymagane wysokie obuwie.', FALSE, TRUE, 'Trudny dojazd wąskimi ścieżkami leśnymi; brak oficjalnych parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81739, 'Eutroficzne (podgrzewane)', 380, 1.8, 4.5, 'Rozległe muliste blaty', 'Miękkie, żyzne', 'Niska (zakwity, zawiesina)', 'Bardzo bogata (moczarka)', 'Amur, Tołpyga, Sandacz, Leszcz', TRUE, 'Intensywne pod kątem ryb roślinożernych', TRUE, 'Licencja G.R. Gosławice', FALSE, FALSE, 'Dobra (z grobli)', TRUE, TRUE, 'Asfaltowa', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80601, 'Rynnowe leśne', 48, 4.5, 11.5, 'Wyraźna centralna rynna, strome piaszczyste skarpy, brak górek podwodnych.', 'Twarde: jasny piasek i drobny żwir, cienka warstwa mułu w dołach.', 'Dobra; woda przejrzysta, natleniona przez źródła poddenne.', 'Umiarkowana: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz, Wzdręga', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez lokalne koło.', TRUE, 'Zezwolenia PZW Chojnice.', FALSE, TRUE, 'Dobra; liczne pomosty wędkarskie i kładki wokół jeziora.', TRUE, TRUE, 'Utwardzone drogi leśne; dostępne miejsca postojowe w borze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80619, 'Eutroficzne (małe)', 12, 1.8, 4, 'Mały talerz o równomiernym dnie, powolny przyrost głębokości od brzegu.', 'Miękkie i muliste; głęboka warstwa osadów liściastych z otaczającego lasu.', 'Średnia; latem mętna z powodu nagrzewania wody i wegetacji.', 'Bardzo obfita: jezioro silnie zarastające trzciną i liliami wodnymi.', 'Lin, Karaś, Szczupak, Płoć, Wzdręga', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu linem narybkowym.', TRUE, 'Standardowe zezwolenia PZW.', FALSE, TRUE, 'Ograniczona przez roślinność; kilka stanowisk przygotowanych ręcznie.', FALSE, TRUE, 'Leśne dukty; parkingi oddalone o kilkaset metrów od brzegu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80705, 'Polodowcowe rynnowe (zarośnięte)', 28, 3.5, 8.5, 'Długa, wąska rynna leśna o zróżnicowanej głębokości i licznych przeszkodach.', 'Mieszane: piasek u brzegów, mulisty szlam w najgłębszych punktach.', 'Dobra do średniej; woda o leśnym charakterze, jesienią ciemniejsza.', 'Bujna: gęste trzcinowiska, liczne powalone kłody dębów i sosen.', 'Szczupak, Płoć, Okoń, Wzdręga, Lin', TRUE, 'Ochrona naturalna; zarybienia szczupakiem i białą rybą.', TRUE, 'Zezwolenia PZW Chojnice.', FALSE, TRUE, 'Trudna przez gęsty las; ograniczone dojście do krawędzi litoralu.', FALSE, TRUE, 'Wąskie drogi pożarowe; przejazd po opadach tylko dla aut terenowych.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80711, 'Rynnowe sielawowe (głębokie)', 56, 8.2, 18.5, 'Głęboki kocioł rynnowy, strome piaszczyste klify podwodne.', 'Bardzo twarde: piasek i skały wapienne, brak osadów organicznych.', 'Wysoka (I klasa); wybitnie czysta i przezroczysta toń sielawowa.', 'Znikoma: wąski pas trzcin, roślinność podwodna kończy się gwałtownie.', 'Sielawa, Szczupak pelagiczny, Okoń, Płoć, Leszcz', TRUE, 'Intensywne zarybienia sielawą i drapieżnikiem; ochrona tarlisk.', TRUE, 'Licencja PZW Chojnice; obowiązuje strefa ciszy.', FALSE, TRUE, 'Trudna przez wysokie skarpy; wędkowanie z nielicznych wycięć.', FALSE, TRUE, 'Dojazd leśnymi drogami szutrowymi; piaszczyste podjazdy.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80713, 'Rynnowe sielawowe', 362, 11.5, 40.2, 'Potężna centralna rynna, strome stoki, liczne podwodne górki i blaty.', 'Twarde: piaszczysto-żwirowe i gliniaste, lokalnie warstwa mułu w dołach.', 'Wysoka, krystaliczna toń sprzyjająca bytowaniu sielawy i drapieżników.', 'Umiarkowana: wąski pas trzcin, roślinność podwodna tylko na spadkach.', 'Sielawa, Szczupak, Okoń, Leszcz, Płoć', TRUE, 'Intensywne zarybienia sielawą i drapieżnikami przez PZW Olsztyn.', TRUE, 'Standardowe składki PZW Olsztyn; obowiązuje strefa ciszy.', FALSE, TRUE, 'Utrudnione przez wysokie skarpy; ograniczone do kilku punktów.', FALSE, TRUE, 'Drogi szutrowe i leśne, piaszczyste, zalecane auta wyższe.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80714, 'Rynnowe eutroficzne', 52, 4.2, 12.5, 'Regularna rynna z piaszczystymi wypłyceniami i mulistym korytem centralnym.', 'Mieszane: piasek u brzegów, miękki muł organiczny w głębi.', 'Średnia, latem możliwe okresowe zakwity alg w cieplejszej wodzie.', 'Bogata: szerokie trzcinowiska, liczne połacie grążeli żółtych.', 'Lin, Karaś, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny rozród wspierany okresowymi zarybieniami linem i szczupakiem.', TRUE, 'Zezwolenia PZW Olsztyn, dostępne w sklepach i online.', FALSE, FALSE, 'Średnia, dostępne wydeptane stanowiska w pasie trzcin.', TRUE, TRUE, 'Dojazd drogami polnymi i utwardzonymi, bliskość Tymawy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80715, 'Dystroficzne leśne', 15, 1.8, 4, 'Mała, płytka misa bez wyraźnych rynien, dno niemal płaskie.', 'Bardzo miękkie: płynny muł organiczny i osad liściasty.', 'Niska, woda o charakterystycznym herbacianym kolorze.', 'Ekstremalna: jezioro silnie zarastające, bagniste brzegi, trzciny.', 'Wzdręga, Lin, Szczupak, Karaś', TRUE, 'Brak zarybień masowych, stabilna populacja dzikich ryb leśnych.', TRUE, 'Składki PZW Olsztyn.', FALSE, TRUE, 'Bardzo trudna przez bagno; wymagane wodery lub kładki.', FALSE, TRUE, 'Trudny dojazd wąskimi ścieżkami leśnymi; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80716, 'Rynnowe', 104, 7.2, 21.5, 'Wyraźna centralna rynna, strome piaszczyste spady, twarde podłoże.', 'Twarde: czysty piasek i drobny żwir, cienka warstwa osadów w osi.', 'Wysoka, woda przejrzysta i dobrze natleniona przez cały sezon.', 'Skąpa: wąski pierścień trzcin, mało roślinności podwodnej.', 'Okoń, Sandacz, Szczupak, Płoć, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikami i białą rybą przez PZW.', TRUE, 'Zezwolenia PZW Olsztyn, dopłata na połów z łodzi.', FALSE, TRUE, 'Średnia, ograniczone do dzikich wejść w pasie leśnym.', TRUE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi, miejsca w borze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80717, 'Eutroficzne', 26, 3.5, 8, 'Misa o łagodnych spadkach, piaszczyste wypłycenia w części północnej.', 'Muliste, lokalnie piaszczyste w strefie litoralu i na kąpieliskach.', 'Średnia, typowa dla jezior żyznych; latem widoczność do 1.5 metra.', 'Bardzo obfita: gęste trzcinowiska, liczne połacie lilii wodnych.', 'Karp, Leszcz, Lin, Szczupak, Płoć', TRUE, 'Regularne zarybienia karpiem i rybami białymi przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom brzegowym.', TRUE, TRUE, 'Dobry dojazd drogami polnymi i asfaltem do wsi Gaj.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80719, 'Polodowcowe rynnowe', 48, 5.8, 15.2, 'Wyraźna rynna z twardym dnem i stromymi piaszczystymi skarpami.', 'Twarde: jasny piasek i drobny żwir, muliste w najgłębszych punktach.', 'Dobra, woda przejrzysta wiosną i jesienią, natleniona.', 'Umiarkowana: pasy trzcin i rdestnica na podwodnych spadach.', 'Sandacz, Okoń, Płoć, Leszcz, Szczupak', TRUE, 'Zarybienia sandaczem i szczupakiem, stabilna populacja ryb białych.', TRUE, 'Zezwolenia PZW Olsztyn, dostępne online.', FALSE, FALSE, 'Dobra dzięki miejskim pomostom i łagodnym zejściom.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy do wsi Gąsiorowo.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80720, 'Lagunowe rezerwatowe', 475, 0.9, 1.3, 'Płaski talerz, brak rynien, dno niemal całkowicie wyrównane.', 'Bardzo miękkie, muł organiczny i piasek morski z cofki.', 'Niska, woda mętna i słonawa (zasolona z Bałtyku).', 'Ekstremalna: szerokie pasy trzcin, gęste łąki moczarki.', 'Karaś srebrzysty, Lin, Szczupak, Płoć, Flądra', TRUE, 'Brak zarybień (rezerwat), naturalna migracja gatunków.', TRUE, 'Specjalne zezwolenie PZW + zgoda rezerwatu (strefy).', FALSE, TRUE, 'Tylko z wyznaczonych pomostów ornitologicznych.', TRUE, FALSE, 'Dojazd asfaltowy do Niechorza, dojście pieszo.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80721, 'Dystroficzne przybrzeżne', 150, 1, 1.8, 'Płytka niecka w fazie zarastania, brak urozmaiceń dna.', 'Bagniste, głęboki torf i płynny muł organiczny.', 'Niska, woda o ciemnym, herbacianym kolorze humusowym.', 'Bardzo bogata: grążele, trzciny, mszary bagniste.', 'Szczupak, Wzdręga, Lin, Karaś pospolity', TRUE, 'Całkowicie naturalny rybostan, brak ingerencji człowieka.', TRUE, 'Standardowe zezwolenia PZW Szczecin.', FALSE, TRUE, 'Ekstremalnie trudna (trzęsawiska), zalecany ponton.', FALSE, TRUE, 'Drogi polne, utrudniony dojazd po deszczu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80722, 'Rynnowe sielawowe', 612, 12.5, 32, 'Głęboka centralna rynna, strome stoki, liczne górki podwodne.', 'Twarde: piasek, żwir, glina w najgłębszych partiach rynny.', 'Wysoka, krystaliczna toń sprzyjająca sielawie i sandaczowi.', 'Umiarkowana: wąski pas trzcin, roślinność na stokach.', 'Sandacz, Leszcz, Szczupak, Okoń, Płoć, Sieja', TRUE, 'Intensywne zarybienia sandaczem i sielawą przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn, strefa ciszy.', FALSE, TRUE, 'Średnia przez wysokie brzegi; liczne kładki i pomosty.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy do Dąbrówna.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80725, 'Rynnowe sielawowe (głębokie)', 105, 14.8, 31, 'Głęboki rów o bardzo stromych stokach, dno twarde.', 'Bardzo twarde: piasek krasowy, kamienie, kreda.', 'Ekstremalnie wysoka (I klasa), widoczność do kilku metrów.', 'Znikoma: roślinność podwodna kończy się gwałtownie.', 'Sielawa, Szczupak pelagiczny, Okoń sielawowy, Płoć', TRUE, 'Systematyczne zarybienia sielawą i drapieżnikiem.', TRUE, 'Licencja Gospodarstwa Rybackiego / PZW; strefa ciszy.', FALSE, FALSE, 'Trudna przez strome skarpy; głównie z łodzi.', TRUE, TRUE, 'Dobry dojazd do ośrodków wypoczynkowych, parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80663, 'Rynnowe eutroficzne', 38, 3.5, 8.5, 'Łagodne spadki, dno wyrównane z centralnym głęboczkiem.', 'Przeważnie muliste, lokalnie piaszczyste przy brzegach.', 'Średnia, typowa dla jezior żyznych w otoczeniu pól.', 'Bujna: pasy trzcin, liczne lilie wodne i moczarka.', 'Lin, Krąp, Leszcz, Szczupak, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Zezwolenia PZW Olsztyn.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom brzegowym.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi, łatwy dostęp.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80726, 'Eutroficzne leśne', 12, 1.8, 3.5, 'Mała misa o regularnych spadkach, dno bez wyraźnych rynien i uskoków.', 'Bardzo miękkie, muł liściasty i osady torfowe, piaszczyste pasy przy brzegu.', 'Średnia do niskiej; woda o charakterystycznym herbacianym kolorze humusowym.', 'Bardzo obfita: gęste trzcinowiska, szerokie połacie grążeli żółtych.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowymi zarybieniami linem przez PZW.', TRUE, 'Standardowe składki PZW Koszalin.', FALSE, TRUE, 'Ograniczona do kilku stanowisk brzegowych w pasie leśnym.', FALSE, TRUE, 'Drogi leśne, piaszczyste, utrudniony dojazd po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80727, 'Nadmorskie lagunowe', 2240, 1.4, 3.9, 'Gigantyczna, płaska niecka bez wyraźnych rynien i górek podwodnych.', 'Skrajnie miękkie, bardzo głęboka warstwa żyznego mułu organicznego.', 'Niska; woda bardzo mętna, silnie mącona przez falowanie wiatrowe.', 'Bardzo bogata: gigantyczne pasy trzcinowisk, moczarka, rdestnica.', 'Leszcz, Sum, Sandacz, Szczupak, Krąp', TRUE, 'Intensywne zarybienia sumem, szczupakiem i karpiem przez G.R. Mielno.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Mielno; dostępne online.', FALSE, FALSE, 'Średnia, dostępne stanowiska w Unieściu, Mielnie i Podamirowie.', TRUE, TRUE, 'Pełny dojazd asfaltowy, liczne przystanie, porty i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80728, 'Lagunowe przymorskie', 1747, 1.8, 2.8, 'Monotonna niecka o dnie piaszczysto-mulistym, rynny tylko w kanałach.', 'Piasek przy mierzei, muł w częściach południowych, twardy pas Kanału Szczuczego.', 'Niska do średniej; woda słonawa i mętna od wiatru, dobrze natleniona.', 'Bogata w zatokach: trzcina, rdestnica, wywłócznik, łąki moczarki.', 'Sandacz, Okoń, Leszcz, Certa, Szczupak', TRUE, 'Intensywne zarybienia sandaczem i węgorzem przez zarządcę.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Mielno.', FALSE, FALSE, 'Dobra od strony Dąbek i Bukowa Morskiego; liczne dojścia.', TRUE, TRUE, 'Asfalt i drogi utwardzone, parkingi w Dąbkach i Bukowie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80730, 'Lagunowe przybrzeżne', 789, 1.9, 4, 'Równinny blat piaszczysty z osadami, dno bez wyraźnych spadków.', 'Głównie piaszczyste z warstwą mułu, piaszczyste wypłukania od wydm.', 'Niska do średniej; woda słonawa, silnie wietrzna, okresowo mętna.', 'Uboga w pasie mierzei, gęstsze trzciny w części południowej.', 'Sandacz, Okoń, Szczupak, Leszcz, Płoć', TRUE, 'Naturalna migracja gatunków słonawych, wspierana zarybieniami PZW.', TRUE, 'Zezwolenia PZW Słupsk.', FALSE, FALSE, 'Ograniczona do kilku wyznaczonych punktów od strony wsi Kopań.', FALSE, TRUE, 'Dojazd drogami utwardzonymi, miejsca postojowe przy brzegu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80731, 'Przymorskie / przybrzeżne', 1059, 2.3, 6.1, 'Płaska misa z lekkim zagłębieniem w osi centralnej, brak górek.', 'Muliste, lokalnie piaszczyste w strefie mierzei i przewężeń.', 'Średnia, okresowo mętna (woda żyzna i słonawa).', 'Umiarkowana: pasy trzcin, rogatek, gęsta moczarka kanadyjska.', 'Szczupak, Sandacz, Węgorz, Leszcz, Okoń', TRUE, 'Systematyczne zarybianie gatunkami drapieżnymi przez PZW.', TRUE, 'Standardowe zezwolenia PZW Słupsk.', FALSE, FALSE, 'Utrudniona przez trzciny; głównie pomosty i łodzie.', TRUE, TRUE, 'Dobry dojazd do miejscowości Jezierzany i Wicko Morskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80732, 'Nadmorskie rezerwatowe', 52, 0.8, 1.5, 'Skrajnie płytki talerz, dno niemal całkowicie płaskie.', 'Bagniste, głęboki torf i płynny muł organiczny.', 'Niska, woda o ciemnym (herbacianym) odcieniu.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce, grążele.', 'Lin, Karaś, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych (rezerwat), naturalna reprodukcja.', TRUE, 'Specjalna licencja PZW + zgoda rezerwatu; surowe limity.', FALSE, TRUE, 'Ekstremalnie trudna przez trzęsawiska; wymagane kładki.', FALSE, FALSE, 'Dojazd utrudniony, drogi polne, brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80733, 'Lagunowe przymorskie', 2469, 1.3, 2.6, 'Rozległa, płytka niecka o niemal płaskim ukształtowaniu podłoża.', 'Piaszczysto-muliste, twardsze w osi przepływu rzeki Łupawy.', 'Niska do średniej; woda słonawa i mętna od piasku podrywanego wiatrem.', 'Bogata: gęste trzcinowiska, wywłócznik i rdestnica w zatokach.', 'Szczupak, Okoń, Sandacz, Leszcz, Węgorz', TRUE, 'Ochrona tarlisk, zarybienia węgorzem i gatunkami słodkowodnymi.', TRUE, 'Specjalna licencja Słowińskiego Parku Narodowego.', FALSE, TRUE, 'Średnia, dostępne wyznaczone pomosty w Gardnie i Rowach.', TRUE, TRUE, 'Dobry dojazd asfaltowy do miejscowości Gardna Wielka.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80734, 'Lagunowe przybrzeżne', 577, 1.5, 2.8, 'Płytki talerz piaszczysto-mulisty bez wyraźnych rynien i górek.', 'Piasek przy mierzei, miękki muł w rejonach wylotu rzek.', 'Średnia do niskiej; woda żyzna i słonawa, okresowo mętna.', 'Bujna: trzcina, pałka wodna, liczne łąki roślinności podwodnej.', 'Sandacz, Szczupak, Okoń, Leszcz, Węgorz', TRUE, 'Regularne zarybienia drapieżnikami przez Gospodarstwo Rybackie.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego Mielno.', FALSE, FALSE, 'Dobra od strony Dźwirzyna i ośrodków wypoczynkowych w Rogowie.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy do Dźwirzyna i Rogowa.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80735, 'Rynnowe', 42, 6.5, 15.5, 'Ostry spadek brzegowy, twarde dno rynnowe, podwodne głazy narzutowe.', 'Twarde: piaszczysto-żwirowe z licznymi kamieniami, muliste w osi rynny.', 'Wysoka, woda czysta i dobrze natleniona przez źródła poddenne.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko na wypłyceniach.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Zarybienia szczupakiem i okoniem, stabilna populacja naturalna.', TRUE, 'Standardowe składki PZW Koszalin.', FALSE, TRUE, 'Trudna przez strome skarpy i las; ograniczone do kilku punktów.', FALSE, TRUE, 'Drogi leśne, piaszczyste, dojazd utrudniony po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80737, 'Zbiornik elektrowni', 75, 3.2, 8.5, 'Sztuczne profilowanie, wymyte dno rzeczne, silne codzienne wahania poziomu.', 'Piaszczysto-kamieniste, częściowo umocnione betonem, brak mułu.', 'Niska do średniej, woda mętna w czasie pracy turbin elektrowni.', 'Brak roślinności z powodu dużych wahań lustra wody i prądów.', 'Sandacz, Szczupak, Boleń, Leszcz, Brzana', TRUE, 'Stały napływ ryb z rzeki Radwi, zarybienia drapieżnikami.', TRUE, 'Zezwolenia RZGW / Wody Polskie, dopłata na połów z łodzi.', FALSE, FALSE, 'Dobra od strony umocnionych wałów; wymaga ostrożności.', FALSE, TRUE, 'Bardzo dobry dojazd asfaltowy pod samą elektrownię.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80738, 'Rynnowe leśne', 55, 4.8, 12, 'Regularna rynna, strome piaszczyste skarpy, liczne powalone drzewa.', 'Mieszane: piasek u brzegów, mulisty szlam organiczny w głębi.', 'Dobra, woda przejrzysta, leśny charakter o lekkim zabarwieniu.', 'Umiarkowana: pasy trzcin, rogatek, lilie wodne w zatokach.', 'Lin, Szczupak, Okoń, Płoć, Leszcz', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Składki PZW Koszalin.', FALSE, TRUE, 'Średnia, dostępne wydeptane stanowiska brzegowe.', TRUE, TRUE, 'Utwardzone drogi leśne, piaszczyste parkingi w borze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80739, 'Eutroficzne', 28, 2.5, 6, 'Misa o łagodnych spadkach, wyrównane dno bez gwałtownych uskoków.', 'Miękkie: muł organiczny i detrytus roślinny, piaszczyste kąpieliska.', 'Średnia, latem typowe zakwity fitoplanktonu i zmętnienie.', 'Bardzo obfita: szerokie pasy trzcin, liczne połacie grążeli żółtych.', 'Lin, Karaś pospolity, Szczupak, Płoć', TRUE, 'Głównie naturalny rozród wspierany okresowo narybkiem lina.', TRUE, 'Standardowe zezwolenia PZW Koszalin.', FALSE, TRUE, 'Dobra dzięki licznym dzikim stanowiskom w pasie trzcin.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80741, 'Zbiornik zaporowy', 180, 4.5, 12, 'Bardzo urozmaicone: zalane rowy, korzenie, koryto rzeki Radwi.', 'Mulisto-piaszczyste, twarde blaty żwirowe wzdłuż nurtu rzeki.', 'Średnia do niskiej, woda żyzna, latem częste zakwity alg.', 'Umiarkowana: pasy trzcin w zatokach, rdestnica na wypłyceniach.', 'Leszcz, Sandacz, Okoń, Sum, Szczupak', TRUE, 'Intensywne zarybienia drapieżnikami i rybami białymi.', TRUE, 'Zezwolenia PZW Koszalin, bardzo popularne łowisko.', FALSE, FALSE, 'Doskonała dzięki licznym pomostom i promenadzie.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80742, 'Rynnowo-przepływowe', 45, 3.8, 9.5, 'Wyraźny nurt rzeki Radwi, twarde rynny prądowe, powalone dęby.', 'Twarde: piaszczysto-żwirowe, wypłukane przez nurt rzeki.', 'Dobra, woda chłodna i dobrze natleniona przez cały sezon.', 'Skąpa: głównie trzcina na brzegach, mało roślinności podwodnej.', 'Okoń, Szczupak, Kleń, Płoć, Jaź', TRUE, 'Systematyczne zarybienia szczupakiem i wsparcie ryb reofilnych.', TRUE, 'Zezwolenia PZW Koszalin, okresowe kontrole.', FALSE, TRUE, 'Trudna przez gęsty las i strome zbocza; głównie łódź.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80743, 'Eutroficzne tarliskowe', 40, 1.5, 3.5, 'Płytka niecka, dno wyrównane, bagniste strefy przybrzeżne.', 'Bardzo miękkie, głęboki muł organiczny i torf.', 'Niska, woda mętna i żyzna, szybko nagrzewająca się.', 'Ekstremalna: szerokie trzcinowiska, grążele, moczarka.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród (strefa tarliskowa), ochrona drapieżnika.', TRUE, 'Standardowe składki PZW Koszalin; strefy rezerwatu.', FALSE, TRUE, 'Utrudniona przez bagno; wyznaczone pojedyncze punkty.', FALSE, TRUE, 'Drogi gruntowe, dojazd utrudniony po opadach deszczu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80744, 'Eutroficzne otwarte', 45, 2.5, 4.5, 'Łagodne piaszczyste spady, rozległe blaty żwirowe.', 'Mieszane: piasek, żwir, lokalnie warstwa mułu w dołach.', 'Średnia do dobrej, woda dobrze natleniona przez wiatr.', 'Umiarkowana: pas trzcin węższy niż na południu, rogatek.', 'Leszcz, Okoń, Płoć, Szczupak', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem.', TRUE, 'Zezwolenia PZW Koszalin dostępne online.', FALSE, TRUE, 'Bardzo dobra, liczne piaszczyste wejścia i stanowiska.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80642, 'Rynnowe głębokie', 50, 4.2, 7.5, 'Wyraźna rynna centralna, strome stoki, dno pofałdowane.', 'Przeważnie muliste w głębi, piaszczyste na spadkach dna.', 'Dobra do średniej, woda chłodniejsza niż w zatokach.', 'Skąpa: głównie roślinność podwodna na krawędziach rynny.', 'Szczupak, Sandacz, Okoń, Leszcz, Płoć', TRUE, 'Systematyczne zarybienia drapieżnikami rynnowymi.', TRUE, 'Licencja PZW Koszalin, wymagana dopłata na łódź.', FALSE, TRUE, 'Średnia, ograniczone przez strome skarpy i zarośla.', TRUE, TRUE, 'Dojazd leśnymi drogami utwardzonymi, piaszczyste wjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80745, 'Dystroficzne / Eutroficzne', 18, 1.8, 3.5, 'Płytka misa o bardzo miękkim dnie, brak wyraźnych uskoków i górek.', 'Głównie miękki muł organiczny, torf i gruby osad liściasty.', 'Niska, woda o ciemnym (czarnym) zabarwieniu humusowym.', 'Bardzo obfita: szerokie pasy trzcin, lilie wodne, rzęsa.', 'Lin, Karaś pospolity, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem szczupaka przez PZW.', TRUE, 'Standardowe składki PZW Słupsk.', FALSE, TRUE, 'Ekstremalnie trudna (trzęsawiska); wymaga woderów lub pontonu.', FALSE, TRUE, 'Drogi leśne, piaszczyste, utrudniony dojazd po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80746, 'Rynnowe leśne', 42, 4.5, 10.5, 'Regularna centralna rynna, łagodne piaszczyste stoki u brzegów.', 'Mieszane: piasek na spadkach, miękki muł w najgłębszych punktach.', 'Dobra, woda przejrzysta, leśny charakter o lekkim zabarwieniu.', 'Umiarkowana: pasy trzcin, rdestnica, moczarka w zatokach.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Słupsk.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i wydeptanym stanowiskom.', TRUE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi; parkingi w borze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80748, 'Rynnowe małe', 12, 3.2, 7.8, 'Mały talerz o regularnych spadkach, dno twarde piaszczyste.', 'Twarde: jasny piasek i drobny żwir polodowcowy, mało mułu.', 'Wysoka, krystaliczna toń widoczna do 3-4 metrów głębokości.', 'Skąpa: wąski pierścień trzciny, mało roślinności zanurzonej.', 'Płoć, Okoń, Krąp, Szczupak', TRUE, 'Głównie naturalna reprodukcja, okresowe wsparcie narybkiem PZW.', TRUE, 'Zezwolenia PZW Słupsk, dostępne online.', FALSE, TRUE, 'Dobra dzięki licznym kładkom i pomostom wędkarskim.', TRUE, TRUE, 'Dobry dojazd drogami polnymi i szutrowymi do Świeszyna.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80749, 'Rynnowe głębokie', 98, 7.2, 16.5, 'Urozmaicona rynna, liczne podwodne górki i twarde kanty.', 'Twarde: piasek i glina, muliste w najgłębszych punktach rynny.', 'Wysoka (I klasa), woda bardzo czysta i dobrze natleniona.', 'Umiarkowana: trzcina na brzegach, podwodne łąki moczarki.', 'Sandacz, Szczupak, Leszcz, Okoń, Płoć', TRUE, 'Intensywne zarybienia drapieżnikami i sielawą przez PZW Słupsk.', TRUE, 'Składki PZW Słupsk; obowiązuje strefa ciszy.', FALSE, TRUE, 'Dobra w rejonie Świeszyna, trudniejsza na dzikim brzegu.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy do miejscowości.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80750, 'Rynnowe wąskie', 35, 5.2, 12, 'Wyraźna centralna rynna o stromych zboczach, dno twarde.', 'Głównie twarde: piasek i drobny żwir polodowcowy.', 'Dobra, woda przejrzysta, chłodniejsza w osi rynny.', 'Umiarkowana: wąski pas trzciny, liczne powalone drzewa.', 'Okoń, Szczupak, Leszcz, Płoć', TRUE, 'Regularne zarybienia drapieżnikiem przez lokalne koło PZW.', TRUE, 'Standardowe składki PZW Słupsk.', FALSE, TRUE, 'Średnia, dostępne stanowiska w rejonie miejscowości Starzno.', TRUE, TRUE, 'Dobry dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80751, 'Rynnowe sielawowe', 112, 8.5, 20.2, 'Urozmaicona rynna, strome stoki, piaszczyste wypłycenia północne.', 'Twarde: piasek, żwir i glina, lokalnie warstwa mułu organicznego.', 'Dobra do wysokiej, woda natleniona przez źródła poddenne.', 'Średnio obfita: pasy trzcin, moczarka, rdestnica na spadkach.', 'Szczupak, Sandacz, Leszcz, Okoń, Płoć, Sielawa', TRUE, 'Systematyczne zarybienia sielawą i drapieżnikami rynnowymi.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego / PZW.', FALSE, FALSE, 'Bardzo dobra, liczne pomosty, kładki i dojścia plażowe.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80665, 'Eutroficzne', 25, 2.8, 7.5, 'Regularna niecka o łagodnych spadkach dna, brak uskoków.', 'Przeważnie miękkie i muliste, gruba warstwa osadów organicznych.', 'Średnia, woda żyzna, cieplejsza, latem typowe zakwity alg.', 'Bardzo obfita: gęste trzcinowiska, liczne połacie grążeli.', 'Lin, Karaś, Szczupak, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu linem.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego.', FALSE, FALSE, 'Średnia, ograniczone przez roślinność; głównie małe dojścia.', TRUE, TRUE, 'Dobry dojazd drogami polnymi i szutrowymi do Studzienic.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81740, 'Eutroficzne (podgrzewane)', 250, 3.5, 6.2, 'Rynnowa z dołkami', 'Mieszane (piasek/muł)', 'Średnia', 'Bogata na obrzeżach', 'Sum, Sandacz, Karaś, Lin', TRUE, 'Regularne zarybienia sumem i sandaczem', TRUE, 'Licencja G.R. Gosławice', FALSE, FALSE, 'Wyśmienita', TRUE, TRUE, 'Dojazd miejski/asfalt', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80646, 'Oligotroficzne (lobeliowe)', 15, 3.8, 8.5, 'Piaszczysty lej krasowy o regularnym kształcie i dnie.', 'Bardzo twarde: czysty piasek, brak mułu i osadów organicznych.', 'Ekstremalnie wysoka; woda krystalicznie czysta (I klasa).', 'Unikatowa: lobelia jeziorna, poryblin; brak trzcin przy brzegu.', 'Okoń, Płoć, Szczupak', TRUE, 'Brak zarybień masowych; ochrona rzadkiego ekosystemu.', TRUE, 'Specjalna licencja PZW Słupsk; ograniczenia nęcenia.', TRUE, TRUE, 'Średnia przez piaszczyste brzegi; wyznaczone miejsca.', FALSE, FALSE, 'Zakaz używania łodzi w celu ochrony jeziora lobeliowego.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80693, 'Eutroficzne podmiejskie', 20, 2.5, 6.2, 'Misa jeziorna o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek w litoralu, miękki muł w środkowej części.', 'Średnia, typowa dla jezior żyznych; okresowo zakwita.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, grążele.', 'Lin, Karaś, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami spokojnego żeru i szczupakiem.', TRUE, 'Standardowe składki PZW Słupsk.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i kładkom.', TRUE, TRUE, 'Bardzo dobry dojazd drogami szutrowymi do miejscowości.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80753, 'Oligotroficzne lobeliowe (GIGANT)', 512, 14.5, 48.2, 'Przepotężne uskoki krasowe, strome klify, głębokie rynny.', 'Wybitnie twarde: piasek, żwir, kreda, kamienie, brak mułu.', 'Krystaliczna (I klasa); widoczność do kilku-kilkunastu metrów.', 'Skąpa: lobelia, poryblin, brak trzcin na większości brzegów.', 'Okoń "pelagiczny", Szczupak, Płoć, Sielawa, Sieja', TRUE, 'Ochrona tarlisk sielawy i rzadkich gatunków drapieżnych.', TRUE, 'Zezwolenia PZW Słupsk / G.R.; bezwzględna strefa ciszy.', FALSE, TRUE, 'Bardzo trudna przez strome brzegi; głównie z łodzi.', TRUE, TRUE, 'Dobry dojazd do Bobięcina, dalej drogi leśne i szutrowe.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80754, 'Oligotroficzne lobeliowe', 320, 12, 35.5, 'Głęboka rynna krasowa z podwodnymi górami i stromymi klifami.', 'Wybitnie twarde: czysty piasek, wapień i krasowa kreda.', 'Ekstremalnie wysoka (I klasa); przejrzystość sielawowa.', 'Minimalistyczna: rzadka roślinność lobeliowa, brak trzcin.', 'Szczupak pelagiczny, Okoń, Sielawa, Płoć', TRUE, 'Systematyczne zarybienia sielawą i ochrona drapieżnika.', TRUE, 'Licencja PZW Słupsk; rygorystyczne limity połowu.', FALSE, TRUE, 'Ograniczona do wyznaczonych punktów na piaszczystych skarpach.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80747, 'Rynnowe sielawowe', 85, 6.8, 18.5, 'Regularna centralna rynna, strome piaszczyste skarpy leśne.', 'Twarde: piasek i drobny żwir polodowcowy, mało osadów.', 'Wysoka (I klasa); krystaliczna toń sprzyjająca spinningowi.', 'Umiarkowana: wąski pas trzcin, rzadka moczarka na dnie.', 'Okoń, Płoć, Szczupak, Sielawa, Leszcz', TRUE, 'Naturalny ekosystem wspierany zarybieniami sielawą przez PZW.', TRUE, 'Zezwolenia PZW Słupsk; obowiązuje strefa ciszy.', FALSE, TRUE, 'Trudna przez wysokie skarpy i las; kilka dzikich wejść.', TRUE, TRUE, 'Dojazd drogami leśnymi, piaszczystymi; parkingi w borze.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80755, 'Rynnowe', 45, 5.2, 12.5, 'Regularna centralna rynna, strome piaszczyste skarpy, brak górek.', 'Twarde: jasny piasek i drobny żwir, mało mułu w osi głównej.', 'Wysoka, woda przejrzysta, dobrze natleniona przez cały rok.', 'Skąpa: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Słupsk.', FALSE, TRUE, 'Średnia, kilka wydeptanych stanowisk w pasie leśnym.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony po deszczu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80756, 'Eutroficzne', 22, 2.8, 6.5, 'Misa jeziorna o łagodnych spadkach, wyrównane dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł organiczny w głębi.', 'Średnia, typowa dla jezior żyznych; latem okresowo zakwita.', 'Bardzo obfita: gęste trzcinowiska, liczne połacie grążeli żółtych.', 'Lin, Karaś pospolity, Szczupak, Płoć, Okoń', TRUE, 'Systematyczne zarybienia rybami białymi i drapieżnymi przez PZW.', TRUE, 'Standardowe zezwolenia PZW Słupsk.', FALSE, FALSE, 'Bardzo dobra dzięki licznym pomostom i łagodnym zejściom.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80757, 'Dystroficzne leśne', 8, 1.5, 4.8, 'Mała, mroczna niecka bez wyraźnych rynien, dno silnie zamulone.', 'Bardzo miękkie: płynny muł organiczny i gruby osad liściasty.', 'Niska; woda o charakterystycznym ciemnym zabarwieniu humusowym.', 'Średnia: pasy trzcin, lilie wodne i moczarka w płytszych partiach.', 'Lin, Karaś, Szczupak, Płoć', TRUE, 'Głównie naturalny rozród, okresowe wsparcie narybkiem linowym.', TRUE, 'Zezwolenia PZW Słupsk.', FALSE, TRUE, 'Trudna przez bagniste brzegi; kilka dzikich wejść leśnych.', FALSE, TRUE, 'Wąskie ścieżki leśne; dojazd tylko dla aut z wyższym zawieszeniem.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80758, 'Polodowcowe rynnowe', 68, 7.5, 19.5, 'Wyraźna centralna rynna, strome piaszczyste spady, twarde dno.', 'Twarde: piasek i żwir polodowcowy, cienka warstwa osadów w osi.', 'Dobra; woda przejrzysta, natleniona, sprzyjająca spinningowi.', 'Umiarkowana: wąski pas trzciny pospolitej, mało roślin podwodnych.', 'Okoń, Sandacz, Szczupak, Płoć, Leszcz', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez PZW Słupsk.', TRUE, 'Standardowe składki PZW Słupsk.', FALSE, FALSE, 'Bardzo dobra; liczne pomosty wędkarskie od strony wsi.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i szutrowymi do Piaszna.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80759, 'Eutroficzne (małe)', 12, 1.8, 4, 'Mały talerz o równomiernym dnie, powolny przyrost głębokości.', 'Miękkie i muliste; dno wyścielone osadem roślinnym i mułem.', 'Średnia; latem mętna z powodu nagrzewania wody i wegetacji.', 'Bardzo obfita: jezioro silnie zarastające grążelem i rogatkiem.', 'Lin, Karaś, Szczupak, Płoć, Wzdręga', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Zezwolenia PZW Słupsk.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom brzegowym.', FALSE, TRUE, 'Dojazd drogami polnymi, utwardzony, bliskość miejscowości.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80760, 'Rynnowe leśne', 35, 4.5, 10.2, 'Urozmaicona rzeźba z podwodnymi górkami i centralną rynną.', 'Głównie twarde: piasek i drobny żwir, lokalnie warstwa mułu.', 'Dobra; woda przejrzysta, leśny charakter, chłodna w głębi.', 'Skąpa: wąski pierścień trzcin, mało roślinności miękkiej.', 'Szczupak, Okoń, Płoć, Leszcz, Węgorz', TRUE, 'Naturalna ochrona drapieżnika; okresowe zarybienia szczupakiem.', TRUE, 'Składki PZW Słupsk.', FALSE, TRUE, 'Trudna przez strome skarpy i las; ograniczone do kilku punktów.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi; parkingi w borze.', FALSE);
