INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80781, 'Rynnowe głębokie', 45, 7.2, 18.5, 'Wyraźna centralna rynna, strome piaszczyste skarpy, twarde dno.', 'Twarde: czysty piasek i drobny żwir, mało osadów organicznych.', 'Wysoka, woda bardzo czysta i dobrze natleniona przez cały rok.', 'Skąpa: wąski pierścień trzcin, podwodne łąki ramienic.', 'Okoń, Szczupak, Leszcz, Płoć', TRUE, 'Systematyczne zarybienia szczupakiem i białą rybą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Suwałki.', FALSE, TRUE, 'Średnia przez strome brzegi; wyznaczone pojedyncze punkty.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi; utwardzone wjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80782, 'Dystroficzne leśne', 8, 1.5, 3.8, 'Mała, mroczna niecka bez wyraźnych rynien, dno silnie zamulone.', 'Bardzo miękkie: płynny muł organiczny i gruby osad torfowy.', 'Niska; woda o charakterystycznym ciemnym zabarwieniu humusowym.', 'Średnia: pasy trzcin, lilie wodne i moczarka w płytszych partiach.', 'Lin, Karaś pospolity, Szczupak, Płoć', TRUE, 'Ochrona naturalna; okresowe wsparcie narybkiem przez lokalne koło.', TRUE, 'Zezwolenia PZW Suwałki.', FALSE, TRUE, 'Bardzo trudna przez bagno; wymagane wodery lub mały ponton.', FALSE, TRUE, 'Wąskie drogi leśne; dojazd tylko dla aut z wyższym zawieszeniem.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80783, 'Eutroficzne podmiejskie', 35, 3.2, 7.5, 'Niecka o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek w litoralu, miękki muł w środkowej części.', 'Średnia, typowa dla jezior żyznych; latem okresowo mętna.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, grążele.', 'Leszcz, Płoć, Szczupak, Okoń, Krąp', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem przez PZW.', TRUE, 'Standardowe składki PZW Suwałki.', FALSE, FALSE, 'Bardzo dobra dzięki licznym pomostom i łagodnym zejściom.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy w samej miejscowości Przerośl.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80761, 'Polodowcowe rynnowe', 22, 4.5, 10.2, 'Regularna rynna o dość stromych stokach, dno twarde.', 'Głównie twarde: piasek i żwir polodowcowy, cienka warstwa mułu.', 'Dobra; woda przejrzysta, natleniona, sprzyjająca spinningowi.', 'Umiarkowana: wąski pas trzciny pospolitej, rdestnica na spadkach.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Naturalny rozród wspierany okresowo przez okręg PZW.', TRUE, 'Standardowe zezwolenia PZW Suwałki.', FALSE, FALSE, 'Średnia, dostępne dzikie stanowiska i dojścia piaszczyste.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80784, 'Rynnowe sielawowe (głębokie)', 85, 11.2, 28.5, 'Głęboki rów o stromych stokach, liczne podwodne górki.', 'Twarde: piasek krasowy, glina i skały wapienne w głębi.', 'Ekstremalnie wysoka (I klasa); krystaliczna toń sielawowa.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Sandacz, Sielawa, Szczupak, Okoń, Leszcz', TRUE, 'Systematyczne zarybienia sandaczem i sielawą przez PZW Suwałki.', TRUE, 'Licencja PZW Suwałki; obowiązuje strefa ciszy.', FALSE, TRUE, 'Średnia przez wysokie skarpy; wędkowanie głównie z łodzi.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy do Przerośli; parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80785, 'Eutroficzne (płytkie)', 18, 2.5, 5.8, 'Misa jeziorna o łagodnych spadkach, dno muliste.', 'Miękkie i muliste; dno wyścielone grubą warstwą osadów.', 'Średnia do niskiej; latem mętna z powodu nagrzewania wody.', 'Bardzo obfita: jezioro silnie zarastające grążelem i moczarką.', 'Lin, Karaś, Szczupak, Płoć, Wzdręga', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe zezwolenia PZW Suwałki.', FALSE, FALSE, 'Ograniczona przez roślinność; kilka wydeptanych stanowisk.', FALSE, TRUE, 'Dojazd drogami polnymi, utwardzony, bliskość miejscowości.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80787, 'Rynnowe leśne', 26, 5.8, 16.5, 'Wyraźna centralna rynna, strome piaszczyste skarpy leśne.', 'Twarde: piasek i drobny żwir polodowcowy, mało osadów.', 'Wysoka, woda bardzo czysta i przejrzysta przez cały sezon.', 'Umiarkowana: wąski pas trzciny pospolitej, mało rogatka.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Składki PZW Suwałki; obowiązuje strefa ciszy.', FALSE, TRUE, 'Trudna przez wysokie skarpy i las; kilka dzikich wejść.', FALSE, TRUE, 'Dojazd drogami leśnymi, piaszczystymi; parkingi w borze.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80788, 'Rynnowe eutroficzne', 32, 4.2, 10, 'Regularna rynna, piaszczyste wypłycenia, dno pofałdowane.', 'Mieszane: piasek u brzegów, mulisty szlam w rynnie środkowej.', 'Dobra do średniej; woda przejrzysta wiosną, latem zakwita.', 'Bogata: gęste trzcinowiska, rdestnica na podwodnych spadach.', 'Lin, Szczupak, Okoń, Płoć, Leszcz', TRUE, 'Zarybienia szczupakiem i białą rybą przez PZW Suwałki.', TRUE, 'Zezwolenia PZW Suwałki dostępne online.', FALSE, FALSE, 'Średnia, dostępne wydeptane stanowiska w pasie trzcin.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80789, 'Eutroficzne leśne', 14, 3.5, 7.8, 'Mała niecka o łagodnych spadkach, dno wyrównane.', 'Przeważnie muliste, głęboka warstwa osadów liściastych.', 'Dobra; woda przejrzysta, leśny charakter, chłodna w głębi.', 'Umiarkowana: pasy trzcin, lilie wodne i moczarka w zatokach.', 'Płoć, Lin, Szczupak, Okoń, Leszcz', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Suwałki.', FALSE, TRUE, 'Trudna przez gęsty las; ograniczone do kilku punktów.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80790, 'Polodowcowe rynnowe', 38, 5.5, 18, 'Wyraźna centralna rynna, strome piaszczyste spady, brak górek.', 'Twarde: jasny piasek i żwir polodowcowy, mało osadów organicznych.', 'Wysoka, woda bardzo czysta, leśny charakter o dobrym natlenieniu.', 'Skąpa: wąski pas trzciny pospolitej, rzadka rdestnica na spadkach.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem drapieżnika przez PZW.', TRUE, 'Standardowe składki PZW Suwałki.', FALSE, TRUE, 'Średnia przez wysokie skarpy i las; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80791, 'Dystroficzne leśne', 12, 2.5, 7.5, 'Mały, głęboki kociołek o stromych zboczach i mulistym podłożu.', 'Bardzo miękkie: płynny muł organiczny i gruby osad liściasty.', 'Niska; woda o charakterystycznym ciemnym (herbacianym) odcieniu.', 'Średnia: pasy trzcin, lilie wodne i moczarka w płytszych partiach.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Głównie naturalny rozród wspierany okresowo wsparciem linowym PZW.', TRUE, 'Standardowe zezwolenia PZW Suwałki.', FALSE, TRUE, 'Bardzo trudna przez bagno i las; wymagany mały ponton.', FALSE, TRUE, 'Wąskie ścieżki leśne; dojazd tylko dla aut z wyższym zawieszeniem.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80792, 'Eutroficzne', 25, 3.2, 6.5, 'Misa o łagodnych spadkach, dno piaszczysto-muliste bez uskoków.', 'Mieszane: piasek w litoralu, miękki muł w środkowej części.', 'Średnia, typowa dla jezior żyznych; latem okresowo mętna.', 'Bogata: gęste trzcinowiska, liczne połacie grzybieni białych.', 'Lin, Karaś srebrzysty, Szczupak, Leszcz, Płoć', TRUE, 'Regularne zarybienia rybami spokojnego żeru i szczupakiem przez PZW.', TRUE, 'Standardowe składki PZW Suwałki.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom brzegowym i kładkom.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi do brzegów.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80794, 'Rynnowe małe', 18, 2.8, 8.2, 'Regularna rynna leśna o łagodnych piaszczystych stokach.', 'Twarde: jasny piasek i drobny żwir, cienka warstwa mułu w osi.', 'Dobra; woda przejrzysta, natleniona przez wiatr, chłodna w głębi.', 'Umiarkowana: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Płoć, Krąp, Okoń, Szczupak', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Suwałki.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i licznym wejściom piaszczystym.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80795, 'Rynnowe podmiejskie', 148, 4.5, 11.5, 'Wyraźna centralna rynna, strome stoki wschodnie, mulista zatoka.', 'Zróżnicowane: piasek, żwir, lokalnie warstwa mułu organicznego.', 'Średnia; latem mętna z powodu nagrzewania wody i wegetacji.', 'Umiarkowana: pasy trzcin, rogatek, lilie wodne w zatokach.', 'Sandacz, Szczupak, Leszcz, Okoń, Płoć', TRUE, 'Intensywne zarybienia sandaczem przez Gospodarstwo Rybackie.', TRUE, 'Standardowe opłaty PZW / G.R.; wymagane zgłoszenie graniczne.', FALSE, FALSE, 'Bardzo dobra dzięki licznym pomostom i promenadzie miejskiej.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi i slipy.', TRUE);
