INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80798, 'Dystroficzne puszczańskie', 15, 1.5, 3.2, 'Mała niecka bez wyraźnych rynien, dno silnie zamulone i torfowe.', 'Bardzo miękkie: płynny muł organiczny i głęboki osad leśny.', 'Niska; woda o charakterystycznym ciemnobrunatnym kolorze.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce, grążele.', 'Lin, Karaś, Szczupak, Okoń', TRUE, 'Brak zarybień masowych; stabilna populacja dzikich ryb.', TRUE, 'Zezwolenia PZW Olsztyn.', FALSE, TRUE, 'Bardzo trudna przez bagno; wymagane wodery lub mały ponton.', FALSE, TRUE, 'Trudny dojazd wąskimi ścieżkami leśnymi; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80799, 'Eutroficzne', 22, 2.5, 6, 'Misa jeziorna o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł organiczny w rynnie.', 'Średnia, typowa dla jezior żyznych; okresowo zakwita.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, grążele.', 'Lin, Leszcz, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami spokojnego żeru i szczupakiem.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i kładkom.', TRUE, TRUE, 'Bardzo dobry dojazd drogami szutrowymi do miejscowości.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80800, 'Eutroficzne (płytkie)', 18, 1.8, 4, 'Niecka o łagodnych spadkach, dno wyrównane bez uskoków.', 'Przeważnie muliste, lokalnie piaszczyste strefy przybrzeżne.', 'Średnia do niskiej, woda żyzna, cieplejsza, latem mętna.', 'Bardzo obfita: gęste trzcinowiska, liczne połacie grążeli.', 'Lin, Karaś srebrzysty, Płoć, Szczupak', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Zezwolenia PZW Olsztyn.', FALSE, FALSE, 'Średnia, ograniczone przez roślinność; głównie małe dojścia.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi, łatwy dostęp.', TRUE);
