INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80804, 'Rynnowo-przepływowe', 32, 4.2, 9.5, 'Wyraźny nurt rzeki Gawlik, twarde rynny prądowe, pofalowane dno.', 'Twarde: piaszczysto-żwirowe, wypłukane przez nurt rzeki.', 'Dobra, woda dobrze natleniona i chłodniejsza niż w zatokach.', 'Średnia: trzcina na brzegach, roślinność prądolubna w nurcie.', 'Jaź, Kleń, Szczupak, Leszcz, Płoć', TRUE, 'Systematyczne zarybienia szczupakiem i wsparcie ryb reofilnych.', TRUE, 'Zezwolenia PZW Olsztyn, popularny szlak wodny.', FALSE, FALSE, 'Średnia, dostępne wydeptane stanowiska w pasie trzcin.', TRUE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80805, 'Rynnowe sielawowe (głębokie)', 112, 11.5, 28.5, 'Głęboka centralna rynna, strome stoki, liczne górki podwodne.', 'Bardzo twarde: piasek krasowy, glina i skały polodowcowe.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca spinningowi.', 'Skąpa: wąski pas trzcin, roślinność podwodna kończy się gwałtownie.', 'Sielawa, Sandacz, Szczupak pelagiczny, Okoń, Płoć', TRUE, 'Systematyczne zarybienia sandaczem i sielawą przez PZW.', TRUE, 'Licencja PZW Olsztyn; obowiązuje strefa ciszy.', FALSE, TRUE, 'Trudna przez wysokie skarpy; wędkowanie głównie z łodzi.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy do miejscowości.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80806, 'Eutroficzne rzeczne', 18, 1.2, 2.5, 'Płaski talerz, dno bez rynien, liczne naniesienia rzeczne w osi nurtu.', 'Bardzo miękkie, muł organiczny i gruby osad liściasty.', 'Niska, woda mętna i żyzna, okresowo zasilana wodami Pisy.', 'Ekstremalna: szerokie pasy trzcin, dywany grążeli i moczarki.', 'Lin, Karaś srebrzysty, Szczupak, Płoć', TRUE, 'Naturalna migracja gatunków rzecznych, okresowe wsparcie linem.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, FALSE, 'Bardzo trudna przez bagno; wymagane wodery lub ponton.', FALSE, TRUE, 'Dojazd polny, utrudniony po deszczu; brak oficjalnych parkingów.', FALSE);
