INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80808, 'Eutroficzne leśne', 85, 2.8, 6.5, 'Misa o łagodnych spadkach, piaszczyste wypłycenia, dno muliste.', 'Mieszane: piasek w litoralu, miękki muł w środkowej części.', 'Średnia, typowa dla jezior żyznych; latem widoczność do 1.5 m.', 'Bogata: gęste trzcinowiska, liczne połacie lilii wodnych.', 'Karp, Leszcz, Amur, Szczupak, Płoć', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, FALSE, 'Bardzo dobra dzięki piaszczystym wejściom i licznym kładkom.', TRUE, TRUE, 'Bardzo dobry dojazd drogami asfaltowymi i utwardzonymi.', TRUE);
