INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80829, 'Eutroficzne leśne małe', 8, 1.8, 4.5, 'Mała misa o łagodnych spadkach, dno muliste bez uskoków.', 'Miękkie: muł organiczny i osad liściasty z otaczającego boru.', 'Średnia; latem mętna z powodu nagrzewania wody i wegetacji.', 'Bardzo obfita: jezioro silnie zarastające grążelem i rogatkiem.', 'Wzdręga, Lin, Szczupak, Okoń, Płoć', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Składki PZW Olsztyn.', FALSE, TRUE, 'Średnia; dostępne dzikie wejścia w pasie leśnym.', FALSE, TRUE, 'Dojazd leśny, piaszczysty; zalecane auta wyższe.', FALSE);
