INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80847, 'Rynnowe rezerwatowe', 552, 14.8, 42.5, 'Potężna centralna rynna, gwałtowne uskoki, dno twarde.', 'Bardzo twarde: piasek krasowy, żwir i skały polodowcowe.', 'Ekstremalnie wysoka (I klasa); widoczność do kilku metrów.', 'Skąpa: roślinność podwodna kończy się gwałtownie na stokach.', 'Szczupak pelagiczny, Okoń, Sielawa, Leszcz, Sandacz', TRUE, 'Rezerwat: ograniczona ingerencja, naturalny rozród sielawy.', TRUE, 'Specjalna licencja rezerwatowa (PZW Olsztyn); surowe limity.', FALSE, TRUE, 'Ograniczona do ściśle wyznaczonych stanowisk brzegowych.', FALSE, TRUE, 'Dojazd utrudniony (zakazy wjazdu w rezerwat); parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80848, 'Eutroficzne (dzikie)', 6, 1.2, 2.8, 'Płaski talerz, dno bez urozmaiceń, silnie zarastające.', 'Bardzo miękkie: głęboki muł organiczny i osady bagienne.', 'Niska, woda mętna i żyzna, szybko nagrzewająca się.', 'Ekstremalna: całe jezioro porośnięte roślinnością miękką.', 'Lin, Karaś pospolity, Szczupak, Wzdręga', TRUE, 'Brak zarybień sztucznych; całkowicie naturalny rybostan.', TRUE, 'Standardowe zezwolenia PZW Olsztyn.', FALSE, TRUE, 'Ekstremalnie trudna; brak pomostów i przygotowanych wejść.', FALSE, FALSE, 'Brak dojazdu pod samo lustro wody; dojście przez las.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80849, 'Polodowcowe rynnowe', 26, 4.5, 13.5, 'Regularna rynna o dość stromych stokach, dno twarde.', 'Twarde: jasny piasek krasowy i drobny żwir polodowcowy.', 'Dobra; woda przejrzysta, sprzyjająca technikom opadowym.', 'Umiarkowana: wąski pas trzciny pospolitej, kępy rdestnicy.', 'Okoń, Sandacz, Szczupak, Płoć, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, TRUE, 'Średnia, dostępne dzikie stanowiska i leśne dojścia.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80850, 'Polodowcowe rynnowe', 22, 4.5, 12, 'Regularna rynna centralna, twarde piaszczyste stoki, brak górek podwodnych.', 'Twarde: jasny piasek i żwir polodowcowy, cienka warstwa mułu w osi.', 'Wysoka, woda bardzo czysta i przejrzysta przez cały sezon.', 'Umiarkowana: wąski pas trzciny pospolitej, kępy rdestnicy na spadkach.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo przez okręg PZW Olsztyn.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi i polnymi, utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80851, 'Eutroficzne leśne', 8, 1.5, 4, 'Mała niecka o łagodnych spadkach, dno muliste bez wyraźnych uskoków.', 'Bardzo miękkie: muł organiczny i osad liściasty z otaczającego boru.', 'Średnia; latem mętna z powodu nagrzewania wody i intensywnej wegetacji.', 'Bardzo obfita: jezioro silnie zarastające grążelem i moczarką kanadyjską.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu narybkiem lina.', TRUE, 'Zezwolenia PZW Olsztyn dostępne online.', FALSE, TRUE, 'Średnia; dostępne dzikie wejścia w pasie leśnym.', FALSE, TRUE, 'Dojazd leśny, piaszczysty; zalecane auta z wyższym zawieszeniem.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80852, 'Rynnowe', 35, 4.2, 10.5, 'Wyraźna centralna rynna, strome piaszczyste skarpy, dno pofalowane.', 'Mieszane: piasek u brzegów, mulisty szlam organiczny w głębi.', 'Dobra; woda przejrzysta wiosną, latem możliwe okresowe zakwity alg.', 'Umiarkowana: pasy trzcin, rdestnica na podwodnych spadach dna.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez lokalne koło.', TRUE, 'Standardowe zezwolenia PZW Olsztyn.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80853, 'Rynnowe sielawowe', 85, 7.5, 19.8, 'Głęboka rynna, strome piaszczyste klify podwodne, dno twarde.', 'Bardzo twarde: piasek krasowy, żwir i lita glina polodowcowa.', 'Wysoka (I klasa), woda bardzo czysta, chłodna i dobrze natleniona.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Okoń, Sielawa, Szczupak, Płoć, Leszcz', TRUE, 'Systematyczne zarybienia sielawą i drapieżnikami przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn; obowiązuje strefa ciszy.', FALSE, TRUE, 'Trudna przez wysokie skarpy; wyznaczone miejsca biwakowe.', FALSE, TRUE, 'Dojazd drogami leśnymi; parkingi leśne przy wjazdach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80854, 'Eutroficzne rynnowe', 112, 3.5, 7.2, 'Rozległa misa o pofalowanym dnie, liczne podwodne górki i blaty.', 'Mieszane: piasek na wypłyceniach, miękki muł w środkowej części.', 'Średnia, typowa dla jezior żyznych; okresowo mętna latem.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, rozległe latorośla.', 'Szczupak, Leszcz, Płoć, Okoń, Lin', TRUE, 'Intensywne zarybienia szczupakiem i rybami białymi przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, FALSE, 'Bardzo dobra dzięki licznym dzikim stanowiskom i kładkom.', TRUE, TRUE, 'Bardzo dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80855, 'Eutroficzne przepływowe', 45, 2.5, 6, 'Pofalowane dno z wyraźnym nurtem rzeki Pisy, łagodne spadki.', 'Miękkie i muliste; dno wyścielone osadem rzecznym i bentosem.', 'Średnia do niskiej; dobrze natleniona dzięki przepływowi rzeki.', 'Bardzo obfita: gęste trzcinowiska, grążele żółte, rzadki rogatek.', 'Lin, Leszcz, Karaś srebrzysty, Szczupak, Okoń', TRUE, 'Naturalny rozród wspierany napływem ryb rzecznych i zarybieniami.', TRUE, 'Standardowe zezwolenia PZW Olsztyn.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i leśnym dojściom.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi pod sam brzeg.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80856, 'Rynnowe sielawowe (czyste)', 92, 8.5, 18.2, 'Głęboka centralna rynna, strome piaszczyste stoki, dno twarde.', 'Twarde: piasek krasowy, żwir polodowcowy, marginalna ilość mułu.', 'Ekstremalnie wysoka (I klasa), widoczność do kilku metrów.', 'Skąpa: wąski pierścień trzcin, podwodne łąki ramienic.', 'Sandacz, Okoń, Sielawa, Płoć, Leszcz', TRUE, 'Intensywne zarybienia sandaczem i sielawą przez okręg PZW.', TRUE, 'Licencja PZW Olsztyn; obowiązuje bezwzględna strefa ciszy.', FALSE, TRUE, 'Średnia przez wysokie skarpy; wyznaczone pojedyncze punkty.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy do Kierzlin.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80857, 'Eutroficzne (małe)', 14, 2.2, 5.8, 'Mała niecka o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł organiczny w głębi.', 'Średnia, typowa dla jezior żyznych; latem okresowo zakwita.', 'Bogata: gęste trzcinowiska, liczne połacie lilii wodnych.', 'Lin, Karaś, Szczupak, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu narybkiem.', TRUE, 'Standardowe zezwolenia PZW Olsztyn.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i kładkom.', FALSE, TRUE, 'Dobry dojazd drogami polnymi i szutrowymi pod samo jezioro.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81744, 'Rynnowe', 80, 5.2, 14.5, 'Pofałdowana rynna', 'Mieszane', 'Wysoka', 'Trzcina, rdestnica', 'Leszcz, Szczupak, Okoń, Płoć', TRUE, 'Regularne PZW', TRUE, 'PZW Konin', FALSE, FALSE, 'Dobra', TRUE, TRUE, 'Dobra szutrowa', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80858, 'Rynnowe leśne małe', 12, 4.5, 9.5, 'Mały talerz rynnowy o twardym dnie i stromych piaszczystych zboczach.', 'Twarde: jasny piasek krasowy i żwir polodowcowy.', 'Wysoka, woda bardzo czysta i przejrzysta przez cały sezon.', 'Umiarkowana: wąski pas trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem drapieżnika.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80886, 'Eutroficzne / Poleskie', 70, 1.1, 2.5, 'Płaska niecka, liczne naniesienia połączone z kanałem Wieprz-Krzna.', 'Miękkie i muliste; dno wyścielone grubą warstwą detrytusu.', 'Niska; latem mętna z powodu nagrzewania wody i wegetacji.', 'Bardzo obfita: gigantyczne trzcinowiska, rdestnica, wywłócznik.', 'Karp, Amur, Lin, Szczupak, Leszcz', TRUE, 'Intensywne zarybienia karpiem przez PZW i gospodarstwo.', TRUE, 'Składki PZW Lublin / G.R. Tyśmienica.', FALSE, FALSE, 'Średnia; dostępne wyznaczone stanowiska w pasie trzcin.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi; wietrzny teren.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80859, 'Polodowcowe rynnowe (zarośnięte)', 28, 3.8, 8.5, 'Długa, wąska rynna leśna o zróżnicowanej głębokości i przeszkodach.', 'Mieszane: piasek u brzegów, mulisty szlam organiczny w rynnie.', 'Dobra do średniej; woda o leśnym charakterze, chłodna w głębi.', 'Bujna: gęste trzcinowiska, liczne powalone kłody dębów i sosen.', 'Szczupak, Płoć, Okoń, Wzdręga, Lin', TRUE, 'Ochrona naturalna; okresowe zarybienia szczupakiem i białą rybą.', TRUE, 'Zezwolenia PZW Olsztyn.', FALSE, TRUE, 'Trudna przez gęsty las; ograniczone dojście do krawędzi wody.', FALSE, TRUE, 'Wąskie drogi pożarowe; piaszczyste wjazdy leśne.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80860, 'Polodowcowe rynnowe', 14, 4.2, 9.8, 'Wyraźna centralna rynna, strome piaszczyste skarpy, twarde podłoże.', 'Twarde: jasny piasek i żwir polodowcowy, mało osadów w osi rynny.', 'Wysoka, woda bardzo czysta, leśny charakter o dobrym natlenieniu.', 'Skąpa: wąski pierścień trzcin, podwodne łąki ramienic na stokach.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem szczupaka przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, TRUE, 'Średnia przez wysokie skarpy i gęsty las; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony dla niskich aut.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80861, 'Rynnowe eutroficzne', 18, 3.5, 7.5, 'Regularna rynna, piaszczyste wypłycenia, dno pofałdowane w części środkowej.', 'Mieszane: piasek u brzegów, miękki muł organiczny w głębi.', 'Dobra do średniej; woda przejrzysta wiosną, latem możliwe zakwity alg.', 'Bogata: gęste trzcinowiska, rdestnica na podwodnych spadach, grążele.', 'Lin, Szczupak, Okoń, Płoć, Karaś', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą przez okręg PZW.', TRUE, 'Standardowe zezwolenia PZW Olsztyn.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom; kładki.', TRUE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami; parkingi leśne.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80862, 'Eutroficzne rynnowe', 12, 2.5, 5.8, 'Wąska centralna rynna, łagodne piaszczyste stoki, silnie zamulone koryto.', 'Mieszane: piasek u brzegów, mulisty szlam organiczny w osi głównej.', 'Średnia; okresowo zakwita w lecie; żyzna woda o odcieniu zielonkawym.', 'Ekstremalna: szerokie i gęste pasy trzcinowisk wokół niemal całego jeziora.', 'Lin, Szczupak, Karaś srebrzysty, Leszcz, Płoć', TRUE, 'Regularne zarybienia szczupakiem i białą rybą przez PZW Olsztyn.', TRUE, 'Zezwolenia PZW Olsztyn dostępne online; opłata roczna/okresowa.', FALSE, TRUE, 'Trudna przez zwarty trzcinowiec; wymaga łodzi lub woderów.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami z Bartołt.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80863, 'Rynnowe sielawowe (głębokie)', 148, 11.5, 32.5, 'Głęboka centralna rynna, gwałtowne uskoki krasowe, liczne górki podwodne.', 'Bardzo twarde: piasek krasowy, glina i skały polodowcowe.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca technikom opadowym.', 'Skąpa: wąski pas trzcin, roślinność podwodna kończy się gwałtownie.', 'Sandacz, Sielawa, Szczupak pelagiczny, Okoń, Leszcz', TRUE, 'Systematyczne zarybienia sandaczem i sielawą przez PZW Olsztyn.', TRUE, 'Licencja PZW Olsztyn; obowiązuje bezwzględna strefa ciszy.', FALSE, TRUE, 'Średnia przez wysokie skarpy; wyznaczone liczne kładki i pomosty.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy do Bartołt Wielkich.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80864, 'Rynnowe małe (czyste)', 10, 3.8, 8.2, 'Mały talerz rynnowy o twardym dnie i stromych piaszczystych skarpach.', 'Twarde: jasny piasek krasowy i żwir polodowcowy, brak mułu.', 'Wysoka, woda bardzo czysta i przejrzysta przez cały sezon letni.', 'Umiarkowana: wąski pas trzcin, podwodne kępy moczarki kanadyjskiej.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem drapieżnika przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn; taryfy okresowe online.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i urokliwym leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami; parkingi w borze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80865, 'Rynnowe wąskie', 22, 6.5, 19.5, 'Wyraźna centralna rynna o twardym dnie i bardzo stromych zboczach.', 'Twarde: piaszczysto-żwirowe, cienka warstwa osadów w osi głęboczka.', 'Wysoka, woda bardzo czysta i przejrzysta przez cały sezon.', 'Skąpa: wąski pas trzciny pospolitej, roślinność podwodna tylko punktowo.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo przez okręg PZW Olsztyn.', TRUE, 'Standardowe składki PZW Olsztyn; wymagana karta wędkarska.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom; wydeptane punkty.', FALSE, TRUE, 'Dojazd drogami leśnymi i polnymi, utwardzonymi szutrami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80866, 'Rynnowe przepływowe', 128, 5.8, 17.5, 'Urozmaicona batymetria, liczne podwodne górki, koryto rzeki Pisy.', 'Zróżnicowane: twardy piasek, glina, lokalnie osady muliste w zatokach.', 'Dobra do średniej; woda doskonale natleniona dzięki przepływowi rzeki.', 'Umiarkowana: pasy trzcin na brzegach, moczarka kanadyjska na spadkach.', 'Szczupak, Sandacz, Leszcz, Okoń, Płoć', TRUE, 'Intensywne zarybienia sandaczem i drapieżnikiem przez PZW Olsztyn.', TRUE, 'Standardowe składki PZW Olsztyn; obowiązuje strefa ciszy.', FALSE, TRUE, 'Bardzo dobra; liczne plaże, pomosty i kładki w miejscowości Tumiany.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi i slipy betonowe.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80867, 'Eutroficzne podmiejskie', 25, 2.5, 6.2, 'Misa jeziorna o łagodnych spadkach, dno piaszczysto-muliste bez uskoków.', 'Mieszane: piasek w litoralu, miękki muł organiczny w środkowej części.', 'Średnia, typowa dla jezior żyznych; okresowo mętna w pełni lata.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, lilie wodne.', 'Lin, Karaś srebrzysty, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem przez PZW Olsztyn.', TRUE, 'Standardowe składki PZW Olsztyn; zezwolenia w Barczewie.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i wygodnym kładkom.', TRUE, TRUE, 'Bardzo dobry dojazd drogami szutrowymi i polnymi z Ruszajn.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80868, 'Dystroficzne (bagienne)', 8, 1.2, 3.5, 'Płaski talerz otoczony bagnem, dno bez wyraźnych urozmaiceń batymetrycznych.', 'Bardzo miękkie, płynny muł organiczny i głęboki osad torfowy.', 'Niska, woda o charakterystycznym ciemnym (herbacianym) odcieniu.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce, grążele żółte.', 'Lin, Karaś pospolity, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych, stabilna populacja dzikich ryb puszczańskich.', TRUE, 'Licencja PZW Olsztyn; zezwolenia okresowe dostępne online.', FALSE, TRUE, 'Ekstremalnie trudna przez bagno; wymagane kładki lub lekki ponton.', FALSE, TRUE, 'Trudny dojazd wąskimi ścieżkami leśnymi; brak oficjalnych parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80870, 'Polodowcowe rynnowe', 40, 5.2, 14.5, 'Regularna rynna w osi jeziora, strome piaszczyste skarpy, twarde dno.', 'Twarde: jasny piasek i żwir puszczański, mało osadów organicznych.', 'Wysoka, woda krystalicznie czysta, leśny charakter o dobrym natlenieniu.', 'Skąpa: wąski pierścień trzcin, podwodne kępy rdestnicy na spadkach.', 'Okoń, Szczupak, Płoć sielawowa, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem drapieżnika przez PZW.', TRUE, 'Standardowe składki PZW Suwałki; obowiązuje karta wędkarska.', FALSE, TRUE, 'Średnia przez wysokie skarpy i gęsty las; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony dla niskich aut.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80871, 'Eutroficzne', 28, 2.2, 5, 'Misa jeziorna o łagodnych spadkach, dno muliste bez uskoków.', 'Miękkie: muł organiczny i bentos, piaszczyste pasy przy brzegach.', 'Średnia, typowa dla jezior żyznych; okresowo zakwita w lecie.', 'Bardzo obfita: gęste trzcinowiska, szerokie połacie grążeli żółtych.', 'Lin, Leszcz, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami spokojnego żeru i szczupakiem przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn; zezwolenia okresowe online.', FALSE, FALSE, 'Bardzo dobra dzięki licznym dzikim stanowiskom i pomostom.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy w Kruklankach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80872, 'Rynnowe', 35, 6.5, 18.5, 'Wyraźna centralna rynna, strome piaszczysto-gliniaste stoki.', 'Twarde: piasek i glina, cienka warstwa osadów w osi rynny.', 'Dobra; woda przejrzysta wiosną, latem możliwe okresowe zakwity alg.', 'Umiarkowana: pasy trzcin, rdestnica i moczarka na podwodnych spadach.', 'Sandacz, Okoń, Szczupak, Leszcz, Płoć', TRUE, 'Systematyczne zarybienia sandaczem i drapieżnikiem przez okręg PZW.', TRUE, 'Standardowe zezwolenia PZW Olsztyn dostępne w Kruklankach.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom; wydeptane punkty.', FALSE, TRUE, 'Dojazd drogami szutrowymi i polnymi; parkingi leśne.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80873, 'Rynnowe sielawowe (głębokie)', 115, 14.5, 42, 'Głęboka centralna rynna, gwałtowne uskoki krasowe, liczne górki.', 'Bardzo twarde: piasek krasowy, żwir i skały polodowcowe.', 'Ekstremalnie wysoka (I klasa), widoczność do kilku metrów.', 'Skąpa: wąski pas trzcin, roślinność podwodna kończy się gwałtownie.', 'Sielawa, Szczupak pelagiczny, Okoń sielawowy, Płoć', TRUE, 'Systematyczne zarybienia sandaczem i sielawą przez PZW Olsztyn.', TRUE, 'Licencja Gospodarstwa Rybackiego / PZW; bezwzględna strefa ciszy.', FALSE, TRUE, 'Utrudniona przez wysokie skarpy; wędkowanie głównie z łodzi.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy; parkingi przy ośrodkach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80874, 'Polodowcowe rynnowe', 42, 5.8, 12.5, 'Urozmaicona batymetria, strome piaszczyste spady, dno twarde.', 'Twarde: jasny piasek i drobny żwir polodowcowy, mało mułu.', 'Wysoka, woda bardzo czysta, surowy charakter północny.', 'Skąpa: wąski pierścień trzcin, podwodne łąki ramienic na stokach.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW Suwałki.', TRUE, 'Standardowe składki PZW Suwałki; opłaty okresowe online.', FALSE, FALSE, 'Średnia przez strome brzegi; wyznaczone stanowiska gruntowe.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi; wietrzny teren.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80875, 'Eutroficzne podmiejskie', 15, 2.5, 5.5, 'Niecka o łagodnych spadkach, dno piaszczysto-muliste bez uskoków.', 'Mieszane: piasek w litoralu, miękki muł organiczny w głębi.', 'Średnia, typowa dla jezior żyznych; okresowo mętna w lecie.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, grążele żółte.', 'Lin, Karaś srebrzysty, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem przez PZW Suwałki.', TRUE, 'Standardowe składki PZW Suwałki; zezwolenia w Rutce-Tartak.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i wygodnym dojścom.', FALSE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80876, 'Eutroficzne wytopiskowe', 10, 2.8, 6.2, 'Misa jeziorna o łagodnych spadkach, dno muliste, wyrównane.', 'Miękkie i muliste; dno wyścielone osadem roślinnym i bentosem.', 'Średnia; typowa dla małych akwenów śródpolnych, cieplejsza woda.', 'Bardzo obfita: jezioro silnie zarastające grążelem i rogatkiem.', 'Lin, Karaś, Szczupak, Płoć', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe zezwolenia PZW Suwałki dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom brzegowym; zacisznie.', FALSE, TRUE, 'Dojazd drogami polnymi, utwardzony szutrem.', TRUE);
