INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80880, 'Rynnowe przepływowe (czyste)', 22, 4.5, 10.5, 'Regularna rynna, nurt rzeki Szeszupy, twarde piaszczyste spady.', 'Twarde: jasny piasek i drobny żwir rzeczny, brak mułu w nurcie.', 'Ekstremalnie wysoka (I klasa), woda krystaliczna przez cały rok.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Okoń, Jaź, Szczupak, Płoć, Leszcz', TRUE, 'Ochrona tarlisk rzeczny przez SPK; okresowe wsparcie narybkiem.', TRUE, 'Specjalna licencja PZW Suwałki + regulamin Parku.', FALSE, TRUE, 'Średnia przez strome brzegi; wyznaczone punkty brzegowe.', TRUE, TRUE, 'Dojazd drogami szutrowymi SPK; malownicze parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80881, 'Eutroficzne (dzikie)', 12, 2.2, 5.8, 'Płaski talerz, dno bez urozmaiceń, bagniste strefy litoralu.', 'Bardzo miękkie: muł organiczny i osady bagienne.', 'Średnia do niskiej; woda żyzna, o leśnym charakterze.', 'Ekstremalna: szerokie pasy trzcin, lilie wodne, moczarka.', 'Lin, Karaś, Szczupak leśny, Płoć', TRUE, 'Brak zarybień sztucznych; całkowicie naturalny rybostan.', TRUE, 'Standardowe zezwolenia PZW Suwałki.', FALSE, TRUE, 'Trudna przez trzęsawiska; wymagane wodery lub ponton.', FALSE, TRUE, 'Utrudniony dojazd drogami polnymi po opadach.', FALSE);
