INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80883, 'Rynnowe (czyste)', 14, 3.8, 10.2, 'Regularna rynna leśna o twardym dnie i stromych zboczach.', 'Twarde: jasny piasek i żwir polodowcowy, brak mułu.', 'Wysoka (I klasa), woda krystalicznie czysta, sprzyjająca okoniom.', 'Skąpa: wąski pierścień trzcin, roślinność podwodna na spadkach.', 'Okoń, Płoć, Szczupak, Leszcz', TRUE, 'Naturalna ochrona drapieżnika; okresowe zarybienia drapieżnikiem.', TRUE, 'Licencja PZW Suwałki; obowiązuje strefa ciszy SPK.', FALSE, TRUE, 'Średnia przez wysokie skarpy; wyznaczone punkty Parku.', FALSE, TRUE, 'Dojazd drogami szutrowymi i leśnymi SPK.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80884, 'Eutroficzne / Poleskie', 25, 0.9, 2, 'Płaski talerz, dno bez urozmaiceń, silnie zarastające.', 'Bardzo miękkie: głęboki muł torfowy i osady organiczne.', 'Niska, woda o brunatnym odcieniu, okresowo mętna.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Głównie naturalny rozród, okresowe wsparcie narybkiem lina.', TRUE, 'Standardowe składki PZW Lublin.', FALSE, FALSE, 'Bardzo trudna przez bagno; wymagane wodery lub ponton.', FALSE, TRUE, 'Dojazd polny, utrudniony po opadach; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80887, 'Eutroficzne', 18, 1.5, 3.2, 'Misa o łagodnych spadkach dna, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł w środkowej części.', 'Średnia, typowa dla płytkich jezior żyznych; okresowo zakwita.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, grążele.', 'Płoć, Leszcz, Szczupak, Lin, Okoń', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Lublin.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', TRUE, TRUE, 'Dobry dojazd drogami polnymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80889, 'Dystroficzne (bagienne)', 12, 1.2, 2.5, 'Płaski talerz otoczony bagnem, dno bez urozmaiceń batymetrycznych.', 'Bardzo miękkie, płynny muł organiczny i głęboki osad torfowy.', 'Niska, woda o ciemnym (brunatnym) odcieniu humusowym.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce, grążele.', 'Lin, Karaś złoty, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych, całkowicie naturalny rybostan.', TRUE, 'Standardowe składki PZW Biała Podlaska.', FALSE, TRUE, 'Ekstremalnie trudna przez bagno; wymagane kładki lub ponton.', FALSE, TRUE, 'Trudny dojazd wąskimi ścieżkami leśnymi; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80890, 'Antropogeniczne (żwirownia)', 45, 4.5, 12, 'Bardzo urozmaicone: uskoki, twarde blaty, głębokie rynny poeksploatacyjne.', 'Twarde: żwir i piasek, marginalna ilość mułu w zatokach.', 'Wysoka, woda czysta i dobrze natleniona przez cały rok.', 'Skąpa: punktowe pasy trzcin i rzadka moczarka na dnie.', 'Okoń, Sandacz, Karp, Amur, Szczupak', TRUE, 'Intensywne zarybienia okręgowe i dbanie o rybostan okazowy.', TRUE, 'Zezwolenia PZW Biała Podlaska; możliwe opłaty okresowe.', FALSE, FALSE, 'Bardzo dobra dzięki wysokim brzegom i licznym stanowiskom.', TRUE, TRUE, 'Bardzo dobry dojazd utwardzony, parkingi przy zbiorniku.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80891, 'Starorzecze (rzeczne)', 15, 2.2, 4.5, 'Rynnowe koryto dawnej rzeki, liczne zatory i powalone drzewa.', 'Mulisto-piaszczyste, twarde dno w miejscach dawnego nurtu.', 'Średnia; zależna od poziomu wody w rzece Bug (wylewy).', 'Bogata: gęste trzcinowiska, lilie wodne, liczne zwaliska dębów.', 'Sandacz, Szczupak, Jaź, Leszcz, Kleń', TRUE, 'Zależne od corocznych wylewów rzeki Bug; naturalna migracja.', TRUE, 'Standardowe składki PZW Biała Podlaska; zgłoszenie SG.', FALSE, FALSE, 'Dobra w wyznaczonych punktach brzegowych; strome skarpy.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi; malownicze tereny.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80892, 'Pożwirowe', 25, 3.5, 6.2, 'Urozmaicone: podwodne wyspy, uskoki po wydobyciu, blaty żwirowe.', 'Twarde: żwir i piasek, lokalnie cienka warstwa osadów organicznych.', 'Dobra; woda przejrzysta dzięki filtracji żwirowej, natleniona.', 'Umiarkowana: rzadkie pasy trzcin, podwodne kępy rdestnicy.', 'Szczupak, Okoń, Amur, Karp, Płoć', TRUE, 'Regularne zarybienia drapieżnikiem i rybami białymi przez PZW.', TRUE, 'Standardowe składki PZW Katowice.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska z łatwym dojściem do wody.', TRUE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80894, 'Pożwirowe małe', 12, 2.5, 4.2, 'Regularna misa z łagodnymi spadkami dna, brak wyraźnych rynien.', 'Twarde: żwirowe z grubszą warstwą mułu w zatokach leśnych.', 'Średnia; latem możliwe lekkie zakwity alg w cieplejszej wodzie.', 'Bogata: gęste trzcinowiska, liczne skupiska grążeli żółtych.', 'Lin, Karaś pospolity, Szczupak, Płoć, Leszcz', TRUE, 'Głównie naturalny rozród wspierany okresowo narybkiem lina.', TRUE, 'Składki PZW Katowice dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym wydeptanym stanowiskom i łagodnym zejściom.', TRUE, TRUE, 'Dobry dojazd drogami polnymi i utwardzonymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80895, 'Pożwirowe (techniczne)', 45, 4.5, 8.5, 'Bardzo urozmaicone: głębokie rynny, twarde kanty, uskoki techniczne.', 'Bardzo twarde: czysty żwir i lita glina, brak mułu w rynnach.', 'Wysoka, woda przejrzysta przez większą część sezonu.', 'Skąpa: wąski pas trzcin, mało roślinności podwodnej na spadkach.', 'Sandacz, Szczupak, Karp, Okoń, Leszcz', TRUE, 'Intensywne zarybienia sandaczem i drapieżnikiem przez okręg.', TRUE, 'Zezwolenia PZW Katowice; wymagana karta wędkarska.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska z bezpośrednim dojazdem aut.', TRUE, TRUE, 'Bardzo dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80896, 'Pożwirowe małe', 10, 2.2, 3.8, 'Pofalowana niecka z licznymi zatokami i płytkimi piaszczystymi łachami.', 'Mieszane: piasek w litoralu, żwirowe podłoże w środkowej części.', 'Średnia, typowa dla jezior żyznych; okresowo mętna latem.', 'Bogata: pasy trzcin, moczarka kanadyjska, rdestnica pływająca.', 'Leszcz, Płoć, Szczupak, Okoń, Karaś', TRUE, 'Systematyczne zarybienia białą rybą przez lokalne koło PZW.', TRUE, 'Standardowe zezwolenia PZW Katowice.', FALSE, FALSE, 'Bardzo dobra dzięki licznym stanowiskom i piaszczystym plażom.', TRUE, TRUE, 'Dobry dojazd drogami polnymi i utwardzonymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80898, 'Pożwirowe głębokie', 38, 5.2, 9.5, 'Głębokie centralne rynny o stromych zboczach, dno twarde.', 'Bardzo twarde: gruby żwir i kamienie, marginalna ilość osadów.', 'Wysoka, woda czysta, chłodna w głębi rynny głównej.', 'Znikoma: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Szczupak, Sandacz, Karp, Okoń, Leszcz', TRUE, 'Zarybienia drapieżnikiem rynnowym i karpiem przez PZW.', TRUE, 'Standardowe składki PZW Katowice.', FALSE, FALSE, 'Średnia przez strome brzegi; wyznaczone główne dojścia.', FALSE, TRUE, 'Dobry dojazd drogami szutrowymi pod sam zbiornik.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80899, 'Pożwirowe małe', 8, 2.8, 5.2, 'Mała niecka o łagodnych spadkach, twarde piaszczyste podłoże.', 'Twarde: jasny piasek i żwir, brak grubszego mułu.', 'Wysoka, woda bardzo czysta i przejrzysta przez cały sezon.', 'Umiarkowana: wąski pierścień trzcin, kępy moczarki kanadyjskiej.', 'Okoń, Karaś srebrzysty, Płoć, Szczupak, Wzdręga', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Zezwolenia PZW Katowice dostępne w sklepach i online.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska brzegowe i dojścia piaszczyste.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80900, 'Pożwirowe głębokie', 28, 6.5, 10.5, 'Głęboki rów o bardzo stromych stokach, liczne podwodne uskoki.', 'Bardzo twarde: lity żwir kopalniany, kamienie, brak osadów.', 'Ekstremalnie wysoka, krystaliczna toń sprzyjająca spinningowi.', 'Skąpa: wąski pas trzcin, roślinność podwodna kończy się gwałtownie.', 'Sandacz, Szczupak, Okoń, Karp amur, Płoć', TRUE, 'Intensywne zarybienia sandaczem i sielawą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Katowice; karta wędkarska.', FALSE, FALSE, 'Trudna przez wysokie skarpy; wyznaczone pojedyncze punkty.', TRUE, TRUE, 'Dojazd drogami szutrowymi i polnymi; utwardzone wjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80901, 'Antropogeniczne (żwirownia)', 78, 4.8, 12.5, 'Bardzo urozmaicone: liczne wyspy, zatoki, głębokie rynny i blaty.', 'Twarde: żwir i piasek, lokalnie warstwa mułu w starych rynnach.', 'Średnia do dobrej; woda żyzna, doskonale natleniona przez wiatr.', 'Umiarkowana: pasy trzcin wokół wysp, podwodne łąki moczarki.', 'Karp, Amur, Sandacz, Sum, Okoń', TRUE, 'Rekordowe zarybienia karpiem i sumem; dbanie o rybostan okazowy.', TRUE, 'Zezwolenia PZW Opole; możliwe specjalne opłaty okresowe.', FALSE, FALSE, 'Bardzo dobra dzięki przygotowanym stanowiskom i infrastrukturze.', TRUE, TRUE, 'Bardzo dobry dojazd utwardzony i asfaltowy; parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80902, 'Pożwirowe (linowe)', 15, 1.8, 3.5, 'Płytka misa o łagodnych spadkach, dno wyrównane, silnie zarastające.', 'Miękkie: żwir przykryty warstwą mułu i osadów organicznych.', 'Niska; typowa dla jezior żyznych; okresowo mętna latem.', 'Bardzo obfita: gęste trzcinowiska, lilie wodne, moczarka.', 'Lin, Karaś złoty, Szczupak, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu linem.', TRUE, 'Standardowe zezwolenia PZW Opole.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom w pasie trzcinowisk.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi Bierawy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80903, 'Eutroficzny staw dolinowy', 15, 0.9, 1.8, 'Płaski talerz, dno bez uskoków, silnie zarastające.', 'Bardzo miękkie, głęboki muł organiczny i detrytus roślinny.', 'Niska, woda mętna, żyzna, okresowo zakwita latem.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina.', TRUE, 'Standardowe składki PZW Wrocław.', FALSE, TRUE, 'Trudna przez bagno; wymagane kładki lub wodery.', FALSE, FALSE, 'Dojazd polny, utrudniony po opadach deszczu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80904, 'Staw paciorkowy', 22, 1.2, 2.5, 'Regularna niecka z wyraźnym korytem przepływowym na dnie.', 'Mieszane: piasek w osi przepływu, muł w zatokach.', 'Średnia do niskiej, woda żyzna, dobrze natleniona przez wiatr.', 'Bogata: pasy trzcin, rogatek, grążele żółte w zatokach.', 'Karp, Leszcz, Szczupak, Okoń, Płoć', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez PZW.', TRUE, 'Składki PZW Wrocław dostępne w Miliczu i online.', FALSE, FALSE, 'Bardzo dobra wzdłuż grobli; twarde piaszczyste stanowiska.', TRUE, TRUE, 'Dobry dojazd drogami utwardzonymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80906, 'Staw hodowlany / wędkarski', 18, 1.1, 2, 'Płaska niecka o regularnych kształtach, dno piaszczysto-muliste.', 'Przeważnie miękkie z twardymi piaszczystymi łachami.', 'Niska, typowa dla zbiorników intensywnie użytkowanych.', 'Umiarkowana: wąski pas trzcin, rzadka roślinność podwodna.', 'Karp, Amur, Leszcz, Szczupak, Karaś', TRUE, 'Rekordowe zarybienia karpiem; dbanie o rybostan okazowy.', TRUE, 'Standardowe zezwolenia PZW / Stawy Milickie.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska z łatwym zejściem.', FALSE, TRUE, 'Bardzo dobry dojazd utwardzony, parkingi przy groblach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80907, 'Eutroficzny staw leśny', 12, 1.3, 2.2, 'Łagodne spadki, dno wyrównane z centralnym korytem.', 'Miękkie i muliste; dno wyścielone grubą warstwą osadów.', 'Średnia, woda o lekkim odcieniu brunatnym (humusowa).', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, lilie.', 'Płoć, Leszcz, Sandacz, Szczupak, Lin', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą.', TRUE, 'Zezwolenia PZW Wrocław dostępne online.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, FALSE, 'Dojazd leśny, piaszczysty; parkingi przy wjazdach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80908, 'Staw paciorkowy (Natura 2000)', 45, 1, 2, 'Rozległa, płytka misa, liczne mielizny i wyspy zielne.', 'Wybitnie miękkie, muł organiczny i torf.', 'Niska; woda mętna, silnie mącona przez żerujące karpie.', 'Bardzo obfita: gigantyczne pasy trzcinowisk, lilia wodna.', 'Amur, Karp, Szczupak, Lin, Krąp', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu amurem.', TRUE, 'Specjalne zezwolenie PZW + regulamin ochronny.', FALSE, TRUE, 'Średnia; dostępne stanowiska na groblach i kładkach.', TRUE, FALSE, 'Dojazd drogami polnymi i szutrowymi; zakaz silników.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80909, 'Staw paciorkowy stary', 20, 1.4, 2.5, 'Urozmaicona rzeźba, liczne zatoki i zatopione korzenie dębów.', 'Miękkie i muliste; bogate w bentos i osady organiczne.', 'Średnia do niskiej; okresowo mętna z powodu nagrzewania.', 'Bardzo bogata: gęste trzcinowiska, grążele żółte, rogatek.', 'Lin, Karaś pospolity, Okoń, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina.', TRUE, 'Standardowe składki PZW Wrocław.', FALSE, TRUE, 'Dobra dzięki licznym dzikim stanowiskom i groblom.', TRUE, FALSE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80885, 'Eutroficzny staw polny', 14, 1.2, 1.8, 'Misa o łagodnych spadkach dna, dno piaszczysto-muliste.', 'Mieszane: piasek w osi dopływu, miękki muł w osadnikach.', 'Średnia, typowa dla płytkich zbiorników żyznych.', 'Umiarkowana: pasy trzcin, liczne połacie roślinności miękkiej.', 'Leszcz, Karp, Płoć, Szczupak, Karaś', TRUE, 'Regularne zarybienia białą rybą przez lokalne koło.', TRUE, 'Standardowe zezwolenia PZW Wrocław.', FALSE, FALSE, 'Dobra dzięki wysokim brzegom i łatwym wejściom.', FALSE, FALSE, 'Dojazd drogami utwardzonymi pod samo lustro wody.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80910, 'Eutroficzny staw śródpolny', 16, 1.5, 2.5, 'Regularna niecka, dno wyrównane bez wyraźnych rynien.', 'Mieszane: piasek w litoralu, muł w części centralnej.', 'Średnia do dobrej; woda dobrze natleniona przez wiatr.', 'Bogata: pasy trzcin, liczne lilie wodne i moczarka.', 'Okoń, Szczupak, Płoć, Wzdręga, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i wsparcie PZW.', TRUE, 'Zezwolenia PZW Wrocław dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80911, 'Staw przepływowy', 10, 0.8, 1.5, 'Rynnowe koryto przepływowe, twarde dno w osi nurtu.', 'Twarde: piaszczysto-kamieniste, lokalnie warstwa mułu.', 'Średnia; dobrze natleniona dzięki przepływowi rzeki.', 'Bogata: gęste trzcinowiska, roślinność prądolubna w nurcie.', 'Jaź, Kleń, Płoć, Szczupak, Lin', TRUE, 'Naturalny napływ ryb rzecznych, zarybienia drapieżnikiem.', TRUE, 'Standardowe składki PZW Wrocław; zezwolenia okresowe.', FALSE, FALSE, 'Dobra; liczne stanowiska tuż przy drodze lokalnej.', FALSE, FALSE, 'Bardzo dobry dojazd asfaltowy i szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80913, 'Eutroficzny staw dolinowy', 12, 1.1, 1.8, 'Płaska niecka o regularnych spadkach dna, dno piaszczysto-muliste.', 'Mieszane: piasek w osi dopływu, miękki muł w strefach osadowych.', 'Średnia, typowa dla płytkich zbiorników żyznych; okresowo mętna.', 'Bogata: pasy trzcin wzdłuż nasypu, moczarka kanadyjska, rdestnica.', 'Karp, Płoć, Szczupak, Leszcz', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez zarządcę.', TRUE, 'Standardowe składki PZW Wrocław + regulamin Stawów Milickich.', FALSE, FALSE, 'Bardzo dobra dzięki zagospodarowanym brzegom i ścieżkom.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy i szutrowy pod sam akwen.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80914, 'Staw po-hodowlany leśny', 8, 1.2, 2, 'Niecka o twardym dnie z licznymi podwodnymi korzeniami dębów.', 'Twarde: piaszczysto-żwirowe z cienką warstwą osadów organicznych.', 'Dobra; woda przejrzystsza dzięki twardemu podłożu i filtracji leśnej.', 'Umiarkowana: pasy trzcin, liczne powalone drzewa w litoralu.', 'Lin, Okoń, Karaś, Płoć, Szczupak', TRUE, 'Systematyczne zarybienia linem i karasiem przez lokalne koło.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i wydeptanym stanowiskom.', FALSE, FALSE, 'Dojazd drogami szutrowymi i leśnymi; parkingi przy wjazdach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81745, 'Eutroficzne (duże)', 640, 4.5, 21, 'Urozmaicona, wyspy, blaty', 'Mieszane', 'Wysoka', 'Bardzo bogata', 'Szczupak, Lin, Leszcz, Okoń', TRUE, 'Intensywne gospodarcze', TRUE, 'Licencja G.R. Bogucin', FALSE, FALSE, 'Wyśmienita poza plażami', TRUE, TRUE, 'Asfaltowa/Miejska', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80915, 'Eutroficzny staw hodowlany', 45, 1.3, 2.5, 'Rozległa misa o regularnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek na wypłyceniach, miękki muł organiczny w głębi.', 'Średnia do niskiej; woda żyzna, mącona przez żerujące ryby.', 'Bogata: szerokie pasy trzcinowisk, liczne latorośla podwodne.', 'Karp, Amur, Szczupak, Leszcz, Płoć', TRUE, 'Rekordowe zarybienia karpiem; dbanie o rybostan okazowy.', TRUE, 'Składki PZW Wrocław; wymagana karta wędkarska i zezwolenie.', FALSE, FALSE, 'Bardzo dobra wzdłuż twardych grobli; liczne stanowiska.', FALSE, FALSE, 'Dobry dojazd drogami utwardzonymi i szutrowymi groblami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80916, 'Eutroficzny staw (tarlisko)', 10, 0.9, 1.5, 'Płaski talerz, dno bez uskoków, silnie zarastające roślinnością.', 'Bardzo miękkie: głęboki muł organiczny i detrytus roślinny.', 'Niska, woda mętna i żyzna, szybko nagrzewająca się wiosną.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką kanadyjską.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina.', TRUE, 'Standardowe zezwolenia PZW / Stawy Milickie.', FALSE, TRUE, 'Średnia; dostępne kilka wydeptanych stanowisk w trzcinach.', FALSE, FALSE, 'Dojazd polny, utrudniony po opadach; brak oficjalnych parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80917, 'Eutroficzny staw śródpolny', 15, 1.4, 2.2, 'Misa o łagodnych spadkach, twarde piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, muł w częściach centralnych.', 'Dobra; woda przejrzystsza niż w stawach produkcyjnych.', 'Bogata: pasy trzcin, liczne grążele żółte, moczarka kanadyjska.', 'Okoń, Szczupak, Płoć, Wzdręga, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i wsparcie białorybem.', TRUE, 'Standardowe składki PZW Wrocław dostępne w Miliczu.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', FALSE, FALSE, 'Dojazd drogami polnymi i szutrowymi; wietrzny teren.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80893, 'Staw paciorkowy (Natura 2000)', 35, 1, 1.8, 'Rozległa, płytka misa, liczne mielizny i korytarze zielne.', 'Wybitnie miękkie, muł organiczny i torf, bogaty bentos.', 'Niska; woda mętna, silnie mącona przez żerujące ryby ryjące.', 'Bardzo obfita: gigantyczne pasy trzcinowisk, lilia wodna.', 'Karp, Szczupak, Lin, Krąp, Leszcz', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu karpiem.', TRUE, 'Specjalne zezwolenie PZW + regulamin Doliny Baryczy.', FALSE, TRUE, 'Średnia; dostępne wyznaczone stanowiska na groblach.', TRUE, FALSE, 'Dojazd drogami polnymi i szutrowymi; zakaz silników.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80919, 'Staw tarliskowy (mały)', 6, 0.7, 1.2, 'Płytka niecka o miękkim dnie, brak wyraźnych uskoków.', 'Bardzo miękkie, płynny muł organiczny i osady bagienne.', 'Niska, woda o ciemnym odcieniu, okresowo mętna i żyzna.', 'Ekstremalna: bagniste brzegi, trzciny, moczarka, grążele.', 'Lin, Karaś złoty, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych, całkowicie naturalna reprodukcja.', TRUE, 'Licencja PZW Wrocław / Stawy Milickie; surowe limity.', FALSE, TRUE, 'Ekstremalnie trudna; wymagane wodery lub kładki deszczowe.', FALSE, FALSE, 'Trudny dojazd wąskimi ścieżkami; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80920, 'Staw rezerwatowy (dziki)', 18, 1.2, 1.8, 'Płaska misa z centralnym korytem korytowym, dno zamulone.', 'Bardzo miękkie, muł organiczny i osady torfowe (humusowe).', 'Niska; woda o charakterystycznym ciemnobrunatnym odcieniu.', 'Bardzo obfita: gęste trzcinowiska, rdestnica, moczarka.', 'Lin, Szczupak, Karaś złoty, Płoć, Leszcz', TRUE, 'Naturalna ochrona drapieżnika; stabilna populacja lina.', TRUE, 'Zezwolenia PZW Wrocław; obowiązują strefy rezerwatu.', FALSE, TRUE, 'Trudna przez bagno i las; ograniczone do wyznaczonych punktów.', FALSE, FALSE, 'Dojazd leśny, utrudniony; parkingi oddalone od brzegu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80816, 'Eutroficzny staw polny', 8, 1.1, 1.6, 'Mała niecka o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł w osi głównej.', 'Średnia, typowa dla płytkich zbiorników żyznych.', 'Bogata: gęste trzcinowiska, liczne połacie roślinności miękkiej.', 'Lin, Wzdręga, Szczupak, Karaś, Płoć', TRUE, 'Regularne zarybienia rybami spokojnego żeru przez zarządcę.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, FALSE, 'Dobra dzięki twardym fragmentom grobli i wycięciom w trzcinach.', FALSE, FALSE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80921, 'Eutroficzny staw hodowlany', 38, 1.3, 2, 'Niecka o regularnych kształtach, wyrównane piaszczysto-muliste dno.', 'Przeważnie miękkie z twardymi piaszczystymi łachami na groblach.', 'Niska, typowa dla zbiorników intensywnie zarybianych.', 'Umiarkowana: wąski pas trzcin, rzadka roślinność podwodna.', 'Karp, Amur, Szczupak, Leszcz, Płoć', TRUE, 'Rekordowe zarybienia karpiem; dbanie o rybostan okazowy.', TRUE, 'Standardowe składki PZW Wrocław; taryfy okresowe.', FALSE, FALSE, 'Bardzo dobra wzdłuż twardych grobli; liczne stanowiska.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi groblami pod samo łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80922, 'Eutroficzny staw leśny', 12, 1.1, 1.8, 'Płytka niecka o łagodnych spadkach, brak wyraźnych uskoków i rynien.', 'Mieszane: piasek u brzegów, miękki muł organiczny w środkowej części.', 'Średnia, typowa dla płytkich zbiorników żyznych; okresowo mętna.', 'Bardzo obfita: gęste trzcinowiska, szerokie połacie grążeli żółtych.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina przez PZW.', TRUE, 'Standardowe składki PZW Wrocław + regulamin milicki.', FALSE, TRUE, 'Ograniczona przez gęstą roślinność; kilka wydeptanych stanowisk.', FALSE, FALSE, 'Drogi leśne, piaszczyste; utrudniony dojazd po opadach.', FALSE);
