INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80924, 'Dystroficzny staw leśny', 15, 1, 1.8, 'Płaska misa z centralnym przegłębieniem, dno silnie zamulone.', 'Bardzo miękkie, muł organiczny i gruby osad torfowy (humusowy).', 'Niska; woda o charakterystycznym ciemnobrunatnym odcieniu.', 'Bardzo obfita: gęste trzcinowiska, rdestnica, mchy torfowce.', 'Szczupak, Lin, Karaś złoty, Płoć', TRUE, 'Naturalna ochrona drapieżnika; stabilna populacja lina bagiennego.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, TRUE, 'Trudna przez bagno i las; ograniczone do wyznaczonych punktów.', FALSE, FALSE, 'Dojazd leśny, utrudniony; parkingi oddalone od brzegu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80925, 'Eutroficzny staw rynnowy', 18, 1.2, 2, 'Podłużna niecka z wyraźnym korytem przepływowym na dnie.', 'Mieszane: żwir przy mnichach, miękki muł w osi głównej.', 'Średnia do niskiej, woda żyzna, dobrze natleniona przez wiatry.', 'Bogata: pasy trzcin, rogatek, grążele żółte w spokojnych zatokach.', 'Leszcz, Płoć, Okoń, Szczupak, Karp', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez zarządcę.', TRUE, 'Standardowe składki PZW Wrocław; opłaty roczne/okresowe.', FALSE, FALSE, 'Bardzo dobra wzdłuż grobli; twarde piaszczyste stanowiska.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi groblami pod samo łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80969, 'Eutroficzne śródpolne', 14, 2.5, 5.5, 'Niecka o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł w osi głównej.', 'Średnia, typowa dla jezior żyznych; okresowo mętna w lecie.', 'Bogata: gęste trzcinowiska, lilie wodne, moczarka kanadyjska.', 'Płoć, Leszcz, Okoń, Szczupak, Krąp', TRUE, 'Regularne zarybienia rybami białymi przez okręg PZW.', TRUE, 'Standardowe zezwolenia PZW Poznań.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', FALSE, TRUE, 'Dobry dojazd drogami polnymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80926, 'Eutroficzny staw polny', 8, 1.1, 1.6, 'Mała niecka o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł w osi głównej.', 'Średnia, typowa dla płytkich zbiorników żyznych w Dolinie Baryczy.', 'Bogata: gęste trzcinowiska, liczne połacie roślinności miękkiej.', 'Lin, Karaś pospolity, Szczupak, Płoć, Krąp', TRUE, 'Regularne zarybienia rybami spokojnego żeru przez lokalne koło.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, FALSE, 'Dobra dzięki twardym fragmentom grobli i wycięciom w trzcinach.', FALSE, FALSE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80927, 'Eutroficzny staw hodowlany', 55, 1.4, 2.5, 'Rozległa misa o regularnych spadkach, liczne uskoki techniczne.', 'Przeważnie miękkie z twardymi piaszczystymi łachami na groblach.', 'Niska, typowa dla zbiorników intensywnie zarybianych i żyznych.', 'Umiarkowana: wąski pas trzcin, rzadka roślinność podwodna.', 'Karp, Amur, Szczupak, Leszcz, Płoć', TRUE, 'Rekordowe zarybienia karpiem; dbanie o rybostan okazowy PZW.', TRUE, 'Standardowe składki PZW Wrocław; taryfy okresowe online.', FALSE, FALSE, 'Bardzo dobra wzdłuż twardych grobli; liczne stanowiska rzutowe.', FALSE, FALSE, 'Bardzo dobry dojazd utwardzony, parkingi przy groblach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80928, 'Staw rezerwatowy (płytki)', 295, 0.8, 1.5, 'Gigantyczna płaska niecka, dno piaszczysto-muliste, bardzo płytkie.', 'Mieszane: piasek drobnoziarnisty, gruby muł w strefach trzcin.', 'Niska; woda mętna, silnie mącona przez falowanie i ptactwo.', 'Ekstremalna: gigantyczne trzcinowiska, wyspy zielne, rdestnice.', 'Amur, Karp, Szczupak, Lin, Krąp', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu amurem.', TRUE, 'Specjalne zezwolenie PZW + regulamin rezerwatu Grabownica.', FALSE, TRUE, 'Ograniczona do ściśle wyznaczonych stanowisk na groblach.', FALSE, FALSE, 'Dojazd drogami szutrowymi; parkingi przy wieżach widokowych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80841, 'Eutroficzny staw przepływowy', 14, 1.2, 2.2, 'Urozmaicona rzeźba, centralna rynna przepływowa, twarde dno.', 'Twarde: piaszczysto-żwirowe, cienka warstwa osadów organicznych.', 'Dobra; woda przejrzystsza dzięki twardemu podłożu i natlenieniu.', 'Średnio obfita: pasy trzcin, kępy grzybieni białych, rogatek.', 'Okoń, Szczupak, Płoć, Wzdręga, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i wsparcie białorybem.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne w Miliczu.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i groblom rzecznym.', FALSE, FALSE, 'Dojazd drogami szutrowymi groblami pod samo łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80929, 'Eutroficzny staw hodowlany', 18, 1.2, 1.8, 'Misa jeziorna o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek w litoralu, miękki muł w osi głównej.', 'Średnia, typowa dla jezior żyznych; okresowo zakwita w lecie.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, grążele żółte.', 'Lin, Leszcz, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem przez okręg.', TRUE, 'Standardowe składki PZW Wrocław; zezwolenia okresowe.', FALSE, FALSE, 'Dobra dzięki twardym groblom i wygodnym leśnym polanom.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi i polnymi z Grabownicy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80930, 'Eutroficzny staw otwarty', 12, 0.9, 1.4, 'Płytka niecka o wyrównanym dnie, brak wysokiej osłony brzegowej.', 'Głównie twardy piasek i żwir, marginalna ilość mułu osadowego.', 'Średnia do dobrej; woda doskonale natleniona przez wiatr.', 'Skąpa: punktowe kępy trzcin, mało roślinności zanurzonej.', 'Karp, Płoć, Szczupak, Karaś, Leszcz', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu karpiem.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, FALSE, 'Bardzo dobra; piaszczyste wejścia i stanowiska na groblach.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi groblami pod samo łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80931, 'Eutroficzny staw tarliskowy', 16, 1.1, 1.6, 'Płytka niecka o miękkim dnie, dno piaszczysto-muliste.', 'Bardzo miękkie, muł organiczny i osady detrytusowe roślinne.', 'Niska; typowa dla jezior żyznych; okresowo mętna i kwitnąca.', 'Bogata: gęste trzcinowiska, lilie wodne, moczarka kanadyjska.', 'Lin, Karaś złoty, Szczupak, Płoć, Leszcz', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe składki PZW Wrocław; taryfy okresowe.', FALSE, FALSE, 'Średnia; dostępne wydeptane stanowiska w pasie szuwarów.', FALSE, FALSE, 'Dojazd drogami szutrowymi i polnymi; utwardzone wjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80932, 'Eutroficzny staw dolinowy', 18, 1.2, 1.8, 'Płaska niecka o regularnych spadkach dna, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł organiczny w środkowej części.', 'Średnia, typowa dla płytkich zbiorników żyznych; okresowo mętna.', 'Bogata: pasy trzcin, moczarka kanadyjska, rdestnica na spadkach.', 'Karp, Amur, Płoć, Szczupak, Leszcz', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez zarządcę.', TRUE, 'Standardowe składki PZW Wrocław + regulamin milicki.', FALSE, FALSE, 'Bardzo dobra wzdłuż twardych grobli; liczne stanowiska.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy i szutrowy pod sam akwen.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80933, 'Staw po-hodowlany leśny', 12, 1.1, 1.6, 'Niecka o urozmaiconym dnie z licznymi zatopionymi korzeniami dębów.', 'Twarde: piaszczysto-żwirowe z cienką warstwą osadów organicznych.', 'Średnia; woda o lekkim odcieniu brunatnym, naturalna filtracja.', 'Bogata: gęste trzcinowiska, grążele żółte, moczarka kanadyjska.', 'Lin, Karaś, Okoń, Szczupak, Płoć', TRUE, 'Systematyczne zarybienia linem i karasiem przez lokalne koło.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom; wydeptane punkty.', FALSE, FALSE, 'Dojazd drogami szutrowymi i leśnymi; parkingi przy groblach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80935, 'Eutroficzny staw (górny)', 10, 0.9, 1.2, 'Płytki talerz, dno wyrównane, szybko nagrzewające się wiosną.', 'Mieszane: piasek u brzegów, mulisty szlam organiczny w osi.', 'Niska, woda żyzna, mącona przez żerujące ryby spokojnego żeru.', 'Bogata: pasy trzcin, liczne połacie roślinności miękkiej na dnie.', 'Karp, Płoć, Szczupak, Karaś, Leszcz', TRUE, 'Regularne zarybienia karpiem i amurem przez okręg PZW Wrocław.', TRUE, 'Składki PZW Wrocław; wymagana karta wędkarska i zezwolenie.', FALSE, FALSE, 'Dobra dzięki twardym groblom i wygodnym leśnym polanom.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi i polnymi z Krośnic.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80936, 'Eutroficzny staw (tarlisko)', 8, 1, 1.5, 'Płytka niecka o miękkim dnie, brak uskoków, silnie zarastająca.', 'Bardzo miękkie: muł organiczny i gęsty osad detrytusowy roślin.', 'Niska, woda mętna i żyzna, doskonałe warunki dla lęgów ryb.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką kanadyjską.', 'Lin, Karaś złoty, Szczupak, Płoć, Leszcz', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina przez PZW.', TRUE, 'Standardowe zezwolenia PZW / Stawy Milickie; opłaty roczne.', FALSE, TRUE, 'Średnia; dostępne kilka wydeptanych stanowisk w pasie trzcin.', FALSE, FALSE, 'Dojazd polny, utwardzony szutrem; parkingi oddalone od brzegu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80937, 'Eutroficzny staw otwarty', 25, 1.2, 1.8, 'Rozległa niecka o piaszczystym dnie, brak wysokiej osłony brzegowej.', 'Twarde: piasek krasowy i żwir, cienka warstwa mułu w głęboczku.', 'Dobra; woda doskonale natleniona przez wiatr; okresowe zakwity.', 'Umiarkowana: wąski pas trzcin, podwodne łąki moczarki na blatach.', 'Karp, Leszcz, Okoń, Płoć, Szczupak', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez PZW Wrocław.', TRUE, 'Standardowe składki PZW Wrocław dostępne w Miliczu i online.', FALSE, FALSE, 'Bardzo dobra wzdłuż grobli; twarde piaszczyste stanowiska.', FALSE, FALSE, 'Bardzo dobry dojazd drogami technicznymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81746, 'Mezotroficzne', 45, 3.8, 10.2, 'Misa łagodna', 'Piaszczyste', 'Wysoka', 'Umiarkowana', 'Płoć, Leszcz, Szczupak, Lin', TRUE, 'Naturalne', TRUE, 'G.R. Bogucin', FALSE, TRUE, 'Dobra', FALSE, TRUE, 'Leśna utwardzona', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80938, 'Eutroficzny staw leśny', 14, 1.1, 1.5, 'Misa jeziorna o łagodnych spadkach, liczne zatoki i zwaliska drzew.', 'Bardzo miękkie: muł organiczny i osad liściasty z otaczającego boru.', 'Niska; woda o charakterystycznym mrocznym odcieniu humusowym.', 'Bardzo obfita: gęste trzcinowiska, szerokie połacie grążeli żółtych.', 'Lin, Karp, Szczupak, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu karpiem.', TRUE, 'Zezwolenia PZW Wrocław dostępne w sklepach i online.', FALSE, TRUE, 'Dobra dzięki licznym kładkom i wygodnym leśnym stanowiskom.', TRUE, FALSE, 'Dojazd drogami leśnymi, utwardzonymi szutrami; parkingi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80939, 'Eutroficzny staw hodowlany', 35, 1.3, 2, 'Regularna niecka o wyrównanym dnie piaszczysto-mulistym.', 'Przeważnie miękkie z twardymi piaszczystymi łachami przy groblach.', 'Niska, typowa dla zbiorników intensywnie użytkowanych; żyzna.', 'Bogata: szerokie pasy trzcinowisk, liczne latorośla podwodne.', 'Karp, Amur, Szczupak, Leszcz, Płoć', TRUE, 'Rekordowe zarybienia karpiem; dbanie o rybostan okazowy PZW.', TRUE, 'Składki PZW Wrocław; wymagana karta wędkarska i zezwolenie.', FALSE, FALSE, 'Bardzo dobra wzdłuż twardych grobli; liczne stanowiska rzutowe.', FALSE, FALSE, 'Dobry dojazd drogami utwardzonymi i szutrowymi groblami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80940, 'Eutroficzny staw (dziki)', 12, 0.9, 1.2, 'Płytka niecka o miękkim dnie, brak wyraźnych uskoków i rynien.', 'Bardzo miękkie, muł organiczny i gruby osad torfowy (humusowy).', 'Niska, woda o ciemnym odcieniu, okresowo mętna i kwitnąca.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką.', 'Lin, Szczupak, Karaś złoty, Płoć, Leszcz', TRUE, 'Naturalna ochrona drapieżnika; stabilna populacja lina bagiennego.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, TRUE, 'Trudna przez bagno i las; ograniczone do wyznaczonych punktów.', FALSE, FALSE, 'Dojazd polny, utrudniony po opadach; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80941, 'Eutroficzny staw hodowlany', 28, 1.2, 1.8, 'Misa jeziorna o łagodnych spadkach, twarde piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, miękki muł w osi głównej stawu.', 'Średnia, typowa dla jezior żyznych; okresowo mętna latem.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, rzadki rogatek.', 'Karp, Leszcz, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem przez okręg.', TRUE, 'Standardowe składki PZW Wrocław; zezwolenia w Miliczu.', FALSE, FALSE, 'Bardzo dobra dzięki twardym groblom i łagodnym zejściom.', FALSE, FALSE, 'Bardzo dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80942, 'Dystroficzny staw leśny', 6, 0.8, 1.3, 'Mała, mroczna niecka bez rynien, dno silnie zamulone i torfowe.', 'Bardzo miękkie, płynny muł organiczny i gruby osad torfowy.', 'Niska; woda o charakterystycznym ciemnobrunatnym odcieniu.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce, grążele.', 'Lin, Karaś pospolity, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych, stabilna populacja dzikich ryb stawowych.', TRUE, 'Licencja PZW Wrocław / Stawy Milickie; surowe limity.', FALSE, TRUE, 'Ekstremalnie trudna przez bagno; wymagane kładki lub wodery.', FALSE, FALSE, 'Trudny dojazd wąskimi ścieżkami leśnymi; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80943, 'Eutroficzny staw leśny', 15, 1.1, 1.5, 'Podłużna niecka o regularnych spadkach dna, liczne korzenie dębów.', 'Twarde: piaszczysto-żwirowe u brzegów, miękki muł w głębi.', 'Średnia, woda żyzna, dobrze natleniona dzięki osłonie leśnej.', 'Bogata: pasy trzcin, moczarka kanadyjska, lilie wodne.', 'Okoń, Płoć, Lin, Karp, Szczupak', TRUE, 'Naturalny rozród wspierany okresowo narybkiem szczupaka przez PZW.', TRUE, 'Standardowe składki PZW Wrocław + regulamin milicki.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, FALSE, 'Dojazd drogami szutrowymi i leśnymi; parkingi przy groblach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80944, 'Eutroficzny staw hodowlany', 42, 1.3, 2.2, 'Rozległa misa o pofałdowanym dnie, liczne piaszczyste wypłycenia.', 'Przeważnie miękkie z twardymi piaszczystymi łachami na groblach.', 'Średnia; typowa dla zbiorników intensywnie zarybianych i żyznych.', 'Bogata: szerokie pasy trzcinowisk, liczne latorośla podwodne.', 'Karp, Amur, Szczupak, Leszcz, Płoć', TRUE, 'Rekordowe zarybienia karpiem i amurem przez okręg PZW.', TRUE, 'Zezwolenia PZW Wrocław dostępne w sklepach i online.', FALSE, FALSE, 'Bardzo dobra wzdłuż twardych grobli; liczne stanowiska rzutowe.', FALSE, FALSE, 'Bardzo dobry dojazd drogami utwardzonymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80945, 'Eutroficzny staw dolinowy', 28, 1.3, 2.2, 'Płaska niecka o regularnych spadkach dna, liczne piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, miękki muł organiczny w osi głównej.', 'Średnia, typowa dla jezior żyznych; okresowo mętna latem.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, rdestnica.', 'Karp, Lin, Szczupak, Płoć, Karaś', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez PZW.', TRUE, 'Standardowe składki PZW Wrocław + regulamin Stawów Milickich.', FALSE, FALSE, 'Bardzo dobra dzięki twardym groblom i zagospodarowanym brzegom.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy i szutrowy pod sam akwen.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80946, 'Eutroficzny staw leśny', 15, 1, 1.5, 'Płytka niecka o miękkim dnie, brak wyraźnych uskoków i rynien.', 'Bardzo miękkie: muł organiczny i gruby osad liściasty.', 'Niska; woda o lekkim zabarwieniu humusowym, okresowo mętna.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką kanadyjską.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina przez PZW.', TRUE, 'Składki PZW Wrocław; wymagana karta wędkarska.', FALSE, TRUE, 'Ograniczona przez gęstą roślinność; kilka wydeptanych stanowisk.', FALSE, FALSE, 'Drogi leśne, szutrowe; utrudniony dojazd po opadach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80947, 'Eutroficzny staw hodowlany', 22, 1.4, 2.5, 'Niecka o regularnych kształtach, wyrównane piaszczysto-muliste dno.', 'Przeważnie miękkie z twardymi piaszczystymi łachami przy groblach.', 'Średnia do niskiej; woda żyzna, mącona przez żerujące ryby.', 'Umiarkowana: wąski pas trzcin, rzadka roślinność podwodna na dnie.', 'Karp, Amur, Szczupak, Leszcz, Płoć', TRUE, 'Rekordowe zarybienia karpiem; dbanie o rybostan okazowy PZW.', TRUE, 'Zezwolenia PZW Wrocław dostępne w Miliczu i online.', FALSE, FALSE, 'Bardzo dobra wzdłuż twardych grobli; liczne stanowiska rzutowe.', FALSE, FALSE, 'Dobry dojazd drogami utwardzonymi i szutrowymi groblami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80948, 'Eutroficzny staw przepływowy', 12, 1.2, 1.8, 'Rynnowe koryto przepływowe, twarde dno w osi nurtu głównego.', 'Twarde: piaszczysto-żwirowe, lokalnie cienka warstwa mułu.', 'Dobra; woda przejrzystsza dzięki stałemu przepływowi i natlenieniu.', 'Umiarkowana: pasy trzcin, kępy grzybieni białych, rogatek.', 'Płoć, Jaź, Szczupak, Okoń, Lin', TRUE, 'Systematyczne zarybienia drapieżnikiem i wsparcie białorybem.', TRUE, 'Standardowe zezwolenia PZW Wrocław dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i groblom rzecznym.', FALSE, FALSE, 'Dojazd drogami szutrowymi groblami pod samo łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80951, 'Eutroficzny staw otwarty', 18, 1.1, 1.6, 'Płytka niecka o wyrównanym dnie, brak wysokiej osłony brzegowej.', 'Miękkie i muliste; bogate w bentos i osady detrytusowe roślin.', 'Średnia; latem mętna z powodu szybkiego nagrzewania wody.', 'Bogata: gęste trzcinowiska, lilie wodne, moczarka kanadyjska.', 'Karp, Leszcz, Szczupak, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu karpiem.', TRUE, 'Standardowe składki PZW Wrocław; taryfy okresowe.', FALSE, FALSE, 'Bardzo dobra; piaszczyste wejścia i stanowiska na groblach.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi i polnymi z Milicza.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81747, 'Eutroficzne leśne', 15, 1.8, 4, 'Płytka niecka', 'Głęboki muł', 'Średnia (torfowa)', 'Bardzo bogata', 'Lin, Karaś złoty, Szczupak leśny', TRUE, 'Brak', TRUE, 'G.R. Bogucin', FALSE, TRUE, 'Trudna (bagna)', FALSE, FALSE, 'Leśna/Polna', FALSE);
