INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80952, 'Dystroficzny staw leśny', 8, 1, 1.8, 'Misa jeziorna o łagodnych spadkach, liczne zwaliska drzew.', 'Bardzo miękkie, muł organiczny i osady torfowe (humusowe).', 'Niska; woda o charakterystycznym mrocznym odcieniu.', 'Bardzo obfita: gęste trzcinowiska, rdestnica, mchy torfowce.', 'Lin, Szczupak, Karaś złoty, Płoć, Okoń', TRUE, 'Naturalna ochrona drapieżnika; stabilna populacja dzikich ryb.', TRUE, 'Zezwolenia PZW Wrocław / Nadleśnictwo; obowiązuje regulamin.', FALSE, TRUE, 'Trudna przez bagno i las; ograniczone do wyznaczonych punktów.', FALSE, FALSE, 'Dojazd leśny, utrudniony; parkingi oddalone od brzegu.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80953, 'Zbiornik zaporowy', 262, 2.1, 4.5, 'Regularna niecka z wyraźnym korytem rzeki Mesny na dnie.', 'Mieszane: piasek w osi nurtu, muł w zatokach, twarde blaty.', 'Średnia do niskiej; żyzna woda o odcieniu zielonkawym.', 'Bogata: szerokie trzcinowiska, rdestnica, moczarka kanadyjska.', 'Sandacz, Sum, Leszcz, Karp, Amur', TRUE, 'Intensywne zarybienia sandaczem i karpiem przez PZW Konin.', TRUE, 'Zezwolenia PZW Konin dostępne online; opłaty okresowe.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska wzdłuż grobli i promenad.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy wokół zalewu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80954, 'Rynnowe sielawowe', 45, 3.8, 8.5, 'Misa jeziorna o łagodnych spadkach, piaszczyste wypłycenia.', 'Twarde: jasny piasek i żwir polodowcowy, brak mułu.', 'Wysoka (I klasa), krystaliczna toń, widoczność do kilku metrów.', 'Średnio obfita: pasy trzcin, podwodne łąki ramienic na stokach.', 'Okoń, Szczupak, Krasnopióra, Płoć, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem szczupaka.', TRUE, 'Standardowe składki PZW / G.R.; obowiązuje strefa ciszy.', FALSE, TRUE, 'Dobra dzięki licznym pomostom i łagodnym zejściom.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy do Powidza.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80955, 'Polodowcowe rynnowe', 142, 8.5, 20.2, 'Głęboka rynna, strome piaszczyste klify podwodne, liczne górki.', 'Wybitnie twarde: piasek krasowy, żwir i lita glina.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca spinningowi.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Okoń, Szczupak, Sielawa, Leszcz, Płoć', TRUE, 'Systematyczne zarybienia sielawą i drapieżnikami przez G.R.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego; obowiązuje strefa ciszy.', FALSE, TRUE, 'Średnia przez strome brzegi; wyznaczone kładki i pomosty.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i leśnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80956, 'Rynnowe sielawowe (GIGANT)', 1035, 12.5, 46.5, 'Potężna rynna, gwałtowne uskoki, liczne wyspy i podwodne góry.', 'Bardzo twarde: piasek, kreda polodowcowa, kamienie, brak mułu.', 'Ekstremalnie wysoka (I klasa); krystaliczna toń sielawowa.', 'Skąpa: wąski pierścień trzcin, roślinność podwodna na spadkach.', 'Szczupak pelagiczny, Okoń sielawowy, Sielawa, Leszcz, Płoć', TRUE, 'Ochrona tarlisk sielawy, zarybienia drapieżnikiem i sielawą.', TRUE, 'Zezwolenia G.R. / PZW; bezwzględna strefa ciszy motorowodnej.', FALSE, TRUE, 'Bardzo dobra w miejscowościach; trudna na dzikich brzegach.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy; liczne parkingi i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80957, 'Rynnowe leśne', 18, 4.2, 9.5, 'Wyraźna centralna rynna, strome piaszczyste skarpy, twarde dno.', 'Twarde: jasny piasek krasowy i żwir, mało osadów organicznych.', 'Wysoka, woda bardzo czysta i dobrze natleniona przez cały rok.', 'Skąpa: wąski pierścień trzcin, podwodne łąki ramienic.', 'Okoń, Płoć, Szczupak, Wzdręga, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Standardowe składki PZW Konin; opłaty roczne i okresowe.', FALSE, TRUE, 'Średnia przez wysokie skarpy i gęsty las; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony dla niskich aut.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80959, 'Polodowcowe rynnowe', 45, 5.8, 14.5, 'Regularna rynna rynnowa, piaszczyste blaty, strome stoki.', 'Twarde: jasny piasek i żwir polodowcowy, lokalnie warstwa mułu.', 'Dobra; woda przejrzysta wiosną, latem lekkie zakwity alg.', 'Umiarkowana: pasy trzcin, rdestnica i moczarka na spadkach.', 'Leszcz, Płoć, Szczupak, Okoń, Krąp', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą przez okręg.', TRUE, 'Standardowe zezwolenia PZW Konin; zezwolenia okresowe online.', FALSE, FALSE, 'Średnia, dostępne dzikie stanowiska i leśne dojścia.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80960, 'Rynnowe przepływowe', 148, 6.2, 15.5, 'Urozmaicona rzeźba dna, liczne podwodne górki i twarde blaty.', 'Zróżnicowane: twardy piasek, glina, lokalnie osady muliste.', 'Dobra do średniej; woda przejrzysta wiosną, latem zakwita.', 'Umiarkowana: pasy trzcin, moczarka kanadyjska na spadkach dna.', 'Okoń, Sandacz, Płoć, Leszcz, Węgorz', TRUE, 'Intensywne zarybienia sandaczem i drapieżnikiem przez PZW.', TRUE, 'Standardowe składki PZW Poznań; obowiązuje karta wędkarska.', FALSE, FALSE, 'Bardzo dobra; liczne plaże i pomosty w miejscowościach.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80961, 'Rynnowe eutroficzne', 32, 3.5, 8.2, 'Misa jeziorna o łagodnych spadkach, dno piaszczysto-muliste.', 'Mieszane: piasek w litoralu, miękki muł w osi głównej.', 'Dobra; woda przejrzystsza niż w stawach, chłodniejsza.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, lilie wodne.', 'Szczupak, Lin, Wzdręga, Leszcz, Okoń', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem przez PZW.', TRUE, 'Standardowe zezwolenia PZW Poznań / Gniezno.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', FALSE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80962, 'Eutroficzne miejskie', 12, 1.8, 3.5, 'Płytka niecka o wyrównanym dnie, dno silnie zamulone.', 'Bardzo miękkie, głęboki muł organiczny i detrytus roślinny.', 'Niska, typowa dla zbiorników miejskich; okresowo mętna.', 'Bardzo obfita: pasy trzcin przy promenadzie, moczarka, lilie.', 'Leszcz, Karp, Płoć, Okoń, Szczupak', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez PZW.', TRUE, 'Standardowe zezwolenia PZW Poznań dostępne online.', FALSE, FALSE, 'Wyśmienita; liczne pomosty miejskie i stanowiska na brzegu.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, parkingi w centrum miasta.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80963, 'Polodowcowe rynnowe', 25, 4.2, 8.5, 'Regularna rynna, strome piaszczyste skarpy, brak górek.', 'Twarde: jasny piasek i drobny żwir, mało osadów organicznych.', 'Wysoka, woda bardzo czysta, leśny charakter o dobrym natlenieniu.', 'Skąpa: wąski pierścień trzcin, rzadka rdestnica na spadkach.', 'Lin, Szczupak, Płoć, Okoń, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Standardowe składki PZW Poznań.', FALSE, TRUE, 'Średnia przez wysokie skarpy i gęsty las; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony po opadach.', FALSE);
