INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80986, 'Dystroficzne (bagienne)', 6, 1.2, 3.5, 'Płaski talerz otoczony bagnem, dno bez urozmaiceń.', 'Bardzo miękkie, płynny muł organiczny i gruby osad torfowy.', 'Niska, woda o ciemnym (herbacianym) odcieniu humusowym.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce, grążele.', 'Lin, Karaś złoty, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych, stabilna populacja dzikich ryb.', TRUE, 'Licencja PZW Bydgoszcz; zezwolenia okresowe.', FALSE, TRUE, 'Ekstremalnie trudna przez bagno; wymagane kładki lub ponton.', FALSE, TRUE, 'Trudny dojazd wąskimi ścieżkami leśnymi; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80987, 'Rynnowe historyczne', 105, 5.8, 13.5, 'Urozmaicona rzeźba dna, koryto rzeki Gąsawki, twarde blaty.', 'Mieszane: piasek u brzegów, mulisty szlam w osi głównej.', 'Średnia do dobrej; woda dobrze natleniona dzięki rzece.', 'Umiarkowana: pasy trzcin wokół osady, moczarka, lilie.', 'Leszcz, Szczupak, Okoń, Płoć, Sandacz', TRUE, 'Intensywne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe składki PZW Bydgoszcz dostępne online.', FALSE, FALSE, 'Bardzo dobra dzięki licznym plażom i pomostom turystycznym.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80988, 'Eutroficzny staw (rezerwat)', 38, 0.9, 1.5, 'Płaski talerz, dno bez uskoków, silnie zarastające roślinnością.', 'Bardzo miękkie: głęboki muł organiczny i detrytus roślinny.', 'Niska, woda mętna i żyzna, okresowo zakwita latem.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką kanadyjską.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina przez PZW.', TRUE, 'Składki PZW Warszawa + zezwolenie na rezerwat; surowe limity.', FALSE, TRUE, 'Ograniczona do wyznaczonych stanowisk na groblach.', FALSE, FALSE, 'Dojazd asfaltowy do granicy rezerwatu; dojście piesze.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80989, 'Eutroficzny staw przepływowy', 12, 1.2, 1.8, 'Rynnowe koryto przepływowe, twarde dno w osi nurtu Raszynki.', 'Twarde: piaszczysto-żwirowe w nurcie, miękki muł w zatokach.', 'Średnia; dobrze natleniona dzięki przepływowi rzeki; zmienna.', 'Bogata: gęste trzcinowiska, roślinność prądolubna w korycie.', 'Płoć, Jaź, Szczupak, Okoń, Lin', TRUE, 'Naturalny napływ ryb z rzeki, okresowe zarybienia drapieżnikiem.', TRUE, 'Standardowe składki PZW Warszawa dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom wzdłuż grobli.', FALSE, FALSE, 'Dojazd drogami szutrowymi i polnymi z Raszyna.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80990, 'Eutroficzny staw parkowy', 22, 1.1, 1.6, 'Płaska niecka o regularnych spadkach dna, dno piaszczysto-muliste.', 'Mieszane: piasek u brzegów, miękki muł w osi głównej.', 'Średnia, typowa dla zbiorników żyznych; okresowo mętna.', 'Bogata: pasy trzcin, moczarka kanadyjska, rdestnica na spadkach.', 'Leszcz, Karp, Szczupak, Płoć, Karaś', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez zarządcę.', TRUE, 'Składki PZW Warszawa; wymagana karta wędkarska i zezwolenie.', FALSE, FALSE, 'Wyśmienita; liczne stanowiska z łatwym zejściem do wody.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, parkingi przy pałacu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80991, 'Eutroficzny staw (tarlisko)', 8, 0.7, 1.2, 'Płytka niecka podzielona groblami, brak wyraźnych uskoków.', 'Bardzo miękkie: płynny muł organiczny i osady torfowe.', 'Niska, woda o ciemnym odcieniu, okresowo mętna i żyzna.', 'Ekstremalna: bagniste brzegi, trzciny, moczarka, grążele.', 'Lin, Karaś złoty, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych, całkowicie naturalna reprodukcja.', TRUE, 'Zezwolenia PZW Warszawa / Rezerwat; surowe limity.', FALSE, TRUE, 'Ekstremalnie trudna; wymagane wodery lub stanowiska na groblach.', FALSE, FALSE, 'Trudny dojazd wąskimi ścieżkami; brak parkingów przy grobli.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80993, 'Eutroficzny staw parkowy', 10, 1.2, 1.8, 'Niecka o łagodnych spadkach, liczne podwodne korzenie dębów.', 'Twarde: piaszczysto-żwirowe u brzegów, miękki muł w głębi.', 'Średnia do dobrej; woda filtrowana przez roślinność parkową.', 'Bogata: gęste trzcinowiska, lilie wodne, moczarka kanadyjska.', 'Lin, Amur, Szczupak, Płoć, Okoń', TRUE, 'Regularne zarybienia rybami białymi i szczupakiem przez okręg.', TRUE, 'Standardowe składki PZW Warszawa dostępne w kołach.', FALSE, TRUE, 'Wyśmienita; twarde brzegi, ławeczki i liczne polany parkowe.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, liczne miejsca postojowe.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80994, 'Eutroficzny staw polny', 6, 1.1, 1.5, 'Mała niecka o łagodnych spadkach, twarde piaszczyste podłoże.', 'Twarde: piasek krasowy i żwir, cienka warstwa mułu w osi.', 'Średnia, typowa dla zbiorników żyznych przy trasach komunikacyjnych.', 'Bogata: gęste trzcinowiska, rzadka roślinność podwodna na dnie.', 'Karp, Płoć, Szczupak, Karaś srebrzysty, Wzdręga', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Zezwolenia PZW Warszawa dostępne online i w sklepach.', FALSE, FALSE, 'Bardzo dobra wzdłuż grobli; twarde stanowiska rzutowe.', FALSE, FALSE, 'Bardzo dobry dojazd asfaltowy pod samą wodę.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80995, 'Eutroficzny staw (cichy)', 14, 0.9, 1.4, 'Płytka niecka o wyrównanym dnie, dno piaszczysto-muliste.', 'Miękkie i muliste; dno wyścielone warstwą detrytusu roślinnego.', 'Niska; latem mętna z powodu nagrzewania wody i wegetacji.', 'Bardzo obfita: gęste trzcinowiska, lilie wodne, moczarka kanadyjska.', 'Lin, Karaś złoty, Szczupak, Płoć, Leszcz', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe składki PZW Warszawa; taryfy okresowe.', FALSE, TRUE, 'Średnia; dostępne wydeptane stanowiska w pasie szuwarów.', FALSE, FALSE, 'Dojazd drogami szutrowymi i polnymi; utwardzone wjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80996, 'Eutroficzny staw (wędkarski)', 18, 1.3, 2, 'Regularna niecka o wyrównanym dnie, piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, miękki muł w osi głównej stawu.', 'Średnia, woda żyzna, dobrze natleniona przez otwarty brzeg.', 'Bogata: pasy trzcin, moczarka kanadyjska, grążele żółte.', 'Amur, Karp, Szczupak, Leszcz, Okoń', TRUE, 'Intensywne zarybienia karpiem i rybami białymi przez PZW.', TRUE, 'Standardowe zezwolenia PZW Warszawa dostępne online.', FALSE, TRUE, 'Dobra dzięki twardym groblom i wygodnym leśnym polanom.', TRUE, FALSE, 'Dobry dojazd drogami szutrowymi i asfaltowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80997, 'Eutroficzny staw otwarty', 15, 1.1, 1.6, 'Płytka niecka o wyrównanym dnie, brak wysokiej osłony brzegowej.', 'Głównie twardy piasek i żwir, marginalna ilość mułu osadowego.', 'Dobra do średniej; woda doskonale natleniona przez wiatr.', 'Umiarkowana: wąski pas trzcin, mało roślinności zanurzonej.', 'Leszcz, Karp, Okoń, Płoć, Szczupak', TRUE, 'Regularne zarybienia rybami spokojnego żeru przez lokalne koło.', TRUE, 'Standardowe składki PZW Warszawa; opłaty roczne.', FALSE, FALSE, 'Bardzo dobra; piaszczyste wejścia i stanowiska na groblach.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi groblami pod samo łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80998, 'Antropogeniczna (żwirownia)', 25, 4.5, 9.5, 'Bardzo urozmaicone: uskoki, twarde blaty, głębokie rynny poeksploatacyjne.', 'Twarde: żwir i piasek polodowcowy, brak mułu w rynnach.', 'Wysoka, woda czysta i dobrze natleniona przez cały rok.', 'Skąpa: punktowe pasy trzcin i rzadka moczarka na dnie.', 'Okoń, Sandacz, Szczupak, Karp, Amur', TRUE, 'Intensywne zarybienia drapieżnikiem i dbanie o rybostan okazowy.', TRUE, 'Zezwolenia PZW Warszawa; możliwe opłaty okresowe online.', FALSE, FALSE, 'Bardzo dobra dzięki wysokim brzegom i licznym stanowiskom.', TRUE, FALSE, 'Bardzo dobry dojazd utwardzony, parkingi przy zbiorniku.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80999, 'Antropogeniczna (glinianka)', 12, 3.5, 7.2, 'Stromo opadające brzegi, twarde gliniaste półki podwodne.', 'Bardzo twarde: lita glina, lokalnie osady muliste w głębi.', 'Średnia do dobrej; woda dobrze natleniona przez napowietrzacze.', 'Bogata w zatokach: trzcina, moczarka kanadyjska, lilie wodne.', 'Sandacz, Szczupak, Leszcz, Karp, Okoń', TRUE, 'Systematyczne zarybienia sandaczem i karpiem przez okręg PZW.', TRUE, 'Standardowe składki PZW Warszawa; łowisko miejskie.', FALSE, FALSE, 'Wyśmienita; liczne pomosty miejskie i przygotowane kładki.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, parkingi w centrum miasta.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81001, 'Antropogeniczna (glinianka)', 5, 2.5, 4.8, 'Małe wyrobisko o stromych zboczach, dno twarde gliniaste.', 'Twarde: lita glina i żwir, marginalna ilość mułu organicznego.', 'Wysoka, woda bardzo czysta jak na warunki miejskie.', 'Umiarkowana: pasy trzcin przy umocnieniach brzegowych.', 'Karp, Płoć, Szczupak, Okoń, Karaś', TRUE, 'Regularne zarybienia rybami białymi przez lokalne koło PZW.', TRUE, 'Zezwolenia PZW Warszawa dostępne online; karta wędkarska.', FALSE, FALSE, 'Bardzo dobra dzięki umocnionym brzegom i alejkom parkowym.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy pod samo lustro wody.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81002, 'Antropogeniczna (glinianka)', 8, 3.2, 5.5, 'Urozmaicona rzeźba dna z licznymi uskokami gliniastymi i rynnami.', 'Bardzo twarde: lita glina, żwir, lokalnie warstwa mułu w dołach.', 'Dobra; woda dobrze natleniona; okresowo zakwita w lecie.', 'Bogata: gęste trzcinowiska, lilie wodne, moczarka kanadyjska.', 'Sandacz, Szczupak, Lin, Wzdręga, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i wsparcie PZW Warszawa.', TRUE, 'Standardowe składki PZW Warszawa; obowiązuje karta wędkarska.', FALSE, FALSE, 'Bardzo dobra dzięki licznym kładkom i pomostom parkowym.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, parkingi przy parku miejskim.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81003, 'Eutroficzne parkowe', 3, 1.2, 2.5, 'Płytka misa, dno wyrównane z łagodnymi spadkami brzegowymi.', 'Miękkie: muł i detrytus roślinny, brzegi umocnione faszyną.', 'Średnia; okresowo mętna latem; regularnie napowietrzana.', 'Bogata przy brzegach: lilie wodne, moczarka, pałka wodna.', 'Lin, Karp, Płoć, Okoń, Szczupak', TRUE, 'Regularne zarybienia rybami spokojnego żeru przez PZW Warszawa.', TRUE, 'Standardowe składki PZW Warszawa.', FALSE, FALSE, 'Wyśmienita; twarde brzegi i liczne pomosty parkowe.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, parkingi miejskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81004, 'Antropogeniczna (glinianka)', 8, 3.5, 6, 'Stromo opadające brzegi, twarde gliniaste półki podwodne.', 'Bardzo twarde: lita glina, lokalnie osady muliste w głębi.', 'Dobra; woda czystsza niż w stawach nizinnych; natleniona.', 'Umiarkowana: pasy trzcin przy starych uskokach technicznych.', 'Sandacz, Szczupak, Leszcz, Karp, Okoń', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą.', TRUE, 'Standardowe zezwolenia PZW Warszawa dostępne online.', FALSE, FALSE, 'Średnia przez strome skarpy; wyznaczone punkty brzegowe.', FALSE, FALSE, 'Bardzo dobry dojazd asfaltowy, miejsca postojowe przy ulicach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81005, 'Antropogeniczna (glinianka)', 12, 2.8, 5.2, 'Urozmaicona rzeźba dna, liczne podwodne górki i rowy techniczne.', 'Twarde: glina i żwir polodowcowy, cienka warstwa mułu.', 'Średnia do dobrej; woda dobrze natleniona przez wiatr.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, lilie.', 'Karp, Amur, Płoć, Szczupak, Okoń', TRUE, 'Intensywne zarybienia karpiem i amurem przez okręg PZW.', TRUE, 'Składki PZW Warszawa; obowiązuje karta wędkarska.', FALSE, FALSE, 'Wyśmienita; liczne pomosty parkowe i przygotowane kładki.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi miejskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81006, 'Antropogeniczna (glinianka)', 5, 2.2, 3.5, 'Małe wyrobisko o wyrównanym dnie piaszczysto-gliniastym.', 'Twarde: glina i drobny żwir, mało osadów organicznych.', 'Wysoka, woda bardzo czysta jak na warunki miejskie.', 'Umiarkowana: wąski pas trzcin, kępy roślinności zanurzonej.', 'Okoń, Krasnopióra, Krąp, Szczupak, Płoć', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Standardowe zezwolenia PZW Warszawa dostępne online.', FALSE, FALSE, 'Bardzo dobra dzięki alejkom parkowym i umocnionym brzegom.', FALSE, FALSE, 'Bardzo dobry dojazd asfaltowy pod same glinianki.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81007, 'Zbiornik retencyjny', 10, 1.5, 2.5, 'Niecka o łagodnych spadkach, piaszczyste wypłycenia wschodnie.', 'Twarde: piasek polodowcowy, marginalna ilość mułu.', 'Wysoka (I klasa), woda czysta, leśny charakter.', 'Średnio obfita: pasy trzcin, podwodne łąki ramienic.', 'Karp, Amur, Szczupak, Płoć, Okoń', TRUE, 'Zarybienia selektywne karpiem i szczupakiem; dbanie o okazy.', TRUE, 'Specjalna licencja stowarzyszenia / gminy; limity nęcenia.', TRUE, TRUE, 'Wyśmienita; teren ogrodzony, pomosty i stanowiska trawiaste.', TRUE, FALSE, 'Dobry dojazd utwardzony, parking przy zbiorniku.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81009, 'Zbiornik zaporowy (GIGANT)', 4230, 4.5, 12.5, 'Monumentalna batymetria, stare koryto Warty, karczowiska dębów.', 'Zróżnicowane: twardy piasek w korycie, miękki muł na blatach.', 'Niska do średniej; żyzna woda rzeczna; silne falowanie.', 'Bogata na południu: gigantyczne trzcinowiska i wyspy zielne.', 'Sandacz, Sum, Leszcz, Szczupak, Boleń', TRUE, 'Intensywne zarybienia sandaczem i sumem przez PZW Sieradz.', TRUE, 'Standardowe składki PZW Sieradz; opłaty roczne i okresowe.', FALSE, FALSE, 'Trudna przez duże wahania wody; wyznaczone główne bazy.', TRUE, TRUE, 'Dobry dojazd asfaltowy do zapory i miejscowości turystycznych.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81010, 'Rynnowe leśne', 14, 4.2, 9.5, 'Regularna rynna w osi jeziora, strome piaszczyste skarpy.', 'Twarde: jasny piasek i żwir polodowcowy, brak mułu.', 'Wysoka, woda bardzo czysta, dobrze natleniona przez cały rok.', 'Skąpa: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Standardowe zezwolenia PZW Olsztyn dostępne online.', FALSE, TRUE, 'Średnia przez wysokie skarpy; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81011, 'Rynnowe przepływowe', 285, 4.2, 9.5, 'Regularna rynna, koryto rzeki Oski, piaszczyste blaty.', 'Mieszane: piasek w osi nurtu, miękki muł w zatokach.', 'Średnia; woda żyzna, dobrze natleniona dzięki rzece.', 'Bogata: gęste trzcinowiska, rdestnica, moczarka.', 'Sandacz, Leszcz, Szczupak, Węgorz, Płoć', TRUE, 'Intensywne zarybienia sandaczem i drapieżnikiem.', TRUE, 'Standardowe składki PZW Olsztyn; zezwolenia online.', FALSE, FALSE, 'Dobra dzięki licznym kładkom i stanowiskom.', TRUE, TRUE, 'Dobry dojazd drogami asfaltowymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81012, 'Eutroficzne (rezerwatowe)', 85, 0.5, 1.2, 'Płaski talerz, dno bez uskoków, silnie zarastające.', 'Bardzo miękkie: głęboki muł torfowy i osady organiczne.', 'Niska; woda mętna, żyzna, silnie nagrzewająca się.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką.', 'Lin, Karaś złoty, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych; ochrona tarlisk naturalnych.', TRUE, 'Specjalna licencja PZW + regulamin rezerwatu Karaś.', FALSE, TRUE, 'Ekstremalnie trudna przez bagno; głównie łódź/pychówka.', FALSE, FALSE, 'Trudny dojazd drogami leśnymi; brak parkingów.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81013, 'Polodowcowe rynnowe', 42, 4.5, 10.2, 'Regularna rynna centralna, strome piaszczyste skarpy.', 'Twarde: jasny piasek i żwir, mało mułu w osi głównej.', 'Dobra; woda przejrzysta wiosną, latem lekkie zakwity.', 'Umiarkowana: wąski pas trzcin, podwodne kępy moczarki.', 'Okoń, Szczupak, Płoć sielawowa, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą.', TRUE, 'Standardowe zezwolenia PZW Olsztyn dostępne online.', FALSE, FALSE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81750, 'Przepływowe', 18, 1.5, 3.5, 'Koryto rzeki na dnie', 'Muliste z łachami piachu', 'Średnia', 'Bogata roślinność wynurzona', 'Płoć, Leszcz, Jaź, Szczupak', TRUE, 'Systematyczne', TRUE, 'PZW Konin', FALSE, FALSE, 'Średnia', FALSE, TRUE, 'Dobra szutrowa', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81014, 'Rynnowe leśne', 35, 4.2, 9.8, 'Wyraźna centralna rynna, strome piaszczyste skarpy leśne.', 'Twarde: jasny piasek krasowy i drobny żwir, mało mułu.', 'Wysoka, woda przejrzysta, doskonale natleniona przez wiatr.', 'Skąpa: wąski pierścień trzcin, podwodne łąki ramienic.', 'Okoń, Płoć, Szczupak, Wzdręga, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Olsztyn; taryfy okresowe.', FALSE, TRUE, 'Średnia przez wysokie skarpy; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony dla niskich aut.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81015, 'Eutroficzne małe', 12, 1.5, 3.5, 'Mała misa o miękkim dnie, brak wyraźnych uskoków.', 'Miękkie i muliste; dno wyścielone warstwą detrytusu roślin.', 'Średnia; latem mętna z powodu nagrzewania wody i wegetacji.', 'Bardzo obfita: jezioro silnie zarastające grążelem i moczarką.', 'Lin, Karaś złoty, Szczupak, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Zezwolenia PZW Olsztyn dostępne w sklepach i online.', FALSE, TRUE, 'Dobra dzięki licznym dzikim stanowiskom i kładkom.', TRUE, FALSE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81017, 'Rynnowo-przepływowe', 48, 3.2, 7.5, 'Rynnowe koryto przepływowe, piaszczyste blaty, twarde dno.', 'Twarde: piaszczysto-żwirowe, lokalnie cienka warstwa mułu.', 'Średnia; dobrze natleniona dzięki przepływowi rzeki Gardęgi.', 'Bogata: gęste trzcinowiska, roślinność prądolubna w nurcie.', 'Jaź, Kleń, Szczupak, Sandacz, Leszcz', TRUE, 'Regularne zarybienia drapieżnikiem i wsparcie białorybem.', TRUE, 'Standardowe składki PZW Olsztyn; zezwolenia okresowe.', FALSE, FALSE, 'Dobra; liczne stanowiska brzegowe i piaszczyste dojścia.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy pod sam akwen.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81018, 'Rynnowe', 145, 4.8, 12, 'Urozmaicona rzeźba dna, liczne podwodne górki i blaty.', 'Mieszane: twardy piasek na wypłyceniach, mulisty szlam w głębi.', 'Średnia do dobrej; woda przejrzysta wiosną, latem zakwita.', 'Bogata: pasy trzcin, rdestnica na podwodnych spadach dna.', 'Leszcz, Płoć, Szczupak, Okoń, Węgorz', TRUE, 'Intensywne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Olsztyn dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81019, 'Eutroficzne miejskie', 65, 2.5, 5.8, 'Misa jeziorna o łagodnych spadkach, piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, miękki muł w osi głównej.', 'Średnia; okresowo mętna; regularnie napowietrzana aeratorami.', 'Bogata: gęste trzcinowiska przy promenadzie, lilie, moczarka.', 'Sandacz, Leszcz, Karp, Szczupak, Okoń', TRUE, 'Intensywne zarybienia drapieżnikiem przez okręg i miasto.', TRUE, 'Standardowe składki PZW Olsztyn; karta wędkarska.', FALSE, FALSE, 'Wyśmienita; liczne pomosty miejskie i stanowiska na brzegu.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, parkingi w centrum miasta.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81020, 'Rynnowe leśne małe', 14, 3.8, 8.2, 'Mała rynna leśna o twardym dnie i stromych zboczach.', 'Twarde: jasny piasek krasowy i drobny żwir polodowcowy.', 'Wysoka, woda krystalicznie czysta, sprzyjająca okoniom.', 'Umiarkowana: wąski pas trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Olsztyn dostępne online.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81021, 'Eutroficzne (rezerwatowe)', 142, 0.9, 2, 'Rozległa, płytka misa, liczne mielizny i korytarze zielne.', 'Wybitnie miękkie, muł organiczny i torf, bogaty bentos.', 'Niska; woda mętna i żyzna, silnie mącona przez ptactwo.', 'Ekstremalna: gigantyczne trzcinowiska, wyspy zielne, lilie.', 'Lin, Karaś złoty, Szczupak, Wzdręga, Leszcz', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu linem.', TRUE, 'Specjalna licencja PZW Olsztyn + regulamin rezerwatu Gaudy.', FALSE, TRUE, 'Ograniczona do ściśle wyznaczonych stanowisk na brzegu.', FALSE, FALSE, 'Dojazd drogami szutrowymi; parkingi przy wieżach widokowych.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81022, 'Rynnowe', 28, 4.2, 10.5, 'Regularna rynna, piaszczyste wypłycenia, dno pofałdowane.', 'Mieszane: piasek u brzegów, miękki muł w rynnie środkowej.', 'Dobra; woda przejrzysta wiosną, dobrze natleniona przez wiatr.', 'Umiarkowana: pasy trzcin, moczarka kanadyjska, rdestnica.', 'Płoć, Leszcz, Okoń, Szczupak, Krąp', TRUE, 'Regularne zarybienia rybami białymi przez lokalne koło.', TRUE, 'Zezwolenia PZW Elbląg / Olsztyn dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', FALSE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81023, 'Rynnowe sielawowe (GIGANT)', 812, 6.5, 15.2, 'Potężna rynna, gwałtowne uskoki, liczne wyspy, podwodne góry.', 'Wybitnie twarde: piasek, żwir i glina polodowcowa, kamienie.', 'Dobra do wysokiej; krystaliczna toń sprzyjająca spinningowi.', 'Umiarkowana: pasy trzcin wokół wysp, podwodne łąki ramienic.', 'Sandacz, Okoń sielawowy, Szczupak pelagiczny, Leszcz, Płoć', TRUE, 'Intensywne zarybienia sandaczem i drapieżnikiem przez zarządcę.', TRUE, 'Zezwolenia PZW Elbląg / G.R.; wymagana karta wędkarska.', FALSE, FALSE, 'Bardzo dobra w miejscowościach; trudna na dzikich brzegach.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy; liczne parkingi i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81025, 'Polodowcowe rynnowe', 45, 5.5, 14, 'Regularna rynna w osi jeziora, strome piaszczyste skarpy, twarde dno.', 'Twarde: jasny piasek i drobny żwir, mało osadów organicznych.', 'Wysoka, woda bardzo czysta, dobrze natleniona przez cały rok.', 'Umiarkowana: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz, Lin', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem szczupaka przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, TRUE, 'Średnia przez wysokie skarpy; liczne kładki od wsi.', TRUE, TRUE, 'Dojazd drogami polnymi i szutrowymi z Witoszewa.', TRUE);
