INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81030, 'Rynnowe leśne (czyste)', 35, 5.8, 14.5, 'Wyraźna rynna leśna o twardym dnie i stromych zboczach.', 'Twarde: jasny piasek krasowy i drobny żwir, mało mułu.', 'Wysoka, woda krystalicznie czysta, natleniona.', 'Skąpa: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Płoć, Szczupak, Leszcz, Wzdręga', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Olsztyn; obowiązuje karta.', FALSE, TRUE, 'Średnia przez wysokie skarpy; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; parkingi w borze.', TRUE);
