INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81056, 'Dystroficzne leśne', 8, 1.5, 3.8, 'Mała niecka o miękkim dnie, brak wyraźnych uskoków i rynien.', 'Bardzo miękkie: muł organiczny i gruby osad liściasty.', 'Średnia; woda o lekkim zabarwieniu humusowym, okresowo mętna.', 'Bardzo obfita: gęste trzcinowiska, szerokie połacie grążeli.', 'Lin, Karaś złoty, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany okresowo narybkiem lina.', TRUE, 'Standardowe składki PZW Olsztyn.', FALSE, TRUE, 'Trudna przez bagno; zalecany lekki ponton.', FALSE, TRUE, 'Drogi leśne, piaszczyste; utrudniony dojazd po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81057, 'Polodowcowe rynnowe', 45, 4.2, 10.5, 'Regularna rynna w osi jeziora, strome piaszczyste skarpy.', 'Twarde: jasny piasek i żwir, mało osadów organicznych.', 'Dobra; woda przejrzysta wiosną, natleniona przez wiatr.', 'Umiarkowana: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz, Lin', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Standardowe składki PZW Toruń / Olsztyn.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', TRUE, TRUE, 'Dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81059, 'Rynnowe leśne małe', 12, 3.8, 8.5, 'Mały talerz rynnowy o twardym dnie i stromych piaszczystych zboczach.', 'Twarde: jasny piasek krasowy i żwir polodowcowy, brak mułu.', 'Wysoka, woda bardzo czysta, sprzyjająca okoniom.', 'Skąpa: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Płoć, Szczupak, Lin, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem drapieżnika.', TRUE, 'Standardowe zezwolenia PZW Toruń dostępne online.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81060, 'Rynnowe sielawowe (czyste)', 98, 7.5, 19.8, 'Głęboka rynna, strome piaszczyste klify podwodne, dno twarde.', 'Bardzo twarde: piasek krasowy, żwir i lita glina polodowcowa.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca technikom opadowym.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Okoń, Szczupak, Płoć sielawowa, Leszcz', TRUE, 'Systematyczne zarybienia sielawą i drapieżnikami przez PZW.', TRUE, 'Standardowe składki PZW Toruń; obowiązuje karta wędkarska.', FALSE, TRUE, 'Średnia przez wysokie skarpy; liczne kładki od wsi.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy do Lekart.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81061, 'Eutroficzne rynnowe', 22, 2.5, 5.2, 'Wąska centralna rynna, łagodne piaszczyste stoki, zamulone koryto.', 'Mieszane: piasek u brzegów, mulisty szlam organiczny w osi.', 'Średnia; okresowo zakwita w lecie; żyzna woda o odcieniu zielonkawym.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, lilie wodne.', 'Lin, Szczupak, Karaś, Leszcz, Płoć', TRUE, 'Regularne zarybienia szczupakiem i białą rybą przez okręg.', TRUE, 'Zezwolenia PZW Toruń dostępne online i w kołach.', FALSE, FALSE, 'Średnia; dostępne stanowiska w pasie szuwarów.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81062, 'Eutroficzne rynnowe małe', 14, 2.8, 5.8, 'Misa o łagodnych spadkach, pofałdowane dno z partiami mułu.', 'Mieszane: piasek w litoralu, miękki muł w środkowej części.', 'Średnia, typowa dla jezior żyznych; natleniona przez wiatr.', 'Bogata: pasy trzcin, lilie wodne, moczarka kanadyjska.', 'Lin, Szczupak, Karaś, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe zezwolenia PZW Toruń.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i kładkom.', FALSE, TRUE, 'Dobry dojazd drogami polnymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81063, 'Eutroficzne śródpolne', 10, 1.8, 4.2, 'Mała niecka o łagodnych spadkach, dno piaszczysto-muliste.', 'Miękkie: muł organiczny i detrytus roślinny, piasek u brzegów.', 'Średnia do niskiej; latem mętna z powodu nagrzewania wody.', 'Bardzo obfita: gęste trzcinowiska, grążele żółte, rzadki rogatek.', 'Lin, Karaś srebrzysty, Płoć, Szczupak, Okoń', TRUE, 'Regularne zarybienia rybami spokojnego żeru przez PZW.', TRUE, 'Standardowe składki PZW Toruń.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', FALSE, TRUE, 'Dojazd drogami polnymi, utwardzony szutrem.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81620, 'Polodowcowe rynnowe', 22, 3.2, 8.5, 'Regularna rynna, łagodne spadki.', 'Piaszczysto-muliste', 'Dobra', 'Umiarkowana (trzcina)', 'Leszcz, Płoć, Szczupak, Okoń', TRUE, 'Systematyczne PZW', TRUE, 'Składki PZW Poznań', FALSE, FALSE, 'Dobra', FALSE, TRUE, 'Szutrowa', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81064, 'Rynnowe leśne (czyste)', 18, 4.5, 8.5, 'Mała rynna leśna o twardym dnie i stromych zboczach.', 'Twarde: jasny piasek krasowy i żwir polodowcowy, mało mułu.', 'Wysoka, woda bardzo czysta i dobrze natleniona przez cały rok.', 'Umiarkowana: wąski pas trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem drapieżnika.', TRUE, 'Standardowe składki PZW Toruń; taryfy okresowe.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81065, 'Rynnowe sielawowe (GIGANT)', 295, 6.5, 15.2, 'Rozległa rynna, liczne blaty piaszczyste, koryto rzeki Skarlanki.', 'Twarde: piasek, żwir i glina polodowcowa, marginalny muł.', 'Dobra do wysokiej; krystaliczna toń sprzyjająca spinningowi.', 'Umiarkowana: pasy trzcin, moczarka kanadyjska na spadkach.', 'Sandacz, Okoń, Szczupak, Leszcz, Płoć', TRUE, 'Intensywne zarybienia sandaczem i drapieżnikiem przez okręg.', TRUE, 'Standardowe zezwolenia PZW Toruń; opłaty roczne.', FALSE, FALSE, 'Bardzo dobra w miejscowościach; kładki i pomosty.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy do Skarlina.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81067, 'Eutroficzny staw dolinowy', 25, 0.9, 1.5, 'Płaski talerz, dno bez wyraźnych rynien, piaszczyste groble.', 'Miękkie: muł organiczny i piasek drobnoziarnisty.', 'Średnia do niskiej; żyzna woda, okresowo zakwita latem.', 'Bardzo obfita: pasy trzcin, moczarka kanadyjska, rdestnica.', 'Karp, Amur, Płoć, Szczupak, Leszcz', TRUE, 'Intensywne zarybienia karpiem i amurem przez okręg PZW.', TRUE, 'Standardowe składki PZW Warszawa.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska rzutowe na groblach.', TRUE, FALSE, 'Dobry dojazd drogami polnymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81068, 'Eutroficzny staw zaciszny', 12, 1.1, 1.8, 'Misa o łagodnych spadkach, liczne zatoki leśne.', 'Mieszane: piasek u brzegów, miękki muł w osi głównej.', 'Średnia, woda o odcieniu zielonkawym, bogata w plankton.', 'Bogata: gęste trzcinowiska, grążele żółte, tatarak.', 'Lin, Karaś złoty, Okoń, Szczupak, Płoć', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe zezwolenia PZW Warszawa dostępne online.', FALSE, FALSE, 'Dobra dzięki twardym fragmentom grobli i kładkom.', TRUE, FALSE, 'Dobry dojazd drogami szutrowymi pod same groble.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81069, 'Eutroficzny staw przepływowy', 18, 1.2, 2, 'Rynnowe koryto przepływowe, dno twarde w osi nurtu.', 'Twarde: piaszczysto-żwirowe w nurcie, muliste w zatokach.', 'Średnia; dobrze natleniona dzięki rzece Mieni.', 'Umiarkowana: pasy trzcin, kępy roślinności prądolubnej.', 'Jaź, Krąp, Szczupak, Sandacz, Leszcz', TRUE, 'Regularne zarybienia sandaczem i wsparcie białorybem.', TRUE, 'Zezwolenia PZW Warszawa; obowiązuje karta wędkarska.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska z bezpośrednim dojazdem.', TRUE, FALSE, 'Dobry dojazd asfaltowy i szutrowy z Natolina.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81070, 'Eutroficzny staw (główny)', 35, 1.3, 2.2, 'Regularna niecka, dno pofałdowane piaszczysto-muliste.', 'Przeważnie twarde: piasek z cienką warstwą osadów.', 'Dobra; woda przejrzystsza wiosną, natleniona przez wiatr.', 'Umiarkowana: pasy trzcin, moczarka kanadyjska na dnie.', 'Karp, Amur, Szczupak, Okoń, Leszcz', TRUE, 'Rekordowe zarybienia karpiem; dbanie o rybostan przez PZW.', TRUE, 'Standardowe składki PZW Warszawa; taryfy okresowe.', FALSE, FALSE, 'Bardzo dobra; szerokie stanowiska rzutowe wzdłuż grobli.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, liczne miejsca postojowe.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81071, 'Rynnowo-przepływowy', 10, 1.2, 2.5, 'Wyraźne koryto rzeczne na dnie, liczne korzenie dębów.', 'Twarde: piaszczysto-żwirowe, wypłukane przez nurt rzeki.', 'Dobra, woda dobrze natleniona i chłodniejsza.', 'Średnia: trzcina na brzegach, roślinność zanurzona w nurcie.', 'Jaź, Płoć rzeczna, Szczupak, Lin, Okoń', TRUE, 'Systematyczne zarybienia szczupakiem i wsparcie ryb reofilnych.', TRUE, 'Standardowe składki PZW Warszawa; popularny szlak.', FALSE, FALSE, 'Dobra dzięki licznym kładkom i stanowiskom leśnym.', TRUE, FALSE, 'Dobry dojazd drogami szutrowymi i leśnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81072, 'Eutroficzny staw hodowlany', 8, 1, 1.4, 'Mała niecka o wyrównanym dnie, piaszczyste groble.', 'Mieszane: piasek w litoralu, muł w części centralnej.', 'Średnia do niskiej; żyzna woda szybko nagrzewająca się.', 'Bogata: gęste trzcinowiska, rzadka roślinność podwodna.', 'Leszcz, Karp, Płoć, Szczupak, Karaś', TRUE, 'Regularne zarybienia białą rybą przez lokalne koło.', TRUE, 'Zezwolenia PZW Warszawa dostępne online.', FALSE, FALSE, 'Bardzo dobra wzdłuż grobli; twarde piaszczyste zejścia.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy pod samo łowisko.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81073, 'Eutroficzny staw (cichy)', 6, 0.9, 1.2, 'Płytki talerz o miękkim dnie, brak uskoków rynnowych.', 'Wybitnie miękkie: muł organiczny i detrytus roślinny.', 'Niska; typowa dla jezior żyznych; okresowo mętna.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką.', 'Lin, Karaś złoty, Szczupak, Płoć, Krąp', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe składki PZW Warszawa; karta wędkarska.', FALSE, FALSE, 'Średnia; dostępne wydeptane stanowiska w pasie trzcin.', FALSE, FALSE, 'Dojazd szutrowy i polny; utwardzone wjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81074, 'Eutroficzny staw (dziki)', 14, 1.1, 1.5, 'Misa o łagodnych spadkach, dno silnie zamulone.', 'Bardzo miękkie, muł organiczny i osady detrytusowe.', 'Niska, woda mętna, szybko nagrzewająca się wiosną.', 'Bardzo obfita: gęste trzcinowiska, lilie wodne, moczarka.', 'Lin, Szczupak, Karaś złoty, Płoć, Leszcz', TRUE, 'Naturalna ochrona drapieżnika; stabilna populacja lina.', TRUE, 'Standardowe zezwolenia PZW Warszawa.', FALSE, FALSE, 'Dobra dzięki twardym fragmentom grobli i kładkom.', TRUE, FALSE, 'Dobry dojazd drogami szutrowymi z Natolina.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80869, 'Eutroficzny staw leśny', 10, 1, 1.6, 'Niecka o regularnych spadkach dna, liczne korzenie olch.', 'Twarde: piaszczysto-żwirowe u brzegów, miękki muł w głębi.', 'Średnia, woda żyzna, dobrze natleniona dzięki osłonie leśnej.', 'Bogata: pasy trzcin, moczarka kanadyjska, lilie wodne.', 'Okoń, Lin, Karaś, Płoć, Szczupak', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą.', TRUE, 'Składki PZW Warszawa dostępne online.', FALSE, FALSE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, FALSE, 'Dojazd leśny i szutrowy; parkingi przy groblach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81075, 'Stawy narybkowe (małe)', 5, 0.8, 1.2, 'Płytkie talerze narybkowe, dno wyrównane piaszczyste.', 'Twarde: piasek drobnoziarnisty z cienką warstwą mułu.', 'Średnia do wysokiej; woda żyzna, dobrze wymieszana.', 'Umiarkowana: wąski pas trzcin przy groblach technicznych.', 'Płoć, Wzdręga, Karp (kroczek), Karaś srebrzysty', TRUE, 'Regularne dorybianie narybkiem i rybami białymi.', TRUE, 'Standardowe składki PZW Warszawa.', FALSE, FALSE, 'Wyśmienita; twarde groble i liczne ścieżki brzegowe.', FALSE, FALSE, 'Bardzo dobry dojazd asfaltowy pod same akweny.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81076, 'Rynnowe sielawowe (głębokie)', 205, 8.5, 24.8, 'Głęboka rynna, strome piaszczyste klify podwodne, liczne górki.', 'Wybitnie twarde: piasek krasowy, żwir i lita glina.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca spinningowi.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Sandacz, Okoń sielawowy, Sielawa, Leszcz, Płoć', TRUE, 'Intensywne zarybienia sandaczem i sielawą przez PZW.', TRUE, 'Licencja PZW Olsztyn; obowiązuje strefa ciszy.', FALSE, TRUE, 'Średnia przez wysokie skarpy; wyznaczone kładki i pomosty.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy do Kierzlin.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81077, 'Rynnowe leśne', 22, 4.2, 9.5, 'Mała niecka rynnowa, strome piaszczyste skarpy, twarde dno.', 'Twarde: jasny piasek krasowy i drobny żwir, mało mułu.', 'Wysoka, woda przejrzysta, leśny charakter o dobrym natlenieniu.', 'Skąpa: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz, Wzdręga', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Olsztyn dostępne online.', FALSE, TRUE, 'Średnia przez wysokie skarpy i gęsty las; kilka dzikich wejść.', FALSE, TRUE, 'Drogi leśne, piaszczyste; dojazd utrudniony dla niskich aut.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81094, 'Rynnowe sielawowe (czyste)', 28, 6.5, 17.5, 'Głęboka rynna, stromo opadające skarpy, dno twarde.', 'Bardzo twarde: piasek krasowy i skały polodowcowe.', 'Wysoka (I klasa), krystaliczna toń sielawowa.', 'Skąpa: roślinność podwodna kończy się gwałtownie na stokach.', 'Okoń, Szczupak, Płoć, Leszcz, Wzdręga', TRUE, 'Ochrona tarlisk naturalnych; systematyczne wsparcie PZW.', TRUE, 'Standardowe zezwolenia PZW Olsztyn; strefa ciszy.', FALSE, TRUE, 'Średnia przez wysokie skarpy; kilka dzikich wejść.', FALSE, TRUE, 'Dojazd utrudniony drogami leśnymi; parkingi leśne.', TRUE);
