INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81122, 'Dystroficzne leśne małe', 12, 1.8, 5.5, 'Mała misa o miękkim dnie, brak wyraźnych uskoków.', 'Bardzo miękkie: muł organiczny i osad liściasty z boru.', 'Niska; woda o mrocznym, herbacianym odcieniu humusowym.', 'Bardzo obfita: jezioro silnie zarastające grążelem i trzciną.', 'Lin, Karaś złoty, Szczupak leśny, Płoć, Wzdręga', TRUE, 'Brak zarybień masowych, stabilna populacja dzikich ryb.', TRUE, 'Standardowe zezwolenia PZW Olsztyn dostępne online.', FALSE, TRUE, 'Trudna przez bagno; zalecane wysokie wodery lub ponton.', FALSE, FALSE, 'Dojazd leśny, piaszczysty; utrudniony po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81123, 'Eutroficzne śródpolne', 6, 1.5, 3.8, 'Płytka niecka o wyrównanym dnie, dno piaszczysto-muliste.', 'Miękkie: muł organiczny i detrytus roślinny, piasek.', 'Niska; typowa dla małych zbiorników żyznych; mętna.', 'Ekstremalna: całe jezioro porośnięte moczarką i liliami.', 'Lin, Karaś srebrzysty, Płoć, Szczupak, Okoń', TRUE, 'Regularne zarybienia rybami spokojnego żeru przez PZW.', TRUE, 'Standardowe składki PZW Olsztyn; taryfy okresowe.', FALSE, FALSE, 'Dobra dzięki licznym kładkom i pomostom parkowym.', TRUE, FALSE, 'Dojazd asfaltowy pod sam zbiornik, parkingi miejskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81124, 'Eutroficzne rynnowe (DUŻE)', 425, 3.5, 8.2, 'Rozległa niecka o pofalowanym dnie, piaszczyste blaty.', 'Mieszane: twardy piasek na górkach, głęboki muł w dołach.', 'Niska; woda żyzna, silnie mącona przez wiatr; mętna.', 'Bogata: gigantyczne trzcinowiska, rdestnica, moczarka.', 'Sandacz, Szczupak, Leszcz, Płoć, Sum', TRUE, 'Intensywne zarybienia sandaczem przez okręg PZW Olsztyn.', TRUE, 'Składki PZW Olsztyn; wymagana karta i zezwolenie.', FALSE, FALSE, 'Bardzo dobra w miejscowości Blanki; liczne pomosty.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy wokół jeziora.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81125, 'Polodowcowe rynnowe', 152, 4.8, 9.8, 'Urozmaicona rzeźba dna, liczne wyspy i podwodne górki.', 'Twarde: jasny piasek i drobny żwir, lokalnie cienki muł.', 'Dobra; woda przejrzysta wiosną, natleniona przez wiatr.', 'Umiarkowana: pasy trzcin, rdestnica na spadkach dna.', 'Okoń, Szczupak, Leszcz, Płoć, Lin', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe zezwolenia PZW Olsztyn dostępne online.', FALSE, FALSE, 'Bardzo dobra dzięki licznym pomostom i plażom turystycznym.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81323, 'Rynnowe małe', 18, 3.5, 7.8, 'Mały talerz rynnowy o pofałdowanym dnie i twardych skarpach.', 'Twarde: jasny piasek krasowy i żwir polodowcowy.', 'Dobra; woda przejrzysta wiosną, natleniona przez wiatr.', 'Umiarkowana: wąski pierścień trzcin, kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem i wsparcie PZW.', TRUE, 'Standardowe zezwolenia PZW Bydgoszcz dostępne online.', FALSE, FALSE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami lokalnymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81141, 'Polodowcowe rynnowe', 52, 6.5, 17.5, 'Regularna rynna w osi jeziora, strome piaszczyste skarpy.', 'Twarde: jasny piasek i żwir, cienka warstwa mułu w osi.', 'Wysoka, woda bardzo czysta, dobrze natleniona przez cały rok.', 'Umiarkowana: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Systematyczne zarybienia drapieżnikiem przez okręg PZW.', TRUE, 'Standardowe składki PZW Gdańsk dostępne online.', FALSE, TRUE, 'Dobra dzięki licznym dzikim stanowiskom i polanom.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi pod sam akwen.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81127, 'Obszar rozlewiskowy (BAGIENNY)', 85, 0.5, 1.2, 'Gigantyczna, płytka niecka, koryta dawnych rzek.', 'Wybitnie miękkie: głęboki muł rzeczny i osady organiczne.', 'Niska; woda bardzo mętna, silnie mącona przez ptactwo.', 'Ekstremalna: bezkresne trzcinowiska, wyspy zielne, lilie.', 'Karaś srebrzysty, Lin, Szczupak, Płoć, Krąp', TRUE, 'Naturalna regeneracja; rekordowe przyrosty karasia.', TRUE, 'Standardowe zezwolenia PZW Olsztyn; surowy regulamin.', FALSE, FALSE, 'Ekstremalnie trudna; wymagane wysokie wodery i mobilność.', FALSE, TRUE, 'Dojazd drogami polnymi wzdłuż kanałów; utrudniony.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81128, 'Eutroficzne leśne (dzikie)', 14, 2.2, 4.8, 'Misa o łagodnych spadkach, dno silnie zamulone.', 'Bardzo miękkie, muł organiczny i osady detrytusowe leśne.', 'Niska; woda o ciemnym odcieniu, okresowo mętna i żyzna.', 'Bardzo obfita: gęste trzcinowiska, rdestnica, moczarka.', 'Lin, Szczupak, Karaś złoty, Płoć, Okoń', TRUE, 'Naturalna ochrona drapieżnika; stabilna populacja lina.', TRUE, 'Standardowe składki PZW Olsztyn; opłaty roczne.', FALSE, TRUE, 'Trudna przez bagno i gęsty las; wydeptane punkty.', FALSE, FALSE, 'Dojazd leśny, piaszczysty; zalecane auta wyższe.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81129, 'Polodowcowe rynnowe', 45, 4.2, 12, 'Regularna rynna w osi jeziora, strome piaszczyste skarpy.', 'Twarde: jasny piasek i drobny żwir, cienka warstwa mułu.', 'Dobra; woda przejrzysta wiosną, natleniona przez wiatr.', 'Umiarkowana: wąski pierścień trzcin, kępy rdestnicy pływającej.', 'Okoń, Szczupak, Płoć, Leszcz, Lin', TRUE, 'Systematyczne zarybienia drapieżnikiem przez lokalne koło.', TRUE, 'Standardowe składki PZW Olsztyn dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i pomostom.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81130, 'Rynnowe podmiejskie', 52, 3.8, 10.5, 'Niecka o regularnych spadkach dna, piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, miękki muł w osi rynny.', 'Średnia do dobrej; okresowo mętna w pełni lata.', 'Umiarkowana: pasy trzcin przy plażach, lilie wodne, moczarka.', 'Sandacz, Szczupak, Leszcz, Płoć, Okoń', TRUE, 'Intensywne zarybienia drapieżnikiem przez okręg PZW.', TRUE, 'Standardowe składki PZW Olsztyn; karta wędkarska.', FALSE, FALSE, 'Wyśmienita; liczne pomosty, plaże i alejki spacerowe.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, parkingi miejskie.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81131, 'Antropogeniczne (staw)', 12, 2.5, 5.2, 'Urozmaicona rzeźba poeksploatacyjna, twarde półki podwodne.', 'Bardzo twarde: lita glina i żwir polodowcowy.', 'Dobra; woda dobrze natleniona; okresowo zakwita w lecie.', 'Bogata: kępy trzcin, moczarka kanadyjska, grążele żółte.', 'Lin, Karaś złoty, Amur, Szczupak, Okoń', TRUE, 'Regularne dorybianie rybami białymi przez lokalne koło.', TRUE, 'Zezwolenia PZW Olsztyn dostępne online i w sklepach.', FALSE, FALSE, 'Dobra dzięki twardym brzegom i licznym zejściom.', FALSE, FALSE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81132, 'Zbiornik zaporowy', 185, 3.5, 8.5, 'Stare koryto rzeki Pasłęki, liczne karczowiska i zatopione pnie.', 'Zróżnicowane: piasek w korycie, gruby muł organiczny w zatokach.', 'Niska do średniej; żyzna woda rzeczna; osady niesione nurtu.', 'Bogata: szerokie pasy trzcinowisk, wyspy zielne, rogatek.', 'Sandacz, Kleń, Jaź, Szczupak, Okoń', TRUE, 'Ochrona tarlisk naturalnych (rezerwat); wsparcie PZW.', TRUE, 'Specjalna licencja PZW Elbląg + regulamin rezerwatu.', FALSE, TRUE, 'Trudna; dozwolona tylko w wyznaczonych punktach rezerwatu.', FALSE, TRUE, 'Dojazd utrudniony drogami leśnymi; parkingi rezerwatu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81133, 'Rynnowe sielawowe (GIGANT)', 735, 12.5, 42, 'Monumentalna batymetria, gwałtowne uskoki krasowe, głęboka rynna.', 'Wybitnie twarde: piasek krasowy, żwir i głazy polodowcowe.', 'Ekstremalnie wysoka (I klasa), krystaliczna toń sielawowa.', 'Skąpa: wąski pas trzcin, roślinność podwodna punktowo.', 'Okoń sielawowy, Szczupak pelagiczny, Sielawa, Płoć, Leszcz', TRUE, 'Intensywne zarybienia sielawą i drapieżnikiem przez fundację.', TRUE, 'Licencja RFW / PZW; bezwzględna strefa ciszy motorowodnej.', FALSE, TRUE, 'Średnia przez wysokie skarpy; liczne kładki turystyczne.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81134, 'Rynnowe małe (czyste)', 18, 4.2, 9.8, 'Mała niecka rynnowa o twardym piaszczystym dnie.', 'Twarde: jasny piasek krasowy i żwir polodowcowy.', 'Wysoka, woda krystalicznie czysta, sprzyjająca okoniom.', 'Umiarkowana: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Krasnopióra, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem drapieżnika.', TRUE, 'Standardowe składki PZW Gdańsk dostępne online.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi z Chmielna.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81135, 'Rynnowe', 145, 6.5, 20.2, 'Wyraźna centralna rynna, strome stoki, dno pofałdowane.', 'Twarde: piaszczysto-żwirowe, marginalna ilość mułu w głębi.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca spinningowi.', 'Skąpa: wąski pas trzcin, roślinność podwodna na spadkach.', 'Okoń, Szczupak, Sielawa, Leszcz, Płoć', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą.', TRUE, 'Zezwolenia PZW Gdańsk; obowiązuje karta wędkarska.', FALSE, TRUE, 'Dobra dzięki licznym kładkom i stanowiskom leśnym.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i leśnymi.', TRUE);
