INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81185, 'Dystroficzne (bagienne)', 8, 2.2, 5.8, 'Płaski talerz otoczony bagnem, dno wysoce zamulone.', 'Bardzo miękkie, płynny muł organiczny i gruby osad torfowy.', 'Niska, woda o ciemnym (herbacianym) odcieniu humusowym.', 'Ekstremalna: bagniste brzegi, trzciny, mchy torfowce, grążele.', 'Lin, Karaś złoty, Szczupak, Wzdręga', TRUE, 'Brak zarybień masowych, stabilna populacja dzikich ryb.', TRUE, 'Standardowe zezwolenia PZW Gdańsk; taryfy okresowe.', FALSE, TRUE, 'Ekstremalnie trudna przez bagno; wymagane kładki lub ponton.', FALSE, FALSE, 'Trudny dojazd piaszczystymi duktami Borów Tucholskich.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81721, 'Parkowy / Górski', 5, 1.2, 2.5, 'Nieregularna niecka o miękkim dnie.', 'Bardzo miękkie: osady organiczne i liściaste.', 'Dobra; woda chłodna, zasilana potokami.', 'Bogata: lilie wodne, moczarka kanadyjska.', 'Lin, Karp, Płoć, Karaś', TRUE, 'Okresowe zarybienia rybą białą.', TRUE, 'Składki PZW Jelenia Góra / Park Bukowiec.', FALSE, TRUE, 'Wyśmienita; brzegi niskie i trawiaste.', FALSE, FALSE, 'Dobry dojazd do parkingu przypałacowego.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81186, 'Rynnowo-przepływowe (GIGANT)', 675, 7.8, 27.2, 'Monumentalna batymetria, nurt Brdy, liczne wyspy i rynny.', 'Zróżnicowane: twardy piasek w nurcie, muł w zatokach.', 'Dobra; woda dobrze natleniona i chłodniejsza dzięki Brdzie.', 'Umiarkowana: pasy trzcin wokół wysp, podwodne łąki ramienic.', 'Sandacz, Okoń, Szczupak, Leszcz, Płoć, Jaź', TRUE, 'Intensywne zarybienia sandaczem przez okręg i G.R.', TRUE, 'Licencja PZW Bydgoszcz; popularny szlak żeglarski.', FALSE, FALSE, 'Bardzo dobra w miejscowościach; liczne pomosty i slipy.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, liczne parkingi w Swornegaciach.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81188, 'Rynnowe sielawowe', 192, 8.5, 24.5, 'Głęboka rynna, strome piaszczyste klify podwodne, liczne górki.', 'Bardzo twarde: piasek krasowy, żwir i lita glina.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca spinningowi.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Okoń, Szczupak pelagiczny, Sielawa, Leszcz, Płoć', TRUE, 'Intensywne zarybienia sielawą i drapieżnikiem przez PZW.', TRUE, 'Licencja PZW Suwałki; obowiązuje karta wędkarska.', FALSE, TRUE, 'Średnia przez wysokie skarpy; kilka wydeptanych dojść.', FALSE, TRUE, 'Dobry dojazd asfaltowy i szutrowy do Mieruniszek.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81189, 'Polodowcowe rynnowe', 42, 6.2, 20.5, 'Wyraźna centralna rynna, strome piaszczyste skarpy, twarde dno.', 'Twarde: jasny piasek i drobny żwir, mało mułu.', 'Wysoka (I klasa), woda krystalicznie czysta, natleniona.', 'Umiarkowana: wąski pierścień trzcin, rdestnica na spadkach.', 'Okoń, Szczupak, Płoć sielawowa, Krasnopióra, Sielawa', TRUE, 'Systematyczne zarybienia drapieżnikiem i białą rybą.', TRUE, 'Standardowe składki PZW Suwałki dostępne online.', FALSE, FALSE, 'Średnia przez wysokie skarpy; wyznaczone kładki.', TRUE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81190, 'Polodowcowe rynnowe', 28, 4.2, 12, 'Regularna rynna w osi jeziora, łagodne piaszczyste stoki.', 'Mieszane: piasek u brzegów, miękki muł w środkowej części.', 'Dobra; woda przejrzysta wiosną, natleniona przez wiatr.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, rdestnica.', 'Szczupak, Lin, Leszcz, Płoć, Okoń', TRUE, 'Regularne zarybienia drapieżnikiem przez okręg PZW Suwałki.', TRUE, 'Standardowe zezwolenia PZW Suwałki dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81191, 'Rynnowe (ekstremalnie głębokie)', 12, 10.5, 22.5, 'Wąska centralna rynna o bardzo stromych piaszczystych stokach.', 'Wybitnie twarde: lity piasek, żwir i głazy narzutowe.', 'Ekstremalnie wysoka (I klasa), widoczność do kilku metrów.', 'Skąpa: wąski pas trzcin, podwodne łąki ramienic.', 'Okoń, Szczupak, Sieja, Płoć, Sielawa', TRUE, 'Naturalna ochrona drapieżnika; wsparcie narybkiem przez PZW.', TRUE, 'Zezwolenia Gospodarstwa Rybackiego / PZW Suwałki.', FALSE, TRUE, 'Średnia przez strome brzegi; kilka wydeptanych punktów.', FALSE, TRUE, 'Dojazd drogami leśnymi i polnymi; utrudniony po opadach.', FALSE);
