INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81257, 'Rynnowe leśne (czyste)', 25, 4.2, 9.8, 'Wyraźna centralna rynna leśna o twardym piaszczystym dnie.', 'Twarde: jasny piasek krasowy i drobny żwir polodowcowy.', 'Wysoka, woda krystalicznie czysta, sprzyjająca okoniom.', 'Skąpa: wąski pierścień trzcin, podwodne kępy rdestnicy.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Olsztyn; taryfy okresowe.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi, utwardzonymi szutrami.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81258, 'Polodowcowe rynnowe (kanałowe)', 32, 3.5, 7.8, 'Mały talerz rynnowy o piaszczystych blatach przy kanale.', 'Mieszane: piasek w osi kanału, miękki muł w rynnie środkowej.', 'Dobra; woda przejrzystsza wiosną, natleniona przez przepływ.', 'Bogata: pasy trzcin, lilie wodne, moczarka kanadyjska.', 'Leszcz, Sandacz, Płoć, Szczupak, Okoń', TRUE, 'Systematyczne zarybienia sandaczem przez okręg PZW.', TRUE, 'Zezwolenia PZW Olsztyn; obowiązuje karta wędkarska.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i pomostom.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy pod sam akwen.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81259, 'Eutroficzna zatoka jeziorna', 85, 1.8, 4.2, 'Rozległa, płytka niecka zatokowa, liczne mielizny roślinne.', 'Wybitnie miękkie: głęboki muł organiczny i detrytus.', 'Niska; woda mętna i żyzna, silnie mącona przez ptactwo.', 'Ekstremalna: bezkresne trzcinowiska, wyspy zielne, lilie.', 'Lin, Szczupak, Karaś złoty, Płoć, Krąp', TRUE, 'Ochrona tarlisk naturalnych (Jeziorak); wsparcie narybkiem.', TRUE, 'Standardowe zezwolenia Gospodarstwa Rybackiego Iława.', FALSE, TRUE, 'Ekstremalnie trudna; wymagane wysokie wodery lub ponton.', FALSE, TRUE, 'Dojazd leśny, piaszczysty; zalecane auta wyższe.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81260, 'Rynnowe (krystalicznie czyste)', 45, 6.5, 17.5, 'Wyraźna rynna rynnowa o twardym piaszczystym dnie.', 'Twarde: jasny piasek krasowy i żwir, mało osadów.', 'Wysoka (I klasa), krystaliczna toń sprzyjająca spinningowi.', 'Umiarkowana: pasy trzcin, podwodne łąki ramienic na stokach.', 'Okoń, Szczupak, Płoć sielawowa, Leszcz, Wzdręga', TRUE, 'Systematyczne zarybienia drapieżnikiem przez okręg PZW.', TRUE, 'Licencja PZW Olsztyn; obowiązuje bezwzględna strefa ciszy.', FALSE, TRUE, 'Dobra dzięki piaszczystym plażom i łagodnym zejściom.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy pod sam akwen.', TRUE);
