INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81476, 'Zaporowy wyrównawczy', 200, 5, 15, 'Stare koryto rzeczne, liczne mielizny żwirowe i głębokie rynny.', 'Twarde: żwir, otoczaki Sanu, lokalnie warstwy osadów.', 'Dobra; woda zimna i przejrzysta, sielawowy charakter.', 'Skąpa: punktowe pasy trzcin, mchy wodne na kamieniach.', 'Pstrąg potokowy, Kleń, Szczupak, Lipień, Brzana', TRUE, 'Systematyczne zarybienia pstrągiem i drapieżnikiem.', TRUE, 'Składki PZW Krosno; zezwolenia okresowe online.', FALSE, TRUE, 'Średnia przez wysokie brzegi; liczne stanowiska leśne.', FALSE, FALSE, 'Dojazd asfaltowy pod zaporę, leśny szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81477, 'Zaporowy górski (nowy)', 820, 15, 45, 'Ekstremalne spadki dna, zalana infrastruktura drogowa.', 'Bardzo twarde: skała, łupki, betonowe pozostałości.', 'Wysoka; woda czysta, okresowo mętna po opadach w górach.', 'Minimalna: zbiornik młody, brak wykształconego litoralu.', 'Sandacz, Okoń, Szczupak, Leszcz, Płoć', TRUE, 'Intensywne zarybienia sandaczem i drapieżnikami.', TRUE, 'Licencja PZW Kraków; karta wędkarska.', FALSE, FALSE, 'Trudna; brzegi strome i kamieniste; wymagane dobre obuwie.', FALSE, TRUE, 'Dojazd drogami lokalnymi, utrudniony dostęp do tafli.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81037, 'Staw hodowlany (leśny)', 38, 1, 1.5, 'Misa łagodna', 'Głęboki muł i torf', 'Niska', 'Bogata roślinność pływająca', 'Lin, Karp, Karaś, Szczupak', TRUE, 'Produkcja towarowa', TRUE, 'Zakaz amatorskiego połowu', FALSE, TRUE, 'Średnia', FALSE, FALSE, 'Piaszczysta leśna', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81479, 'Zaporowy górski (duży)', 1000, 8.5, 27, 'Urozmaicona: koryto Soły, rozległe blaty i podwodne rafy.', 'Mieszane: twarda glina, kamienie, w cofce muł rzeźny.', 'Średnia; typowa dla zbiorników zaporowych; zakwity letnie.', 'Umiarkowana: pasy trzcin w zatokach, rdestnice w cofce.', 'Sandacz, Sum, Leszcz, Szczupak, Okoń', TRUE, 'Systematyczne zarybienia sandaczem i sumem przez PZW.', TRUE, 'Standardowe składki PZW Bielsko-Biała.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska, pomosty i slipy.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy pod samo jezioro.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81481, 'Zaporowy rynnowy', 380, 6, 18, 'Wąska rynna rzeczna, strome brzegi, twarde dno.', 'Twarde: kamienie polodowcowe, żwir, piaszczyste blaty.', 'Dobra; woda czysta, dobrze natleniona przez nurt.', 'Skąpa: rzadkie trzcinowiska przy miejscowościach.', 'Sandacz, Okoń, Świnka, Leszcz, Pstrąg (okresowo)', TRUE, 'Systematyczne zarybienia drapieżnikiem przez lokalne koła.', TRUE, 'Standardowe zezwolenia PZW Bielsko-Biała.', FALSE, FALSE, 'Średnia; dostępne stanowiska wzdłuż dróg brzegowych.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy (droga nr 948).', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81482, 'Techniczny / Zaporowy', 100, 3.5, 10, 'Niecka wyrównawcza, brzegi betonowe, dno twarde.', 'Bardzo twarde: beton, żwir, piasek kopalniany.', 'Dobra; woda filtrowana i osadzana przed ujęciem.', 'Brak: zbiornik techniczny o gołych brzegach.', 'Brak połowu (woda pitna)', FALSE, 'Brak oficjalnych zarybień dla wędkarzy.', FALSE, 'Strefa ochronna - zakaz połowu.', FALSE, FALSE, 'Brak dostępu.', FALSE, FALSE, 'Dojazd technologiczny.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81483, 'Zaporowy (GIGANT)', 3200, 5.2, 14, 'Ogromne piaszczyste blaty, koryto Wisły, karczowiska.', 'Mieszane: piasek krasowy, muł organiczny w cofce.', 'Średnia; woda dobrze natleniona przez wiatr; sielawowa.', 'Bogata: gigantyczne pasy trzcinowisk (ostoje ptactwa).', 'Sandacz, Leszcz, Szczupak, Płoć, Sum', TRUE, 'Limitowane zarybienia drapieżnikiem; ścisła gospodarka.', TRUE, 'Zezwolenia GPW Katowice (limitowana ilość).', FALSE, FALSE, 'Trudna; ograniczone strefy wejścia; ostoja przyrody.', FALSE, TRUE, 'Bardzo dobry dojazd pod wyznaczone punkty i slipy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81484, 'Zalew parkowy', 15, 1.8, 4.2, 'Mała niecka rzeczna, dno piaszczysto-muliste.', 'Mieszane: piasek w litoralu, miękki muł w osi nurtu.', 'Średnia; okresowo mętna po opadach; żyzna.', 'Bogata: trzciny, lilie wodne, moczarka kanadyjska.', 'Karp, Lin, Karaś, Płoć, Szczupak', TRUE, 'Regularne zarybienia karpiem przez lokalne koło.', TRUE, 'Standardowe składki PZW Katowice.', FALSE, FALSE, 'Wyśmienita; liczne alejki spacerowe i mola.', TRUE, FALSE, 'Bardzo dobry dojazd asfaltowy, parkingi przy zamku.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81485, 'Zaporowy / Elektrowniany', 450, 6, 12, 'Piaszczyste blaty, twarde uskoki, dno czyste od lodu.', 'Twarde: piasek i żwir polodowcowy, cienka warstwa mułu.', 'Niska do średniej; woda ciepła, żyzna, silnie natleniona.', 'Umiarkowana: pasy trzcin, brak lodu zimą sprzyja roślinom.', 'Sum, Karp (medalowy), Sandacz, Amur, Tołpyga', TRUE, 'Intensywne zarybienia gatunkami ciepłolubnymi i sumem.', TRUE, 'Licencja PZW Katowice / Elektrownia; łowisko specjalne.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska rzutowe i slipy.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, parkingi strzeżone.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81486, 'Poeksploatacyjny rynnowy', 250, 8, 18, 'Głębokie wyrobisko o stromych piaszczystych stokach.', 'Wybitnie twarde: piasek kopalniany i gruby żwir.', 'Wysoka; woda czysta, krystaliczna toń sielawowa.', 'Umiarkowana: pasy trzcin na wypłyceniach, moczarka.', 'Okoń, Sandacz, Leszcz, Szczupak, Płoć', TRUE, 'Systematyczne zarybienia drapieżnikiem przez PZW.', TRUE, 'Standardowe składki PZW Katowice.', FALSE, FALSE, 'Bardzo dobra; piaszczyste plaże i utwardzone brzegi.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy pod samo jezioro.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81487, 'Zaporowy (duży)', 2400, 5.5, 13, 'Urozmaicona: koryto rzeki, piaszczyste blaty, karczowiska.', 'Mieszane: piasek krasowy, glina, muł organiczny.', 'Średnia do niskiej; letnie zakwity z powodu żyzności.', 'Umiarkowana: trzciny w zatokach, rzadkie moczarki.', 'Sandacz, Sum, Boleń, Szczupak, Leszcz', TRUE, 'Intensywne zarybienia sandaczem przez okręg PZW Opole.', TRUE, 'Standardowe składki PZW Opole; karta wędkarska.', FALSE, FALSE, 'Dobra w miejscowościach; trudna przy wysokim stanie wody.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81107, 'Wyrobisko poeksploatacyjne', 18, 3.2, 8.5, 'Niecka o stromych spadkach, liczne półki żwirowe.', 'Bardzo twarde: gruby żwir i piasek kopalniany.', 'Wysoka; woda przejrzysta, dobrze natleniona.', 'Bogata: rdestnica na uskokach, pasy trzcin.', 'Karp, Amur, Szczupak, Okoń, Płoć', TRUE, 'Regularne zarybienia karpiem i drapieżnikiem przez PZW.', TRUE, 'Standardowe składki PZW Opole; zezwolenia online.', FALSE, FALSE, 'Bardzo dobra; brzegi dostępne i stabilne.', FALSE, FALSE, 'Bardzo dobry dojazd asfaltowy, parkingi osiedlowe.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81489, 'Eutroficzne / Stawowe', 12, 1.5, 3.8, 'Płytka misa o wyrównanym dnie, brzegi silnie zarośnięte.', 'Miękkie: muł organiczny i torf.', 'Niska; typowa dla małych zbiorników żyznych.', 'Bogata: gęste trzcinowiska, lilie wodne, moczarka.', 'Lin, Szczupak, Karaś złoty, Płoć, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe składki PZW Kalisz.', FALSE, FALSE, 'Średnia przez trzciny; dostępne wydeptane stanowiska.', FALSE, TRUE, 'Dojazd drogami polnymi i szutrowymi; utrudniony.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81490, 'Polodowcowe rynnowe', 142, 2.8, 5.5, 'Regularna rynna w osi jeziora, piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, miękki muł w osi rynny.', 'Średnia do niskiej; okresowo mętna latem.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, lilie.', 'Leszcz, Sandacz, Płoć, Szczupak, Okoń', TRUE, 'Regularne zarybienia drapieżnikiem i białorybem przez PZW.', TRUE, 'Standardowe zezwolenia PZW Poznań.', FALSE, FALSE, 'Wyśmienita; liczne pomosty miejskie i plaże piaszczyste.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, parkingi w centrum.', TRUE);
