INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81492, 'Polodowcowe rynnowe (duże)', 185, 4.5, 11.5, 'Urozmaicona rzeźba dna, wyraźna rynna centralna.', 'Twarde: piasek i drobny żwir polodowcowy, cienki muł.', 'Dobra; woda przejrzysta wiosną, natleniona przez wiatr.', 'Bogata: gęste trzcinowiska przy miejscowości, moczarka.', 'Sandacz, Leszcz, Amur, Szczupak, Okoń', TRUE, 'Intensywne zarybienia sandaczem przez okręg PZW Poznań.', TRUE, 'Standardowe zezwolenia PZW Poznań; szlak wodny.', FALSE, FALSE, 'Wyśmienita; liczne pomosty, mariny i slipy.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, parkingi turystyczne.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81493, 'Rynnowe małe', 14, 2.5, 4.8, 'Mała niecka o łagodnych spadkach dna.', 'Miękkie: muł organiczny i detrytus, piasek u brzegów.', 'Średnia; typowa dla małych zbiorników żyznych.', 'Bogata: kępy trzcin, lilie wodne, moczarka kanadyjska.', 'Lin, Karaś, Płoć, Szczupak, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe składki PZW Poznań.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i łagodnym zejściom.', FALSE, TRUE, 'Dojazd drogami polnymi i utwardzonymi szutrami.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81494, 'Eutroficzne rynnowe', 105, 1.8, 4.2, 'Płaski talerz, dno bez uskoków rynnowych, silnie zarastające.', 'Wybitnie miękkie: głęboki muł organiczny i torf.', 'Niska; woda żyzna, silnie nagrzewająca się wiosną.', 'Ekstremalna: całe jezioro porośnięte grążelem i liliami.', 'Szczupak, Wzdręga, Leszcz, Lin, Karaś', TRUE, 'Naturalna regeneracja drapieżnika; wsparcie narybkiem.', TRUE, 'Standardowe zezwolenia PZW Poznań; karta wędkarska.', FALSE, FALSE, 'Trudna przez trzciny; większość stanowisk z pomostów.', TRUE, TRUE, 'Dobry dojazd drogami szutrowymi i polnymi.', TRUE);
