INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81498, 'Polodowcowe rynnowe', 45, 3.5, 6.2, 'Urozmaicona rzeźba dna, piaszczyste blaty rynnowe.', 'Twarde: jasny piasek i drobny żwir polodowcowy.', 'Dobra; woda przejrzystsza wiosną, natleniona przez wiatr.', 'Bogata: pasy trzcin, rdestnica na spadkach dna.', 'Lin, Szczupak, Płoć, Wzdręga, Okoń', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem PZW.', TRUE, 'Standardowe składki PZW Leszno dostępne online.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i kładkom.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy.', TRUE);
