INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81532, 'Polodowcowe rynnowe (Rezerwat)', 92, 8.5, 17.2, 'Głęboka rynna centralna, bardzo strome stoki, dno twarde.', 'Wybitnie twarde: piasek krasowy i glina polodowcowa.', 'Wysoka (I klasa), krystaliczna toń, sielawowy charakter.', 'Skąpa: wąski pas trzcin, roślinność podwodna tylko punktowo.', 'Szczupak, Okoń, Płoć, Sielawa (zakaz połowu)', TRUE, 'Brak zarybień gospodarczych; naturalny ekosystem.', FALSE, 'Zakaz połowu - Ścisły Rezerwat Przyrody.', FALSE, TRUE, 'Brak (zakaz wstępu do wody).', FALSE, FALSE, 'Dojazd do parkingów leśnych WPN, dalej pieszo.', TRUE);
