INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81672, 'Rynnowe leśne (czyste)', 22, 4.2, 10.5, 'Niecka o regularnych spadkach dna, twarde piaszczyste blaty.', 'Twarde: jasny piasek krasowy i drobny żwir.', 'Wysoka (I klasa), krystaliczna toń leśna.', 'Skąpa: wąski pierścień trzcin, podwodne mchy.', 'Okoń, Szczupak, Lin, Płoć, Krasnopióra', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem szczupaka.', TRUE, 'Składki PZW Gorzów Wlkp.; karta wędkarska.', FALSE, TRUE, 'Dobra dzięki twardym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi, piaszczystymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81673, 'Polodowcowe rynnowe', 58, 5.5, 15.2, 'Regularna rynna w osi jeziora, wyraźne strome skarpy.', 'Twarde: piasek polodowcowy i żwir, mało mułu.', 'Wysoka, woda krystaliczna, dobrze natleniona.', 'Umiarkowana: pasy trzcin, rdestnica na spadkach dna.', 'Szczupak, Okoń, Leszcz, Płoć sielawowa, Lin', TRUE, 'Systematyczne zarybienia drapieżnikiem i białorybem.', TRUE, 'Zezwolenia PZW Gorzów Wlkp. dostępne online.', FALSE, TRUE, 'Wyśmienita; liczne piaszczyste dojścia i biwaki.', TRUE, TRUE, 'Bardzo dobry dojazd drogami szutrowymi i lokalnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81674, 'Eutroficzne rynnowe (Poligon)', 18, 2.5, 6.2, 'Mała niecka o łagodnych spadkach dna, dno piaszczysto-muliste.', 'Mieszane: piasek w litoralu, miękki muł w osi rynny.', 'Dobra; woda natleniona przez bór; okresowo mętna.', 'Bogata: gęste trzcinowiska, rdestnica, moczarka.', 'Lin, Szczupak, Płoć, Karaś srebrzysty, Okoń', TRUE, 'Gospodarka oparta na naturalnym rozrodzie (znikoma presja).', TRUE, 'Standardowe składki PZW Koszalin; strefa wojskowa.', FALSE, TRUE, 'Średnia przez trzciny; dostępne wydeptane stanowiska.', FALSE, FALSE, 'Dojazd utrudniony; drogi poligonowe, piaszczyste.', FALSE);
