INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81713, 'Rynnowe sielawowe (czyste)', 28, 8.5, 19.5, 'Głęboka rynna, stromo opadające skarpy, dno twarde.', 'Wybitnie twarde: piasek krasowy i biały wapień polodowcowy.', 'Ekstremalnie wysoka (I klasa), widoczność do 6 metrów.', 'Skąpa: wąski pas trzcin, roślinność podwodna punktowo.', 'Okoń sielawowy, Szczupak pelagiczny, Płoć, Leszcz', TRUE, 'Ochrona tarlisk naturalnych; systematyczne wsparcie PZW.', TRUE, 'Standardowe składki PZW Zielona Góra; strefa ciszy.', FALSE, TRUE, 'Średnia przez wysokie skarpy; wyznaczone dojścia leśne.', FALSE, TRUE, 'Dojazd drogami leśnymi i szutrowymi; utrudniony.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81714, 'Polodowcowe rynnowe leśne', 20, 4.2, 11.8, 'Wyraźna centralna rynna, strome piaszczyste skarpy.', 'Twarde: jasny piasek i żwir polodowcowy, mało mułu.', 'Wysoka, woda bardzo czysta, dobrze natleniona przez bór.', 'Umiarkowana: wąski pierścień trzcin, podwodne kępy moczarki.', 'Okoń, Szczupak, Płoć, Lin, Leszcz', TRUE, 'Naturalny ekosystem wspierany okresowo narybkiem przez PZW.', TRUE, 'Standardowe zezwolenia PZW Zielona Góra.', FALSE, TRUE, 'Dobra dzięki twardszym brzegom i leśnym polanom.', FALSE, TRUE, 'Dojazd drogami leśnymi i piaszczystymi pod sam akwen.', TRUE);
