INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81008, 'Staw hodowlany', 9, 1, 1.4, 'Płytka misa', 'Muł organiczny', 'Niska', 'Bardzo bogata', 'Lin, Karaś złoty, Płoć', TRUE, 'Brak (naturalny rozród)', TRUE, 'Zezwolenia Stawy Milickie', FALSE, TRUE, 'Trudna (krzaki)', FALSE, FALSE, 'Leśna', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81728, 'Polodowcowe (duże)', 95, 4.5, 14.2, 'Urozmaicona rzeźba dna, piaszczyste blaty, głęboka rynna środkowa.', 'Mieszane: piasek u brzegów, mulisty szlam w głębi.', 'Średnia; okresowo mętna latem; żyzna.', 'Bogata: gęste trzcinowiska, moczarka kanadyjska, rdestnica.', 'Leszcz, Amur, Szczupak, Okoń, Płoć', TRUE, 'Intensywne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Standardowe składki PZW Legnica; karta wędkarska.', FALSE, FALSE, 'Wyśmienita; liczne pomosty wiejskie i piaszczyste dojścia.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy i szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81729, 'Polodowcowe rynnowe', 25, 3.2, 6.5, 'Misa o łagodnych spadkach dna, piaszczyste wypłycenia.', 'Mieszane: piasek w litoralu, miękki muł w osi rynny.', 'Dobra; woda przejrzystsza wiosną, natleniona przez wiatr.', 'Bogata: kępy trzcin, lilie wodne, moczarka kanadyjska.', 'Lin, Karaś, Płoć, Szczupak, Okoń', TRUE, 'Systematyczne zarybienia drapieżnikiem przez okręg PZW.', TRUE, 'Standardowe składki PZW Legnica.', FALSE, FALSE, 'Dobra dzięki licznym dzikim stanowiskom i polanom.', FALSE, TRUE, 'Dobry dojazd drogami lokalnymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81730, 'Eutroficzne / Rezerwat', 62, 1.2, 3, 'Płytka niecka o wyrównanym dnie, silnie zarastająca.', 'Wybitnie miękkie: gruby muł organiczny i torf.', 'Niska; typowa dla jezior żyznych; okresowo mętna.', 'Ekstremalna: gigantyczne trzcinowiska, wyspy zielne, lilie.', 'Lin, Karp, Szczupak, Karaś złoty, Płoć', TRUE, 'Naturalna regeneracja; wsparcie narybkiem w strefach gospodarczych.', TRUE, 'Składki PZW Legnica; obowiązują rygory rezerwatu.', FALSE, TRUE, 'Ograniczona do wyznaczonych kładek i stanowisk.', TRUE, FALSE, 'Dobry dojazd do granic rezerwatu, zakaz wjazdu nad samą wodę.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81731, 'Stawowe śródpolne', 8, 1.2, 2.8, 'Płytka misa o wyrównanym dnie.', 'Miękkie: muł organiczny i detrytus roślinny.', 'Niska; typowa dla małych zbiorników żyznych.', 'Bogata: gęste trzcinowiska, rzęsa wodna.', 'Płoć, Wzdręga, Lin, Okoń, Szczupak', TRUE, 'Systematyczne zarybienia białorybem przez PZW Wrocław.', TRUE, 'Standardowe składki PZW Wrocław.', FALSE, FALSE, 'Wyśmienita; brzegi niskie i trawiaste.', FALSE, FALSE, 'Dobry dojazd drogami polnymi i szutrowymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81732, 'Stawowe eutroficzne', 6, 1, 2.2, 'Płytka niecka rzeczna, brzegi niskie i bagniste.', 'Wybitnie miękkie: muł i osady liściaste.', 'Niska; woda żyzna, mętna latem.', 'Bardzo obfita: trzcina pospolita, grążele żółte.', 'Karaś srebrzysty, Lin, Płoć, Szczupak', TRUE, 'Naturalny ekosystem wspierany okresowo przez lokalne koło.', TRUE, 'Standardowe składki PZW Wrocław.', FALSE, FALSE, 'Średnia; wymagane szukanie stanowisk w szuwarach.', FALSE, FALSE, 'Dojazd drogami polnymi; utrudniony po opadach.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81733, 'Zalewowe / Starorzecze', 12, 1.8, 4.2, 'Nieregularna niecka rzeczna, liczne doły i przykosy.', 'Mieszane: piasek w nurcie, miękki muł w zatokach.', 'Średnia; okresowo mętna po przyborach rzeki.', 'Bogata: powalone drzewa, lilie wodne, trzcina.', 'Szczupak, Leszcz, Okoń, Płoć, Lin', TRUE, 'Gospodarka oparta na naturalnym rozrodzie i wsparciu PZW.', TRUE, 'Standardowe składki PZW Wrocław; karta wędkarska.', FALSE, FALSE, 'Trudna; brzegi naturalne i zakrzaczone.', FALSE, TRUE, 'Dojazd drogami polnymi i łąkowymi; wymagany suchy teren.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81734, 'Eutroficzne bagienne', 9, 1.1, 2.5, 'Płaski talerz o bardzo miękkim dnie, brak uskoków.', 'Wybitnie miękkie: gruby muł i torf.', 'Niska; woda żyzna, o ciemniejszym odcieniu.', 'Ekstremalna: całe jezioro porośnięte grążelem i moczarką.', 'Lin, Karaś złoty, Płoć, Szczupak', TRUE, 'Naturalny ekosystem leśno-łąkowy.', TRUE, 'Standardowe składki PZW Wrocław.', FALSE, FALSE, 'Trudna przez szuwary; zalecane wodery.', FALSE, FALSE, 'Dojazd utrudniony przez podmokłe łąki.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81735, 'Stawowe rekreacyjne', 22, 1.5, 3.2, 'Płytka misa o wyrównanym dnie, piaszczyste brzegi.', 'Mieszane: piasek u brzegów, muł w osi.', 'Średnia; okresowo zakwita latem.', 'Bogata: pasy trzcin przy groblach, moczarka.', 'Karp, Amur, Płoć, Krąp, Okoń', TRUE, 'Intensywne zarybienia karpiem i amurem przez PZW.', TRUE, 'Standardowe zezwolenia PZW Wrocław.', FALSE, FALSE, 'Bardzo dobra; liczne stanowiska rzutowe.', TRUE, FALSE, 'Bardzo dobry dojazd szutrowy pod sam zbiornik.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81736, 'Zaporowy retencyjny', 90, 1.8, 3.5, 'Niecka rzeczna, wyraźne koryto rzeki Orla na dnie.', 'Twarde: piasek i drobny żwir polodowcowy, cienki muł.', 'Średnia; woda natleniona przez przepływ rzeki.', 'Umiarkowana: pasy trzcin na brzegach, rzadki rogatek.', 'Sandacz, Karp, Boleń, Szczupak, Leszcz', TRUE, 'Intensywne coroczne zarybienia sandaczem i karpiem.', TRUE, 'Składki PZW Poznań / Leszno; obowiązuje karta.', FALSE, FALSE, 'Wyśmienita; brzegi otwarte i dostępne dla spinningistów.', FALSE, TRUE, 'Bardzo dobry dojazd asfaltowy, duże parkingi.', TRUE);
