INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81801, 'Eutroficzne małe', 15, 1.8, 4.2, 'Mała niecka o wyrównanym dnie, silnie zarastająca.', 'Wybitnie miękkie: muł organiczny i osad leśny.', 'Niska do średniej; woda żyzna o herbacianym odcieniu.', 'Ekstremalna: gęste trzcinowiska, grążel żółty, rogatek.', 'Lin, Karaś, Szczupak, Płoć', TRUE, 'Naturalny rozród wspierany zarybieniami PZW.', TRUE, 'Zezwolenia PZW Białystok; mała woda leśna.', FALSE, FALSE, 'Średnia; specyficzne wejścia w szuwarach.', FALSE, TRUE, 'Drogi leśne gruntowe; trudny dojazd po deszczu.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81802, 'Polodowcowe rynnowe', 25, 4.2, 11.5, 'Regularna rynna z wyraźnymi spadkami i piaszczystymi blatami.', 'Mieszane: piasek przy brzegu, muł w głębszych partiach.', 'Dobra; woda przejrzysta wiosną i jesienią.', 'Umiarkowana: pierścienie trzcin, rdestnica na spadkach.', 'Okoń, Szczupak, Płoć, Leszcz, Lin', TRUE, 'Systematyczne zarybienia drapieżnikiem przez PZW Suwałki.', TRUE, 'Standardowe zezwolenia PZW Suwałki; dostęp online.', FALSE, FALSE, 'Dobra dzięki piaszczystym zejściom i polanom leśnym.', FALSE, TRUE, 'Dobry dojazd drogami szutrowymi i lokalnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81803, 'Polodowcowe rynnowe', 42, 3.8, 9.8, 'Niecka rynnowa z urozmaiconą strefą litoralu.', 'Twarde: piasek i żwir, lokalnie warstwy mułu.', 'Dobra; woda przejrzysta wiosną, dobrze natleniona.', 'Umiarkowana: trzcinowiska, podwodne łąki osoki aloesowatej.', 'Okoń, Płoć, Szczupak, Lin, Leszcz', TRUE, 'Regularne zarybienia drapieżnikiem przez lokalne koło PZW.', TRUE, 'Zezwolenia PZW Białystok dostępne online.', FALSE, FALSE, 'Dobra dzięki twardym brzegom i licznym pomostom.', TRUE, TRUE, 'Dojazd drogami szutrowymi i polnymi; latem bardzo dobry.', TRUE);
