INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80099, 'Polodowcowe rynnowe (duże)', 198, 6.5, 17.8, 'Szeroka głęboka rynna z górkami podwodnymi.', 'Twarde: glina polodowcowa i piasek, lokalnie muł.', 'Dobra; dobrze natleniona; przejrzysta wiosną.', 'Bogata: pasy trzcin, rdestnica, lilie wodne.', 'Sandacz, Leszcz, Szczupak, Okoń, Węgorz', TRUE, 'Intensywne zarybienia sandaczem i węgorzem przez GR.', TRUE, 'Licencja GR Szwaderowo; zezwolenia online.', FALSE, TRUE, 'Bardzo dobra; liczne pomosty i dzikie wejścia.', TRUE, TRUE, 'Dobry dojazd asfaltowy i szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (81799, 'Polodowcowe rynnowe (złożone)', 562, 4.5, 13.5, 'Wybitnie urozmaicona: liczne zatoki, wyspy i górki.', 'Mieszane: piasek i glina na górkach, muł w zatokach.', 'Dobra do średniej; okresowo żyzna latem.', 'Bardzo bogata: rozległe trzcinowiska, podwodne łąki.', 'Sandacz, Leszcz (medalowy), Szczupak, Okoń, Węgorz', TRUE, 'Stałe, intensywne zarybienia sandaczem i leszczem.', TRUE, 'Licencja GR Szwaderowo; infrastruktura turystyczna.', FALSE, FALSE, 'Wyśmienita; setki pomostów i wejść z brzegu.', TRUE, TRUE, 'Asfalt i szuter; wyśmienita dostępność.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80000, 'Zaporowy (płytki)', 60, 1.8, 3.5, 'Płaska misa z piaszczystymi łachami i wysepkami.', 'Mieszane: głównie piasek, w zatokach cienki muł.', 'Średnia; okresowo mętna latem (turystyka).', 'Bogata: rdestnica, trzcina pospolita, lilie w zatokach.', 'Okoń, Szczupak, Leszcz, Płoć, Węgorz', TRUE, 'Regularne zarybienia drapieżnikiem i białą rybą przez PZW.', TRUE, 'Składki PZW Kielce; karta wędkarska.', FALSE, FALSE, 'Wyśmienita; liczne piaszczyste dojścia i mola.', TRUE, TRUE, 'Bardzo dobry dojazd asfaltowy, parkingi turystyczne.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80001, 'Stawowy hodowlany', 25, 1.2, 2, 'Płaski talerz rzeźbiony pod odłowy.', 'Wybitnie miękkie: żyzny muł organiczny.', 'Niska; typowa dla stawów karpiowych; mętna.', 'Bogata: gęste trzcinowiska na obrzeżach.', 'Karp milicki (odmiana ruda), Lin, Karaś', TRUE, 'Intensywna hodowla towarowa.', TRUE, 'Zazwyczaj zakaz połowu (gospodarstwo produkcyjne).', FALSE, TRUE, 'Ograniczona do grobli.', FALSE, FALSE, 'Dojazd drogami szutrowymi i polnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80002, 'Stawowy hodowlany', 12, 1.1, 1.6, 'Równomierne dno z lekkim spadkiem ku mnichowi.', 'Miękkie: muł i osady liściaste.', 'Niska; woda żyzna.', 'Umiarkowana: pasy trzcin i tataraku.', 'Karp, Amur, Płoć', TRUE, 'Naturalny rozród i zarybienia hodowlane.', TRUE, 'Wymagana zgoda właściciela / Gospodarstwa.', FALSE, TRUE, 'Dobra z grobli.', FALSE, FALSE, 'Dojazd drogami polnymi.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80003, 'Stawowy hodowlany', 10, 1, 1.5, 'Płytka niecka.', 'Bardzo miękkie: gruby muł.', 'Niska.', 'Bardzo bogata: roślinność wynurzona (szuwary).', 'Lin, Karaś złoty, Szczupak (tarlisko)', TRUE, 'Naturalna regeneracja populacji.', TRUE, 'Zakaz amatorskiego połowu ryb.', FALSE, TRUE, 'Trudna przez zarośla.', FALSE, FALSE, 'Dojazd utrudniony.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80004, 'Stawowy (kompleks)', 45, 1.3, 1.8, 'Skomplikowany system grobli i niecek.', 'Miękkie: żyzny muł bentosowy.', 'Średnia do niskiej.', 'Bogata: grążele żółte, rzęsa wodna (okresowo).', 'Karp, Amur, Lin, Szczupak', TRUE, 'Produkcja towarowa karpia.', TRUE, 'Zazwyczaj wyłączone z amatorskiego połowu.', FALSE, TRUE, 'Średnia (groble).', FALSE, FALSE, 'Dojazd szutrowy pod zabudowania gospodarstwa.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80005, 'Techniczny / Spiętrzenie', 8, 1.5, 2.5, 'Wąskie koryto rzeczne z poszerzeniami.', 'Mieszane: piasek u wlotów, muł przy zastawkach.', 'Średnia; woda przepływowa.', 'Umiarkowana: trzcina, moczarka.', 'Płoć, Okoń, Jaź, Szczupak', TRUE, 'Migracja naturalna z rzeki Czarnej.', TRUE, 'Wymagana zgoda zarządcy obiektu.', FALSE, FALSE, 'Dobra przy zabytkowych obiektach.', TRUE, FALSE, 'Dojazd asfaltowy pod Muzeum.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80006, 'Zaporowy (rzeczny)', 35, 2.2, 4.5, 'Wyraźne koryto rzeki, liczne piaszczyste uskoki.', 'Twarde w osi rzeki, muliste na rozlewiskach.', 'Dobra; woda dobrze natleniona i chłodniejsza.', 'Bogata: pasy trzcin, lilie wodne, rdestnica.', 'Szczupak, Okoń, Leszcz, Lin, Jaź', TRUE, 'Systematyczne zarybienia przez okręg PZW Kielce.', TRUE, 'Standardowe składki PZW Kielce.', FALSE, FALSE, 'Dobra dzięki twardszym brzegom leśnym.', FALSE, TRUE, 'Dojazd drogami leśnymi i lokalnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80192, 'Rynnowe (rezerwat przyrody)', 160, 4.5, 11.8, 'Wąska, wyrównana rynna w osi jeziora.', 'Twarde: piasek polodowcowy i żwir.', 'Wysoka; woda wybitnie przejrzysta (leśna).', 'Umiarkowana: pasy trzcin, gęste łąki ramienic pod wodą.', 'Szczupak, Lin, Okoń, Leszcz, Krasnopióra', TRUE, 'Naturalna regeneracja; wsparcie narybkiem przez PZW.', TRUE, 'Składki PZW Suwałki; rygory rezerwatu przyrody.', FALSE, TRUE, 'Średnia (ograniczona rygorami ochronnymi).', FALSE, TRUE, 'Leśna piaszczysta; zakaz wjazdu nad samą wodę.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80193, 'Rynnowe przepływowe', 135, 5.8, 16.2, 'Bardzo urozmaicona: ostre stoki, głęboka rynna koryta Rospudy.', 'Bardzo twarde: kamienie, piasek, gruby żwir.', 'Wysoka (I klasa); woda chłodna i dobrze natleniona.', 'Skąpa: punktowe trzciny, brak roślinności miękkiej.', 'Sandacz, Szczupak, Okoń, Jaź, Płoć', TRUE, 'Regularne zarybianie sandaczem i drapieżnikiem.', TRUE, 'Licencja G.R. Suwałki; dostępne online.', FALSE, TRUE, 'Trudna przez strome, zalesione i osuwające się skarpy.', FALSE, TRUE, 'Dojazd leśny i utwardzony; lokalne zjazdy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80196, 'Wytopiskowe (kociołek)', 12, 6.5, 14.5, 'Kształt lejka; stromo opadające ku środkowi dno.', 'Twarde: czysty piasek, w centrum minimalny muł.', 'Ekstremalnie wysoka; woda krystaliczna.', 'Umiarkowana w litoralu: lilie wodne i moczarka.', 'Okoń, Szczupak, Płoć, Lin', TRUE, 'Oparta na naturalnym rozrodzie i wsparciu dzikim narybkiem.', TRUE, 'Standardowe składki PZW Suwałki.', FALSE, TRUE, 'Dobra dzięki wydeptanym w lesie stanowiskom.', FALSE, TRUE, 'Dojazd drogami leśnymi.', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80197, 'Eutroficzne (sztuczny zalew)', 35, 1.8, 2.5, 'Płaska misa z drobnymi przegłębieniami w osi rzeki.', 'Miękkie: muł organiczny i iły.', 'Niska; typowa dla zbiorników miejskich, żyzna.', 'Bardzo bogata: rozległe pasy moczarki i grążeli.', 'Karp, Amur, Leszcz, Karaś, Szczupak', TRUE, 'Bardzo intensywne zarybianie przez PZW (karp, drapieżnik).', TRUE, 'Składki PZW Białystok.', FALSE, FALSE, 'Bardzo dobra; świetnie przygotowana infrastruktura miejska.', TRUE, TRUE, 'Asfalt; dojazd miejski, duże parkingi BOSiR.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80198, 'Wyrobisko pożwirowe', 22, 6.5, 18, 'Ekstremalnie zróżnicowana: pionowe skarpy, półki, doły.', 'Bardzo twarde: gruby żwir i kamienie polne.', 'Bardzo wysoka; woda filtrująca się przez żwir.', 'Brak roślinności wynurzonej; skąpa podwodna.', 'Okoń, Szczupak, Karp (okazy), Płoć', TRUE, 'Zarybienia celowe (karp, sandacz) przez PZW.', TRUE, 'Składki PZW Ciechanów.', FALSE, FALSE, 'Średnia; skarpy strome i niebezpieczne dla wędkarzy.', FALSE, TRUE, 'Dojazd techniczny/szutrowy.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80199, 'Zalewowe / Wyrobisko rzecznie', 40, 3.5, 7.5, 'Pofałdowane dno po dawnej eksploatacji mas.', 'Mieszane: piach rzeczny z naniesionym mułem zalewowym.', 'Średnia; uzależniona od stanu wód rzeki Narew.', 'Bogata: gęste trzcinowiska, zalane krzewy i wierzby.', 'Boleń, Sum, Szczupak, Leszcz, Lin', TRUE, 'Naturalna potężna migracja z rzeki Narew podczas wylewów.', TRUE, 'Standardowe opłaty PZW Mazowsze.', FALSE, FALSE, 'Dobra dzięki naturalnym wyrwom w trzcinowiskach.', FALSE, TRUE, 'Polna/Łąkowa (trudny wjazd po deszczach).', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80200, 'Rynnowe leśne', 108, 4.2, 14.5, 'Rynna o asymetrycznych stokach, liczne piaszczyste wypłycenia.', 'Mieszane: piaszczysto-żwirowe na stokach, w zatokach miękkie.', 'Dobra; woda czysta, ale o typowo leśnym, ciemnym zabarwieniu.', 'Bogata: szerokie pola lilii wodnych i gęste grążele.', 'Lin, Wzdręga, Szczupak, Węgorz, Okoń', TRUE, 'Gospodarka ukierunkowana na drapieżnika i węgorza (G.R. Pisz).', TRUE, 'Licencja G.R. Pisz; standardowe opłaty mazurskie.', FALSE, TRUE, 'Średnia przez trzciny; doskonałe miejsca na pomostach.', TRUE, TRUE, 'Dojazd drogami leśnymi i piaszczystymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80371, 'Sielawowe (gigant)', 903, 14.5, 52, 'Krajobraz księżycowy: potężne góry, rynny i przepaście podwodne.', 'Wybitnie twarde: piasek, wapień i skały, brak mułu.', 'Ekstremalnie wysoka (I klasa); sielawowa widoczność.', 'Skąpa w toni; wąskie trzcinowiska w wybranych zatokach.', 'Sielawa, Szczupak pelagiczny, Okoń (gigant), Sandacz, Płoć', TRUE, 'Intensywne zarybianie sielawą i sandaczem przez G.R.', TRUE, 'Licencja G.R. Szwaderowo; opłaty online.', FALSE, TRUE, 'Dobra przy plażach, utrudniona z powodu stromych spadów.', TRUE, TRUE, 'Znakomity dojazd asfaltowy (Pluski).', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80396, 'Rynnowe przepływowe (rezerwatowe)', 1042, 16.2, 53, 'Wąska, monumentalnie głęboka rynna rzeki Łyny.', 'Bardzo twarde: kamienie, piasek.', 'Wysoka (I klasa); bardzo chłodna woda.', 'Skąpa: podwodne łąki mchów, rzadka trzcina.', 'Szczupak, Sandacz, Okoń, Sielawa, Leszcz', TRUE, 'Ochrona tarlisk naturalnych; silne stada drapieżnika.', TRUE, 'Licencja G.R. Szwaderowo; zakaz silników spalinowych.', FALSE, TRUE, 'Trudna przez zalesione i bardzo strome skarpy jeziora.', TRUE, TRUE, 'Dojazd drogami asfaltowymi/leśnymi.', TRUE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80473, 'Rynnowe (leśny rezerwat)', 45, 5.5, 16.5, 'Koryto Łyny rzeźbiące wyraźne uskoki, zatopione lasy.', 'Mieszane: piasek w osi, bardzo gruby detrytus liściasty.', 'Dobra (leśna, brunatna woda).', 'Zatopione drzewa, kępy grążeli i trzcin w płytkich strefach.', 'Okoń, Szczupak, Płoć, Lin', TRUE, 'Gospodarka ukierunkowana na zachowanie dzikiego stada.', TRUE, 'Licencja PZW Olsztyn; surowe rygory rezerwatu leśnego.', FALSE, TRUE, 'Bardzo trudna; ograniczona przez powalone drzewa i rezerwat.', FALSE, TRUE, 'Drogi leśne (tylko pieszo na ostatnim odcinku).', FALSE);
INSERT INTO public.map_lakes (id, lake_type, area_hectares, avg_depth, max_depth, bottom_formation, bottom_type, water_clarity, vegetation, dominant_species, has_predators, stocking_info, requires_permit, permit_cost_info, catch_and_release, silent_zone, shore_fishing, has_piers, boat_fishing_allowed, access_road, has_parking) VALUES (80474, 'Rynnowe leśne', 28, 6.5, 21, 'Rogalikowata, bardzo głęboka rynna z gwałtownymi stokami.', 'Twarde: piasek polodowcowy z cienką warstwą mułu w głębinach.', 'Wysoka; wybitnie przejrzysta woda zasilająca bory.', 'Umiarkowana: wąski pas trzcin, bardzo gęste łąki rdestnicy.', 'Okoń, Szczupak, Płoć, Leszcz', TRUE, 'Naturalna regeneracja; jezioro rzadko odławiane.', TRUE, 'Licencja G.R. Szwaderowo.', FALSE, TRUE, 'Średnia ze względu na gwałtowne usypiska i stromy brzeg.', FALSE, TRUE, 'Dojazd leśnymi, utwardzonymi szutrami.', FALSE);
